    "\u041e\u0442\u043a\u0440\u044b\u0432\u0430\u0439 \u044d\u0442\u0443 \u043f\u0430\u043d\u0435\u043b\u044c \u0442\u043e\u043b\u044c\u043a\u043e \u043a\u043e\u0433\u0434\u0430 \u043d\u0443\u0436\u043d\u043e \u0441\u043e\u0445\u0440\u0430\u043d\u0438\u0442\u044c \u0438\u043b\u0438 \u043f\u043e\u043f\u0440\u0430\u0432\u0438\u0442\u044c \u0443\u0437\u0435\u043b.",
  "deviceNodes.fleet.cards.online": "\u041e\u043d\u043b\u0430\u0439\u043d",
  "deviceNodes.fleet.cards.degraded": "\u0414\u0435\u0433\u0440\u0430\u0434\u0438\u0440\u043e\u0432\u0430\u043d",
  "deviceNodes.fleet.cards.offline": "\u041e\u0444\u0444\u043b\u0430\u0439\u043d",
  "deviceNodes.fleet.cards.stale": "\u0423\u0441\u0442\u0430\u0440\u0435\u0432\u0448\u0438\u0435",
  "deviceNodes.populated.intro":
    "\u0424\u043b\u043e\u0442 \u0443\u0436\u0435 \u0433\u043e\u0442\u043e\u0432. \u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0432\u044b\u0431\u0435\u0440\u0438 \u0443\u0437\u0435\u043b, \u0430 \u0442\u043e\u0447\u0435\u0447\u043d\u044b\u0435 \u043f\u0440\u043e\u0432\u0435\u0440\u043a\u0438 \u0434\u0435\u0440\u0436\u0438 \u0432\u0442\u043e\u0440\u0438\u0447\u043d\u044b\u043c\u0438.",
  "deviceNodes.populated.quickStart.kicker": "\u0424\u043b\u043e\u0442 \u0433\u043e\u0442\u043e\u0432",
  "deviceNodes.populated.quickStart.heading": "\u0424\u043b\u043e\u0442 \u0433\u043e\u0442\u043e\u0432 \u043a \u043e\u0431\u0437\u043e\u0440\u0443",
  "deviceNodes.populated.quickStart.copy":
    "\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u043f\u0440\u043e\u0432\u0435\u0440\u044c \u0446\u0435\u043b\u044c, \u043c\u0430\u0440\u0448\u0440\u0443\u0442 \u0438 heartbeat \u043d\u0438\u0436\u0435. \u041f\u0440\u043e\u0432\u0435\u0440\u043a\u0438 \u0438 \u0440\u0435\u0434\u0430\u043a\u0442\u043e\u0440 \u043e\u0442\u043a\u0440\u044b\u0432\u0430\u0439 \u0442\u043e\u043b\u044c\u043a\u043e \u043f\u043e \u0437\u0430\u043f\u0440\u043e\u0441\u0443.",
  "deviceNodes.populated.guide.kicker": "\u041f\u0440\u0430\u0432\u0430",
  "deviceNodes.populated.guide.heading": "Admin \u043d\u0443\u0436\u0435\u043d \u0442\u043e\u043b\u044c\u043a\u043e \u0434\u043b\u044f \u0437\u0430\u043f\u0438\u0441\u0438",
  "deviceNodes.populated.guide.copy":
    "\u0414\u043b\u044f \u0447\u0442\u0435\u043d\u0438\u044f \u0438 \u043f\u0440\u043e\u0432\u0435\u0440\u043e\u043a \u0445\u0432\u0430\u0442\u0438\u0442 operator. \u0412 admin \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0430\u0439\u0441\u044f \u0442\u043e\u043b\u044c\u043a\u043e \u0434\u043b\u044f \u0434\u043e\u0431\u0430\u0432\u043b\u0435\u043d\u0438\u044f \u0438\u043b\u0438 \u043f\u0440\u0430\u0432\u043a\u0438.",
  "deviceNodes.populated.guide.muted":
    "\u0414\u0435\u0440\u0436\u0438 \u044d\u0442\u043e\u0442 \u0440\u0435\u0434\u0430\u043a\u0442\u043e\u0440 \u0437\u0430\u043a\u0440\u044b\u0442\u044b\u043c, \u043f\u043e\u043a\u0430 identity \u0438\u043b\u0438 routing \u0440\u0435\u0430\u043b\u044c\u043d\u043e \u043d\u0435 \u043d\u0443\u0436\u043d\u043e \u043c\u0435\u043d\u044f\u0442\u044c.",
  "deviceNodes.advanced.hint": "\u041e\u0442\u043a\u0440\u044b\u0432\u0430\u0439 \u0442\u043e\u043b\u044c\u043a\u043e \u0434\u043b\u044f \u043f\u0440\u043e\u0432\u0435\u0440\u043e\u043a \u043f\u043e \u043e\u0434\u043d\u043e\u043c\u0443 \u0432\u044b\u0431\u0440\u0430\u043d\u043d\u043e\u043c\u0443 \u0443\u0437\u043b\u0443.",
