  "deviceNodes.advanced.actionsHint":
    "\u0414\u0435\u0440\u0436\u0438 \u044d\u0442\u0443 \u043f\u0430\u043d\u0435\u043b\u044c \u043a\u043e\u0440\u043e\u0442\u043a\u043e\u0439: \u043f\u0435\u0439\u043b\u043e\u0430\u0434 \u0438 \u0432\u0438\u0434 \u0444\u043b\u043e\u0442\u0430 \u043e\u0442\u043a\u0440\u044b\u0432\u0430\u0439 \u0442\u043e\u043b\u044c\u043a\u043e \u043a\u043e\u0433\u0434\u0430 \u043d\u0443\u0436\u0435\u043d \u0434\u043e\u043f\u043a\u043e\u043d\u0442\u0435\u043a\u0441\u0442.",
