      currentHint: isRu
        ? "\u041d\u0438\u0436\u0435 \u043e\u0442\u043a\u0440\u044b\u0442 \u0441\u043b\u0443\u0436\u0435\u0431\u043d\u044b\u0439 \u0442\u0440\u0435\u0439: \u043c\u0438\u043a\u0440\u043e\u0444\u043e\u043d, \u0441\u0435\u0441\u0441\u0438\u044f \u0438 \u044d\u043a\u0441\u043f\u043e\u0440\u0442."
        : "The utility tray below contains mic, session, and export tools.",
