function nowLabel() {
  return new Date().toLocaleTimeString();
}

function makeId() {
  if (window.crypto?.randomUUID) {
    return window.crypto.randomUUID();
  }
  return `id-${Date.now()}-${Math.floor(Math.random() * 100000)}`;
}

function normalizeThemeMode(value) {
  return value === "light" ? "light" : "dark";
}

function readStoredThemeMode() {
  try {
    const stored = window.localStorage?.getItem(THEME_STORAGE_KEY);
    return normalizeThemeMode(stored);
  } catch {
    return "dark";
  }
}

function normalizeLanguageMode(value) {
  return value === "ru" ? "ru" : "en";
}

function readStoredLanguageMode() {
  try {
    const stored = window.localStorage?.getItem(LANGUAGE_STORAGE_KEY);
    return normalizeLanguageMode(stored);
  } catch {
    return "en";
  }
}

function formatLocalizedCopy(template, values = {}) {
  if (typeof template !== "string" || template.length === 0) {
    return "";
  }
  return template.replace(/\{(\w+)\}/g, (match, key) => {
    const value = values[key];
    return value === undefined || value === null ? match : String(value);
  });
}

function t(key, values = null, fallback = "") {
  const languageMode = normalizeLanguageMode(state.languageMode);
  const languagePack = UI_LANGUAGE_COPY[languageMode] ?? UI_LANGUAGE_COPY.en;
  const template = languagePack[key] ?? UI_LANGUAGE_COPY.en[key] ?? fallback;
  if (typeof template !== "string") {
    return typeof fallback === "string" ? fallback : "";
  }
  return values && typeof values === "object" ? formatLocalizedCopy(template, values) : template;
}

function getLiveTargetLanguageValue() {
  const rawValue =
    el.targetLanguage instanceof HTMLInputElement || el.targetLanguage instanceof HTMLSelectElement
      ? el.targetLanguage.value.trim()
      : "";
  return rawValue.length > 0 ? rawValue : "en";
}

function getLiveTargetLanguageDisplayLabel() {
  if (el.targetLanguage instanceof HTMLSelectElement) {
    const selectedOption = el.targetLanguage.options.item(el.targetLanguage.selectedIndex);
    const optionLabel = typeof selectedOption?.textContent === "string" ? selectedOption.textContent.trim() : "";
    if (optionLabel.length > 0) {
      return optionLabel;
    }
  }
  return getLiveTargetLanguageValue();
}

function getLiveSpeechLanguageValue() {
  const rawValue =
    el.speechLanguage instanceof HTMLInputElement || el.speechLanguage instanceof HTMLSelectElement
      ? el.speechLanguage.value.trim()
      : "";
  if (rawValue.length > 0 && rawValue !== "browser") {
    return rawValue;
  }
  if (typeof navigator === "object" && navigator && Array.isArray(navigator.languages)) {
    const firstPreferred = navigator.languages.find(
      (value) => typeof value === "string" && value.trim().length > 0,
    );
    if (typeof firstPreferred === "string" && firstPreferred.trim().length > 0) {
      return firstPreferred.trim();
    }
  }
  if (typeof navigator === "object" && navigator && typeof navigator.language === "string") {
    const normalized = navigator.language.trim();
    if (normalized.length > 0) {
      return normalized;
    }
  }
  return state.languageMode === "ru" ? "ru-RU" : "en-US";
}

function getLiveSpeechLanguageDisplayLabel() {
  if (el.speechLanguage instanceof HTMLSelectElement) {
    const selectedOption = el.speechLanguage.options.item(el.speechLanguage.selectedIndex);
    const optionLabel = typeof selectedOption?.textContent === "string" ? selectedOption.textContent.trim() : "";
    if (optionLabel.length > 0) {
      return optionLabel;
    }
  }
  return getLiveSpeechLanguageValue();
}

function getLiveTranslationDirectionSummary(intent = getCurrentLiveIntentValue()) {
  if (!shouldUseMicTranslationCapture(intent)) {
    return {
      visible: false,
      label: "",
      value: "",
    };
  }
  const isRu = state.languageMode === "ru";
  return {
    visible: true,
    label: isRu ? "Направление перевода" : "Translation direction",
    value: `${getLiveSpeechLanguageDisplayLabel()} -> ${getLiveTargetLanguageDisplayLabel()}`,
  };
}

function syncLiveTranslationDirectionSummary(intent = getCurrentLiveIntentValue()) {
  const summary = getLiveTranslationDirectionSummary(intent);
  if (!(el.translationDirectionSummary instanceof HTMLElement)) {
    return summary;
  }
  el.translationDirectionSummary.hidden = !summary.visible;
  el.translationDirectionSummary.setAttribute("aria-hidden", summary.visible ? "false" : "true");
  if (el.translationDirectionSummaryLabel instanceof HTMLElement) {
    el.translationDirectionSummaryLabel.textContent = summary.label;
  }
  if (el.translationDirectionSummaryValue instanceof HTMLElement) {
    el.translationDirectionSummaryValue.textContent = summary.value;
  }
  return summary;
}

