function getLiveResultActionConfig(intent, latestResult, hasIntentMatchedResult) {
  const normalizedIntent = typeof intent === "string" && intent.trim().length > 0 ? intent.trim() : "conversation";
  if (!hasIntentMatchedResult || normalizedIntent !== "story") {
    return null;
  }
  if (!latestResult || latestResult.role === "error" || latestResult.streaming === true) {
    return null;
  }
  return {
    action: "story_view",
    label: state.languageMode === "ru" ? "Открыть Сторителлер" : "Open Storyteller",
  };
}

