          hint: isRu ? "\u041f\u0435\u0440\u0435\u0447\u0438\u0442\u044b\u0432\u0430\u0435\u0442 runtime-\u0441\u0442\u0430\u0442\u0443\u0441\u044b \u0438 evidence." : "Reload runtime health and evidence cards.",
