function renderDashboardWorkspace(tabId = null) {
  const resolvedTabId = resolveTabId(tabId ?? tabButtons.find((button) => button.classList.contains("active"))?.dataset.tabTarget);
  const config = getDashboardWorkspaceConfig(resolvedTabId);
  const isStoryTab = resolvedTabId === "storyteller";
  const isOperatorTab = resolvedTabId === "operator";
  const isDeviceTab = resolvedTabId === "device-nodes";
  const workspaceSummary =
    el.workspaceTitle instanceof HTMLElement ? el.workspaceTitle.closest(".dashboard-workspace-summary") : null;
  const layoutRoot = document.querySelector(".layout");
  const dashboardBody = document.querySelector(".dashboard-body");
  const dashboardSidebar = document.querySelector(".dashboard-sidebar");

  if (workspaceSummary instanceof HTMLElement) {
    workspaceSummary.classList.toggle("is-story-minimal", isStoryTab);
    workspaceSummary.classList.toggle("is-operator-minimal", isOperatorTab);
    workspaceSummary.classList.toggle("is-device-minimal", isDeviceTab);
    workspaceSummary.classList.toggle(
      "is-device-populated",
      isDeviceTab && state.deviceNodes instanceof Map && state.deviceNodes.size > 0,
    );
  }
  if (layoutRoot instanceof HTMLElement) {
    layoutRoot.classList.toggle("is-story-focused", isStoryTab);
    layoutRoot.dataset.activeTab = resolvedTabId;
  }
  if (dashboardBody instanceof HTMLElement) {
    dashboardBody.classList.toggle("is-story-focused", isStoryTab);
  }
  if (dashboardSidebar instanceof HTMLElement) {
    dashboardSidebar.classList.toggle("is-story-focused", isStoryTab);
  }

  if (el.tabLiveHint instanceof HTMLElement) {
    el.tabLiveHint.textContent = config.navHints.live;
  }
  if (el.tabStoryHint instanceof HTMLElement) {
    el.tabStoryHint.textContent = config.navHints.story;
  }
  if (el.tabOperatorHint instanceof HTMLElement) {
    el.tabOperatorHint.textContent = config.navHints.operator;
  }
  if (el.tabDeviceHint instanceof HTMLElement) {
    el.tabDeviceHint.textContent = config.navHints.device;
  }
  if (el.workspaceEyebrow instanceof HTMLElement) {
    el.workspaceEyebrow.textContent = config.eyebrow;
  }
  if (el.workspaceTitle instanceof HTMLElement) {
    el.workspaceTitle.textContent = config.title;
  }
  if (el.workspaceDescription instanceof HTMLElement) {
    el.workspaceDescription.textContent = config.description;
  }
  if (el.workspaceStatusBadge instanceof HTMLElement) {
    setStatusPill(el.workspaceStatusBadge, config.statusText, config.statusTone);
  }

  setDashboardGlanceCard(el.workspaceGlanceOneLabel, el.workspaceGlanceOneValue, el.workspaceGlanceOneHint, config.glances[0]);
  setDashboardGlanceCard(el.workspaceGlanceTwoLabel, el.workspaceGlanceTwoValue, el.workspaceGlanceTwoHint, config.glances[1]);
  setDashboardGlanceCard(el.workspaceGlanceThreeLabel, el.workspaceGlanceThreeValue, el.workspaceGlanceThreeHint, config.glances[2]);
}

function setUiTaskFieldsVisibility() {
  if (!el.uiTaskFields || !el.intent) {
    renderLiveContextDock();
    renderLiveIntentExperience();
    renderDashboardWorkspace();
    return;
  }
  const intent = typeof el.intent.value === "string" ? el.intent.value.trim() : "";
  const isUiTaskIntent = intent === "ui_task";
  el.uiTaskFields.hidden = !isUiTaskIntent;
  el.uiTaskFields.setAttribute("aria-hidden", isUiTaskIntent ? "false" : "true");
  if (el.uiTaskAdvancedSection) {
    el.uiTaskAdvancedSection.hidden = !isUiTaskIntent;
    el.uiTaskAdvancedSection.setAttribute("aria-hidden", isUiTaskIntent ? "false" : "true");
    el.uiTaskAdvancedSection.open = isUiTaskIntent;
  }
  if (LIVE_INTENT_SECONDARY_CARD_ORDER.includes(intent)) {
    setActiveLiveContextPanel("workflow", { force: true });
  } else if (state.liveContextDockPanel === "workflow") {
    setActiveLiveContextPanel(null, { force: true });
  } else {
    renderLiveContextDock();
  }
  renderLiveIntentExperience();
  renderDashboardWorkspace();
}

function closeAllCustomSelectMenus(exceptShell = null) {
  for (const shell of customSelectShells) {
    if (!(shell instanceof HTMLElement)) {
      continue;
    }
    if (exceptShell && shell === exceptShell) {
      continue;
    }
    shell.classList.remove("is-open");
    const trigger = shell.querySelector(".select-trigger");
    if (trigger instanceof HTMLButtonElement) {
      trigger.setAttribute("aria-expanded", "false");
      trigger.removeAttribute("aria-activedescendant");
    }
  }
}

function syncCustomSelectControl(select) {
  if (!(select instanceof HTMLSelectElement)) {
    return;
  }
  const shell = select.closest(".select-shell");
  const sync = shell?.__syncCustomSelect;
  if (typeof sync === "function") {
    sync();
  }
}

function syncAllCustomSelectControls() {
  for (const shell of customSelectShells) {
    if (!(shell instanceof HTMLElement)) {
      continue;
    }
    const sync = shell.__syncCustomSelect;
    if (typeof sync === "function") {
      sync();
    }
  }
}

function getCustomSelectOptionDescription(selectId, optionValue) {
  const normalizedSelectId = typeof selectId === "string" ? selectId.trim() : "";
  if (!normalizedSelectId) {
    return "";
  }
  const descriptions = CUSTOM_SELECT_OPTION_DESCRIPTIONS[normalizedSelectId];
  if (!descriptions || typeof descriptions !== "object") {
    return "";
  }
  const normalizedValue = optionValue ?? "";
  const description = descriptions[normalizedValue];
  return typeof description === "string" ? description : "";
}

function ensureCustomSelectDismissHandlers() {
  if (ensureCustomSelectDismissHandlers.bound === true) {
    return;
  }
  document.addEventListener("pointerdown", (event) => {
    const target = event.target;
    if (!(target instanceof Node)) {
      return;
    }
    for (const shell of customSelectShells) {
      if (shell instanceof HTMLElement && shell.contains(target)) {
        return;
      }
    }
    closeAllCustomSelectMenus();
  });
  document.addEventListener("keydown", (event) => {
    if (event.key === "Escape") {
      closeAllCustomSelectMenus();
    }
  });
  ensureCustomSelectDismissHandlers.bound = true;
}
ensureCustomSelectDismissHandlers.bound = false;

function createCustomSelect(select) {
  if (!(select instanceof HTMLSelectElement)) {
    return;
  }
  if (CUSTOM_SELECT_EXCLUDE_IDS.has(select.id)) {
    return;
  }
  if (select.dataset.customSelectEnhanced === "true") {
    return;
  }

  select.dataset.customSelectEnhanced = "true";
  select.classList.add("select-native-enhanced");
  select.setAttribute("aria-hidden", "true");
  select.tabIndex = -1;
  select.addEventListener("mousedown", (event) => {
    event.preventDefault();
  });

  const parent = select.parentElement;
  if (!parent) {
    return;
  }

  const shell = document.createElement("div");
  shell.className = "select-shell";
  parent.insertBefore(shell, select);
  shell.appendChild(select);

  const trigger = document.createElement("button");
  trigger.type = "button";
  trigger.className = "select-trigger";
  trigger.setAttribute("role", "combobox");
  trigger.setAttribute("aria-haspopup", "listbox");
  trigger.setAttribute("aria-autocomplete", "none");
  trigger.setAttribute("aria-expanded", "false");
  const triggerId = select.id ? `${select.id}-trigger` : `select-trigger-${makeId()}`;
  trigger.id = triggerId;
  const fieldLabel = select.closest(".field")?.querySelector(":scope > span");
  if (fieldLabel instanceof HTMLElement) {
    const labelId = fieldLabel.id || `${triggerId}-label`;
    fieldLabel.id = labelId;
    trigger.setAttribute("aria-labelledby", labelId);
  }
  shell.appendChild(trigger);

  const menu = document.createElement("div");
  menu.className = "select-menu";
  menu.setAttribute("role", "listbox");
  const menuId = `${select.id || `select-${makeId()}`}-menu`;
  menu.id = menuId;
  trigger.setAttribute("aria-controls", menuId);
  menu.setAttribute("aria-labelledby", triggerId);
  shell.appendChild(menu);

  const setCustomSelectActiveDescendant = (optionButton = null) => {
    if (optionButton instanceof HTMLButtonElement && optionButton.id) {
      trigger.setAttribute("aria-activedescendant", optionButton.id);
      return;
    }
    trigger.removeAttribute("aria-activedescendant");
  };

  const getEnabledOptionButtons = () =>
    Array.from(menu.querySelectorAll(".select-option")).filter(
      (node) => node instanceof HTMLButtonElement && !node.disabled,
    );

  const focusCustomSelectOptionByIndex = (index) => {
    const options = getEnabledOptionButtons();
    if (options.length === 0) {
      return;
    }
    const boundedIndex = Math.max(0, Math.min(options.length - 1, index));
    const nextOption = options[boundedIndex];
    setCustomSelectActiveDescendant(nextOption);
    nextOption.focus();
  };

  const focusCustomSelectOptionByOffset = (currentOption, offset) => {
    const options = getEnabledOptionButtons();
    if (options.length === 0) {
      return;
    }
    const currentIndex = options.findIndex((option) => option === currentOption);
    if (currentIndex < 0) {
      focusCustomSelectOptionByIndex(offset >= 0 ? 0 : options.length - 1);
      return;
    }
    const nextIndex = (currentIndex + offset + options.length) % options.length;
    options[nextIndex].focus();
  };

  const focusSelectedCustomSelectOption = (fallbackEdge = "start") => {
    const options = getEnabledOptionButtons();
    if (options.length === 0) {
      return;
    }
    const selectedOption = options.find((option) => option.classList.contains("is-selected"));
    if (selectedOption instanceof HTMLButtonElement) {
      setCustomSelectActiveDescendant(selectedOption);
      selectedOption.focus();
      return;
    }
    if (fallbackEdge === "end") {
      const option = options[options.length - 1];
      setCustomSelectActiveDescendant(option);
      option.focus();
      return;
    }
    const option = options[0];
    setCustomSelectActiveDescendant(option);
    option.focus();
  };

  const syncCustomSelectMenuPlacement = () => {
    shell.classList.remove("is-open-upward");
    menu.style.removeProperty("max-height");
    if (!shell.classList.contains("is-open")) {
      return;
    }
    const shellRect = shell.getBoundingClientRect();
    const viewportHeight =
      window.innerHeight ||
      document.documentElement?.clientHeight ||
      document.body?.clientHeight ||
      0;
    const viewportPadding = 16;
    const menuOffset = 8;
    const measuredMenuHeight = Math.max(menu.scrollHeight, 0);
    const preferredMenuHeight = Math.min(Math.max(measuredMenuHeight, 180), 320);
    const spaceBelow = Math.max(0, viewportHeight - shellRect.bottom - viewportPadding - menuOffset);
    const spaceAbove = Math.max(0, shellRect.top - viewportPadding - menuOffset);
    const shouldOpenUpward = spaceBelow < preferredMenuHeight && spaceAbove > spaceBelow;
    const availableSpace = shouldOpenUpward ? spaceAbove : spaceBelow;
    shell.classList.toggle("is-open-upward", shouldOpenUpward);
    if (availableSpace > 0) {
      menu.style.maxHeight = `${Math.max(140, Math.floor(availableSpace))}px`;
    }
  };

  const closeCustomSelectMenu = (restoreTriggerFocus = false) => {
    shell.classList.remove("is-open");
    shell.classList.remove("is-open-upward");
    trigger.setAttribute("aria-expanded", "false");
    setCustomSelectActiveDescendant();
    menu.style.removeProperty("max-height");
    if (restoreTriggerFocus) {
      trigger.focus();
    }
  };

  const openCustomSelectMenu = (focusEdge = "start") => {
    if (trigger.disabled) {
      return;
    }
    closeAllCustomSelectMenus(shell);
    shell.classList.add("is-open");
    trigger.setAttribute("aria-expanded", "true");
    syncCustomSelectMenuPlacement();
    focusSelectedCustomSelectOption(focusEdge);
  };

  const syncCustomSelect = () => {
    const selectedOption = select.options[select.selectedIndex] ?? null;
    const selectedText =
      selectedOption?.textContent?.trim() ??
      selectedOption?.label?.trim() ??
      selectedOption?.value ??
      "";
    trigger.textContent = selectedText || "Select option";
    trigger.disabled = select.disabled;
    trigger.setAttribute("aria-disabled", select.disabled ? "true" : "false");

    setCustomSelectActiveDescendant();
    menu.innerHTML = "";
    const optionIdRoot = select.id ? `${select.id}-option` : `select-option-${makeId()}`;
    for (const option of Array.from(select.options)) {
      const optionButton = document.createElement("button");
      optionButton.type = "button";
      optionButton.className = "select-option";
      optionButton.setAttribute("role", "option");
      optionButton.dataset.value = option.value;
      optionButton.id = `${optionIdRoot}-${menu.childElementCount}`;
      optionButton.setAttribute("aria-selected", option.selected ? "true" : "false");
      optionButton.setAttribute("aria-disabled", option.disabled ? "true" : "false");
      optionButton.disabled = option.disabled;
      if (option.selected) {
        optionButton.classList.add("is-selected");
      }

      const optionLabel = document.createElement("span");
      optionLabel.className = "select-option-label";
      optionLabel.textContent = option.textContent?.trim() || option.value;
      optionButton.appendChild(optionLabel);

      const optionDescription = getCustomSelectOptionDescription(select.id, option.value);
      if (optionDescription) {
        const optionHint = document.createElement("small");
        optionHint.textContent = optionDescription;
        optionButton.appendChild(optionHint);
      }

      optionButton.addEventListener("click", () => {
        if (option.disabled) {
          return;
        }
        select.value = option.value;
        select.dispatchEvent(new Event("change", { bubbles: true }));
        syncCustomSelect();
        closeCustomSelectMenu();
      });

      optionButton.addEventListener("keydown", (event) => {
        if (event.key === "ArrowDown") {
          event.preventDefault();
          focusCustomSelectOptionByOffset(optionButton, 1);
          return;
        }
        if (event.key === "ArrowUp") {
          event.preventDefault();
          focusCustomSelectOptionByOffset(optionButton, -1);
          return;
        }
        if (event.key === "Home") {
          event.preventDefault();
          focusCustomSelectOptionByIndex(0);
          return;
        }
        if (event.key === "End") {
          event.preventDefault();
          const options = getEnabledOptionButtons();
          focusCustomSelectOptionByIndex(Math.max(0, options.length - 1));
          return;
        }
        if (event.key === "Escape") {
          event.preventDefault();
          closeCustomSelectMenu(true);
          return;
        }
        if (event.key === "Tab") {
          closeCustomSelectMenu();
        }
      });

      optionButton.addEventListener("focus", () => {
        setCustomSelectActiveDescendant(optionButton);
      });

      menu.appendChild(optionButton);
    }
    syncCustomSelectMenuPlacement();
  };

  trigger.addEventListener("click", (event) => {
    event.preventDefault();
    const willOpen = !shell.classList.contains("is-open");
    if (willOpen) {
      openCustomSelectMenu("start");
      return;
    }
    closeCustomSelectMenu();
  });

  trigger.addEventListener("keydown", (event) => {
    if (event.key === "Enter" || event.key === " ") {
      event.preventDefault();
      if (shell.classList.contains("is-open")) {
        closeCustomSelectMenu();
        return;
      }
      openCustomSelectMenu("start");
      return;
    }
    if (event.key === "ArrowDown") {
      event.preventDefault();
      openCustomSelectMenu("start");
      return;
    }
    if (event.key === "ArrowUp") {
      event.preventDefault();
      openCustomSelectMenu("end");
      return;
    }
    if (event.key === "Escape" && shell.classList.contains("is-open")) {
      event.preventDefault();
      closeCustomSelectMenu();
    }
  });

  select.addEventListener("change", syncCustomSelect);

  const observer = new MutationObserver(() => {
    syncCustomSelect();
  });
  observer.observe(select, {
    childList: true,
    subtree: true,
    attributes: true,
    attributeFilter: ["disabled", "label"],
  });

  shell.addEventListener("keydown", (event) => {
    if (event.key === "Escape") {
      closeCustomSelectMenu(true);
    }
  });

  window.addEventListener("resize", () => {
    syncCustomSelectMenuPlacement();
  });
  document.addEventListener(
    "scroll",
    () => {
      syncCustomSelectMenuPlacement();
    },
    true,
  );

  shell.__syncCustomSelect = syncCustomSelect;
  customSelectShells.add(shell);
  ensureCustomSelectDismissHandlers();
  syncCustomSelect();
}

function enhanceSelectControls() {
  const selects = document.querySelectorAll("select");
  for (const node of selects) {
    if (node instanceof HTMLSelectElement) {
      createCustomSelect(node);
    }
  }
}

function observeCustomSelectControls() {
  if (customSelectObserver instanceof MutationObserver) {
    return;
  }

  if (!(document.body instanceof HTMLElement)) {
    return;
  }

  customSelectObserver = new MutationObserver((entries) => {
    for (const entry of entries) {
      for (const node of entry.addedNodes) {
        if (node instanceof HTMLSelectElement) {
          createCustomSelect(node);
          continue;
        }
        if (!(node instanceof HTMLElement)) {
          continue;
        }
        const nestedSelects = node.querySelectorAll("select");
        for (const nestedSelect of nestedSelects) {
          if (nestedSelect instanceof HTMLSelectElement) {
            createCustomSelect(nestedSelect);
          }
        }
      }
    }
  });

  customSelectObserver.observe(document.body, {
    childList: true,
    subtree: true,
  });
}

function initFilePickerControl(input, options = {}) {
  if (!(input instanceof HTMLInputElement) || input.type !== "file" || !input.id) {
    return;
  }

  const shell = document.querySelector(`[data-file-picker-for="${input.id}"]`);
  if (!(shell instanceof HTMLElement)) {
    return;
  }

  const trigger = shell.querySelector("[data-file-picker-trigger]");
  const nameNode = shell.querySelector("[data-file-picker-name]");
  if (!(trigger instanceof HTMLButtonElement) || !(nameNode instanceof HTMLElement)) {
    return;
  }

  const emptyLabel = typeof options.emptyLabel === "string" && options.emptyLabel.trim()
    ? options.emptyLabel.trim()
    : "No file selected";
  const buttonLabel = typeof options.buttonLabel === "string" && options.buttonLabel.trim()
    ? options.buttonLabel.trim()
    : "Choose file";

  trigger.textContent = buttonLabel;
  trigger.setAttribute("aria-controls", input.id);

  const syncFilePicker = () => {
    const file = input.files && input.files.length > 0 ? input.files[0] : null;
    if (file) {
      nameNode.textContent = file.name;
      nameNode.classList.remove("is-empty");
    } else {
      nameNode.textContent = emptyLabel;
      nameNode.classList.add("is-empty");
    }
    trigger.disabled = input.disabled;
  };

  trigger.addEventListener("click", () => {
    if (!input.disabled) {
      input.click();
    }
  });

  shell.addEventListener("click", (event) => {
    if (input.disabled) {
      return;
    }
    if (event.target instanceof Node && trigger.contains(event.target)) {
      return;
    }
    input.click();
  });

  input.addEventListener("change", syncFilePicker);
  input.addEventListener("input", syncFilePicker);
  syncFilePicker();
}

function initFilePickerControls() {
  initFilePickerControl(el.imageInput, {
    buttonLabel: t("filePicker.chooseImage"),
    emptyLabel: t("filePicker.noImage"),
  });
  initFilePickerControl(el.audioInput, {
    buttonLabel: t("filePicker.chooseAudio"),
    emptyLabel: t("filePicker.noAudio"),
  });
}

function setOperatorGroupCollapsed(group, collapsed) {
  if (!(group instanceof HTMLElement)) {
    return;
  }
  const isCollapsed = collapsed === true;
  group.classList.toggle("is-collapsed", isCollapsed);
  const toggle = group.querySelector("[data-operator-group-toggle]");
  if (toggle instanceof HTMLButtonElement) {
    toggle.setAttribute("aria-expanded", isCollapsed ? "false" : "true");
    toggle.textContent = isCollapsed ? "Open lane" : "Hide details";
  }
  syncOperatorGroupCardHierarchy(group);
  syncOperatorBoardCardPresentationTitles();
}

function getVisibleOperatorGroups() {
  return Array.from(document.querySelectorAll(".operator-health-group")).filter(
    (group) => !group.classList.contains("operator-health-group-hidden"),
  );
}

function getOperatorGroupPriorityMeta(group) {
  if (!(group instanceof HTMLElement)) {
    return null;
  }

  const key = typeof group.dataset.operatorGroup === "string" ? group.dataset.operatorGroup.trim() : "";
  const baseOrder = Number.isFinite(OPERATOR_GROUP_BASE_ORDER[key]) ? OPERATOR_GROUP_BASE_ORDER[key] : 99;
  if (group.classList.contains("operator-health-group-hidden")) {
    return {
      group,
      key,
      stateLabel: "dormant",
      priorityBucket: 5,
      baseOrder,
    };
  }

  const cards = Array.from(group.querySelectorAll(".operator-health-card"));
  let hasFail = false;
  let hasWatch = false;
  let hasStale = false;
  let hasOk = false;
  let hasDormant = false;

  for (const card of cards) {
    if (!(card instanceof HTMLElement) || card.classList.contains("operator-health-card-hidden")) {
      continue;
    }
    const statusNode = card.querySelector(".status-pill");
    const statusCode = getOperatorStatusCode(statusNode);
    if (statusCode === "summary_stale") {
      hasStale = true;
      continue;
    }
    if (isOperatorUninitializedStatusText(statusCode)) {
      hasDormant = true;
      continue;
    }
    const variant = readOperatorStatusVariant(statusNode);
    if (variant === "fail") {
      hasFail = true;
      continue;
    }
    if (variant === "ok") {
      hasOk = true;
      continue;
    }
    hasWatch = true;
  }

  let stateLabel = "dormant";
  let priorityBucket = 4;
  if (hasFail) {
    stateLabel = "fail";
    priorityBucket = 0;
  } else if (hasWatch) {
    stateLabel = "watch";
    priorityBucket = 1;
  } else if (hasStale) {
    stateLabel = "stale";
    priorityBucket = 2;
  } else if (hasOk) {
    stateLabel = "ok";
    priorityBucket = 3;
  } else if (hasDormant) {
    stateLabel = "dormant";
    priorityBucket = 4;
  }

  return {
    group,
    key,
    stateLabel,
    priorityBucket,
    baseOrder,
  };
}

function syncOperatorGroupPriorities() {
  const metas = Array.from(document.querySelectorAll(".operator-health-group"))
    .map((group) => getOperatorGroupPriorityMeta(group))
    .filter(Boolean);
  for (const meta of metas) {
    meta.group.dataset.operatorGroupState = meta.stateLabel;
    meta.group.style.order = String(meta.priorityBucket * 10 + meta.baseOrder);
  }
  return metas.sort((left, right) => (left.priorityBucket - right.priorityBucket) || (left.baseOrder - right.baseOrder));
}

function applyOperatorDefaultGroupFocus() {
  if (state.operatorSummaryUserRefreshed === true) {
    return;
  }
  const visibleGroups = getVisibleOperatorGroups();
  if (visibleGroups.length === 0) {
    return;
  }
  for (const group of visibleGroups) {
    const key = group.getAttribute("data-operator-group");
    setOperatorGroupCollapsed(group, key !== "bridge-safety");
  }
}

function applyOperatorDemoGroupPreset() {
  const metas = syncOperatorGroupPriorities();
  if (metas.length === 0) {
    syncOperatorCollapseActionButtons();
    return;
  }

  if (state.operatorSummaryUserRefreshed !== true) {
    for (const meta of metas) {
      setOperatorGroupCollapsed(meta.group, meta.key !== "bridge-safety");
    }
    syncOperatorCollapseActionButtons();
    return;
  }

  const highPriority = metas.filter((meta) => meta.stateLabel === "fail" || meta.stateLabel === "watch");
  const stalePriority = metas.filter((meta) => meta.stateLabel === "stale");
  const expandKeys = new Set();

  if (highPriority.length > 0) {
    for (const meta of highPriority.slice(0, 2)) {
      expandKeys.add(meta.key);
    }
    if (expandKeys.size < 2) {
      for (const meta of stalePriority) {
        expandKeys.add(meta.key);
        if (expandKeys.size >= 2) {
          break;
        }
      }
    }
  } else if (stalePriority.length > 0) {
    expandKeys.add(stalePriority[0].key);
  } else {
    expandKeys.add("bridge-safety");
  }

  for (const meta of metas) {
    setOperatorGroupCollapsed(meta.group, !expandKeys.has(meta.key));
  }
  syncOperatorCollapseActionButtons();
}

function syncOperatorCollapseActionButtons() {
  const groups = getVisibleOperatorGroups();
  if (groups.length === 0) {
    state.operatorCardsCollapsed = false;
    if (el.operatorHealthBoard) {
      el.operatorHealthBoard.classList.remove("is-collapsed");
    }
    if (el.operatorCollapseAllBtn) {
      el.operatorCollapseAllBtn.disabled = true;
    }
    if (el.operatorExpandAllBtn) {
      el.operatorExpandAllBtn.disabled = true;
    }
    renderOperatorLaneFocusRail();
    return;
  }

  const allCollapsed = groups.every((group) => group.classList.contains("is-collapsed"));
  const allExpanded = groups.every((group) => !group.classList.contains("is-collapsed"));
  state.operatorCardsCollapsed = allCollapsed;
  if (el.operatorHealthBoard) {
    el.operatorHealthBoard.classList.toggle("is-collapsed", state.operatorCardsCollapsed);
  }
  if (el.operatorCollapseAllBtn) {
    el.operatorCollapseAllBtn.disabled = allCollapsed;
  }
  if (el.operatorExpandAllBtn) {
    el.operatorExpandAllBtn.disabled = allExpanded;
  }
  renderOperatorLaneFocusRail();
}

function setAllOperatorGroupsCollapsed(collapsed) {
  const groups = document.querySelectorAll(".operator-health-group");
  for (const group of groups) {
    setOperatorGroupCollapsed(group, collapsed);
  }
}

function setOperatorCardsCollapsed(collapsed) {
  state.operatorCardsCollapsed = collapsed === true;
  if (el.operatorHealthBoard) {
    el.operatorHealthBoard.classList.toggle("is-collapsed", state.operatorCardsCollapsed);
  }
  setAllOperatorGroupsCollapsed(state.operatorCardsCollapsed);
  syncOperatorCollapseActionButtons();
}

function isOperatorCriticalCard(card) {
  return card instanceof HTMLElement && card.hasAttribute("data-operator-critical");
}

function setOperatorFocusCriticalMode(enabled) {
  state.operatorFocusCriticalOnly = enabled === true;
  if (el.operatorHealthBoard) {
    el.operatorHealthBoard.classList.toggle("is-focus-critical", state.operatorFocusCriticalOnly);
  }
  if (el.operatorFocusCriticalBtn) {
    const focusCriticalLabel = state.operatorFocusCriticalOnly ? "Show All Cards" : "Focus Critical";
    el.operatorFocusCriticalBtn.classList.toggle("is-active", state.operatorFocusCriticalOnly);
    el.operatorFocusCriticalBtn.setAttribute("aria-pressed", state.operatorFocusCriticalOnly ? "true" : "false");
    el.operatorFocusCriticalBtn.setAttribute("aria-label", focusCriticalLabel);
    el.operatorFocusCriticalBtn.title = state.operatorFocusCriticalOnly ? "Show all cards" : "Focus critical cards";
    el.operatorFocusCriticalBtn.textContent = state.operatorFocusCriticalOnly ? "All Cards" : "Critical";
  }
  applyOperatorCardsVisibility();
  if (state.operatorFocusCriticalOnly && normalizeOperatorBoardMode(state.operatorBoardMode) === "demo") {
    applyOperatorDemoGroupPreset();
  }
}

function setOperatorIssuesOnlyMode(enabled) {
  state.operatorIssuesOnly = enabled === true;
  if (el.operatorIssuesOnlyBtn) {
    const issuesOnlyLabel = state.operatorIssuesOnly ? "Show All Statuses" : "Issues Only";
    el.operatorIssuesOnlyBtn.classList.toggle("is-active", state.operatorIssuesOnly);
    el.operatorIssuesOnlyBtn.setAttribute("aria-pressed", state.operatorIssuesOnly ? "true" : "false");
    el.operatorIssuesOnlyBtn.setAttribute("aria-label", issuesOnlyLabel);
    el.operatorIssuesOnlyBtn.title = issuesOnlyLabel;
    el.operatorIssuesOnlyBtn.textContent = state.operatorIssuesOnly ? "All Statuses" : "Issues";
  }
  applyOperatorCardsVisibility();
}

function normalizeOperatorBoardMode(value) {
  return value === "full" ? "full" : "demo";
}

function readStoredOperatorBoardMode() {
  try {
    const stored = window.localStorage?.getItem(OPERATOR_BOARD_MODE_STORAGE_KEY);
    return normalizeOperatorBoardMode(stored);
  } catch {
    return "demo";
  }
}

function normalizeOperatorSavedView(value) {
  if (typeof value !== "string") {
    return "";
  }
  const normalized = value.trim().toLowerCase();
  return Object.prototype.hasOwnProperty.call(OPERATOR_SAVED_VIEWS, normalized) ? normalized : "";
}

function normalizeOperatorEvidenceDrawerView(value) {
  if (typeof value !== "string") {
    return "";
  }
  const normalized = value.trim().toLowerCase();
  return OPERATOR_EVIDENCE_DRAWER_VIEWS.some((view) => view.id === normalized) ? normalized : "";
}

function ensureOperatorMobileDockMounted() {
  if (!(el.operatorMobileDock instanceof HTMLElement) || typeof document === "undefined") {
    return;
  }
  if (el.operatorMobileDock.parentElement === document.body) {
    return;
  }
  document.body.appendChild(el.operatorMobileDock);
}

function syncOperatorMobileDockVisibility(tabId = null) {
  if (!(el.operatorMobileDock instanceof HTMLElement) || typeof window === "undefined") {
    return;
  }
  const requestedTab = typeof tabId === "string" ? tabId : document.querySelector(".layout")?.dataset.activeTab ?? readStoredTabId();
  const activeTab = resolveTabId(requestedTab);
  const isMobileViewport = window.matchMedia("(max-width: 620px)").matches;
  const shouldShow = isMobileViewport && activeTab === "operator";
  el.operatorMobileDock.classList.toggle("is-hidden", !shouldShow);
  el.operatorMobileDock.setAttribute("aria-hidden", shouldShow ? "false" : "true");
}

function readStoredOperatorSavedView() {
  try {
    const stored = window.localStorage?.getItem(OPERATOR_SAVED_VIEW_STORAGE_KEY);
    return normalizeOperatorSavedView(stored);
  } catch {
    return "";
  }
}

function normalizeOperatorPurposeCategory(value) {
  const normalized = toOptionalText(value)?.toLowerCase() ?? "other";
  return OPERATOR_PURPOSE_CATEGORY_OPTIONS.includes(normalized) ? normalized : "other";
}

function normalizeOperatorPurposeDeclaration(value) {
  const typed = isRecord(value) ? value : {};
  const purpose = toOptionalText(typed.purpose);
  if (!purpose) {
    return null;
  }
  return {
    category: normalizeOperatorPurposeCategory(typed.category),
    purpose,
    declaredAt: toOptionalText(typed.declaredAt) ?? toIsoNow(),
  };
}

function cloneOperatorPurposeDeclaration(value) {
  const normalized = normalizeOperatorPurposeDeclaration(value);
  return normalized ? { ...normalized } : null;
}

function readStoredOperatorPurposeDeclaration() {
  try {
    const stored = window.localStorage?.getItem(OPERATOR_PURPOSE_DECLARATION_STORAGE_KEY);
    if (typeof stored !== "string" || stored.trim().length === 0) {
      return null;
    }
    return normalizeOperatorPurposeDeclaration(JSON.parse(stored));
  } catch {
    return null;
  }
}

function persistOperatorPurposeDeclaration(value) {
  try {
    const normalized = normalizeOperatorPurposeDeclaration(value);
    if (!normalized) {
      window.localStorage?.removeItem(OPERATOR_PURPOSE_DECLARATION_STORAGE_KEY);
      return;
    }
    window.localStorage?.setItem(OPERATOR_PURPOSE_DECLARATION_STORAGE_KEY, JSON.stringify(normalized));
  } catch {
    /* no-op on storage failures */
  }
}

function getOperatorPurposeRequestPayload() {
  return cloneOperatorPurposeDeclaration(state.operatorPurposeDeclaration);
}

function ensureOperatorPurposeDeclaration(actionLabel) {
  const declaration = cloneOperatorPurposeDeclaration(state.operatorPurposeDeclaration);
  if (declaration) {
    return declaration;
  }
  setOperatorSessionOpsControlStatus("purpose_required", "warn");
  state.operatorSessionOpsLastResult = {
    action: "purpose_gate_blocked",
    actionLabel: toOptionalText(actionLabel) ?? "operator action",
    blockedAt: toIsoNow(),
    reason: "Declare operator purpose before high-risk control-plane actions.",
  };
  renderOperatorSessionOpsPanel();
  openOperatorSupportPanel(el.operatorSessionOpsControl, el.operatorPurposeInput);
  appendTranscript(
    "error",
    `${toOptionalText(actionLabel) ?? "Operator action"} requires a saved purpose declaration in Operator Session Ops`,
  );
  return null;
}

function getOperatorSummaryGuideSignals() {
  const entries = [];
  for (const signal of OPERATOR_SUMMARY_GUIDE_SIGNAL_PRIORITIES) {
    const node = document.getElementById(signal.id);
    if (!(node instanceof HTMLElement)) {
      continue;
    }
    entries.push({
      ...signal,
      node,
      text: typeof node.textContent === "string" ? node.textContent.trim() : "",
      statusCode: getOperatorStatusCode(node),
      variant: readOperatorStatusVariant(node),
    });
  }
  return entries;
}

function formatOperatorSummaryGuideLabelList(items, maxItems = 2) {
  const labels = Array.isArray(items)
    ? items
        .slice(0, Math.max(1, maxItems))
        .map((item) => (item && typeof item.label === "string" ? item.label.trim() : ""))
        .filter((label) => label.length > 0)
    : [];
  if (labels.length === 0) {
    return "critical lanes";
  }
  if (labels.length === 1) {
    return labels[0];
  }
  if (labels.length === 2) {
    return `${labels[0]} and ${labels[1]}`;
  }
  return `${labels.slice(0, -1).join(", ")}, and ${labels.at(-1)}`;
}

function runOperatorSummaryGuidePathAction(actionId, options = {}) {
  const normalizedAction = typeof actionId === "string" ? actionId.trim() : "";
  if (!normalizedAction) {
    return;
  }
  if (normalizedAction === "refresh_summary") {
    runOperatorEmptyStateAction("refresh_summary");
    return;
  }
  if (normalizedAction === "inspect_status") {
    const targetStatusId = typeof options?.targetStatusId === "string" ? options.targetStatusId.trim() : "";
    if (targetStatusId) {
      jumpToOperatorStatusCard(targetStatusId);
    }
    return;
  }
  if (normalizedAction === "inspect_saved_view") {
    const savedView = typeof options?.savedView === "string" ? options.savedView.trim() : "";
    if (savedView) {
      setOperatorSavedView(savedView);
    }
    return;
  }
  if (normalizedAction === "open_playbook") {
    openOperatorSupportPanel(el.operatorLanePlaybook, el.operatorPlaybookRunNegotiationBtn);
    return;
  }
  if (normalizedAction === "open_quick_start") {
    openOperatorSupportPanel(el.operatorQuickStart, el.operatorQuickStartRunNegotiationBtn);
  }
}

function syncOperatorSummaryGuidePathStep(stepElements, config = {}) {
  if (!stepElements || !(stepElements.step instanceof HTMLElement) || !(stepElements.status instanceof HTMLElement)) {
    return;
  }
  const stateKey = typeof config.state === "string" && config.state.trim().length > 0 ? config.state.trim() : "later";
  const titleText = typeof config.title === "string" && config.title.trim().length > 0 ? config.title.trim() : "";
  const hintText = typeof config.hint === "string" && config.hint.trim().length > 0 ? config.hint.trim() : "";
  const statusText = typeof config.statusText === "string" && config.statusText.trim().length > 0
    ? config.statusText.trim()
    : stateKey;
  const statusTone = config.statusTone === "ok" || config.statusTone === "fail" ? config.statusTone : "neutral";
  const buttonLabel = typeof config.buttonLabel === "string" && config.buttonLabel.trim().length > 0
    ? config.buttonLabel.trim()
    : "Open";
  const actionId = typeof config.actionId === "string" && config.actionId.trim().length > 0 ? config.actionId.trim() : "";
  const buttonDisabled = config.disabled === true || !actionId;

  stepElements.step.dataset.stepState = stateKey;
  stepElements.step.classList.toggle("is-disabled", buttonDisabled);

  if (stepElements.title instanceof HTMLElement) {
    stepElements.title.textContent = titleText;
  }
  if (stepElements.hint instanceof HTMLElement) {
    stepElements.hint.textContent = hintText;
  }

  setStatusPill(stepElements.status, statusText, statusTone);
  stepElements.status.dataset.statusCode = stateKey;

  if (stepElements.button instanceof HTMLButtonElement) {
    stepElements.button.textContent = buttonLabel;
    stepElements.button.disabled = buttonDisabled;
    if (actionId) {
      stepElements.button.dataset.guideStepAction = actionId;
    } else {
      delete stepElements.button.dataset.guideStepAction;
    }
    if (typeof config.targetStatusId === "string" && config.targetStatusId.trim().length > 0) {
      stepElements.button.dataset.guideStepTargetStatusId = config.targetStatusId.trim();
    } else {
      delete stepElements.button.dataset.guideStepTargetStatusId;
    }
    if (typeof config.savedView === "string" && config.savedView.trim().length > 0) {
      stepElements.button.dataset.guideStepSavedView = config.savedView.trim();
    } else {
      delete stepElements.button.dataset.guideStepSavedView;
    }
  }
}

function syncOperatorSummaryGuidePath(params = {}) {
  if (!(el.operatorSummaryGuidePath instanceof HTMLElement)) {
    return;
  }

  const hasManualRefresh = params.hasManualRefresh === true;
  const refreshFailed = params.refreshFailed === true;
  const activeSavedView = params.activeSavedView && typeof params.activeSavedView === "object" ? params.activeSavedView : null;
  const failSignals = Array.isArray(params.failSignals) ? params.failSignals : [];
  const neutralSignals = Array.isArray(params.neutralSignals) ? params.neutralSignals : [];
  const okSignals = Array.isArray(params.okSignals) ? params.okSignals : [];

  const refreshStep = {
    step: el.operatorSummaryGuideStepRefresh,
    title: el.operatorSummaryGuideStepRefreshTitle,
    hint: el.operatorSummaryGuideStepRefreshHint,
    status: el.operatorSummaryGuideStepRefreshStatus,
    button: el.operatorSummaryGuideStepRefreshBtn,
  };
  const inspectStep = {
    step: el.operatorSummaryGuideStepInspect,
    title: el.operatorSummaryGuideStepInspectTitle,
    hint: el.operatorSummaryGuideStepInspectHint,
    status: el.operatorSummaryGuideStepInspectStatus,
    button: el.operatorSummaryGuideStepInspectBtn,
  };
  const recoverStep = {
    step: el.operatorSummaryGuideStepRecover,
    title: el.operatorSummaryGuideStepRecoverTitle,
    hint: el.operatorSummaryGuideStepRecoverHint,
    status: el.operatorSummaryGuideStepRecoverStatus,
    button: el.operatorSummaryGuideStepRecoverBtn,
  };

  if (!hasManualRefresh) {
    syncOperatorSummaryGuidePathStep(refreshStep, {
      state: "current",
      title: "Refresh overview workspace",
      hint: "Hydrate the overview workspace before you inspect deeper proof.",
      statusText: "current",
      statusTone: "neutral",
      buttonLabel: "Refresh Summary",
      actionId: "refresh_summary",
    });
    syncOperatorSummaryGuidePathStep(inspectStep, {
      state: "next",
      title: "Inspect the highlighted workspace",
      hint: "After refresh, open the highlighted workspace instead of scanning the whole console.",
      statusText: "next",
      statusTone: "neutral",
      buttonLabel: "Open workspace",
      disabled: true,
    });
    syncOperatorSummaryGuidePathStep(recoverStep, {
      state: "later",
      title: "Recover only if needed",
      hint: "Use Recovery Playbook or Quick Start only after you confirm the workspace still needs help.",
      statusText: "later",
      statusTone: "neutral",
      buttonLabel: "Recovery Playbook",
      disabled: true,
    });
    return;
  }

  if (refreshFailed) {
    syncOperatorSummaryGuidePathStep(refreshStep, {
      state: "current",
      title: "Retry the refresh",
      hint: "The console did not hydrate cleanly. Refresh again before you inspect or recover lanes.",
      statusText: "retry",
      statusTone: "fail",
      buttonLabel: "Refresh Summary",
      actionId: "refresh_summary",
    });
    syncOperatorSummaryGuidePathStep(inspectStep, {
      state: "next",
      title: "Inspect after refresh",
      hint: "Once the board refresh succeeds, open the loudest workspace instead of scanning the full console.",
      statusText: "waiting",
      statusTone: "neutral",
      buttonLabel: "Open workspace",
      disabled: true,
    });
    syncOperatorSummaryGuidePathStep(recoverStep, {
      state: "later",
      title: "Recover after the board is hydrated",
      hint: "Use Recovery Playbook only after the refreshed board confirms which workspace is still degraded.",
      statusText: "hold",
      statusTone: "neutral",
      buttonLabel: "Recovery Playbook",
      disabled: true,
    });
    return;
  }

  const inspectSignal = failSignals[0] ?? neutralSignals[0] ?? okSignals[0] ?? null;
  const hasActiveSavedView = Boolean(activeSavedView && activeSavedView.id && activeSavedView.id !== "incidents");
  const inspectNeedsAttention = failSignals.length > 0 || neutralSignals.length > 0 || hasActiveSavedView;
  const inspectStatusTone = failSignals.length > 0 ? "fail" : inspectNeedsAttention ? "neutral" : "ok";
  const inspectTitle = hasActiveSavedView
    ? `Inspect ${activeSavedView.label}`
    : inspectSignal
      ? `Inspect ${inspectSignal.label}`
      : "Inspect the board only if you need proof";
  const inspectHint = hasActiveSavedView
    ? (activeSavedView.contextNote ?? `${activeSavedView.label} is the active posture. Open it before deeper recovery surfaces.`)
    : inspectSignal
      ? `Jump straight into ${inspectSignal.label} before you open deeper operator tools.`
      : "The board looks nominal. Open the lead workspace only when you need deeper proof or replay.";
  const inspectButtonLabel = hasActiveSavedView
    ? `Open ${activeSavedView.label}`
    : inspectSignal
      ? "Open workspace"
      : "Review board";
  syncOperatorSummaryGuidePathStep(inspectStep, {
    state: inspectNeedsAttention ? "current" : "done",
    title: inspectTitle,
    hint: inspectHint,
    statusText: inspectNeedsAttention ? "current" : "done",
    statusTone: inspectStatusTone,
    buttonLabel: inspectButtonLabel,
    actionId: hasActiveSavedView ? "inspect_saved_view" : inspectSignal ? "inspect_status" : "",
    targetStatusId: inspectSignal?.id ?? "",
    savedView: hasActiveSavedView ? activeSavedView.id : "",
    disabled: !hasActiveSavedView && !inspectSignal,
  });

  const recoverNeedsPlaybook = failSignals.length > 0;
  const recoverNeedsQuickStart = !recoverNeedsPlaybook && neutralSignals.length > 0;
  const recoverTargetLabel = (failSignals[0] ?? neutralSignals[0])?.label ?? "the active workspace";
  syncOperatorSummaryGuidePathStep(refreshStep, {
    state: "done",
    title: "Board refreshed",
    hint: "The first operator snapshot is hydrated. Move straight to the highlighted workspace instead of rescanning the console.",
    statusText: "done",
    statusTone: "ok",
    buttonLabel: "Refresh Summary",
    actionId: "refresh_summary",
  });
  syncOperatorSummaryGuidePathStep(recoverStep, {
    state: recoverNeedsPlaybook ? "next" : recoverNeedsQuickStart ? "next" : "later",
    title: recoverNeedsPlaybook
      ? `Recover ${recoverTargetLabel}`
      : recoverNeedsQuickStart
        ? "Reseed only if the workspace stays quiet"
        : "Recover only if something drifts",
    hint: recoverNeedsPlaybook
      ? `Use Recovery Playbook only after you confirm ${recoverTargetLabel} still needs help.`
      : recoverNeedsQuickStart
        ? `If ${recoverTargetLabel} still looks incomplete after inspection, use Quick Start to seed one focused scenario.`
        : "Current operator lanes look nominal. Keep recovery kits secondary until a signal changes.",
    statusText: recoverNeedsPlaybook ? "ready" : recoverNeedsQuickStart ? "if needed" : "optional",
    statusTone: recoverNeedsPlaybook ? "fail" : recoverNeedsQuickStart ? "neutral" : "ok",
    buttonLabel: recoverNeedsPlaybook ? "Recovery Playbook" : recoverNeedsQuickStart ? "Open Quick Start" : "Recovery Playbook",
    actionId: recoverNeedsPlaybook ? "open_playbook" : recoverNeedsQuickStart ? "open_quick_start" : "",
    disabled: !recoverNeedsPlaybook && !recoverNeedsQuickStart,
  });
}

function renderOperatorSummaryGuideWatchlist(items, fallbackText = "Refresh summary first") {
  if (!(el.operatorSummaryGuideWatchlist instanceof HTMLElement)) {
    return;
  }
  const watchShell = el.operatorSummaryGuideWatchlist.closest(".operator-summary-guide-watch");
  el.operatorSummaryGuideWatchlist.innerHTML = "";
  const watchItems = Array.isArray(items) ? items.slice(0, 4) : [];
  if (watchShell instanceof HTMLElement) {
    watchShell.dataset.watchState = watchItems.length > 0 ? "active" : "empty";
    watchShell.hidden = watchItems.length === 0;
  }
  if (watchItems.length === 0) {
    const emptyChip = document.createElement("span");
    emptyChip.className = "operator-summary-guide-watch-chip is-empty";
    emptyChip.textContent = fallbackText;
    el.operatorSummaryGuideWatchlist.append(emptyChip);
    return;
  }

  for (const item of watchItems) {
    const chip = document.createElement("button");
    chip.type = "button";
    chip.className = `operator-summary-guide-watch-chip is-${item.variant ?? "neutral"}`;
    chip.textContent = item.label;
    chip.title = item.text || item.label;
    chip.addEventListener("click", () => {
      jumpToOperatorStatusCard(item.id);
    });
    el.operatorSummaryGuideWatchlist.append(chip);
  }
}

function runOperatorPriorityQueueAction(actionId, options = {}) {
  const normalizedAction = typeof actionId === "string" ? actionId.trim() : "";
  if (!normalizedAction) {
    return;
  }

  if (normalizedAction === "jump_status_card") {
    const targetStatusId = typeof options?.targetStatusId === "string" ? options.targetStatusId.trim() : "";
    if (targetStatusId) {
      jumpToOperatorStatusCard(targetStatusId);
    }
    return;
  }

  if (normalizedAction.startsWith("saved_view_")) {
    setOperatorSavedView(normalizedAction.slice("saved_view_".length));
    return;
  }

  switch (normalizedAction) {
    case "refresh_summary":
    case "run_negotiation":
    case "run_story":
    case "run_ui_task":
    case "open_device_nodes":
      runOperatorEmptyStateAction(normalizedAction);
      return;
    case "open_quick_start":
      openOperatorSupportPanel(el.operatorQuickStart, el.operatorQuickStartRunNegotiationBtn);
      return;
    case "open_playbook":
      openOperatorSupportPanel(el.operatorLanePlaybook, el.operatorPlaybookRunNegotiationBtn);
      return;
    case "open_workflow_control":
      openOperatorSupportPanel(el.operatorWorkflowControl, el.operatorWorkflowRefreshBtn);
      return;
    case "run_runtime_guardrail_path":
      void runOperatorRuntimeGuardrailsAction();
      return;
    case "show_all_cards":
      clearOperatorSavedView();
      setOperatorFocusCriticalMode(false);
      return;
    case "full_ops_view":
      clearOperatorSavedView();
      setOperatorBoardMode("full");
      return;
    default:
      return;
  }
}

function createOperatorPriorityQueueActionButton(config) {
  if (!config || typeof config !== "object" || typeof config.label !== "string") {
    return null;
  }
  const button = document.createElement("button");
  button.type = "button";
  const fullLabel = config.label.trim();
  const visibleLabel =
    typeof config.shortLabel === "string" && config.shortLabel.trim().length > 0
      ? config.shortLabel.trim()
      : fullLabel;
  button.className = config.kind === "secondary"
    ? "button-muted operator-priority-queue-action operator-priority-queue-action-secondary"
    : "operator-priority-queue-action";
  button.textContent = visibleLabel;
  if (visibleLabel !== fullLabel) {
    button.title = fullLabel;
    button.setAttribute("aria-label", fullLabel);
  }
  button.addEventListener("click", () => {
    runOperatorPriorityQueueAction(config.actionId, config);
  });
  return button;
}

function resolveOperatorPriorityQueueCompactTitle(entry) {
  if (!entry || typeof entry !== "object") {
    return "Operator action";
  }

  const key = typeof entry.key === "string" ? entry.key.trim().toLowerCase() : "";
  const tone = typeof entry.tone === "string" ? entry.tone.trim().toLowerCase() : "";
  const fullTitle = typeof entry.title === "string" && entry.title.trim().length > 0
    ? entry.title.trim()
    : "Operator action";

  if (key === "hydrate_board") {
    return "Hydrate board";
  }
  if (key === "refresh_failed") {
    return "Refresh stale board";
  }
  if (key === "runtime_guardrail_path") {
    return "Run guardrail path";
  }
  if (key === "nominal_overview") {
    return "Board looks steady";
  }
  if (key === "queue_empty") {
    return "Queue is waiting";
  }
  if (tone === "fail" && /\sneeds action$/iu.test(fullTitle)) {
    return fullTitle.replace(/\sneeds action$/iu, " action");
  }
  if (tone === "watch" && /\sneeds one check$/iu.test(fullTitle)) {
    return fullTitle.replace(/\sneeds one check$/iu, " needs check");
  }
  return fullTitle;
}

function resolveOperatorPriorityQueueCompactActionLabel(config) {
  if (!config || typeof config !== "object" || typeof config.label !== "string") {
    return "";
  }

  const fullLabel = config.label.trim();
  if (!fullLabel) {
    return "";
  }

  const compactLabelMap = new Map([
    ["Refresh Summary", "Refresh"],
    ["Open Quick Start", "Quick Start"],
    ["Open Playbook", "Playbook"],
    ["Open Lane", "Lane"],
    ["Open Workspace", "Workspace"],
    ["Open Guardrails", "Guardrails"],
    ["Show All Cards", "All Cards"],
    ["Full Ops View", "Full Ops"],
    ["Run Negotiation", "Negotiate"],
  ]);
  return compactLabelMap.get(fullLabel) ?? fullLabel;
}

function resolveOperatorActionCenterUtilityActionLabel(config) {
  if (!config || typeof config !== "object" || typeof config.label !== "string") {
    return "";
  }

  const fullLabel = config.label.trim();
  if (!fullLabel) {
    return "";
  }

  const compactLabelMap = new Map([
    ["Refresh Summary", "Refresh"],
    ["Run Negotiation", "Negotiate"],
    ["Open Playbook", "Playbook"],
    ["Open Quick Start", "Quick Start"],
    ["Show All Cards", "All Cards"],
    ["Full Ops View", "Full Ops"],
  ]);

  return compactLabelMap.get(fullLabel) ?? fullLabel;
}

function resolveOperatorActionCenterUtilityTitle(card) {
  if (!card || typeof card !== "object" || typeof card.title !== "string") {
    return "";
  }

  const key = typeof card.key === "string" ? card.key.trim().toLowerCase() : "";
  const title = card.title.trim();
  if (!title) {
    return "";
  }

  if (key === "support_seed_board") {
    return "Hydrate evidence";
  }
  if (key === "support_nominal") {
    return "Board steady";
  }
  if (key === "support_refresh_failed") {
    return "Refresh evidence";
  }

  return clipOperatorEvidenceDrawerSentence(title, 26);
}

function createOperatorActionCenterActionButton(config, options = {}) {
  if (!config || typeof config !== "object" || typeof config.label !== "string") {
    return null;
  }
  const compact = options.compact === true;
  const fullLabel = config.label.trim();
  const compactLabel = compact ? resolveOperatorActionCenterUtilityActionLabel(config) : "";
  const button = document.createElement("button");
  button.type = "button";
  button.className = config.kind === "secondary"
    ? "button-muted operator-action-center-action operator-action-center-action-secondary"
    : "operator-action-center-action";
  button.dataset.actionDensity = compact ? "compact" : "default";
  button.textContent = compactLabel || fullLabel;
  if (compact && fullLabel) {
    button.title = fullLabel;
    button.setAttribute("aria-label", fullLabel);
  }
  button.addEventListener("click", () => {
    runOperatorPriorityQueueAction(config.actionId, config);
  });
  return button;
}

function createOperatorPriorityQueueSignalEntry(signal) {
  if (!signal || typeof signal !== "object" || typeof signal.id !== "string") {
    return null;
  }
  const actionConfig = OPERATOR_PRIORITY_QUEUE_ACTIONS[signal.id] ?? null;
  const isStale = signal.statusCode === "summary_stale";
  const tone = signal.variant === "fail" ? "fail" : isStale ? "stale" : signal.variant === "ok" ? "ok" : "watch";
  const statusLabel = resolveStatusPillDisplayText(
    (typeof signal.text === "string" && signal.text.trim().length > 0) ? signal.text : signal.statusCode ?? "no_data",
  );

  return {
    key: signal.id,
    tone,
    kicker: tone === "fail" ? "Act now" : tone === "stale" ? "Refresh first" : tone === "ok" ? "Monitor" : "Confirm",
    title:
      tone === "fail"
        ? `${signal.label} needs action`
        : tone === "stale"
          ? `${signal.label} needs fresh data`
          : tone === "ok"
            ? `${signal.label} looks steady`
            : `${signal.label} needs one check`,
    meta:
      tone === "fail"
        ? `Status: ${statusLabel}. Open this area before deeper diagnostics.`
        : tone === "stale"
          ? `Status: ${statusLabel}. Refresh summary or reseed this area before trusting downstream evidence.`
          : tone === "ok"
            ? `Status: ${statusLabel}. Keep this area quiet unless a new signal appears.`
            : `Status: ${statusLabel}. Confirm with one refresh or one targeted run.`,
    primary: {
      label: actionConfig?.openLabel ?? "Open Workspace",
      actionId: "jump_status_card",
      targetStatusId: signal.id,
    },
    secondary: actionConfig?.supportAction
      ? {
          label: actionConfig.supportLabel,
          actionId: actionConfig.supportAction,
          kind: "secondary",
        }
      : null,
  };
}

function buildOperatorPriorityQueueCompactMeta(entry) {
  if (!entry || typeof entry !== "object") {
    return "Review the highlighted action.";
  }

  const key = typeof entry.key === "string" ? entry.key.trim().toLowerCase() : "";
  const tone = typeof entry.tone === "string" ? entry.tone.trim().toLowerCase() : "";
  const primaryLabel = entry.primary && typeof entry.primary.label === "string" ? entry.primary.label.trim() : "";
  const normalizedPrimaryLabel = primaryLabel.toLowerCase();

  if (key === "hydrate_board") {
    return "Refresh once, then follow the highlighted workspace.";
  }
  if (key === "refresh_failed") {
    return "Retry summary before trusting stale evidence.";
  }
  if (key === "runtime_guardrail_path") {
    return primaryLabel ? `${primaryLabel} first.` : "Run the recovery path first.";
  }
  if (key === "nominal_overview") {
    return "Keep monitoring unless a new issue appears.";
  }
  if (key === "queue_empty") {
    return "Refresh after the next live action.";
  }
  if (normalizedPrimaryLabel === "open lane" || normalizedPrimaryLabel === "open workspace") {
    if (tone === "fail") {
      return "Open the highlighted workspace first.";
    }
    if (tone === "stale") {
      return "Refresh or reopen the stale workspace.";
    }
    if (tone === "ok") {
      return "Keep monitoring.";
    }
    return "Confirm the highlighted workspace.";
  }
  if (primaryLabel) {
    return `${primaryLabel} first.`;
  }
  if (tone === "fail") {
    return "Open the highlighted workspace first.";
  }
  if (tone === "stale") {
    return "Refresh the stale workspace first.";
  }
  if (tone === "ok") {
    return "Keep monitoring.";
  }
  return "Confirm the highlighted workspace.";
}

function buildOperatorActionCenterCards() {
  const hasManualRefresh = state.operatorSummaryUserRefreshed === true;
  const isDemo = normalizeOperatorBoardMode(state.operatorBoardMode) === "demo";
  const signals = getOperatorSummaryGuideSignals();
  const failSignals = signals.filter((item) => item.variant === "fail");
  const staleSignals = signals.filter((item) => item.statusCode === "summary_stale");
  const watchSignals = signals.filter(
    (item) => item.variant === "neutral" && item.statusCode !== "summary_stale" && !isOperatorUninitializedStatusText(item.statusCode),
  );
  const okSignals = signals.filter((item) => item.variant === "ok");
  const cards = [];

  const pushCard = (card) => {
    if (!card || typeof card !== "object" || typeof card.key !== "string" || cards.length >= 1) {
      return;
    }
    cards.push(card);
  };

  const finalizeActions = (actions) => Array.isArray(actions) ? actions.filter(Boolean).slice(0, 2) : [];

  const buildSignalCard = (signal, options = {}) => {
    const entry = createOperatorPriorityQueueSignalEntry(signal);
    if (!entry) {
      return null;
    }
    const statusLabel = resolveStatusPillDisplayText(
      (typeof signal.text === "string" && signal.text.trim().length > 0) ? signal.text : signal.statusCode ?? "no_data",
    );
    const refreshAction = { label: "Refresh Summary", actionId: "refresh_summary", kind: "secondary" };
    const actions = finalizeActions([
      entry.primary,
      entry.secondary ?? refreshAction,
    ]);
    return {
      key: `support_${signal.id}`,
      tone: options.tone ?? entry.tone ?? "neutral",
      kicker: options.kicker ?? (entry.tone === "fail" ? "Immediate recovery" : entry.tone === "stale" ? "Fresh evidence" : "Verification"),
      title: options.title ?? entry.title,
      meta: options.meta ?? entry.meta,
      tags: options.tags ?? [signal.label, statusLabel].filter(Boolean).slice(0, 2),
      actions,
      compact: true,
    };
  };

  if (!hasManualRefresh) {
    pushCard({
      key: "support_seed_board",
      tone: "neutral",
      kicker: "Reseed",
      title: "Hydrate live evidence",
      meta: "Run one controlled scenario, then refresh summary.",
      tags: ["first refresh", "targeted run"],
      actions: finalizeActions([
        { label: "Refresh Summary", actionId: "refresh_summary" },
        { label: "Run Negotiation", actionId: "run_negotiation", kind: "secondary" },
      ]),
      compact: true,
    });
    return cards;
  }

  if (state.operatorLastRefreshState === "failed") {
    pushCard({
      key: "support_refresh_failed",
      tone: "fail",
      kicker: "Recovery",
      title: "Refresh stale board evidence",
      meta: "Retry summary first, then reseed only the lane that still stays stale.",
      tags: ["stale board", "live data"],
      actions: finalizeActions([
        { label: "Refresh Summary", actionId: "refresh_summary" },
        { label: "Open Playbook", actionId: "open_playbook", kind: "secondary" },
      ]),
      compact: true,
    });
    return cards;
  }

  if (failSignals.length > 0) {
    pushCard(buildSignalCard(failSignals[0], { kicker: "Immediate recovery" }));
    return cards;
  }

  if (watchSignals.length > 0 || staleSignals.length > 0) {
    pushCard(
      buildSignalCard(watchSignals[0] ?? staleSignals[0], {
        kicker: staleSignals.length > 0 ? "Fresh evidence" : "Verification",
      }),
    );
    return cards;
  }

  pushCard({
    key: "support_nominal",
    tone: "ok",
    kicker: "Steady board",
    title: "No blocking workspace needs action",
    meta: isDemo
      ? "Stay in Demo View and open deeper controls only when a real question appears."
      : "Keep the board in watch mode and open lower-frequency controls only when needed.",
    tags: ["nominal", "watch mode"],
    actions: finalizeActions([
      { label: state.operatorFocusCriticalOnly ? "Show All Cards" : "Full Ops View", actionId: state.operatorFocusCriticalOnly ? "show_all_cards" : "full_ops_view" },
      { label: "Refresh Summary", actionId: "refresh_summary", kind: "secondary" },
    ]),
    compact: true,
  });

  return cards;
}

function syncOperatorActionCenter() {
  if (!(el.operatorActionCenterSupport instanceof HTMLElement)) {
    return;
  }
  const cards = buildOperatorActionCenterCards();
  const compactRailOnly =
    cards.length <= 1 && cards.every((card) => card && typeof card === "object" && card.compact !== false);
  const utilityRailOnly =
    compactRailOnly
    && cards.length === 1
    && typeof window !== "undefined"
    && typeof window.matchMedia === "function"
    && window.matchMedia("(min-width: 921px)").matches
    && (cards[0]?.tone ?? "neutral") !== "fail"
    && (cards[0]?.tone ?? "neutral") !== "watch";
  if (el.operatorActionCenterSupportHead instanceof HTMLElement) {
    el.operatorActionCenterSupportHead.hidden = compactRailOnly;
  }
  if (el.operatorTriageSummary instanceof HTMLElement) {
    el.operatorTriageSummary.dataset.supportHead = compactRailOnly ? "hidden" : "visible";
  }
  el.operatorActionCenterSupport.dataset.supportDensity = utilityRailOnly ? "utility" : "card";
  el.operatorActionCenterSupport.innerHTML = "";
  for (const card of cards) {
    const article = document.createElement("article");
    article.className = `operator-action-center-card is-${card.tone ?? "neutral"}`;
    if (card.compact !== false) {
      article.classList.add("is-compact");
    }
    if (utilityRailOnly) {
      article.classList.add("is-utility-rail");
    }

    const copy = document.createElement("div");
    copy.className = "operator-action-center-card-copy";

    const head = document.createElement("div");
    head.className = "operator-action-center-card-head";

    const kicker = document.createElement("p");
    kicker.className = "operator-action-center-card-kicker";
    kicker.textContent = card.kicker ?? "Action kit";
    head.append(kicker);

    if (Array.isArray(card.tags) && card.tags.length > 0) {
      const tagRow = document.createElement("div");
      tagRow.className = "operator-action-center-tags";
      for (const tagText of card.tags.slice(0, utilityRailOnly ? 1 : 3)) {
        if (typeof tagText !== "string" || tagText.trim().length === 0) {
          continue;
        }
        const tag = document.createElement("span");
        tag.className = "operator-action-center-tag";
        tag.textContent = tagText.trim();
        tagRow.append(tag);
      }
      if (tagRow.childElementCount > 0) {
        head.append(tagRow);
      }
    }

    const title = document.createElement("h3");
    const fullTitle = typeof card.title === "string" && card.title.trim().length > 0
      ? card.title.trim()
      : "Operator action";
    const utilityTitle = utilityRailOnly ? resolveOperatorActionCenterUtilityTitle(card) : "";
    title.textContent = utilityTitle || fullTitle;
    if (utilityRailOnly && utilityTitle && utilityTitle !== fullTitle) {
      title.title = fullTitle;
      title.setAttribute("aria-label", fullTitle);
    }

    const meta = document.createElement("p");
    meta.className = "operator-action-center-meta";
    meta.textContent = card.meta ?? "No operator action is available yet.";

    if (utilityRailOnly && typeof card.meta === "string" && card.meta.trim().length > 0) {
      article.title = card.meta.trim();
    }

    copy.append(head, title);
    if (!utilityRailOnly) {
      copy.append(meta);
    }
    article.append(copy);

    const actions = Array.isArray(card.actions)
      ? card.actions.map((item) => createOperatorActionCenterActionButton(item, { compact: utilityRailOnly })).filter(Boolean)
      : [];
    if (actions.length > 0) {
      const actionRow = document.createElement("div");
      actionRow.className = "operator-action-center-actions";
      for (const button of actions) {
        actionRow.append(button);
      }
      article.append(actionRow);
    }

    el.operatorActionCenterSupport.append(article);
  }
}

function getOperatorSummaryGuideSignalById(statusId) {
  if (typeof statusId !== "string" || statusId.trim().length === 0) {
    return null;
  }
  return getOperatorSummaryGuideSignals().find((item) => item.id === statusId.trim()) ?? null;
}

function resolveOperatorEvidenceDrawerVariant(signal) {
  if (!signal || typeof signal !== "object") {
    return "neutral";
  }
  if (signal.variant === "fail") {
    return "fail";
  }
  if (signal.statusCode === "summary_stale") {
    return "stale";
  }
  if (signal.variant === "ok") {
    return "ok";
  }
  if (isOperatorUninitializedStatusText(signal.statusCode)) {
    return "dormant";
  }
  return "watch";
}

function resolveOperatorFocusedEvidenceStatusId() {
  const signals = getOperatorSummaryGuideSignals();
  const activeSavedView = getActiveOperatorSavedViewConfig();
  const currentId = typeof state.operatorFocusedEvidenceStatusId === "string"
    ? state.operatorFocusedEvidenceStatusId.trim()
    : "";
  const currentPinned = state.operatorFocusedEvidencePinned === true;
  const currentSignal = currentId ? signals.find((item) => item.id === currentId) ?? null : null;
  const currentVariant = resolveOperatorEvidenceDrawerVariant(currentSignal);
  const findSignalId = (predicate) => {
    const match = signals.find(predicate);
    return match && typeof match.id === "string" ? match.id : "";
  };
  const topIssueId =
    findSignalId((item) => item.variant === "fail") ||
    findSignalId((item) => item.statusCode === "summary_stale") ||
    findSignalId(
      (item) =>
        item.variant === "neutral" && item.statusCode !== "summary_stale" && !isOperatorUninitializedStatusText(item.statusCode),
    );
  const preferredViewSignalId = resolveOperatorSavedViewEvidenceStatusId(activeSavedView, signals);
  if (currentId && getOperatorCardByStatusId(currentId) instanceof HTMLElement) {
    const currentGroupKey = getOperatorGroupKeyByStatusId(currentId);
    if (currentPinned && (!activeSavedView || currentGroupKey === (activeSavedView.groupKey ?? ""))) {
      return currentId;
    }
    if (activeSavedView && currentGroupKey === (activeSavedView.groupKey ?? "")) {
      if (
        preferredViewSignalId &&
        preferredViewSignalId !== currentId &&
        (currentVariant === "ok" || currentVariant === "dormant")
      ) {
        return preferredViewSignalId;
      }
      return currentId;
    }
    if (
      preferredViewSignalId &&
      preferredViewSignalId !== currentId &&
      activeSavedView &&
      currentGroupKey === (activeSavedView.groupKey ?? "") &&
      (currentVariant === "ok" || currentVariant === "dormant")
    ) {
      return preferredViewSignalId;
    }
    if (topIssueId && (currentVariant === "ok" || currentVariant === "dormant" || currentVariant === "neutral")) {
      return topIssueId;
    }
    return currentId;
  }
  return (
    preferredViewSignalId ||
    topIssueId ||
    findSignalId((item) => item.variant === "ok") ||
    findSignalId((item) => isOperatorUninitializedStatusText(item.statusCode)) ||
    OPERATOR_SUMMARY_GUIDE_SIGNAL_PRIORITIES[0]?.id ||
    ""
  );
}

function sentenceCaseOperatorEvidenceValue(value) {
  if (typeof value !== "string") {
    return "";
  }
  const compact = value.replace(/[_-]+/g, " ").replace(/\s+/g, " ").trim();
  if (!compact) {
    return "";
  }
  return compact.charAt(0).toUpperCase() + compact.slice(1);
}

function formatOperatorEvidenceDrawerFactValue(label, value) {
  const normalizedValue = typeof value === "string" ? value.trim().toLowerCase() : "";
  const normalizedLabel = typeof label === "string" ? label.trim().toLowerCase() : "";
  if (!normalizedValue) {
    return "";
  }
  const compactMatchText = `${normalizedLabel} ${normalizedValue}`;
  if (normalizedValue === "summary_error" || normalizedValue === "refresh_failed") {
    return "Refresh failed";
  }
  if (normalizedValue === "summary_stale") {
    return "Stale";
  }
  if (normalizedValue === "none_yet") {
    return "None yet";
  }
  if (isOperatorUninitializedStatusText(normalizedValue) || normalizedValue === "awaiting_signal") {
    return "Awaiting signal";
  }
  if (compactMatchText.includes("queue empty")) {
    return "Queue empty";
  }
  if (compactMatchText.includes("no approvals")) {
    return "No approvals";
  }
  if (compactMatchText.includes("no nodes")) {
    return "No nodes";
  }
  if (compactMatchText.includes("no_evidence")) {
    return "No evidence";
  }
  if (compactMatchText.includes("workflow_ready")) {
    return "Ready";
  }
  if (compactMatchText.includes("validated")) {
    return "Validated";
  }
  if (compactMatchText.includes("healthy")) {
    return "Healthy";
  }
  if (compactMatchText.includes("partial")) {
    return "Partial";
  }
  if (compactMatchText.includes("degraded")) {
    return "Degraded";
  }
  if (compactMatchText.includes("blocked")) {
    return "Blocked";
  }
  if (compactMatchText.includes("draining")) {
    return "Draining";
  }
  if (compactMatchText.includes("idle")) {
    return "Idle";
  }
  const localized = resolveStatusPillDisplayText(normalizedValue);
  if (typeof localized === "string" && localized.trim().length > 0 && localized.trim().toLowerCase() !== normalizedValue) {
    return localized.trim();
  }
  if (/[_-]/.test(normalizedValue)) {
    return sentenceCaseOperatorEvidenceValue(normalizedValue);
  }
  return typeof value === "string" ? value.trim() : "";
}

function collectOperatorEvidenceDrawerRows(card) {
  if (!(card instanceof HTMLElement)) {
    return [];
  }
  return Array.from(card.querySelectorAll(".operator-health-row"))
    .map((row) => {
      const labelNode = row.querySelector("strong");
      const valueNode = row.querySelector("span");
      const label = labelNode && typeof labelNode.textContent === "string" ? labelNode.textContent.replace(/\s+/g, " ").trim() : "";
      const rawValue = valueNode && typeof valueNode.textContent === "string" ? valueNode.textContent.replace(/\s+/g, " ").trim() : "";
      const value = formatOperatorEvidenceDrawerFactValue(label, rawValue);
      return {
        label,
        value,
        rawValue,
        normalizedLabel: label.toLowerCase(),
        normalizedValue: rawValue.toLowerCase(),
        isPlaceholder:
          valueNode instanceof HTMLElement
            ? valueNode.classList.contains("operator-metric-placeholder")
            : /^(pending|-|unknown|awaiting_signal|none_yet|no_evidence)$/i.test(rawValue),
      };
    })
    .filter((row) => row.label.length > 0 && row.value.length > 0);
}

function pushOperatorEvidenceDrawerFact(target, fact, limit = 3) {
  if (!Array.isArray(target) || target.length >= limit || !fact || typeof fact !== "object") {
    return;
  }
  const label = typeof fact.label === "string" ? fact.label.trim() : "";
  const value = typeof fact.value === "string" ? fact.value.trim() : "";
  if (!label || !value) {
    return;
  }
  const factKey = `${label.toLowerCase()}::${value.toLowerCase()}`;
  if (target.some((item) => `${item.label.toLowerCase()}::${item.value.toLowerCase()}` === factKey)) {
    return;
  }
  target.push({
    label,
    value,
    isPlaceholder: fact.isPlaceholder === true,
  });
}

function normalizeOperatorUiCopy(value) {
  if (typeof value !== "string") {
    return "";
  }
  return value
    .replace(/\s*В·\s*/g, " / ")
    .replace(/\s*·\s*/g, " / ")
    .replace(/\s{2,}/g, " ")
    .trim();
}

function pushOperatorEvidenceDrawerCheckpoint(target, checkpoint, limit = 3) {
  if (!Array.isArray(target) || target.length >= limit || !checkpoint || typeof checkpoint !== "object") {
    return;
  }
  const label = normalizeOperatorUiCopy(checkpoint.label);
  const value = normalizeOperatorUiCopy(checkpoint.value);
  if (!label || !value) {
    return;
  }
  const checkpointKey = `${label.toLowerCase()}::${value.toLowerCase()}`;
  if (target.some((item) => `${item.label.toLowerCase()}::${item.value.toLowerCase()}` === checkpointKey)) {
    return;
  }
  target.push({
    label,
    value,
    tone: typeof checkpoint.tone === "string" ? checkpoint.tone.trim() : "muted",
    isPlaceholder: checkpoint.isPlaceholder === true,
  });
}

function pushOperatorEvidenceDrawerOrigin(target, origin, limit = 3) {
  if (!Array.isArray(target) || target.length >= limit || !origin || typeof origin !== "object") {
    return;
  }
  const label = normalizeOperatorUiCopy(origin.label);
  const value = normalizeOperatorUiCopy(origin.value);
  if (!label || !value) {
    return;
  }
  const originKey = `${label.toLowerCase()}::${value.toLowerCase()}`;
  if (target.some((item) => `${item.label.toLowerCase()}::${item.value.toLowerCase()}` === originKey)) {
    return;
  }
  target.push({
    label,
    value,
    tone: typeof origin.tone === "string" ? origin.tone.trim() : "muted",
    isPlaceholder: origin.isPlaceholder === true,
  });
}

function pushOperatorEvidenceDrawerProvenance(target, item, limit = 3) {
  if (!Array.isArray(target) || target.length >= limit || !item || typeof item !== "object") {
    return;
  }
  const label = normalizeOperatorUiCopy(item.label);
  const value = normalizeOperatorUiCopy(item.value);
  const compactValue = normalizeOperatorUiCopy(item.compactValue);
  if (!label || !value) {
    return;
  }
  const itemKey = `${label.toLowerCase()}::${value.toLowerCase()}`;
  if (target.some((entry) => `${entry.label.toLowerCase()}::${entry.value.toLowerCase()}` === itemKey)) {
    return;
  }
  target.push({
    label,
    value,
    compactValue: compactValue || "",
    tone: typeof item.tone === "string" ? item.tone.trim() : "muted",
    isPlaceholder: item.isPlaceholder === true,
  });
}

function collectOperatorEvidenceDrawerFacts(card) {
  const rows = collectOperatorEvidenceDrawerRows(card);
  if (rows.length === 0) {
    return [];
  }
  const facts = [];
  for (const row of rows.filter((item) => !item.isPlaceholder)) {
    pushOperatorEvidenceDrawerFact(facts, row);
  }
  for (const row of rows.filter((item) => item.isPlaceholder)) {
    pushOperatorEvidenceDrawerFact(facts, row);
  }
  return facts.slice(0, 3);
}

function getOperatorEvidenceDrawerRefreshLabel() {
  if (el.operatorLastRefresh instanceof HTMLElement && typeof el.operatorLastRefresh.textContent === "string") {
    const text = el.operatorLastRefresh.textContent.replace(/\s+/g, " ").trim();
    if (text.length > 0) {
      return text;
    }
  }
  if (state.operatorSummaryUserRefreshed !== true) {
    return "Last refresh: waiting";
  }
  if (state.operatorLastRefreshState === "failed") {
    return "Last refresh: failed";
  }
  return "Last refresh: ok";
}

function getOperatorEvidenceDrawerRefreshStamp(refreshLabel) {
  const normalized = typeof refreshLabel === "string" ? refreshLabel.replace(/\s+/g, " ").trim() : "";
  if (!normalized) {
    return "Awaiting refresh";
  }
  const failedMatch = normalized.match(/^last refresh failed:\s*(.+)$/i);
  if (failedMatch) {
    return `failed ${failedMatch[1].trim()}`.trim();
  }
  const match = normalized.match(/^last refresh:\s*(.+)$/i);
  return match ? match[1].trim() : normalized;
}

function getOperatorEvidenceDrawerSavedViewLabel(viewId) {
  const normalizedView = normalizeOperatorSavedView(viewId);
  return normalizedView ? OPERATOR_SAVED_VIEWS[normalizedView]?.label ?? "" : "";
}

function resolveOperatorEvidenceDrawerSavedViewId(statusId) {
  const groupKey = getOperatorGroupKeyByStatusId(statusId);
  switch (groupKey) {
    case "runtime-device":
      return "runtime";
    case "queue-lifecycle":
      return "approvals";
    case "governance-evidence":
      return "audit";
    case "bridge-safety":
      return "incidents";
    default:
      return "";
  }
}

function dedupeOperatorEvidenceDrawerActions(actions, limit = 3) {
  const deduped = [];
  const seen = new Set();
  for (const action of Array.isArray(actions) ? actions : []) {
    if (!action || typeof action !== "object" || typeof action.label !== "string" || typeof action.actionId !== "string") {
      continue;
    }
    const targetStatusId = typeof action.targetStatusId === "string" ? action.targetStatusId.trim() : "";
    const actionKey = `${action.actionId.trim()}::${targetStatusId}`;
    if (seen.has(actionKey)) {
      continue;
    }
    seen.add(actionKey);
    deduped.push(action);
    if (deduped.length >= limit) {
      break;
    }
  }
  return deduped;
}

function buildOperatorEvidenceDrawerSavedViewAction(viewId) {
  const normalizedView = normalizeOperatorSavedView(viewId);
  if (!normalizedView) {
    return null;
  }
  return {
    label: `Open ${OPERATOR_SAVED_VIEWS[normalizedView].label} view`,
    actionId: `saved_view_${normalizedView}`,
    kind: "secondary",
  };
}

function prioritizeOperatorEvidenceDrawerActionsForWorkspace(actions, details = {}, viewId = "latest") {
  const nextActions = Array.isArray(actions) ? actions.slice() : [];
  const activeSavedView = details.activeSavedView && typeof details.activeSavedView === "object" ? details.activeSavedView : null;
  if (!activeSavedView || activeSavedView.id === "incidents") {
    return nextActions;
  }
  const normalizedViewId = normalizeOperatorEvidenceDrawerView(viewId) || "latest";
  const preferredActionIds = [];
  if (activeSavedView.id === "runtime") {
    preferredActionIds.push("open_workflow_control", "run_runtime_guardrail_path", "saved_view_runtime");
  } else if (activeSavedView.id === "approvals") {
    preferredActionIds.push("saved_view_approvals", "open_playbook", "open_quick_start");
  } else if (activeSavedView.id === "audit") {
    preferredActionIds.push("saved_view_audit", "full_ops_view");
  }
  if (preferredActionIds.length === 0) {
    return nextActions;
  }
  const scored = nextActions.map((action, index) => {
    const actionId = typeof action?.actionId === "string" ? action.actionId.trim() : "";
    const preferredIndex = preferredActionIds.indexOf(actionId);
    const viewBonus = normalizedViewId === "audit" && actionId === "saved_view_audit" ? -1 : 0;
    return {
      action,
      score: preferredIndex === -1 ? Number.MAX_SAFE_INTEGER : preferredIndex + viewBonus,
      index,
    };
  });
  scored.sort((left, right) => {
    if (left.score !== right.score) {
      return left.score - right.score;
    }
    return left.index - right.index;
  });
  return scored.map((entry) => entry.action);
}

function buildOperatorEvidenceDrawerWorkspaceActionRail(actions, details = {}, viewId = "latest", limit = 3) {
  const dedupedActions = dedupeOperatorEvidenceDrawerActions(actions, Number.MAX_SAFE_INTEGER);
  const prioritizedActions = prioritizeOperatorEvidenceDrawerActionsForWorkspace(dedupedActions, details, viewId);
  return prioritizedActions.slice(0, Math.max(1, limit));
}

function resolveOperatorEvidenceDrawerFactPresetPatterns(statusId, viewId) {
  const normalizedStatusId = typeof statusId === "string" ? statusId.trim() : "";
  const normalizedViewId = normalizeOperatorEvidenceDrawerView(viewId) || "latest";
  if (!normalizedStatusId || !Object.prototype.hasOwnProperty.call(OPERATOR_EVIDENCE_FACT_PRESETS, normalizedStatusId)) {
    return [];
  }
  const preset = OPERATOR_EVIDENCE_FACT_PRESETS[normalizedStatusId];
  if (!preset || !Array.isArray(preset[normalizedViewId])) {
    return [];
  }
  return preset[normalizedViewId];
}

function buildOperatorEvidenceDrawerPresetFacts(details, viewId, fallbackEntries = []) {
  const facts = [];
  const rows = Array.isArray(details.rows) ? details.rows : [];
  const presetPatterns = resolveOperatorEvidenceDrawerFactPresetPatterns(details.statusId, viewId);
  for (const pattern of presetPatterns) {
    if (!(pattern instanceof RegExp)) {
      continue;
    }
    const row = findOperatorEvidenceDrawerRow(rows, pattern, { includePlaceholder: true });
    if (row) {
      pushOperatorEvidenceDrawerFact(facts, row);
    }
  }
  for (const entry of Array.isArray(fallbackEntries) ? fallbackEntries : []) {
    pushOperatorEvidenceDrawerFact(facts, entry);
  }
  if (facts.length === 0) {
    for (const fact of Array.isArray(details.fallbackFacts) ? details.fallbackFacts : []) {
      pushOperatorEvidenceDrawerFact(facts, fact);
    }
  }
  return facts.slice(0, 3);
}

function resolveOperatorEvidenceDrawerCompactRefreshFactValue(value) {
  const normalized = normalizeOperatorUiCopy(value);
  if (!normalized) {
    return "Refresh";
  }
  if (/awaiting signal/i.test(normalized)) {
    return "Awaiting";
  }
  if (/\b(awaiting refresh|waiting)\b/i.test(normalized)) {
    return "Awaiting refresh";
  }
  if (/\b(fail|failed|error|stale)\b/i.test(normalized)) {
    return "Refresh failed";
  }
  const timeMatch = normalized.match(/\b\d{1,2}:\d{2}(?::\d{2})?\b/);
  if (timeMatch) {
    return `Updated ${timeMatch[0]}`;
  }
  return clipOperatorEvidenceDrawerSentence(normalized.replace(/^last refresh:\s*/i, ""), 20) || normalized;
}

function buildOperatorEvidenceDrawerLatestCompactFact(fact, details = {}) {
  if (!fact || typeof fact !== "object") {
    return fact;
  }
  const compactFact = { ...fact };
  const normalizedLabel = typeof fact.label === "string" ? fact.label.trim().toLowerCase() : "";
  const normalizedValue = normalizeOperatorUiCopy(fact.value);
  if (!normalizedLabel || !normalizedValue) {
    return compactFact;
  }
  if (normalizedLabel === "status" || normalizedLabel === "state") {
    compactFact.compactLabel = "State";
    compactFact.compactValue = /^awaiting signal$/i.test(normalizedValue)
      ? "Awaiting"
      : clipOperatorEvidenceDrawerSentence(normalizedValue, 22) || normalizedValue;
    return compactFact;
  }
  if (normalizedLabel === "last event" || normalizedLabel === "latest event" || normalizedLabel === "latest") {
    compactFact.compactLabel = "Event";
    compactFact.compactValue = /^awaiting signal$/i.test(normalizedValue)
      ? "No signal yet"
      : clipOperatorEvidenceDrawerSentence(normalizedValue, 24) || normalizedValue;
    return compactFact;
  }
  if (normalizedLabel === "last event at" || normalizedLabel === "latest at" || normalizedLabel === "refresh") {
    compactFact.compactLabel = normalizedLabel.includes("event") ? "Seen" : "Refresh";
    compactFact.compactValue = resolveOperatorEvidenceDrawerCompactRefreshFactValue(normalizedValue);
    return compactFact;
  }
  if (normalizedLabel === "next") {
    compactFact.compactValue =
      normalizedValue === "Refresh Summary"
        ? "Refresh"
        : clipOperatorEvidenceDrawerSentence(normalizedValue, 22) || normalizedValue;
    return compactFact;
  }
  compactFact.compactValue = clipOperatorEvidenceDrawerSentence(normalizedValue, 24) || normalizedValue;
  return compactFact;
}

function resolveOperatorEvidenceDrawerLatestFactsMode(details = {}) {
  return details.variant === "fail" ? "default" : "compact";
}

function buildOperatorEvidenceDrawerLatestFacts(details) {
  const facts =
    details.preserveFallbackFacts === true && Array.isArray(details.fallbackFacts) && details.fallbackFacts.length > 0
      ? details.fallbackFacts.slice(0, 3)
      : buildOperatorEvidenceDrawerPresetFacts(details, "latest", [
        { label: "Status", value: details.statusDisplayText, isPlaceholder: details.variant === "dormant" },
        { label: "Refresh", value: details.refreshLabel, isPlaceholder: state.operatorSummaryUserRefreshed !== true },
        { label: "Next", value: details.primaryActionLabel || "Open lane" },
      ]);
  return prioritizeOperatorEvidenceDrawerFactsForWorkspace(facts, details, "latest")
    .map((fact) => buildOperatorEvidenceDrawerLatestCompactFact(fact, details));
}

function buildOperatorEvidenceDrawerTraceFacts(details) {
  const facts = buildOperatorEvidenceDrawerPresetFacts(details, "trace", [
    { label: "Status", value: details.statusDisplayText, isPlaceholder: details.variant === "dormant" },
    { label: "Refresh", value: details.refreshLabel, isPlaceholder: state.operatorSummaryUserRefreshed !== true },
    { label: "Route", value: details.primaryActionLabel || details.traceLane || "Open lane" },
  ]);
  return prioritizeOperatorEvidenceDrawerFactsForWorkspace(facts, details, "trace");
}

function buildOperatorEvidenceDrawerRecoveryFacts(details) {
  const facts = [];
  pushOperatorEvidenceDrawerFact(facts, {
    label: "Priority",
    value:
      details.variant === "fail"
        ? "P1 act now"
        : details.variant === "stale"
          ? "P1 refresh needed"
          : details.variant === "watch"
            ? "P2 confirm signal"
            : details.variant === "ok"
              ? "P3 monitor only"
              : "P1 hydrate board",
  });
  pushOperatorEvidenceDrawerFact(facts, {
    label: "Primary path",
    value: details.actionsConfig?.supportLabel ?? details.actionsConfig?.openLabel ?? "Open lane",
  });
  pushOperatorEvidenceDrawerFact(facts, {
    label: "Follow-up",
    value: details.savedViewLabel || (details.variant === "ok" ? "Keep board quiet" : "Recovery kits"),
  });
  pushOperatorEvidenceDrawerFact(facts, {
    label: "Refresh",
    value:
      state.operatorSummaryUserRefreshed !== true
        ? "Hydrate summary first"
        : state.operatorLastRefreshState === "failed"
          ? "Retry summary before trusting evidence"
          : "Refresh after any recovery run",
  });
  return prioritizeOperatorEvidenceDrawerFactsForWorkspace(facts, details, "recovery");
}

function buildOperatorEvidenceDrawerAuditFacts(details) {
  const facts = [];
  pushOperatorEvidenceDrawerFact(facts, {
    label: "Posture",
    value: details.activeSavedView?.contextLabel ?? `${details.savedViewLabel || "Incident"} posture`,
  });
  pushOperatorEvidenceDrawerFact(facts, {
    label: "Board",
    value: normalizeOperatorBoardMode(state.operatorBoardMode) === "full" ? "Full Ops View" : "Demo View",
  });
  pushOperatorEvidenceDrawerFact(facts, {
    label: "Evidence",
    value:
      details.variant === "ok"
        ? "Ready for review"
        : details.variant === "dormant"
          ? "Awaiting evidence"
          : details.statusDisplayText,
  });
  pushOperatorEvidenceDrawerFact(facts, {
    label: "Refresh",
    value: details.refreshLabel,
  });
  return facts.slice(0, 3);
}

function buildOperatorEvidenceDrawerLatestOrigins(details) {
  const origins = [];
  const rows = Array.isArray(details.rows) ? details.rows : [];
  const sourceRow = findOperatorEvidenceDrawerRow(rows, /(state|status|mode|health|reason|result|queue|approval|bridge|gateway|pressure|policy|executor|device|event|signal)/i, {
    includePlaceholder: true,
  });
  pushOperatorEvidenceDrawerOrigin(origins, {
    label: "Workspace",
    value: details.cardTitle || details.label || "Focused workspace",
    tone: details.variant,
  });
  pushOperatorEvidenceDrawerOrigin(origins, {
    label: "View",
    value: details.savedViewLabel || "Board scan",
    tone: "muted",
  });
  pushOperatorEvidenceDrawerOrigin(origins, {
    label: "Source",
    value: sourceRow?.label && sourceRow.label.trim().toLowerCase() !== "latest" ? sourceRow.label : "Workspace summary",
    tone: sourceRow?.isPlaceholder ? "muted" : "watch",
  });
  return prioritizeOperatorEvidenceDrawerOriginsForWorkspace(origins, details);
}

function buildOperatorEvidenceDrawerTraceOrigins(details) {
  const origins = [];
  const rows = Array.isArray(details.rows) ? details.rows : [];
  const traceRow = findOperatorEvidenceDrawerRow(rows, /(trace|session|run|request|conversation|job|worker|device|node|source|fingerprint|profile|version)/i, {
    includePlaceholder: true,
  });
  pushOperatorEvidenceDrawerOrigin(origins, {
    label: "Workspace",
    value: details.traceLane || details.groupTitle || "Operator lane",
    tone: details.variant,
  });
  pushOperatorEvidenceDrawerOrigin(origins, {
    label: "View",
    value: details.savedViewLabel || "Runtime posture",
    tone: "muted",
  });
  pushOperatorEvidenceDrawerOrigin(origins, {
    label: "Source",
    value: traceRow?.label || "Trace anchor",
    tone: traceRow?.isPlaceholder ? "muted" : "watch",
  });
  return prioritizeOperatorEvidenceDrawerOriginsForWorkspace(origins, details);
}

function buildOperatorEvidenceDrawerRecoveryOrigins(details) {
  const origins = [];
  pushOperatorEvidenceDrawerOrigin(origins, {
    label: "Workspace",
    value: details.cardTitle || "Focused workspace",
    tone: details.variant,
  });
  pushOperatorEvidenceDrawerOrigin(origins, {
    label: "View",
    value: details.savedViewLabel || "Recovery posture",
    tone: "muted",
  });
  pushOperatorEvidenceDrawerOrigin(origins, {
    label: "Source",
    value: details.primaryActionLabel || "Recovery path",
    tone: "watch",
  });
  return prioritizeOperatorEvidenceDrawerOriginsForWorkspace(origins, details);
}

function buildOperatorEvidenceDrawerAuditOrigins(details) {
  const origins = [];
  pushOperatorEvidenceDrawerOrigin(origins, {
    label: "Workspace",
    value: details.cardTitle || "Focused workspace",
    tone: details.variant,
  });
  pushOperatorEvidenceDrawerOrigin(origins, {
    label: "View",
    value: details.activeSavedView?.contextLabel ?? `${details.savedViewLabel || "Incident"} posture`,
    tone: "muted",
  });
  pushOperatorEvidenceDrawerOrigin(origins, {
    label: "Source",
    value: details.auditActionLabel || details.primaryActionLabel || "Review path",
    tone: "watch",
  });
  return prioritizeOperatorEvidenceDrawerOriginsForWorkspace(origins, details);
}

function buildOperatorEvidenceDrawerWorkspaceLeadFact(details = {}, viewId = "latest") {
  const activeSavedView = details.activeSavedView && typeof details.activeSavedView === "object" ? details.activeSavedView : null;
  if (!activeSavedView || activeSavedView.id === "incidents") {
    return null;
  }
  const normalizedViewId = normalizeOperatorEvidenceDrawerView(viewId) || "latest";
  if (normalizedViewId === "audit") {
    return null;
  }
  return {
    label: normalizedViewId === "latest" ? "Workspace" : "Posture",
    value: activeSavedView.contextLabel ?? `${activeSavedView.label} posture`,
    tone: details.variant === "fail" ? "watch" : "muted",
  };
}

function prioritizeOperatorEvidenceDrawerFactsForWorkspace(facts, details = {}, viewId = "latest") {
  const nextFacts = Array.isArray(facts) ? facts.slice() : [];
  const workspaceLeadFact = buildOperatorEvidenceDrawerWorkspaceLeadFact(details, viewId);
  if (!workspaceLeadFact) {
    return nextFacts.slice(0, 3);
  }
  const filteredFacts = nextFacts.filter((fact) => {
    const label = typeof fact?.label === "string" ? fact.label.trim().toLowerCase() : "";
    return label !== "workspace" && label !== "posture";
  });
  return [workspaceLeadFact, ...filteredFacts].slice(0, 3);
}

function prioritizeOperatorEvidenceDrawerOriginsForWorkspace(origins, details = {}) {
  const activeSavedView = details.activeSavedView && typeof details.activeSavedView === "object" ? details.activeSavedView : null;
  if (!activeSavedView || activeSavedView.id === "incidents") {
    return Array.isArray(origins) ? origins.slice(0, 3) : [];
  }
  const workspaceOrigin = {
    label: "View",
    value: activeSavedView.contextLabel ?? `${activeSavedView.label} posture`,
    tone: "muted",
  };
  const filteredOrigins = (Array.isArray(origins) ? origins : []).filter((origin) => {
    const label = typeof origin?.label === "string" ? origin.label.trim().toLowerCase() : "";
    return label !== "view";
  });
  return [workspaceOrigin, ...filteredOrigins].slice(0, 3);
}

function resolveOperatorEvidenceDrawerWorkspaceFactTone(fact, index, activeView, model) {
  const workspaceId = normalizeOperatorSavedView(model?.activeSavedViewId) || "incidents";
  if (index === 0) {
    if (workspaceId === "audit" && activeView?.id === "audit") {
      return "watch";
    }
    return model?.variant ?? "muted";
  }
  if (workspaceId === "runtime") {
    if (activeView?.id === "trace") {
      return "watch";
    }
    if (activeView?.id === "recovery") {
      return "watch";
    }
  }
  if (workspaceId === "approvals") {
    if (activeView?.id === "latest") {
      return "watch";
    }
    if (activeView?.id === "recovery") {
      return "watch";
    }
  }
  if (workspaceId === "audit" && activeView?.id === "audit") {
    const normalizedLabel = normalizeOperatorUiCopy(fact?.label).toLowerCase();
    if (normalizedLabel === "workspace" || normalizedLabel === "posture") {
      return "watch";
    }
  }
  return "muted";
}

function resolveOperatorEvidenceDrawerWorkspaceOriginTone(origin, activeView, model) {
  const workspaceId = normalizeOperatorSavedView(model?.activeSavedViewId) || "incidents";
  if (workspaceId === "incidents") {
    return origin?.tone ?? "muted";
  }
  const normalizedLabel = normalizeOperatorUiCopy(origin?.label).toLowerCase();
  if (activeView?.id === "recovery" && normalizedLabel === "source") {
    return "watch";
  }
  if (workspaceId === "runtime") {
    if (activeView?.id === "trace" && (normalizedLabel === "view" || normalizedLabel === "source")) {
      return "watch";
    }
    if (activeView?.id === "recovery" && normalizedLabel === "source") {
      return "watch";
    }
  }
  if (workspaceId === "approvals") {
    if (activeView?.id === "latest" && normalizedLabel === "view") {
      return "watch";
    }
    if (activeView?.id === "recovery" && normalizedLabel === "source") {
      return "watch";
    }
  }
  if (workspaceId === "audit" && activeView?.id === "audit" && (normalizedLabel === "view" || normalizedLabel === "source")) {
    return "watch";
  }
  return "muted";
}

function getOperatorEvidenceDrawerWorkspaceConfig(model) {
  const workspaceId = normalizeOperatorSavedView(model?.activeSavedViewId) || "incidents";
  return OPERATOR_SAVED_VIEWS[workspaceId] ?? OPERATOR_SAVED_VIEWS.incidents;
}

function shouldUseOperatorEvidenceDrawerWorkspacePlaceholder(model) {
  return model?.variant === "dormant" || state.operatorSummaryUserRefreshed !== true;
}

function normalizeOperatorEvidenceDrawerHydrateMeta(meta) {
  const normalized = normalizeOperatorUiCopy(meta);
  if (!normalized) {
    return "Refresh Summary to hydrate this workspace.";
  }
  return normalized.replace(/^next:\s*/i, "").trim();
}

function resolveOperatorEvidenceDrawerWorkspaceHint(activeView, model) {
  if (!shouldUseOperatorEvidenceDrawerWorkspacePlaceholder(model)) {
    return model?.hint
      ?? "Use the tabs to confirm the current proof path, freshest signal, recovery path, or audit context before opening the deeper board.";
  }
  const config = getOperatorEvidenceDrawerWorkspaceConfig(model);
  return config.drawerDormantHint
    ?? `Refresh Summary to load ${config.label || "workspace"} evidence, then review the ${activeView?.label?.toLowerCase() ?? "focused"} proof path.`;
}

function buildOperatorEvidenceDrawerWorkspacePlaceholderFacts(activeView, model) {
  const config = getOperatorEvidenceDrawerWorkspaceConfig(model);
  const dormantFacts = Array.isArray(config.drawerDormantFacts) && config.drawerDormantFacts.length > 0
    ? config.drawerDormantFacts
    : [
        { label: "Hydrate", value: "Refresh Summary" },
        { label: "Then check", value: config.label || "Workspace" },
        { label: "Escalate via", value: "Recovery rail" },
      ];
  const limit = activeView?.factsMode === "compact" ? 2 : 3;
  return dormantFacts.slice(0, limit).map((fact, index) => ({
    label: fact.label,
    value: fact.value,
    compactLabel: fact.label,
    compactValue: fact.value,
    tone: index === 0 ? "watch" : "muted",
    isPlaceholder: true,
  }));
}

function buildOperatorEvidenceDrawerWorkspacePlaceholderOrigins(activeView, model) {
  const config = getOperatorEvidenceDrawerWorkspaceConfig(model);
  return [
    {
      label: "Workspace",
      value: config.contextLabel ?? `${config.label} view`,
      tone: "watch",
      isPlaceholder: true,
    },
    {
      label: "Source",
      value: config.drawerKicker ?? activeView?.label ?? "Focused Evidence",
      tone: "muted",
      isPlaceholder: true,
    },
    {
      label: "Next",
      value: normalizeOperatorEvidenceDrawerHydrateMeta(config.hydrateMeta),
      tone: "muted",
      isPlaceholder: true,
    },
  ];
}

function buildOperatorEvidenceDrawerWorkspacePlaceholderTimeline(activeView, model) {
  const config = getOperatorEvidenceDrawerWorkspaceConfig(model);
  const dormantFacts = Array.isArray(config.drawerDormantFacts) && config.drawerDormantFacts.length > 0
    ? config.drawerDormantFacts
    : [];
  return [
    createOperatorEvidenceDrawerTimelineEntry({
      step: "Hydrate",
      title: config.hydrateTitle ?? `Hydrate ${config.label || "workspace"} posture`,
      meta: config.hydrateHint ?? "Refresh Summary to load this workspace.",
      tone: "watch",
      time: "Now",
    }),
    createOperatorEvidenceDrawerTimelineEntry({
      step: "Then review",
      title: dormantFacts[1]?.value || activeView?.label || `${config.label || "Workspace"} proof`,
      meta: normalizeOperatorEvidenceDrawerHydrateMeta(config.hydrateMeta),
      tone: "muted",
      time: "After refresh",
    }),
  ];
}

function buildOperatorEvidenceDrawerWorkspacePlaceholderCheckpoints(activeView, model) {
  const config = getOperatorEvidenceDrawerWorkspaceConfig(model);
  const dormantFacts = Array.isArray(config.drawerDormantFacts) && config.drawerDormantFacts.length > 0
    ? config.drawerDormantFacts
    : [
        { label: "Hydrate", value: "Refresh Summary" },
        { label: "Then check", value: config.label || "Workspace" },
      ];
  return dormantFacts.slice(0, 2).map((fact, index) => ({
    label: fact.label,
    value: fact.value,
    tone: index === 0 ? "watch" : "muted",
    isPlaceholder: true,
  }));
}

function buildOperatorEvidenceDrawerWorkspacePlaceholderProvenance(activeView, model) {
  const config = getOperatorEvidenceDrawerWorkspaceConfig(model);
  return [
    {
      label: "Actor",
      value: config.label || "Workspace",
      compactValue: config.label || "Workspace",
      tone: "muted",
      isPlaceholder: true,
    },
    {
      label: "Route",
      value: "Refresh Summary",
      compactValue: "Refresh",
      tone: "watch",
      isPlaceholder: true,
    },
    {
      label: "Verify",
      value: normalizeOperatorEvidenceDrawerHydrateMeta(config.hydrateMeta),
      compactValue: "After refresh",
      tone: "muted",
      isPlaceholder: true,
    },
  ];
}

function buildOperatorEvidenceDrawerWorkspacePlaceholderActions(activeView, model) {
  const config = getOperatorEvidenceDrawerWorkspaceConfig(model);
  const workspaceId = normalizeOperatorSavedView(model?.activeSavedViewId) || "incidents";
  const label = config.label || "Workspace";
  const hasManualRefresh = state.operatorSummaryUserRefreshed === true;
  if (workspaceId === "approvals") {
    const seedAction = {
      label: `Seed ${label}`,
      actionId: "open_workflow_control",
      meta: hasManualRefresh
        ? "Reseed approval signals if the queue still looks empty."
        : "Run one approval-sensitive path first.",
      kind: hasManualRefresh ? "secondary" : undefined,
    };
    const openAction = {
      label: `Open ${label}`,
      actionId: "saved_view_approvals",
      meta: hasManualRefresh
        ? "Review queue pressure, approvals, and startup gates."
        : "Open the approval queue after the first refresh.",
      kind: hasManualRefresh ? undefined : "secondary",
    };
    return hasManualRefresh ? [openAction, seedAction] : [seedAction, openAction];
  }
  if (workspaceId === "runtime") {
    const hydrateAction = {
      label: `Hydrate ${label}`,
      actionId: "refresh_summary",
      meta: hasManualRefresh
        ? "Refresh runtime proof again if trace posture drifts."
        : "Refresh trace anchors and runtime posture.",
      kind: hasManualRefresh ? "secondary" : undefined,
    };
    const openAction = {
      label: `Open ${label}`,
      actionId: "saved_view_runtime",
      meta: hasManualRefresh
        ? "Inspect workflow, guardrails, and recovery paths."
        : "Open runtime diagnostics after the first refresh.",
      kind: hasManualRefresh ? undefined : "secondary",
    };
    return hasManualRefresh ? [openAction, hydrateAction] : [hydrateAction, openAction];
  }
  if (workspaceId === "audit") {
    const hydrateAction = {
      label: `Hydrate ${label}`,
      actionId: "refresh_summary",
      meta: hasManualRefresh
        ? "Refresh governance proof again if audit posture changes."
        : "Refresh governance proof and audit posture.",
      kind: hasManualRefresh ? "secondary" : undefined,
    };
    const openAction = {
      label: `Open ${label}`,
      actionId: "saved_view_audit",
      meta: hasManualRefresh
        ? "Review governance, cost, and export evidence."
        : "Open audit proof after the first refresh.",
      kind: hasManualRefresh ? undefined : "secondary",
    };
    return hasManualRefresh ? [openAction, hydrateAction] : [hydrateAction, openAction];
  }
  const refreshAction = {
    label: "Refresh Summary",
    actionId: "refresh_summary",
    meta: hasManualRefresh
      ? "Refresh again if the current workspace needs fresher proof."
      : "Hydrate the current workspace before deeper review.",
    kind: hasManualRefresh ? "secondary" : undefined,
  };
  const openAction = {
    label: activeView?.label ? `Open ${activeView.label}` : "Open lane",
    actionId: "open_playbook",
    meta: hasManualRefresh
      ? "Open the current workspace proof path."
      : "Open the current workspace after the first refresh.",
    kind: hasManualRefresh ? undefined : "secondary",
  };
  return hasManualRefresh ? [openAction, refreshAction] : [refreshAction, openAction];
}

function resolveOperatorEvidenceDrawerActionActor(actionConfig, details = {}) {
  const actionId = typeof actionConfig?.actionId === "string" ? actionConfig.actionId.trim() : "";
  if (details.activeViewId === "audit") {
    return actionId.startsWith("saved_view_") ? "Saved view" : "Operator review";
  }
  if (details.activeViewId === "trace") {
    if (actionId === "open_workflow_control" || actionId === "run_runtime_guardrail_path") {
      return "Runtime control";
    }
    if (actionId === "jump_status_card") {
      return "Lane inspector";
    }
    if (actionId.startsWith("saved_view_")) {
      return "Saved view";
    }
    return "Trace review";
  }
  if (details.activeViewId === "recovery") {
    if (actionId === "open_playbook" || actionId === "open_quick_start") {
      return "Recovery rail";
    }
    if (actionId === "open_workflow_control" || actionId === "run_runtime_guardrail_path") {
      return "Runtime control";
    }
    if (actionId === "open_device_nodes") {
      return "Device controls";
    }
    if (actionId.startsWith("saved_view_")) {
      return "Saved view";
    }
    return "Action center";
  }
  if (details.activeViewId === "latest") {
    if (actionId === "jump_status_card") {
      return "Lane inspector";
    }
    if (actionId === "open_playbook" || actionId === "open_quick_start") {
      return "Recovery rail";
    }
    if (actionId === "open_workflow_control" || actionId === "run_runtime_guardrail_path") {
      return "Runtime control";
    }
    if (actionId === "open_device_nodes") {
      return "Device controls";
    }
    if (actionId.startsWith("saved_view_")) {
      return "Saved view";
    }
    return "Active queue";
  }
  if (actionId === "open_workflow_control" || actionId === "run_runtime_guardrail_path") {
    return "Runtime control";
  }
  if (actionId === "open_playbook" || actionId === "open_quick_start") {
    return "Recovery rail";
  }
  if (actionId === "open_device_nodes") {
    return "Device controls";
  }
  if (actionId.startsWith("saved_view_")) {
    return "Saved view";
  }
  if (actionId === "full_ops_view" || actionId === "show_all_cards") {
    return "Board mode";
  }
  return "Operator";
}

function resolveOperatorEvidenceDrawerRouteIntent(details = {}) {
  const activeViewId = normalizeOperatorEvidenceDrawerView(details.activeViewId) || "latest";
  const statusId = typeof details.statusId === "string" ? details.statusId.trim() : "";
  if (statusId && Object.prototype.hasOwnProperty.call(OPERATOR_EVIDENCE_ROUTE_INTENTS, statusId)) {
    const statusIntents = OPERATOR_EVIDENCE_ROUTE_INTENTS[statusId];
    const statusIntent = typeof statusIntents?.[activeViewId] === "string" ? statusIntents[activeViewId].trim() : "";
    if (statusIntent) {
      return statusIntent;
    }
  }
  const groupKey = typeof details.groupKey === "string" ? details.groupKey.trim() : "";
  if (groupKey && Object.prototype.hasOwnProperty.call(OPERATOR_EVIDENCE_ROUTE_GROUP_INTENTS, groupKey)) {
    const groupIntents = OPERATOR_EVIDENCE_ROUTE_GROUP_INTENTS[groupKey];
    const groupIntent = typeof groupIntents?.[activeViewId] === "string" ? groupIntents[activeViewId].trim() : "";
    if (groupIntent) {
      return groupIntent;
    }
  }
  const savedViewId = normalizeOperatorSavedView(details.relatedSavedViewId);
  if (savedViewId && Object.prototype.hasOwnProperty.call(OPERATOR_EVIDENCE_ROUTE_VIEW_INTENTS, savedViewId)) {
    const savedViewIntents = OPERATOR_EVIDENCE_ROUTE_VIEW_INTENTS[savedViewId];
    const savedViewIntent = typeof savedViewIntents?.[activeViewId] === "string" ? savedViewIntents[activeViewId].trim() : "";
    if (savedViewIntent) {
      return savedViewIntent;
    }
  }
  return "";
}

function resolveOperatorEvidenceDrawerActionRoute(actionConfig, details = {}) {
  let baseLabel = "";
  if (typeof actionConfig?.label === "string" && actionConfig.label.trim().length > 0) {
    baseLabel = actionConfig.label.trim();
  } else {
    const actionId = typeof actionConfig?.actionId === "string" ? actionConfig.actionId.trim() : "";
    if (actionId.startsWith("saved_view_")) {
      const savedViewId = actionId.slice("saved_view_".length);
      const savedView = normalizeOperatorSavedView(savedViewId);
      baseLabel = savedView ? `Open ${OPERATOR_SAVED_VIEWS[savedView].label} view` : "Open saved view";
    } else if (actionId === "jump_status_card") {
      baseLabel = details.cardTitle || "Open lane";
    } else {
      baseLabel = "Open lane";
    }
  }
  if (baseLabel.includes(" / ")) {
    return baseLabel;
  }
  const intentLabel = resolveOperatorEvidenceDrawerRouteIntent(details);
  return intentLabel ? `${baseLabel} / ${intentLabel}` : baseLabel;
}

function isOperatorEvidenceDrawerCompactView(viewId) {
  const normalizedViewId = normalizeOperatorEvidenceDrawerView(viewId);
  return normalizedViewId === "latest" || normalizedViewId === "recovery" || normalizedViewId === "audit";
}

function resolveOperatorEvidenceDrawerCompactRouteValue(actionConfig, details = {}) {
  const fullRoute = resolveOperatorEvidenceDrawerActionRoute(actionConfig, details);
  const routeParts = fullRoute
    .split(/\s*\/\s*/u)
    .map((part) => part.trim())
    .filter(Boolean);
  const compactRoute = routeParts.length > 1 ? routeParts[routeParts.length - 1] : routeParts[0] || fullRoute;
  return clipOperatorEvidenceDrawerSentence(compactRoute, 30) || "Open lane";
}

function resolveOperatorEvidenceDrawerWorkspaceCompactRouteValue(actionConfig, details = {}) {
  const workspaceId = normalizeOperatorSavedView(details.activeSavedViewId || details.relatedSavedViewId) || "incidents";
  if (workspaceId === "runtime") {
    if (details.activeViewId === "trace") {
      return "Trace review";
    }
    if (details.activeViewId === "recovery") {
      return "Runtime recovery";
    }
  }
  if (workspaceId === "approvals") {
    if (details.activeViewId === "latest") {
      return "Approval queue";
    }
    if (details.activeViewId === "recovery") {
      return "Approval recovery";
    }
  }
  if (workspaceId === "audit" && details.activeViewId === "audit") {
    return "Audit review";
  }
  return resolveOperatorEvidenceDrawerCompactRouteValue(actionConfig, details);
}

function resolveOperatorEvidenceDrawerVerifyValue(details = {}) {
  if (details.activeViewId === "audit") {
    const boardModeLabel = normalizeOperatorBoardMode(state.operatorBoardMode) === "full" ? "Full Ops View" : "Demo View";
    return `${boardModeLabel} / ${details.refreshLabel || "Refresh Summary"}`;
  }
  if (details.activeViewId === "trace") {
    return details.refreshLabel || "Refresh Summary";
  }
  if (details.activeViewId === "recovery") {
    return details.refreshLabel || "Refresh after action";
  }
  return details.refreshLabel || "Refresh Summary";
}

function resolveOperatorEvidenceDrawerCompactVerifyValue(details = {}) {
  const refreshLabel = normalizeOperatorUiCopy(details.refreshLabel);
  if (refreshLabel) {
    if (/\b(fail|failed|error|stale)\b/i.test(refreshLabel)) {
      return "Refresh failed";
    }
    if (/\b(awaiting|waiting)\b/i.test(refreshLabel)) {
      return "Awaiting refresh";
    }
  }
  if (details.activeViewId === "audit") {
    return normalizeOperatorBoardMode(state.operatorBoardMode) === "full" ? "Full ops / Refresh" : "Demo view / Refresh";
  }
  if (details.activeViewId === "recovery") {
    return "Refresh after action";
  }
  return "Refresh";
}

function resolveOperatorEvidenceDrawerWorkspaceCompactVerifyValue(details = {}) {
  const workspaceId = normalizeOperatorSavedView(details.activeSavedViewId || details.relatedSavedViewId) || "incidents";
  if (workspaceId === "runtime") {
    if (details.activeViewId === "recovery") {
      return "Recover + refresh";
    }
    return "Trace + refresh";
  }
  if (workspaceId === "approvals") {
    if (details.activeViewId === "recovery") {
      return "Recover + refresh";
    }
    return "Decision + refresh";
  }
  if (workspaceId === "audit") {
    return "Audit + refresh";
  }
  return resolveOperatorEvidenceDrawerCompactVerifyValue(details);
}

function resolveOperatorEvidenceDrawerWorkspaceProvenanceLabel(details = {}) {
  const workspaceId = normalizeOperatorSavedView(details.activeSavedViewId) || "incidents";
  if (workspaceId === "runtime") {
    return "Runtime provenance";
  }
  if (workspaceId === "approvals") {
    return "Approval provenance";
  }
  if (workspaceId === "audit") {
    return "Audit provenance";
  }
  return "Action provenance";
}

function buildOperatorEvidenceDrawerProvenance(details = {}) {
  const provenance = [];
  const actions = Array.isArray(details.actions) ? details.actions.filter(Boolean) : [];
  const primaryAction = actions[0] ?? null;
  const secondaryAction = actions[1] ?? null;
  const preferredAction = details.routeAction ?? primaryAction ?? secondaryAction;
  const includeActor = !isOperatorEvidenceDrawerCompactView(details.activeViewId);
  const routeValue = resolveOperatorEvidenceDrawerActionRoute(preferredAction, details);
  const verifyValue = resolveOperatorEvidenceDrawerVerifyValue(details);
  if (includeActor) {
    pushOperatorEvidenceDrawerProvenance(provenance, {
      label: "Actor",
      value: resolveOperatorEvidenceDrawerActionActor(preferredAction, details),
      tone: details.variant,
    });
  }
  pushOperatorEvidenceDrawerProvenance(provenance, {
    label: "Route",
    value: routeValue,
    // Legacy compact-shell token kept for alignment coverage:
    // compactValue: resolveOperatorEvidenceDrawerCompactRouteValue(preferredAction, details),
    compactValue: resolveOperatorEvidenceDrawerWorkspaceCompactRouteValue(preferredAction, details),
    tone: preferredAction?.kind === "secondary" ? "muted" : "watch",
  });
  pushOperatorEvidenceDrawerProvenance(provenance, {
    label: "Verify",
    value: verifyValue,
    // Legacy compact-shell token kept for alignment coverage:
    // compactValue: resolveOperatorEvidenceDrawerCompactVerifyValue(details),
    compactValue: resolveOperatorEvidenceDrawerWorkspaceCompactVerifyValue(details),
    tone: "muted",
  });
  return provenance.slice(0, includeActor ? 3 : 2);
}

function buildOperatorEvidenceDrawerLatestCheckpoints(details) {
  const checkpoints = [];
  const rows = Array.isArray(details.rows) ? details.rows : [];
  const signalRow = findOperatorEvidenceDrawerRow(rows, /(state|status|mode|health|result|queue|approval|bridge|gateway|pressure|policy|executor|device|event|signal)/i, {
    includePlaceholder: true,
  });
  const freshnessRow = findOperatorEvidenceDrawerRow(rows, OPERATOR_EVIDENCE_REFRESH_ROW_PATTERN, {
    includePlaceholder: true,
  });
  pushOperatorEvidenceDrawerCheckpoint(checkpoints, {
    label: signalRow?.label || "State",
    value: signalRow?.value || details.statusDisplayText || "Awaiting signal",
    tone: details.variant,
    isPlaceholder: signalRow?.isPlaceholder === true && !signalRow?.value,
  });
  pushOperatorEvidenceDrawerCheckpoint(checkpoints, {
    label: freshnessRow?.label || "Refresh",
    value: freshnessRow?.value || details.refreshLabel || "Awaiting refresh",
    tone: freshnessRow?.isPlaceholder ? "muted" : "watch",
    isPlaceholder: freshnessRow?.isPlaceholder === true && !freshnessRow?.value,
  });
  pushOperatorEvidenceDrawerCheckpoint(checkpoints, {
    label: "Next",
    value: details.primaryActionLabel || "Open lane",
    tone: "muted",
  });
  return checkpoints.slice(0, 3);
}

function buildOperatorEvidenceDrawerTraceCheckpoints(details) {
  const checkpoints = [];
  const rows = Array.isArray(details.rows) ? details.rows : [];
  const traceRow = findOperatorEvidenceDrawerRow(rows, /(trace|session|run|request|conversation|job|worker|device|node|source|fingerprint|profile|version)/i, {
    includePlaceholder: true,
  });
  const freshnessRow = findOperatorEvidenceDrawerRow(rows, OPERATOR_EVIDENCE_REFRESH_ROW_PATTERN, {
    includePlaceholder: true,
  });
  pushOperatorEvidenceDrawerCheckpoint(checkpoints, {
    label: traceRow?.label || "Trace",
    value: traceRow?.value || details.traceLane || "Awaiting trace id",
    tone: details.variant,
    isPlaceholder: traceRow?.isPlaceholder === true && !traceRow?.value,
  });
  pushOperatorEvidenceDrawerCheckpoint(checkpoints, {
    label: freshnessRow?.label || "Freshness",
    value: freshnessRow?.value || details.refreshLabel || "Awaiting refresh",
    tone: freshnessRow?.isPlaceholder ? "muted" : "watch",
    isPlaceholder: freshnessRow?.isPlaceholder === true && !freshnessRow?.value,
  });
  pushOperatorEvidenceDrawerCheckpoint(checkpoints, {
    label: "Route",
    value: details.primaryActionLabel || details.traceLane || details.savedViewLabel || "Operator lane",
    tone: "watch",
  });
  return checkpoints.slice(0, 3);
}

function buildOperatorEvidenceDrawerRecoveryCheckpoints(details) {
  const checkpoints = [];
  const priorityValue =
    details.variant === "fail"
      ? "P1 act now"
      : details.variant === "stale"
        ? "P1 refresh needed"
        : details.variant === "watch"
          ? "P2 confirm signal"
          : details.variant === "ok"
            ? "P3 monitor only"
            : "P1 hydrate board";
  pushOperatorEvidenceDrawerCheckpoint(checkpoints, {
    label: "Priority",
    value: priorityValue,
    tone: details.variant,
  });
  pushOperatorEvidenceDrawerCheckpoint(checkpoints, {
    label: "Path",
    value: details.primaryActionLabel || "Open lane",
    tone: "watch",
  });
  pushOperatorEvidenceDrawerCheckpoint(checkpoints, {
    label: "Verify",
    value: details.refreshLabel || "Refresh after action",
    tone: "muted",
  });
  return checkpoints.slice(0, 3);
}

function buildOperatorEvidenceDrawerAuditCheckpoints(details) {
  const checkpoints = [];
  pushOperatorEvidenceDrawerCheckpoint(checkpoints, {
    label: "Posture",
    value: details.activeSavedView?.contextLabel ?? `${details.savedViewLabel || "Incident"} posture`,
    tone: details.variant,
  });
  pushOperatorEvidenceDrawerCheckpoint(checkpoints, {
    label: "Board",
    value: normalizeOperatorBoardMode(state.operatorBoardMode) === "full" ? "Full Ops View" : "Demo View",
    tone: "muted",
  });
  pushOperatorEvidenceDrawerCheckpoint(checkpoints, {
    label: "Review",
    value: details.auditActionLabel || details.primaryActionLabel || "Open lane",
    tone: "watch",
  });
  return checkpoints.slice(0, 3);
}

const OPERATOR_EVIDENCE_REFRESH_ROW_PATTERN = /(\bupdated\b|\blast\b|\brefresh\b|\bheartbeat\b|\btime\b|\btimestamp\b|\bseen\b|\bsnapshot\b|\bobserved\b|\brefreshed\b|\bat\b)/i;
const OPERATOR_EVIDENCE_SIGNAL_TIME_PATTERN = /(\blatest\b|\bupdated\b|\blast\b|\btime\b|\btimestamp\b|\bseen\b|\bevent\b|\bsignal\b|\brefresh\b|\bat\b)/i;

function findOperatorEvidenceDrawerRow(rows, pattern, options = {}) {
  const entries = Array.isArray(rows) ? rows : [];
  const includePlaceholder = options.includePlaceholder === true;
  for (const row of entries) {
    if (!row || typeof row !== "object") {
      continue;
    }
    if (!includePlaceholder && row.isPlaceholder) {
      continue;
    }
    const haystack = `${row.normalizedLabel ?? ""} ${row.normalizedValue ?? ""}`;
    if (pattern.test(haystack)) {
      return row;
    }
  }
  if (!includePlaceholder) {
    return findOperatorEvidenceDrawerRow(entries, pattern, { includePlaceholder: true });
  }
  return null;
}

function resolveOperatorEvidenceDrawerTimelineTime(details, pattern, options = {}) {
  const rows = Array.isArray(details?.rows) ? details.rows : [];
  const row = pattern instanceof RegExp ? findOperatorEvidenceDrawerRow(rows, pattern, options) : null;
  if (row && typeof row.value === "string" && row.value.trim().length > 0) {
    return row.value.trim();
  }
  if (typeof details?.refreshStamp === "string" && details.refreshStamp.trim().length > 0) {
    return details.refreshStamp.trim();
  }
  return "Awaiting refresh";
}

function createOperatorEvidenceDrawerTimelineEntry(config) {
  const step = typeof config?.step === "string" && config.step.trim().length > 0 ? config.step.trim() : "Now";
  const title = normalizeOperatorUiCopy(config?.title) || "Awaiting signal";
  const meta = normalizeOperatorUiCopy(config?.meta) || "Refresh Summary to hydrate the proof path.";
  const tone = typeof config?.tone === "string" && config.tone.trim().length > 0 ? config.tone.trim() : "muted";
  const time = normalizeOperatorUiCopy(config?.time) || "Awaiting refresh";
  return { step, title, meta, tone, time };
}

function formatOperatorEvidenceDrawerSummaryPart(value) {
  const normalized = normalizeOperatorUiCopy(value);
  if (!normalized) {
    return "";
  }
  return normalized.replace(/[.\s]+$/g, "").trim();
}

function clipOperatorEvidenceDrawerSentence(value, maxLength = 88) {
  const normalized = formatOperatorEvidenceDrawerSummaryPart(value);
  if (!normalized) {
    return "";
  }
  const sentence = normalized.split(/(?<=[.!?])\s+/u)[0]?.trim() ?? normalized;
  if (sentence.length <= maxLength) {
    return sentence.replace(/[.\s]+$/g, "").trim();
  }
  return `${sentence.slice(0, Math.max(0, maxLength - 3)).trimEnd()}...`;
}

function buildOperatorEvidenceDrawerSummary(viewId, details = {}) {
  const normalizedViewId = normalizeOperatorEvidenceDrawerView(viewId) || "latest";
  const facts = Array.isArray(details.facts) ? details.facts : [];
  const leadFact = facts[0] ?? null;
  const secondaryFact = facts[1] ?? null;
  const hintSentence = clipOperatorEvidenceDrawerSentence(details.hint);
  const leadValueSentence = clipOperatorEvidenceDrawerSentence(leadFact?.value);
  const leadSnippet =
    leadFact && typeof leadFact.label === "string" && typeof leadFact.value === "string"
      ? formatOperatorEvidenceDrawerSummaryPart(`${leadFact.label}: ${leadFact.value}`)
      : "";
  const secondarySnippet =
    secondaryFact &&
    secondaryFact.isPlaceholder !== true &&
    typeof secondaryFact.label === "string" &&
    typeof secondaryFact.value === "string"
      ? formatOperatorEvidenceDrawerSummaryPart(`${secondaryFact.label}: ${secondaryFact.value}`)
      : "";
  const nextActionSnippet = formatOperatorEvidenceDrawerSummaryPart(
    details.primaryActionLabel ? `Next: ${details.primaryActionLabel}` : "",
  );
  const leadValue = normalizeOperatorUiCopy(leadFact?.value);
  const hasWeakLeadValue = Boolean(
    !leadValue ||
      /^(0|none|none yet|awaiting|awaiting signal|0\s*\/\s*0|\d+|\d+\s*\/\s*\d+)$/iu.test(leadValue),
  );
  const actionFirstSnippet = formatOperatorEvidenceDrawerSummaryPart(
    details.primaryActionLabel ? `${details.primaryActionLabel} first` : clipOperatorEvidenceDrawerSentence(details.primaryActionMeta),
  );

  let parts = [];
  if (normalizedViewId === "trace") {
    parts = [
      leadSnippet,
      formatOperatorEvidenceDrawerSummaryPart(
        details.traceLane ? `Scope: ${details.traceLane}` : details.savedViewLabel ? `Scope: ${details.savedViewLabel}` : "",
      ),
      nextActionSnippet,
    ];
  } else if (normalizedViewId === "recovery") {
    parts = [
      formatOperatorEvidenceDrawerSummaryPart(
        details.primaryActionLabel
          ? `${details.primaryActionLabel} first`
          : clipOperatorEvidenceDrawerSentence(details.primaryActionMeta) || "Take the highlighted path first",
      ),
    ];
  } else if (normalizedViewId === "audit") {
    parts = [
      formatOperatorEvidenceDrawerSummaryPart(
        clipOperatorEvidenceDrawerSentence(
          details.savedViewLabel
            ? `Review in ${details.savedViewLabel} posture`
            : details.cardTitle
              ? `Review ${details.cardTitle} in current posture`
              : "",
        ),
      ),
    ];
  } else {
    const leadPlaceholder = leadFact?.isPlaceholder === true || /^awaiting signal$/i.test(leadValue);
    if (leadPlaceholder) {
      parts = [state.operatorSummaryUserRefreshed === true ? "Awaiting fresh signal" : "Refresh Summary first"];
    } else if (details.factsMode === "compact" && hasWeakLeadValue) {
      parts = [actionFirstSnippet || hintSentence || secondarySnippet || leadSnippet];
    } else if (details.factsMode === "compact") {
      parts = [leadValueSentence || leadSnippet || hintSentence];
    } else {
      parts = [hintSentence || leadValueSentence || leadSnippet];
    }
  }

  const compact = parts.filter((part) => part.length > 0);
  if (compact.length > 0) {
    return `${compact.join(". ")}.`;
  }
  return "Use the highlighted issue first, then open deeper diagnostics only if you still need confirmation.";
}

function buildOperatorEvidenceDrawerLatestTimeline(details) {
  const rows = Array.isArray(details.rows) ? details.rows : [];
  const signalRow = findOperatorEvidenceDrawerRow(rows, /(state|status|mode|health|reason|result|queue|approval|bridge|gateway|pressure|policy|executor|device|event|signal)/i);
  const observedTime = resolveOperatorEvidenceDrawerTimelineTime(details, OPERATOR_EVIDENCE_REFRESH_ROW_PATTERN, {
    includePlaceholder: true,
  });
  const signalTime = resolveOperatorEvidenceDrawerTimelineTime(details, OPERATOR_EVIDENCE_SIGNAL_TIME_PATTERN, {
    includePlaceholder: true,
  });
  return [
    createOperatorEvidenceDrawerTimelineEntry({
      step: "Observed",
      title: details.cardTitle || details.label || "Focused lane",
      meta: details.statusDisplayText || "Awaiting refresh",
      tone: details.variant,
      time: observedTime,
    }),
    createOperatorEvidenceDrawerTimelineEntry({
      step: "Signal",
      title: signalRow?.label || "Latest signal",
      meta: signalRow?.value || details.refreshLabel || "Awaiting signal",
      tone: signalRow?.isPlaceholder ? "muted" : "watch",
      time: signalTime,
    }),
    createOperatorEvidenceDrawerTimelineEntry({
      step: "Next check",
      title: details.primaryActionLabel || "Open lane",
      meta: details.primaryActionMeta || "Use the highlighted workspace path before opening the deeper board.",
      tone: "muted",
      time: details.refreshStamp || "After refresh",
    }),
  ];
}

function buildOperatorEvidenceDrawerTraceTimeline(details) {
  const rows = Array.isArray(details.rows) ? details.rows : [];
  const traceRow = findOperatorEvidenceDrawerRow(rows, /(trace|session|run|request|conversation|job|worker|device|node|source|fingerprint|profile|version)/i);
  const freshnessRow = findOperatorEvidenceDrawerRow(rows, OPERATOR_EVIDENCE_REFRESH_ROW_PATTERN, { includePlaceholder: true });
  const traceTime = resolveOperatorEvidenceDrawerTimelineTime(details, OPERATOR_EVIDENCE_REFRESH_ROW_PATTERN, {
    includePlaceholder: true,
  });
  const freshnessTime = resolveOperatorEvidenceDrawerTimelineTime(details, OPERATOR_EVIDENCE_REFRESH_ROW_PATTERN, {
    includePlaceholder: true,
  });
  return [
    createOperatorEvidenceDrawerTimelineEntry({
      step: "Anchor",
      title: traceRow?.label || "Trace anchor",
      meta: traceRow?.value || details.traceLane || "Awaiting trace id",
      tone: details.variant,
      time: traceTime,
    }),
    createOperatorEvidenceDrawerTimelineEntry({
      step: "Freshness",
      title: freshnessRow?.label || "Refresh state",
      meta: freshnessRow?.value || details.refreshLabel || "Awaiting refresh",
      tone: freshnessRow?.isPlaceholder ? "muted" : "watch",
      time: freshnessTime,
    }),
    createOperatorEvidenceDrawerTimelineEntry({
      step: "Context",
      title: details.groupTitle || "Focused lane",
      meta: details.traceLane || details.savedViewLabel || "Operator lane",
      tone: "muted",
      time: details.refreshStamp || "Current",
    }),
  ];
}

function buildOperatorEvidenceDrawerRecoveryTimeline(details) {
  const priorityTitle =
    details.variant === "fail"
      ? "P1 act now"
      : details.variant === "stale"
        ? "P1 refresh needed"
        : details.variant === "watch"
          ? "P2 confirm signal"
          : details.variant === "ok"
            ? "P3 monitor only"
            : "P1 hydrate board";
  return [
    createOperatorEvidenceDrawerTimelineEntry({
      step: "Risk",
      title: priorityTitle,
      meta: details.statusDisplayText || "Awaiting refresh",
      tone: details.variant,
      time: details.refreshStamp || "Current",
    }),
    createOperatorEvidenceDrawerTimelineEntry({
      step: "Path",
      title: details.primaryActionLabel || "Open lane",
      meta: details.primaryActionMeta || "Follow the lane recovery path before opening lower controls.",
      tone: "watch",
      time: details.refreshStamp || "Current",
    }),
    createOperatorEvidenceDrawerTimelineEntry({
      step: "Verify after",
      title: "Refresh Summary",
      meta: details.refreshLabel || "Refresh after recovery action",
      tone: "muted",
      time: details.refreshStamp || "After action",
    }),
  ];
}

function buildOperatorEvidenceDrawerAuditTimeline(details) {
  return [
    createOperatorEvidenceDrawerTimelineEntry({
      step: "Posture",
      title: details.activeSavedView?.contextLabel ?? `${details.savedViewLabel || "Incident"} posture`,
      meta: details.statusDisplayText || "Awaiting evidence",
      tone: details.variant,
      time: details.refreshStamp || "Current",
    }),
    createOperatorEvidenceDrawerTimelineEntry({
      step: "Board state",
      title: normalizeOperatorBoardMode(state.operatorBoardMode) === "full" ? "Full Ops View" : "Demo View",
      meta: details.refreshLabel || "Refresh before review",
      tone: "muted",
      time: details.refreshStamp || "Current",
    }),
    createOperatorEvidenceDrawerTimelineEntry({
      step: "Review",
      title: details.auditActionLabel || details.primaryActionLabel || "Open lane",
      meta: details.savedViewLabel ? `Cross-check with ${details.savedViewLabel}` : "Review evidence in board context.",
      tone: "watch",
      time: details.refreshStamp || "After review",
    }),
  ];
}

function resolveOperatorEvidenceDrawerDefaultView(model) {
  if (!model || typeof model !== "object") {
    return "latest";
  }
  const needsRecoveryView =
    model.variant === "fail"
    || model.variant === "stale"
    || model.variant === "dormant"
    || state.operatorSummaryUserRefreshed !== true;
  if (model.activeSavedViewId === "audit") {
    return "audit";
  }
  if (model.activeSavedViewId === "runtime") {
    return needsRecoveryView ? "recovery" : "trace";
  }
  if (model.activeSavedViewId === "approvals") {
    return needsRecoveryView ? "recovery" : "latest";
  }
  if (needsRecoveryView) {
    return "recovery";
  }
  return "latest";
}

function resolveOperatorEvidenceDrawerViewOrder(model) {
  const defaultOrder = ["latest", "trace", "recovery", "audit"];
  if (!model || typeof model !== "object") {
    return defaultOrder;
  }
  const needsRecoveryView =
    model.variant === "fail"
    || model.variant === "stale"
    || model.variant === "dormant"
    || state.operatorSummaryUserRefreshed !== true;
  if (model.activeSavedViewId === "audit") {
    return ["audit", "latest", "trace", "recovery"];
  }
  if (model.activeSavedViewId === "runtime") {
    return needsRecoveryView
      ? ["recovery", "trace", "latest", "audit"]
      : ["trace", "recovery", "latest", "audit"];
  }
  if (model.activeSavedViewId === "approvals") {
    return needsRecoveryView
      ? ["recovery", "latest", "trace", "audit"]
      : ["latest", "recovery", "trace", "audit"];
  }
  if (needsRecoveryView) {
    return ["recovery", "latest", "trace", "audit"];
  }
  return defaultOrder;
}

function resolveOperatorEvidenceDrawerWorkspaceTabLabel(viewId, model) {
  const normalizedViewId = normalizeOperatorEvidenceDrawerView(viewId) || "latest";
  const fallbackLabel = OPERATOR_EVIDENCE_DRAWER_VIEWS.find((view) => view.id === normalizedViewId)?.label ?? "Latest event";
  if (!shouldUseOperatorEvidenceDrawerWorkspacePlaceholder(model)) {
    return fallbackLabel;
  }
  const workspaceId = normalizeOperatorSavedView(model?.activeSavedViewId) || "incidents";
  return OPERATOR_EVIDENCE_ROUTE_VIEW_INTENTS[workspaceId]?.[normalizedViewId] ?? fallbackLabel;
}

function resolveOperatorEvidenceDrawerWorkspaceHeading(model, activeView) {
  const baseKicker = model?.kicker ?? "Focused Evidence";
  const baseTitle = model?.title ?? "Awaiting focused evidence";
  if (!shouldUseOperatorEvidenceDrawerWorkspacePlaceholder(model) || !activeView) {
    return { kicker: baseKicker, title: baseTitle };
  }
  const config = getOperatorEvidenceDrawerWorkspaceConfig(model);
  const viewLabel = normalizeOperatorUiCopy(activeView?.label);
  const workspaceTitle = normalizeOperatorUiCopy(config?.hydrateTitle);
  if (!viewLabel) {
    return { kicker: baseKicker, title: workspaceTitle ?? baseTitle };
  }
  return {
    kicker: viewLabel,
    title: workspaceTitle ?? baseTitle,
  };
}

function resolveOperatorEvidenceDrawerWorkspaceLane(model, activeView) {
  const baseLane = normalizeOperatorUiCopy(model?.lane)
    ?? "Select a workspace above or refresh summary to hydrate focused evidence.";
  if (!shouldUseOperatorEvidenceDrawerWorkspacePlaceholder(model) || !activeView) {
    return baseLane;
  }
  const config = getOperatorEvidenceDrawerWorkspaceConfig(model);
  return normalizeOperatorUiCopy(config?.contextLabel ?? config?.drawerKicker ?? activeView?.label) ?? baseLane;
}

function resolveOperatorEvidenceDrawerWorkspaceStatusText(model, activeView) {
  const baseStatusText =
    normalizeOperatorUiCopy(model?.statusDisplayText)
    ?? resolveStatusPillDisplayText(model?.statusCode || model?.statusText || "awaiting_refresh");
  if (!shouldUseOperatorEvidenceDrawerWorkspacePlaceholder(model) || !activeView) {
    return baseStatusText;
  }
  const workspaceId = normalizeOperatorSavedView(model?.activeSavedViewId) || "incidents";
  if (workspaceId === "approvals") {
    return "Seed approvals";
  }
  const config = getOperatorEvidenceDrawerWorkspaceConfig(model);
  const workspaceTitle = normalizeOperatorUiCopy(config?.hydrateTitle)?.replace(/\s+posture$/iu, "").trim();
  if (workspaceId === "incidents") {
    return "Hydrate incidents";
  }
  return workspaceTitle || baseStatusText;
}

function buildOperatorEvidenceDrawerModelLegacy(statusId) {
  const normalizedStatusId = typeof statusId === "string" ? statusId.trim() : "";
  const activeSavedView = getActiveOperatorSavedViewConfig();
  const signal = getOperatorSummaryGuideSignalById(normalizedStatusId);
  const statusNode = normalizedStatusId ? document.getElementById(normalizedStatusId) : null;
  const card = getOperatorCardByStatusId(normalizedStatusId);
  const group = card instanceof HTMLElement ? card.closest(".operator-health-group") : null;
  const groupKickerNode = group instanceof HTMLElement ? group.querySelector(".operator-health-group-kicker") : null;
  const groupTitleNode = group instanceof HTMLElement ? group.querySelector(".operator-health-group-title-copy h3") : null;
  const cardTitleNode = card instanceof HTMLElement ? card.querySelector("h3") : null;
  const hintNode = card instanceof HTMLElement ? card.querySelector(".operator-health-hint") : null;
  const variant = resolveOperatorEvidenceDrawerVariant(signal);
  const label = signal && typeof signal.label === "string"
    ? signal.label.trim()
    : cardTitleNode && typeof cardTitleNode.textContent === "string"
      ? cardTitleNode.textContent.trim()
      : "Operator lane";
  const groupKicker = groupKickerNode && typeof groupKickerNode.textContent === "string" ? groupKickerNode.textContent.trim() : "Lane";
  const groupTitle = groupTitleNode && typeof groupTitleNode.textContent === "string" ? groupTitleNode.textContent.trim() : "Focused lane";
  const cardTitle = cardTitleNode && typeof cardTitleNode.textContent === "string" ? cardTitleNode.textContent.trim() : label;
  const hint = hintNode && typeof hintNode.textContent === "string"
    ? hintNode.textContent.trim()
    : "Open the lane for deeper evidence and use recovery kits only if the issue persists.";
  const statusCode = statusNode instanceof HTMLElement && typeof statusNode.dataset.statusCode === "string"
    ? statusNode.dataset.statusCode.trim()
    : "awaiting_refresh";
  const statusText = statusNode instanceof HTMLElement && typeof statusNode.textContent === "string"
    ? statusNode.textContent.trim()
    : resolveStatusPillDisplayText(statusCode);
  const facts = collectOperatorEvidenceDrawerFacts(card);
  const focusTitle =
    variant === "fail"
      ? `${label} needs operator attention`
      : variant === "stale"
        ? `${label} is running on stale evidence`
        : variant === "watch"
          ? `${label} needs a closer look`
          : variant === "ok"
            ? `${label} is stable`
            : `Awaiting ${label.toLowerCase()} signal`;
  const inActiveSavedView =
    !!activeSavedView &&
    (!activeSavedView.groupKey || getOperatorGroupKeyByStatusId(normalizedStatusId) === activeSavedView.groupKey);
  const drawerKicker = inActiveSavedView
    ? activeSavedView.drawerKicker ?? "Focused Evidence"
    : "Focused Evidence";
  let drawerTitle = focusTitle;
  let drawerHint = hint;
  let drawerFacts = facts;
  if ((variant === "dormant" || state.operatorSummaryUserRefreshed !== true) && inActiveSavedView) {
    drawerTitle = activeSavedView.drawerDormantTitle ?? focusTitle;
    drawerHint = activeSavedView.drawerDormantHint ?? hint;
    if (Array.isArray(activeSavedView.drawerDormantFacts) && activeSavedView.drawerDormantFacts.length > 0) {
      drawerFacts = activeSavedView.drawerDormantFacts.map((fact) => ({
        label: fact.label,
        value: fact.value,
        isPlaceholder: true,
      }));
    }
  }
  const actionsConfig = OPERATOR_PRIORITY_QUEUE_ACTIONS[normalizedStatusId] ?? null;
  const actions = [];
  if (normalizedStatusId) {
    actions.push({
      label: actionsConfig?.openLabel ?? "Open lane",
      actionId: "jump_status_card",
      targetStatusId: normalizedStatusId,
    });
  }
  if (
    actionsConfig &&
    typeof actionsConfig.supportAction === "string" &&
    actionsConfig.supportAction.length > 0 &&
    variant !== "ok"
  ) {
    actions.push({
      label: actionsConfig.supportLabel ?? "Open support",
      actionId: actionsConfig.supportAction,
      kind: "secondary",
    });
  }
  if (variant === "fail" || variant === "stale" || variant === "dormant" || state.operatorSummaryUserRefreshed !== true) {
    actions.push({
      label: "Refresh Summary",
      actionId: "refresh_summary",
      kind: "secondary",
    });
  }
  return {
    statusId: normalizedStatusId,
    variant,
    kicker: drawerKicker,
    title: drawerTitle,
    lane: `${groupKicker} / ${groupTitle} / ${cardTitle}`,
    hint: drawerHint,
    statusCode,
    statusText,
    facts: drawerFacts,
    actions: actions.slice(0, 3),
  };
}

function syncOperatorEvidenceDrawerLegacy() {
  if (
    !(el.operatorEvidenceDrawer instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerFacts instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerActions instanceof HTMLElement)
  ) {
    return;
  }
  const focusedStatusId = resolveOperatorFocusedEvidenceStatusId();
  state.operatorFocusedEvidenceStatusId = focusedStatusId;
  syncOperatorBoardCardHierarchy();
  const model = buildOperatorEvidenceDrawerModel(focusedStatusId);
  el.operatorEvidenceDrawer.dataset.evidenceVariant = model.variant ?? "neutral";
  if (el.operatorEvidenceDrawerProofPathSection instanceof HTMLDetailsElement) {
    const isDormantProofPath = model.variant === "dormant" || state.operatorSummaryUserRefreshed !== true;
    el.operatorEvidenceDrawerProofPathSection.open = !isDormantProofPath;
    el.operatorEvidenceDrawerProofPathSection.dataset.proofPathState = isDormantProofPath ? "dormant" : "hydrated";
  }
  const heading = resolveOperatorEvidenceDrawerWorkspaceHeading(model, null);
  setText(el.operatorEvidenceDrawerKicker, heading.kicker);
  setText(el.operatorEvidenceDrawerTitle, heading.title);
  setText(el.operatorEvidenceDrawerLane, resolveOperatorEvidenceDrawerWorkspaceLane(model, null));
  setText(el.operatorEvidenceDrawerHint, model.hint);
  if (el.operatorEvidenceDrawerStatus instanceof HTMLElement) {
    el.operatorEvidenceDrawerStatus.dataset.statusCode = model.statusCode;
    el.operatorEvidenceDrawerStatus.textContent = resolveOperatorEvidenceDrawerWorkspaceStatusText(model, null);
    el.operatorEvidenceDrawerStatus.className = "status-pill";
    if (model.variant === "fail") {
      el.operatorEvidenceDrawerStatus.classList.add("status-fail");
    } else if (model.variant === "ok") {
      el.operatorEvidenceDrawerStatus.classList.add("status-ok");
    } else {
      el.operatorEvidenceDrawerStatus.classList.add("status-neutral");
    }
  }
  el.operatorEvidenceDrawerFacts.innerHTML = "";
  const facts = Array.isArray(model.facts) && model.facts.length > 0
    ? model.facts
    : [{ label: "Awaiting signal", value: "Refresh Summary", isPlaceholder: true }];
  facts.forEach((fact, index) => {
    const article = document.createElement("article");
    article.className = fact.isPlaceholder
      ? "operator-evidence-drawer-fact is-placeholder"
      : "operator-evidence-drawer-fact";
    article.classList.add(index === 0 ? "is-primary" : "is-secondary");
    article.classList.add(`is-${index === 0 ? model.variant ?? "muted" : "muted"}`);
    const label = document.createElement("span");
    label.className = "operator-evidence-drawer-fact-label";
    label.textContent = fact.label;
    const value = document.createElement("strong");
    value.textContent = fact.value;
    article.append(label, value);
    el.operatorEvidenceDrawerFacts.append(article);
  });
  el.operatorEvidenceDrawerActions.innerHTML = "";
  for (const actionConfig of model.actions) {
    const button = createOperatorEvidenceDrawerActionButton(actionConfig);
    if (button) {
      el.operatorEvidenceDrawerActions.append(button);
    }
  }
}

function buildOperatorEvidenceDrawerModel(statusId) {
  const normalizedStatusId = typeof statusId === "string" ? statusId.trim() : "";
  const activeSavedView = getActiveOperatorSavedViewConfig();
  const signal = getOperatorSummaryGuideSignalById(normalizedStatusId);
  const statusNode = normalizedStatusId ? document.getElementById(normalizedStatusId) : null;
  const card = getOperatorCardByStatusId(normalizedStatusId);
  const group = card instanceof HTMLElement ? card.closest(".operator-health-group") : null;
  const groupKickerNode = group instanceof HTMLElement ? group.querySelector(".operator-health-group-kicker") : null;
  const groupTitleNode = group instanceof HTMLElement ? group.querySelector(".operator-health-group-title-copy h3") : null;
  const cardTitleNode = card instanceof HTMLElement ? card.querySelector("h3") : null;
  const hintNode = card instanceof HTMLElement ? card.querySelector(".operator-health-hint") : null;
  const variant = resolveOperatorEvidenceDrawerVariant(signal);
  const label = signal && typeof signal.label === "string"
    ? signal.label.trim()
    : cardTitleNode && typeof cardTitleNode.textContent === "string"
      ? cardTitleNode.textContent.trim()
      : "Operator lane";
  const groupKicker = groupKickerNode && typeof groupKickerNode.textContent === "string" ? groupKickerNode.textContent.trim() : "Lane";
  const groupTitle = groupTitleNode && typeof groupTitleNode.textContent === "string" ? groupTitleNode.textContent.trim() : "Focused lane";
  const cardTitle = cardTitleNode && typeof cardTitleNode.textContent === "string" ? cardTitleNode.textContent.trim() : label;
  const hint = hintNode && typeof hintNode.textContent === "string"
    ? hintNode.textContent.trim()
    : "Open the lane for deeper evidence and use recovery kits only if the issue persists.";
  const statusCode = statusNode instanceof HTMLElement && typeof statusNode.dataset.statusCode === "string"
    ? statusNode.dataset.statusCode.trim()
    : "awaiting_refresh";
  const statusText = statusNode instanceof HTMLElement && typeof statusNode.textContent === "string"
    ? statusNode.textContent.trim()
    : resolveStatusPillDisplayText(statusCode);
  const statusDisplayText = resolveStatusPillDisplayText(statusCode || statusText);
  const rows = collectOperatorEvidenceDrawerRows(card);
  const facts = collectOperatorEvidenceDrawerFacts(card);
  const focusTitle =
    variant === "fail"
      ? `${label} needs operator attention`
      : variant === "stale"
        ? `${label} is running on stale evidence`
        : variant === "watch"
          ? `${label} needs a closer look`
          : variant === "ok"
            ? `${label} is stable`
            : `Awaiting ${label.toLowerCase()} signal`;
  const inActiveSavedView =
    !!activeSavedView &&
    (!activeSavedView.groupKey || getOperatorGroupKeyByStatusId(normalizedStatusId) === activeSavedView.groupKey);
  const drawerKicker = inActiveSavedView
    ? activeSavedView.drawerKicker ?? "Focused Evidence"
    : "Focused Evidence";
  let drawerTitle = focusTitle;
  let drawerHint = hint;
  let drawerFacts = facts;
  if ((variant === "dormant" || state.operatorSummaryUserRefreshed !== true) && inActiveSavedView) {
    drawerTitle = activeSavedView.drawerDormantTitle ?? focusTitle;
    drawerHint = activeSavedView.drawerDormantHint ?? hint;
    if (Array.isArray(activeSavedView.drawerDormantFacts) && activeSavedView.drawerDormantFacts.length > 0) {
      drawerFacts = activeSavedView.drawerDormantFacts.map((fact) => ({
        label: fact.label,
        value: fact.value,
        isPlaceholder: true,
      }));
    }
  }
  const actionsConfig = OPERATOR_PRIORITY_QUEUE_ACTIONS[normalizedStatusId] ?? null;
  const relatedSavedViewId = resolveOperatorEvidenceDrawerSavedViewId(normalizedStatusId) || (activeSavedView?.id ?? "");
  const activeSavedViewId = activeSavedView?.id ?? "";
  const savedViewLabel = getOperatorEvidenceDrawerSavedViewLabel(relatedSavedViewId);
  const refreshLabel = getOperatorEvidenceDrawerRefreshLabel();
  const refreshStamp = getOperatorEvidenceDrawerRefreshStamp(refreshLabel);
  const groupKey = group instanceof HTMLElement ? group.getAttribute("data-operator-group") ?? "" : "";
  const traceLane = [groupTitle, cardTitle].filter((item) => typeof item === "string" && item.trim().length > 0).join(" / ");
  const needsRefreshAction =
    variant === "fail" || variant === "stale" || variant === "dormant" || state.operatorSummaryUserRefreshed !== true;
  const openLaneAction = normalizedStatusId
    ? {
        label: actionsConfig?.openLabel ?? "Open lane",
        actionId: "jump_status_card",
        targetStatusId: normalizedStatusId,
      }
    : null;
  const supportAction =
    actionsConfig &&
    typeof actionsConfig.supportAction === "string" &&
    actionsConfig.supportAction.length > 0 &&
    variant !== "ok"
      ? {
          label: actionsConfig.supportLabel ?? "Open support",
          actionId: actionsConfig.supportAction,
          kind: "secondary",
        }
      : null;
  const refreshAction = needsRefreshAction
    ? {
        label: "Refresh Summary",
        actionId: "refresh_summary",
        kind: "secondary",
      }
    : null;
  const laneSavedViewAction = relatedSavedViewId && relatedSavedViewId !== activeSavedViewId
    ? buildOperatorEvidenceDrawerSavedViewAction(relatedSavedViewId)
    : null;
  const workspaceSavedViewAction = activeSavedViewId && activeSavedViewId !== "incidents" && activeSavedViewId !== relatedSavedViewId
    ? buildOperatorEvidenceDrawerSavedViewAction(activeSavedViewId)
    : null;
  const auditViewAction = activeSavedViewId !== "audit" ? buildOperatorEvidenceDrawerSavedViewAction("audit") : null;
  const recoveryFallbackAction =
    relatedSavedViewId === "runtime" && (!supportAction || supportAction.actionId !== "open_workflow_control")
      ? { label: "Workflow Control", actionId: "open_workflow_control", kind: "secondary" }
      : relatedSavedViewId === "approvals" || relatedSavedViewId === "incidents"
        ? { label: "Open Playbook", actionId: "open_playbook", kind: "secondary" }
        : laneSavedViewAction;
  const compactViewActionLimit = 2;
  const latestActions = buildOperatorEvidenceDrawerWorkspaceActionRail(
    [openLaneAction, supportAction, refreshAction, laneSavedViewAction, workspaceSavedViewAction],
    { activeSavedView },
    "latest",
    compactViewActionLimit,
  );
  const traceActions = buildOperatorEvidenceDrawerWorkspaceActionRail(
    [openLaneAction, laneSavedViewAction, workspaceSavedViewAction, refreshAction, supportAction],
    { activeSavedView },
    "trace",
    compactViewActionLimit,
  );
  const recoveryActions = buildOperatorEvidenceDrawerWorkspaceActionRail([
    supportAction ?? openLaneAction,
    recoveryFallbackAction,
    workspaceSavedViewAction,
    refreshAction,
    openLaneAction,
  ],
    { activeSavedView },
    "recovery",
    compactViewActionLimit,
  );
  const auditActions = buildOperatorEvidenceDrawerWorkspaceActionRail([
    laneSavedViewAction ?? auditViewAction,
    workspaceSavedViewAction,
    openLaneAction,
    normalizeOperatorBoardMode(state.operatorBoardMode) === "full"
      ? null
      : { label: "Full Ops View", actionId: "full_ops_view", kind: "secondary" },
    refreshAction,
  ],
    { activeSavedView },
    "audit",
    compactViewActionLimit,
  );
  const resolveActionRouteLabelForView = (action, viewId) => resolveOperatorEvidenceDrawerActionRoute(action, {
    activeViewId: viewId,
    cardTitle,
    groupKey,
    refreshLabel,
    relatedSavedViewId,
    statusId: normalizedStatusId,
    variant,
  });
  const latestRouteAction = supportAction ?? openLaneAction ?? latestActions[0];
  const traceRouteAction = supportAction ?? openLaneAction ?? traceActions[0];
  const recoveryRouteAction = supportAction ?? openLaneAction ?? recoveryActions[0];
  const auditRouteAction = laneSavedViewAction ?? auditViewAction ?? openLaneAction ?? auditActions[0];
  const primaryActionLabel = resolveActionRouteLabelForView(latestRouteAction, "latest");
  const primaryActionMeta =
    supportAction
      ? `${primaryActionLabel} before reopening deeper diagnostics.`
      : openLaneAction
        ? `${primaryActionLabel} to inspect the deeper evidence cards.`
        : "Reopen the lane to inspect the deeper evidence cards.";
  const traceActionLabel = resolveActionRouteLabelForView(traceRouteAction, "trace");
  const recoveryActionLabel = resolveActionRouteLabelForView(recoveryRouteAction, "recovery");
  const auditActionLabel = auditRouteAction ? resolveActionRouteLabelForView(auditRouteAction, "audit") : "";
  const viewOrder = resolveOperatorEvidenceDrawerViewOrder({
    activeSavedViewId,
    variant,
  });
  const unsortedViewModels = OPERATOR_EVIDENCE_DRAWER_VIEWS.map((view) => {
    if (view.id === "trace") {
      const traceProvenanceActions = traceActions;
      const traceFacts = buildOperatorEvidenceDrawerTraceFacts({
        activeSavedView,
        fallbackFacts: facts,
        primaryActionLabel: traceActionLabel,
        refreshLabel,
        rows,
        statusDisplayText,
        statusId: normalizedStatusId,
        traceLane,
        variant,
      });
      return {
        ...view,
        // facts: buildOperatorEvidenceDrawerTraceFacts({
        facts: traceFacts,
        summary: buildOperatorEvidenceDrawerSummary("trace", {
          facts: traceFacts,
          primaryActionLabel: traceActionLabel,
          savedViewLabel,
          traceLane,
        }),
        showTimeline: true,
        showCheckpoints: true,
        showProvenance: true,
        showMeta: false,
        showOrigins: true,
        factsMode: "default",
        origins: buildOperatorEvidenceDrawerTraceOrigins({
          activeSavedView,
          rows,
          traceLane,
          groupTitle,
          savedViewLabel,
          variant,
        }),
        provenance: buildOperatorEvidenceDrawerProvenance({
          activeViewId: view.id,
          activeSavedViewId,
          actions: traceProvenanceActions,
          groupKey,
          relatedSavedViewId,
          routeAction: traceRouteAction,
          cardTitle,
          refreshLabel,
          statusId: normalizedStatusId,
          variant,
        }),
        timelineLabel: "Trace log",
        timeline: buildOperatorEvidenceDrawerTraceTimeline({
          rows,
          refreshLabel,
          refreshStamp,
          traceLane,
          groupTitle,
          savedViewLabel,
          variant,
        }),
        checkpointsLabel: "Trace anchors",
        checkpoints: buildOperatorEvidenceDrawerTraceCheckpoints({
          rows,
          primaryActionLabel: traceActionLabel,
          refreshLabel,
          traceLane,
          savedViewLabel,
          variant,
        }),
        actions: traceActions,
      };
    }
    if (view.id === "recovery") {
      const recoveryProvenanceActions = recoveryActions;
      const recoveryFacts = buildOperatorEvidenceDrawerRecoveryFacts({
        activeSavedView,
        actionsConfig,
        savedViewLabel,
        variant,
      });
      return {
        ...view,
        facts: recoveryFacts,
        summary: buildOperatorEvidenceDrawerSummary("recovery", {
          facts: recoveryFacts,
          hint,
          primaryActionLabel: recoveryActionLabel,
          primaryActionMeta,
          refreshLabel,
        }),
        showTimeline: false,
        showCheckpoints: false,
        showProvenance: true,
        showMeta: false,
        showLabel: false,
        showOrigins: false,
        factsMode: "compact",
        origins: buildOperatorEvidenceDrawerRecoveryOrigins({
          activeSavedView,
          cardTitle,
          primaryActionLabel: recoveryActionLabel,
          savedViewLabel,
          variant,
        }),
        provenance: buildOperatorEvidenceDrawerProvenance({
          activeViewId: view.id,
          activeSavedViewId,
          actions: recoveryProvenanceActions,
          groupKey,
          relatedSavedViewId,
          routeAction: recoveryRouteAction,
          cardTitle,
          refreshLabel,
          statusId: normalizedStatusId,
          variant,
        }),
        timelineLabel: "Recovery path",
        timeline: buildOperatorEvidenceDrawerRecoveryTimeline({
          refreshLabel,
          refreshStamp,
          statusDisplayText,
          primaryActionLabel: recoveryActionLabel,
          primaryActionMeta,
          variant,
        }),
        checkpointsLabel: "Recovery anchors",
        checkpoints: buildOperatorEvidenceDrawerRecoveryCheckpoints({
          refreshLabel,
          primaryActionLabel: recoveryActionLabel,
          variant,
        }),
        actions: recoveryActions,
      };
    }
    if (view.id === "audit") {
      const auditProvenanceActions = auditActions;
      const auditFacts = buildOperatorEvidenceDrawerAuditFacts({
        activeSavedView,
        refreshLabel,
        savedViewLabel,
        statusDisplayText,
        variant,
      });
      return {
        ...view,
        facts: auditFacts,
        summary: buildOperatorEvidenceDrawerSummary("audit", {
          cardTitle,
          facts: auditFacts,
          hint,
          savedViewLabel,
        }),
        showTimeline: false,
        showCheckpoints: false,
        showProvenance: true,
        showMeta: false,
        showLabel: false,
        showOrigins: false,
        factsMode: "compact",
        origins: buildOperatorEvidenceDrawerAuditOrigins({
          activeSavedView,
          cardTitle,
          savedViewLabel,
          primaryActionLabel,
          auditActionLabel,
          variant,
        }),
        provenance: buildOperatorEvidenceDrawerProvenance({
          activeViewId: view.id,
          activeSavedViewId,
          actions: auditProvenanceActions,
          groupKey,
          relatedSavedViewId,
          routeAction: auditRouteAction,
          cardTitle,
          refreshLabel,
          statusId: normalizedStatusId,
          variant,
        }),
        timelineLabel: "Review log",
        timeline: buildOperatorEvidenceDrawerAuditTimeline({
          activeSavedView,
          savedViewLabel,
          refreshLabel,
          refreshStamp,
          statusDisplayText,
          primaryActionLabel,
          auditActionLabel,
          variant,
        }),
        checkpointsLabel: "Review anchors",
        checkpoints: buildOperatorEvidenceDrawerAuditCheckpoints({
          activeSavedView,
          savedViewLabel,
          primaryActionLabel,
          auditActionLabel,
          variant,
        }),
        actions: auditActions,
      };
    }
    const latestFacts = buildOperatorEvidenceDrawerLatestFacts({
      activeSavedView,
      fallbackFacts: drawerFacts,
      preserveFallbackFacts: drawerFacts !== facts,
      primaryActionLabel,
      refreshLabel,
      rows,
      statusDisplayText,
      statusId: normalizedStatusId,
      variant,
    });
    const latestFactsMode = resolveOperatorEvidenceDrawerLatestFactsMode({
      facts: latestFacts,
      variant,
    });
    return {
      ...view,
      // Keep the lane-aware latest-facts builder explicit for operator regressions.
      // facts: buildOperatorEvidenceDrawerLatestFacts({
      facts: latestFacts,
      summary: buildOperatorEvidenceDrawerSummary("latest", {
        facts: latestFacts,
        factsMode: latestFactsMode,
        hint,
        primaryActionLabel,
      }),
      showTimeline: false,
      showCheckpoints: false,
      showProvenance: true,
      showMeta: false,
      showLabel: false,
      showOrigins: false,
      factsMode: latestFactsMode,
      origins: buildOperatorEvidenceDrawerLatestOrigins({
        activeSavedView,
        rows,
        cardTitle,
        label,
        savedViewLabel,
        variant,
      }),
      provenance: buildOperatorEvidenceDrawerProvenance({
        activeViewId: view.id,
        activeSavedViewId,
        actions: latestActions,
        groupKey,
        relatedSavedViewId,
        routeAction: latestRouteAction,
        cardTitle,
        refreshLabel,
        statusId: normalizedStatusId,
        variant,
      }),
      timelineLabel: "Recent lane log",
      timeline: buildOperatorEvidenceDrawerLatestTimeline({
        rows,
        cardTitle,
        label,
        refreshLabel,
        refreshStamp,
        statusDisplayText,
        primaryActionLabel,
        primaryActionMeta,
        variant,
      }),
      checkpointsLabel: "Recent checkpoints",
      checkpoints: buildOperatorEvidenceDrawerLatestCheckpoints({
        rows,
        refreshLabel,
        statusDisplayText,
        primaryActionLabel,
        variant,
      }),
      actions: latestActions,
    };
  });
  const viewOrderIndex = new Map(viewOrder.map((viewId, index) => [viewId, index]));
  const viewModels = unsortedViewModels.slice().sort((left, right) => {
    const leftIndex = viewOrderIndex.has(left.id) ? viewOrderIndex.get(left.id) : Number.MAX_SAFE_INTEGER;
    const rightIndex = viewOrderIndex.has(right.id) ? viewOrderIndex.get(right.id) : Number.MAX_SAFE_INTEGER;
    if (leftIndex !== rightIndex) {
      return leftIndex - rightIndex;
    }
    return 0;
  });
  return {
    statusId: normalizedStatusId,
    variant,
    kicker: drawerKicker,
    title: drawerTitle,
    lane: `${groupKicker} / ${groupTitle} / ${cardTitle}`,
    hint: drawerHint,
    statusCode,
    statusText,
    statusDisplayText,
    facts: drawerFacts,
    actions: latestActions,
    activeSavedViewId,
    viewOrder,
    views: viewModels,
    defaultView: resolveOperatorEvidenceDrawerDefaultView({
      activeSavedViewId,
      variant,
    }),
  };
}

function resolveOperatorEvidenceDrawerCompactActionLabel(actionConfig, details = {}) {
  const fullLabel = normalizeOperatorUiCopy(actionConfig?.label);
  if (!fullLabel) {
    return "";
  }
  const actionId = typeof actionConfig?.actionId === "string" ? actionConfig.actionId.trim() : "";
  if (actionId === "refresh_summary") {
    return "Refresh";
  }
  if (actionId === "open_playbook") {
    return "Playbook";
  }
  if (actionId === "open_workflow_control") {
    return "Workflow";
  }
  if (actionId === "full_ops_view") {
    return "Full Ops";
  }
  if (/^review\s+/i.test(fullLabel)) {
    return clipOperatorEvidenceDrawerSentence(fullLabel.replace(/^review\s+/i, ""), 18) || "Review";
  }
  if (/^open\s+/i.test(fullLabel)) {
    return clipOperatorEvidenceDrawerSentence(fullLabel.replace(/^open\s+/i, ""), 18) || fullLabel;
  }
  if (/^run\s+/i.test(fullLabel)) {
    return clipOperatorEvidenceDrawerSentence(fullLabel.replace(/^run\s+/i, ""), 18) || fullLabel;
  }
  if (actionId === "jump_status_card") {
    const fallbackLabel = normalizeOperatorUiCopy(details.cardTitle);
    return clipOperatorEvidenceDrawerSentence(fallbackLabel || fullLabel, 18) || fullLabel;
  }
  return clipOperatorEvidenceDrawerSentence(fullLabel, 18) || fullLabel;
}

function createOperatorEvidenceDrawerActionButton(config, options = {}) {
  if (!config || typeof config !== "object" || typeof config.label !== "string") {
    return null;
  }
  const compact = options.compact === true;
  const isPrimary = options.primary === true;
  const workspaceTone = typeof options.workspaceTone === "string" ? options.workspaceTone.trim() : "";
  const fullLabel = config.label;
  const compactLabel = compact ? resolveOperatorEvidenceDrawerCompactActionLabel(config, options) : "";
  const button = document.createElement("button");
  button.type = "button";
  button.className = config.kind === "secondary" ? "button-muted operator-evidence-drawer-action operator-evidence-drawer-action-secondary" : "operator-evidence-drawer-action";
  if (isPrimary) {
    button.classList.add("operator-evidence-drawer-action-primary");
  }
  button.dataset.actionDensity = compact ? "compact" : "default";
  if (isPrimary) {
    button.dataset.actionPrimary = "true";
  }
  if (workspaceTone) {
    button.dataset.actionWorkspace = workspaceTone;
  }
  button.textContent = compactLabel || fullLabel;
  if (compactLabel && compactLabel !== fullLabel) {
    button.title = fullLabel;
    button.setAttribute("aria-label", fullLabel);
  }
  button.addEventListener("click", () => {
    runOperatorPriorityQueueAction(config.actionId, config);
  });
  return button;
}

function createOperatorEvidenceDrawerActionNode(config, options = {}) {
  const button = createOperatorEvidenceDrawerActionButton(config, options);
  if (!(button instanceof HTMLButtonElement)) {
    return null;
  }
  const workspaceTone = typeof options.workspaceTone === "string" ? options.workspaceTone.trim() : "";
  const meta =
    typeof config?.meta === "string" && config.meta.trim().length > 0
      ? config.meta.trim()
      : "";
  if (!meta) {
    return button;
  }
  const wrapper = document.createElement("div");
  wrapper.className = "operator-evidence-drawer-action-stack";
  wrapper.dataset.actionDensity = options.compact === true ? "compact" : "default";
  if (options.primary === true) {
    wrapper.dataset.actionPrimary = "true";
  }
  if (workspaceTone) {
    wrapper.dataset.actionWorkspace = workspaceTone;
  }
  const metaNode = document.createElement("p");
  metaNode.className = "operator-evidence-drawer-action-meta";
  metaNode.textContent = meta;
  wrapper.append(button, metaNode);
  return wrapper;
}

function setOperatorEvidenceDrawerView(viewId, options = {}) {
  const normalizedView = normalizeOperatorEvidenceDrawerView(viewId);
  if (!normalizedView) {
    return;
  }
  state.operatorEvidenceDrawerView = normalizedView;
  syncOperatorEvidenceDrawer();
  if (options.focus === true) {
    const activeButton = document.querySelector(`[data-operator-evidence-view="${normalizedView}"]`);
    if (activeButton instanceof HTMLButtonElement) {
      activeButton.focus();
    }
  }
}

function resolveOperatorEvidenceDrawerWorkspaceNextValue(activeView, presentation) {
  if (!presentation?.hasManualRefresh) {
    return "Refresh Summary";
  }
  const viewId = normalizeOperatorEvidenceDrawerView(activeView?.id) || "latest";
  if (viewId === "trace") {
    return presentation.tone === "fail" ? "Inspect trace anchors" : "Confirm trace freshness";
  }
  if (viewId === "recovery") {
    return presentation.tone === "fail" ? "Run recovery path" : "Review recovery path";
  }
  if (viewId === "audit") {
    return presentation.tone === "fail" ? "Review governance proof" : "Cross-check audit trail";
  }
  return presentation.next || "Open lane";
}

function buildOperatorEvidenceDrawerCompactContextSignalMeta(leadSignalSource, freshnessValue) {
  const sourceText =
    typeof leadSignalSource === "string" && leadSignalSource.trim().length > 0
      ? leadSignalSource.trim()
      : "Source: workspace";
  const freshnessText =
    typeof freshnessValue === "string" && freshnessValue.trim().length > 0
      ? freshnessValue.trim()
      : "Freshness: awaiting refresh";
  return `${sourceText} | ${freshnessText}`;
}

function syncOperatorEvidenceDrawerContext(model, activeView) {
  if (
    !(el.operatorEvidenceDrawerContext instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerContextWorkspaceValue instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerContextFocusValue instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerContextModeValue instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerContextStatusValue instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerContextViewValue instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerContextNextValue instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerContextSignalItem instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerContextSignalValue instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerContextSignalSource instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerContextSignalFreshness instanceof HTMLElement)
  ) {
    return;
  }
  const workspacePresentation = getOperatorWorkspacePresentationState(model?.activeSavedViewId || state.operatorSavedView);
  const workspaceLabel = workspacePresentation.routeFacts?.label ?? "Overview";
  const workspaceState = workspacePresentation.tone ?? "neutral";
  const leadSignal = resolveOperatorWorkspaceLeadSignalPresentation(workspacePresentation);
  const leadSignalSource = resolveOperatorWorkspaceLeadSignalSourcePresentation(workspacePresentation);
  const freshness = resolveOperatorWorkspaceFreshnessPresentation();
  const nextValue = resolveOperatorEvidenceDrawerWorkspaceNextValue(activeView, workspacePresentation);
  const workspaceStatus = !workspacePresentation.hasManualRefresh
    ? "Hydrate"
    : workspacePresentation.tone === "fail"
      ? "Attention"
      : workspacePresentation.tone === "neutral"
        ? "Review"
        : "Steady";
  const useCompactSignalMeta = leadSignal.state === "dormant" || freshness.state === "dormant";
  if (el.operatorEvidenceDrawer instanceof HTMLElement) {
    el.operatorEvidenceDrawer.dataset.evidenceWorkspace =
      workspacePresentation.normalizedView === "incidents" ? "overview" : workspacePresentation.normalizedView;
    el.operatorEvidenceDrawer.dataset.evidenceWorkspaceState = workspaceState;
  }
  el.operatorEvidenceDrawerContext.dataset.workspace =
    workspacePresentation.normalizedView === "incidents" ? "overview" : workspacePresentation.normalizedView;
  el.operatorEvidenceDrawerContext.dataset.workspaceState = workspaceState;
  const contextViewId =
    normalizeOperatorEvidenceDrawerView(activeView?.id) ||
    normalizeOperatorEvidenceDrawerView(state.operatorEvidenceDrawerView) ||
    "latest";
  el.operatorEvidenceDrawerContextWorkspaceValue.textContent = workspaceLabel;
  el.operatorEvidenceDrawerContextFocusValue.textContent = workspacePresentation.routeFacts.focus;
  el.operatorEvidenceDrawerContextModeValue.textContent = workspacePresentation.routeFacts.modeLabel;
  el.operatorEvidenceDrawerContextStatusValue.textContent = workspaceStatus;
  el.operatorEvidenceDrawerContextViewValue.textContent = resolveOperatorEvidenceDrawerWorkspaceTabLabel(
    contextViewId,
    model,
  );
  el.operatorEvidenceDrawerContextNextValue.textContent = nextValue;
  el.operatorEvidenceDrawerContextSignalItem.dataset.signalState = leadSignal.state;
  el.operatorEvidenceDrawerContextSignalItem.dataset.freshnessState = freshness.state;
  el.operatorEvidenceDrawerContextSignalItem.dataset.signalDensity = useCompactSignalMeta ? "compact" : "full";
  el.operatorEvidenceDrawerContextSignalValue.textContent = leadSignal.value;
  el.operatorEvidenceDrawerContextSignalSource.textContent = useCompactSignalMeta
    ? buildOperatorEvidenceDrawerCompactContextSignalMeta(leadSignalSource, freshness.value)
    : leadSignalSource;
  el.operatorEvidenceDrawerContextSignalFreshness.textContent = freshness.value;
  el.operatorEvidenceDrawerContextSignalFreshness.hidden = useCompactSignalMeta;
  el.operatorEvidenceDrawerContextSignalFreshness.setAttribute("aria-hidden", useCompactSignalMeta ? "true" : "false");
}

function buildOperatorEvidenceDrawerWorkspaceSummary(activeView, model) {
  const baseSummary = normalizeOperatorUiCopy(activeView?.summary)
    || "Use the highlighted issue first, then open deeper diagnostics only if you still need confirmation.";
  const workspacePresentation = getOperatorWorkspacePresentationState(model?.activeSavedViewId || state.operatorSavedView);
  if (workspacePresentation.normalizedView === "incidents") {
    return baseSummary;
  }
  const workspaceLabel = workspacePresentation.routeFacts?.label ?? "Overview";
  const nextValue = resolveOperatorEvidenceDrawerWorkspaceNextValue(activeView, workspacePresentation);
  if (!workspacePresentation.hasManualRefresh) {
    // Legacy dormant-summary token kept for alignment coverage:
    // return `Refresh ${workspaceLabel} first to load the ${activeView?.label?.toLowerCase() ?? "focused"} proof path.`;
    const viewLabel = activeView?.label?.toLowerCase() ?? "focused";
    if (workspacePresentation.normalizedView === "approvals") {
      return `Refresh ${workspaceLabel} first to seed the decision queue before opening the ${viewLabel} proof path.`;
    }
    if (workspacePresentation.normalizedView === "runtime") {
      return `Refresh ${workspaceLabel} first to hydrate trace anchors before opening the ${viewLabel} proof path.`;
    }
    if (workspacePresentation.normalizedView === "audit") {
      return `Refresh ${workspaceLabel} first to hydrate governance proof before opening the ${viewLabel} proof path.`;
    }
    return `Refresh ${workspaceLabel} first to load the ${viewLabel} proof path.`;
  }
  const workspaceLead =
    workspacePresentation.tone === "fail"
      ? `${workspaceLabel} needs attention`
      : workspacePresentation.tone === "neutral"
        ? `${workspaceLabel} is in review`
        : `${workspaceLabel} remains steady`;
  const basePart = formatOperatorEvidenceDrawerSummaryPart(baseSummary);
  if (normalizeOperatorEvidenceDrawerView(activeView?.id) === "recovery") {
    return `${workspaceLead}. ${nextValue}.`;
  }
  return `${workspaceLead}. ${basePart || `${activeView?.label ?? "Focused Evidence"} keeps the current proof path visible`}.`;
}

function resolveOperatorEvidenceDrawerWorkspacePanelMeta(activeView, model) {
  const fallbackMeta = activeView?.meta ?? "Recent proof facts stay here so operators can confirm what changed before opening the deeper board.";
  const workspaceId = normalizeOperatorSavedView(model?.activeSavedViewId) || "incidents";
  if (workspaceId === "incidents") {
    return fallbackMeta;
  }
  if (shouldUseOperatorEvidenceDrawerWorkspacePlaceholder(model)) {
    if (workspaceId === "runtime") {
      return "Hydrate runtime evidence first, then confirm trace anchors or recovery.";
    }
    if (workspaceId === "approvals") {
      return "Seed one decision path first, then confirm backlog and next checks.";
    }
    if (workspaceId === "audit") {
      return "Hydrate governance proof first, then review audit trail and export posture.";
    }
    return normalizeOperatorEvidenceDrawerHydrateMeta(getOperatorEvidenceDrawerWorkspaceConfig(model).hydrateMeta);
  }
  if (workspaceId === "runtime") {
    if (activeView?.id === "trace") {
      return "Trace anchors and freshness stay first for runtime review.";
    }
    if (activeView?.id === "recovery") {
      return "Recovery steps stay ahead of deeper runtime diagnostics.";
    }
  }
  if (workspaceId === "approvals") {
    if (activeView?.id === "latest") {
      return "Approval backlog and next decision stay first.";
    }
    if (activeView?.id === "recovery") {
      return "Recovery stays first until approval posture looks steady again.";
    }
  }
  if (workspaceId === "audit" && activeView?.id === "audit") {
    return "Audit proof stays first while deeper board review remains secondary.";
  }
  return fallbackMeta;
}

function resolveOperatorEvidenceDrawerWorkspaceCheckpointsLabel(activeView, model) {
  const fallbackLabel = activeView?.checkpointsLabel ?? "Recent checkpoints";
  const workspaceId = normalizeOperatorSavedView(model?.activeSavedViewId) || "incidents";
  if (workspaceId === "runtime" && activeView?.id === "trace") {
    return "Runtime anchors";
  }
  if (workspaceId === "approvals" && activeView?.id === "latest") {
    return "Decision checks";
  }
  if (workspaceId === "audit" && activeView?.id === "audit") {
    return "Audit checks";
  }
  return fallbackLabel;
}

function resolveOperatorEvidenceDrawerWorkspaceCheckpoints(activeView, model) {
  const checkpoints = Array.isArray(activeView?.checkpoints) ? activeView.checkpoints : [];
  const workspaceId = normalizeOperatorSavedView(model?.activeSavedViewId) || "incidents";
  const prioritized = prioritizeOperatorEvidenceDrawerCheckpointsForWorkspace(checkpoints, activeView, model);
  if (workspaceId === "incidents") {
    return prioritized;
  }
  // Legacy checkpoint-compaction token kept for alignment coverage:
  // return checkpoints.slice(0, 2);
  if (activeView?.id === "trace" && workspaceId === "runtime") {
    return prioritized.slice(0, 2);
  }
  if (activeView?.id === "latest" && workspaceId === "approvals") {
    return prioritized.slice(0, 2);
  }
  if (activeView?.id === "audit" && workspaceId === "audit") {
    return prioritized.slice(0, 2);
  }
  if (activeView?.id === "recovery") {
    return prioritized.slice(0, 2);
  }
  return prioritized;
}

function prioritizeOperatorEvidenceDrawerCheckpointsForWorkspace(checkpoints, activeView, model) {
  const entries = Array.isArray(checkpoints) ? checkpoints.filter(Boolean) : [];
  const workspaceId = normalizeOperatorSavedView(model?.activeSavedViewId) || "incidents";
  if (workspaceId === "incidents") {
    return entries;
  }
  let priorityLabels = [];
  if (activeView?.id === "recovery") {
    priorityLabels = ["Path", "Verify", "Priority"];
  } else if (workspaceId === "runtime" && activeView?.id === "trace") {
    priorityLabels = ["Trace", "Route", "Freshness"];
  } else if (workspaceId === "approvals" && activeView?.id === "latest") {
    priorityLabels = ["State", "Next", "Refresh"];
  } else if (workspaceId === "audit" && activeView?.id === "audit") {
    priorityLabels = ["Review", "Posture", "Board"];
  } else {
    return entries;
  }
  const prioritized = [];
  const used = new Set();
  for (const label of priorityLabels) {
    const match = entries.find((entry) => normalizeOperatorUiCopy(entry?.label) === label);
    if (match && !used.has(match)) {
      prioritized.push(match);
      used.add(match);
    }
  }
  for (const entry of entries) {
    if (!used.has(entry)) {
      prioritized.push(entry);
    }
  }
  return prioritized;
}

function resolveOperatorEvidenceDrawerWorkspaceTimelineLabel(activeView, model) {
  const fallbackLabel = activeView?.timelineLabel ?? "Recent proof path";
  const workspaceId = normalizeOperatorSavedView(model?.activeSavedViewId) || "incidents";
  if (workspaceId === "runtime" && activeView?.id === "trace") {
    return "Runtime trail";
  }
  if (workspaceId === "runtime" && activeView?.id === "recovery") {
    return "Recovery trail";
  }
  if (workspaceId === "approvals" && activeView?.id === "latest") {
    return "Decision trail";
  }
  if (workspaceId === "approvals" && activeView?.id === "recovery") {
    return "Approval recovery";
  }
  if (workspaceId === "audit" && activeView?.id === "audit") {
    return "Audit trail";
  }
  return fallbackLabel;
}

function prioritizeOperatorEvidenceDrawerTimelineForWorkspace(timeline, activeView, model) {
  const entries = Array.isArray(timeline) ? timeline.filter(Boolean) : [];
  const workspaceId = normalizeOperatorSavedView(model?.activeSavedViewId) || "incidents";
  if (workspaceId === "incidents") {
    return entries;
  }
  let prioritySteps = [];
  if (workspaceId === "runtime") {
    prioritySteps = activeView?.id === "recovery" ? ["Path", "Verify after", "Risk"] : ["Anchor", "Freshness", "Context"];
  } else if (workspaceId === "approvals") {
    prioritySteps = activeView?.id === "recovery" ? ["Path", "Verify after", "Risk"] : ["Signal", "Next check", "Observed"];
  } else if (workspaceId === "audit") {
    prioritySteps = ["Review", "Posture", "Board state"];
  } else {
    return entries;
  }
  const prioritized = [];
  const used = new Set();
  for (const step of prioritySteps) {
    const match = entries.find((entry) => normalizeOperatorUiCopy(entry?.step) === step);
    if (match && !used.has(match)) {
      prioritized.push(match);
      used.add(match);
    }
  }
  for (const entry of entries) {
    if (!used.has(entry)) {
      prioritized.push(entry);
    }
  }
  return prioritized.slice(0, 2);
}

function syncOperatorEvidenceDrawerTabOrder(model) {
  if (!(el.operatorEvidenceDrawerTabs instanceof HTMLElement)) {
    return;
  }
  const orderedViewIds = Array.isArray(model?.viewOrder) && model.viewOrder.length > 0
    ? model.viewOrder
    : OPERATOR_EVIDENCE_DRAWER_VIEWS.map((view) => view.id);
  const orderedButtons = orderedViewIds
    .map((viewId) => el.operatorEvidenceDrawerTabs.querySelector(`[data-operator-evidence-view="${viewId}"]`))
    .filter((button) => button instanceof HTMLButtonElement);
  for (const button of orderedButtons) {
    const buttonViewId = normalizeOperatorEvidenceDrawerView(button.dataset.operatorEvidenceView) || "latest";
    const visibleLabel = resolveOperatorEvidenceDrawerWorkspaceTabLabel(buttonViewId, model);
    button.textContent = visibleLabel;
    button.setAttribute("aria-label", visibleLabel);
    el.operatorEvidenceDrawerTabs.append(button);
  }
}

function syncOperatorEvidenceDrawer() {
  if (
    !(el.operatorEvidenceDrawer instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerOrigins instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerFacts instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerTimeline instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerCheckpoints instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerProvenance instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerProofPathSection instanceof HTMLElement) ||
    !(el.operatorEvidenceDrawerActions instanceof HTMLElement)
  ) {
    return;
  }
  const focusedStatusId = resolveOperatorFocusedEvidenceStatusId();
  state.operatorFocusedEvidenceStatusId = focusedStatusId;
  const model = buildOperatorEvidenceDrawerModel(focusedStatusId);
  const contextStatusId = `${focusedStatusId}::${model.activeSavedViewId ?? ""}`;
  if (state.operatorEvidenceDrawerContextStatusId !== contextStatusId) {
    state.operatorEvidenceDrawerContextStatusId = contextStatusId;
    state.operatorEvidenceDrawerView = "";
  }
  const activeViewId = normalizeOperatorEvidenceDrawerView(state.operatorEvidenceDrawerView) || model.defaultView || "latest";
  const activeView = Array.isArray(model.views)
    ? model.views.find((view) => view.id === activeViewId) ?? model.views[0] ?? null
    : null;
  // Legacy compact-view rule remains: const isCompactEvidenceView = !!activeView && activeView.id !== "trace";
  const isCompactEvidenceView = !!activeView && isOperatorEvidenceDrawerCompactView(activeView.id);
  state.operatorEvidenceDrawerView = activeView?.id ?? "latest";
  el.operatorEvidenceDrawer.dataset.evidenceVariant = model.variant ?? "neutral";
  el.operatorEvidenceDrawer.dataset.evidenceView = activeView?.id ?? "latest";
  el.operatorEvidenceDrawer.dataset.evidenceFacts = activeView?.factsMode ?? "default";
  el.operatorEvidenceDrawer.dataset.evidenceActionDensity = isCompactEvidenceView ? "compact" : "default";
  const heading = resolveOperatorEvidenceDrawerWorkspaceHeading(model, activeView);
  setText(el.operatorEvidenceDrawerKicker, heading.kicker);
  setText(el.operatorEvidenceDrawerTitle, heading.title);
  setText(el.operatorEvidenceDrawerLane, resolveOperatorEvidenceDrawerWorkspaceLane(model, activeView));
  syncOperatorEvidenceDrawerContext(model, activeView);
  syncOperatorEvidenceDrawerTabOrder(model);
  if (el.operatorEvidenceDrawerLane instanceof HTMLElement) {
    el.operatorEvidenceDrawerLane.hidden = isCompactEvidenceView;
  }
  setText(el.operatorEvidenceDrawerHint, resolveOperatorEvidenceDrawerWorkspaceHint(activeView, model));
  if (el.operatorEvidenceDrawerStatus instanceof HTMLElement) {
    el.operatorEvidenceDrawerStatus.dataset.statusCode = model.statusCode;
    el.operatorEvidenceDrawerStatus.textContent = resolveOperatorEvidenceDrawerWorkspaceStatusText(model, activeView);
    el.operatorEvidenceDrawerStatus.className = "status-pill";
    if (model.variant === "fail") {
      el.operatorEvidenceDrawerStatus.classList.add("status-fail");
    } else if (model.variant === "ok") {
      el.operatorEvidenceDrawerStatus.classList.add("status-ok");
    } else {
      el.operatorEvidenceDrawerStatus.classList.add("status-neutral");
    }
  }
  if (el.operatorEvidenceDrawerTabs instanceof HTMLElement) {
    const tabButtons = el.operatorEvidenceDrawerTabs.querySelectorAll("[data-operator-evidence-view]");
    for (const button of tabButtons) {
      if (!(button instanceof HTMLButtonElement)) {
        continue;
      }
      const buttonViewId = normalizeOperatorEvidenceDrawerView(button.dataset.operatorEvidenceView);
      const isActive = !!activeView && buttonViewId === activeView.id;
      button.classList.toggle("is-active", isActive);
      button.setAttribute("aria-selected", isActive ? "true" : "false");
      button.tabIndex = isActive ? 0 : -1;
    }
  }
  if (el.operatorEvidenceDrawerPanel instanceof HTMLElement) {
    const labelledBy = activeView ? `operatorEvidenceDrawerTab${activeView.id.charAt(0).toUpperCase()}${activeView.id.slice(1)}` : "operatorEvidenceDrawerTabLatest";
    el.operatorEvidenceDrawerPanel.setAttribute("aria-labelledby", labelledBy);
  }
  const useWorkspacePlaceholderEvidence = shouldUseOperatorEvidenceDrawerWorkspacePlaceholder(model);
  if (el.operatorEvidenceDrawerProofPathSection instanceof HTMLDetailsElement) {
    el.operatorEvidenceDrawerProofPathSection.open = !useWorkspacePlaceholderEvidence;
    el.operatorEvidenceDrawerProofPathSection.dataset.proofPathState = useWorkspacePlaceholderEvidence ? "dormant" : "hydrated";
  }
  setText(
    el.operatorEvidenceDrawerPanelLabel,
    resolveOperatorEvidenceDrawerWorkspaceTabLabel(activeView?.id ?? "latest", model),
  );
  setText(
    el.operatorEvidenceDrawerPanelMeta,
    resolveOperatorEvidenceDrawerWorkspacePanelMeta(activeView, model),
  );
  if (el.operatorEvidenceDrawerPanelLabel instanceof HTMLElement) {
    el.operatorEvidenceDrawerPanelLabel.hidden = activeView?.showLabel === false;
  }
  if (el.operatorEvidenceDrawerPanelMeta instanceof HTMLElement) {
    el.operatorEvidenceDrawerPanelMeta.hidden = activeView?.showMeta === false;
  }
  const panelHead = el.operatorEvidenceDrawerPanelLabel?.closest(".operator-evidence-drawer-panel-head");
  if (panelHead instanceof HTMLElement) {
    panelHead.hidden = activeView?.showLabel === false && activeView?.showMeta === false;
  }
  setText(
    el.operatorEvidenceDrawerSummary,
    buildOperatorEvidenceDrawerWorkspaceSummary(activeView, model),
  );
  // Legacy timeline-label token kept for alignment coverage:
  // setText(el.operatorEvidenceDrawerTimelineLabel, activeView?.timelineLabel ?? "Recent lane flow");
  setText(el.operatorEvidenceDrawerTimelineLabel, resolveOperatorEvidenceDrawerWorkspaceTimelineLabel(activeView, model));
  const timelineShell = el.operatorEvidenceDrawerTimeline.closest(".operator-evidence-drawer-timeline-shell");
  if (timelineShell instanceof HTMLElement) {
    timelineShell.hidden = activeView?.showTimeline === false;
  }
  const checkpointsShell = el.operatorEvidenceDrawerCheckpoints.closest(".operator-evidence-drawer-checkpoints-shell");
  if (checkpointsShell instanceof HTMLElement) {
    checkpointsShell.hidden = activeView?.showCheckpoints === false;
  }
  const provenanceShell = el.operatorEvidenceDrawerProvenance.closest(".operator-evidence-drawer-provenance-shell");
  if (provenanceShell instanceof HTMLElement) {
    provenanceShell.hidden = activeView?.showProvenance === false;
  }
  el.operatorEvidenceDrawerOrigins.hidden = activeView?.showOrigins === false;
  el.operatorEvidenceDrawerOrigins.innerHTML = "";
  const origins = useWorkspacePlaceholderEvidence
    ? buildOperatorEvidenceDrawerWorkspacePlaceholderOrigins(activeView, model)
    : activeView && Array.isArray(activeView.origins) && activeView.origins.length > 0
      ? activeView.origins
      : [{ label: "Workspace", value: "Focused workspace", tone: "muted", isPlaceholder: true }];
  for (const origin of origins) {
    const originTone = resolveOperatorEvidenceDrawerWorkspaceOriginTone(origin, activeView, model);
    const article = document.createElement("article");
    article.className = origin.isPlaceholder
      ? `operator-evidence-drawer-origin is-${originTone} is-placeholder`
      : `operator-evidence-drawer-origin is-${originTone}`;
    const label = document.createElement("span");
    label.className = "operator-evidence-drawer-origin-label";
    label.textContent = origin.label;
    const value = document.createElement("strong");
    value.className = "operator-evidence-drawer-origin-value";
    value.textContent = origin.value;
    article.append(label, value);
    el.operatorEvidenceDrawerOrigins.append(article);
  }
  el.operatorEvidenceDrawerFacts.innerHTML = "";
  const facts = useWorkspacePlaceholderEvidence
    ? buildOperatorEvidenceDrawerWorkspacePlaceholderFacts(activeView, model)
    : activeView && Array.isArray(activeView.facts) && activeView.facts.length > 0
      ? activeView.facts
      : [{ label: "Awaiting signal", value: "Refresh Summary", isPlaceholder: true }];
  facts.forEach((fact, index) => {
    const factTone = resolveOperatorEvidenceDrawerWorkspaceFactTone(fact, index, activeView, model);
    const factLabel =
      activeView?.factsMode === "compact" && typeof fact.compactLabel === "string" && fact.compactLabel.trim().length > 0
        ? fact.compactLabel.trim()
        : fact.label;
    const factValue =
      activeView?.factsMode === "compact" && typeof fact.compactValue === "string" && fact.compactValue.trim().length > 0
        ? fact.compactValue.trim()
        : fact.value;
    const article = document.createElement("article");
    article.className = fact.isPlaceholder
      ? "operator-evidence-drawer-fact is-placeholder"
      : "operator-evidence-drawer-fact";
    article.classList.add(index === 0 ? "is-primary" : "is-secondary");
    // Legacy fact-tone token kept for alignment coverage:
    // article.classList.add(`is-${index === 0 ? model.variant ?? "muted" : "muted"}`);
    article.classList.add(`is-${factTone}`);
    article.title = `${fact.label}: ${fact.value}`;
    const label = document.createElement("span");
    label.className = "operator-evidence-drawer-fact-label";
    label.textContent = factLabel;
    const value = document.createElement("strong");
    value.textContent = factValue;
    article.append(label, value);
    el.operatorEvidenceDrawerFacts.append(article);
  });
  el.operatorEvidenceDrawerTimeline.innerHTML = "";
  const timeline = useWorkspacePlaceholderEvidence
    ? buildOperatorEvidenceDrawerWorkspacePlaceholderTimeline(activeView, model)
    : activeView && Array.isArray(activeView.timeline) && activeView.timeline.length > 0
      ? prioritizeOperatorEvidenceDrawerTimelineForWorkspace(activeView.timeline, activeView, model)
      : [createOperatorEvidenceDrawerTimelineEntry({})];
  for (const entry of timeline) {
    const article = document.createElement("article");
    article.className = `operator-evidence-drawer-timeline-item is-${entry.tone ?? "muted"}`;
    const head = document.createElement("div");
    head.className = "operator-evidence-drawer-timeline-item-head";
    const step = document.createElement("span");
    step.className = "operator-evidence-drawer-timeline-step";
    step.textContent = entry.step;
    const time = document.createElement("span");
    time.className = "operator-evidence-drawer-timeline-time";
    time.textContent = entry.time ?? "Awaiting refresh";
    const title = document.createElement("strong");
    title.className = "operator-evidence-drawer-timeline-title";
    title.textContent = entry.title;
    const meta = document.createElement("p");
    meta.className = "operator-evidence-drawer-timeline-meta";
    meta.textContent = entry.meta;
    head.append(step, time);
    article.append(head, title, meta);
    el.operatorEvidenceDrawerTimeline.append(article);
  }
  // Legacy checkpoint token kept for alignment coverage:
  // setText(el.operatorEvidenceDrawerCheckpointsLabel, activeView?.checkpointsLabel ?? "Recent checkpoints");
  setText(
    el.operatorEvidenceDrawerCheckpointsLabel,
    resolveOperatorEvidenceDrawerWorkspaceCheckpointsLabel(activeView, model),
  );
  el.operatorEvidenceDrawerCheckpoints.innerHTML = "";
  const checkpoints = useWorkspacePlaceholderEvidence
    ? buildOperatorEvidenceDrawerWorkspacePlaceholderCheckpoints(activeView, model)
    : activeView && Array.isArray(activeView.checkpoints) && activeView.checkpoints.length > 0
      ? resolveOperatorEvidenceDrawerWorkspaceCheckpoints(activeView, model)
      : [{ label: "Awaiting signal", value: "Refresh Summary", tone: "muted", isPlaceholder: true }];
  for (const checkpoint of checkpoints) {
    const article = document.createElement("article");
    article.className = checkpoint.isPlaceholder
      ? `operator-evidence-drawer-checkpoint is-${checkpoint.tone ?? "muted"} is-placeholder`
      : `operator-evidence-drawer-checkpoint is-${checkpoint.tone ?? "muted"}`;
    const label = document.createElement("span");
    label.className = "operator-evidence-drawer-checkpoint-label";
    label.textContent = checkpoint.label;
    const value = document.createElement("strong");
    value.className = "operator-evidence-drawer-checkpoint-value";
    value.textContent = checkpoint.value;
    article.append(label, value);
    el.operatorEvidenceDrawerCheckpoints.append(article);
  }
  // Legacy provenance token kept for alignment coverage:
  // setText(el.operatorEvidenceDrawerProvenanceLabel, "Action provenance");
  setText(el.operatorEvidenceDrawerProvenanceLabel, resolveOperatorEvidenceDrawerWorkspaceProvenanceLabel({
    activeSavedViewId: model.activeSavedViewId,
  }));
  el.operatorEvidenceDrawerProvenance.innerHTML = "";
  const provenance = useWorkspacePlaceholderEvidence
    ? buildOperatorEvidenceDrawerWorkspacePlaceholderProvenance(activeView, model)
    : activeView && Array.isArray(activeView.provenance) && activeView.provenance.length > 0
      ? activeView.provenance
      : [{ label: "Actor", value: "Refresh Summary", tone: "muted", isPlaceholder: true }];
  for (const item of provenance) {
    const provenanceValue =
      isCompactEvidenceView && typeof item.compactValue === "string" && item.compactValue.trim().length > 0
        ? item.compactValue.trim()
        : item.value;
    const article = document.createElement("article");
    article.className = item.isPlaceholder
      ? `operator-evidence-drawer-provenance-item is-${item.tone ?? "muted"} is-placeholder`
      : `operator-evidence-drawer-provenance-item is-${item.tone ?? "muted"}`;
    article.title = `${item.label}: ${item.value}`;
    const label = document.createElement("span");
    label.className = "operator-evidence-drawer-provenance-item-label";
    label.textContent = item.label;
    const value = document.createElement("strong");
    value.className = "operator-evidence-drawer-provenance-item-value";
    value.textContent = provenanceValue;
    article.append(label, value);
    el.operatorEvidenceDrawerProvenance.append(article);
  }
  el.operatorEvidenceDrawerActions.innerHTML = "";
  const actions = useWorkspacePlaceholderEvidence
    ? buildOperatorEvidenceDrawerWorkspacePlaceholderActions(activeView, model)
    : activeView && Array.isArray(activeView.actions)
      ? activeView.actions
      : model.actions;
  for (const [index, actionConfig] of actions.entries()) {
      const button = createOperatorEvidenceDrawerActionNode(actionConfig, {
        activeViewId: activeView?.id ?? "latest",
        compact: isCompactEvidenceView,
        cardTitle: model.title,
        primary: useWorkspacePlaceholderEvidence && index === 0,
        workspaceTone:
          useWorkspacePlaceholderEvidence && index === 0
            ? normalizeOperatorSavedView(model?.activeSavedViewId) || "incidents"
            : "",
      });
      if (button) {
      el.operatorEvidenceDrawerActions.append(button);
    }
  }
}

function syncOperatorPriorityQueue() {
  if (!(el.operatorPriorityQueueList instanceof HTMLElement)) {
    return;
  }

  const hasManualRefresh = state.operatorSummaryUserRefreshed === true;
  const isDemo = normalizeOperatorBoardMode(state.operatorBoardMode) === "demo";
  const signals = getOperatorSummaryGuideSignals();
  const failSignals = signals.filter((item) => item.variant === "fail");
  const staleSignals = signals.filter((item) => item.statusCode === "summary_stale");
  const watchSignals = signals.filter(
    (item) => item.variant === "neutral" && item.statusCode !== "summary_stale" && !isOperatorUninitializedStatusText(item.statusCode),
  );
  const okSignals = signals.filter((item) => item.variant === "ok");

  const entries = [];
  const seenKeys = new Set();
  const pushEntry = (entry) => {
    if (!entry || typeof entry !== "object" || typeof entry.key !== "string" || seenKeys.has(entry.key) || entries.length >= 3) {
      return;
    }
    seenKeys.add(entry.key);
    entries.push(entry);
  };

  if (!hasManualRefresh) {
    pushEntry({
      key: "hydrate_board",
      tone: "neutral",
      kicker: "Start here",
      title: "Hydrate the incident board",
      meta: "Refresh summary once, then use the highlighted workspace or recovery path instead of scanning the entire console.",
      primary: {
        label: "Refresh Summary",
        actionId: "refresh_summary",
      },
      secondary: {
        label: "Open Quick Start",
        actionId: "open_quick_start",
        kind: "secondary",
      },
    });
  } else {
    if (state.operatorLastRefreshState === "failed") {
      pushEntry({
        key: "refresh_failed",
        tone: "fail",
        kicker: "Refresh failed",
        title: "Board evidence is stale",
        meta: "Retry summary first. Lane Radar stays navigable, but stale surfaces should not be treated as live evidence.",
        primary: {
          label: "Refresh Summary",
          actionId: "refresh_summary",
        },
        secondary: {
          label: "Open Playbook",
          actionId: "open_playbook",
          kind: "secondary",
        },
      });
    }

    if (state.operatorRuntimeGuardrailAction) {
      const actionState = getOperatorRuntimeGuardrailActionState(state.operatorRuntimeGuardrailAction);
      pushEntry({
        key: "runtime_guardrail_path",
        tone: actionState?.statusCode === "failed" ? "watch" : "fail",
        kicker: "Recovery path",
        title: buildOperatorRuntimeGuardrailActionTitle(state.operatorRuntimeGuardrailAction),
        meta: buildOperatorRuntimeGuardrailActionMeta(state.operatorRuntimeGuardrailAction),
        primary: {
          label: state.operatorRuntimeGuardrailAction.buttonLabel ?? "Run Path",
          actionId: "run_runtime_guardrail_path",
        },
        secondary: {
          label: "Open Guardrails",
          actionId: "jump_status_card",
          targetStatusId: "operatorRuntimeGuardrailsStatus",
          kind: "secondary",
        },
      });
      seenKeys.add("operatorRuntimeGuardrailsStatus");
    }

    for (const signal of failSignals) {
      pushEntry(createOperatorPriorityQueueSignalEntry(signal));
    }
    for (const signal of watchSignals) {
      pushEntry(createOperatorPriorityQueueSignalEntry(signal));
    }
    for (const signal of staleSignals) {
      pushEntry(createOperatorPriorityQueueSignalEntry(signal));
    }

    if (entries.length === 0 && okSignals.length > 0) {
      pushEntry({
        key: "nominal_overview",
        tone: "ok",
        kicker: "Nominal",
        title: "Critical lanes look steady",
        meta: isDemo
          ? "Stay in Demo View for live monitoring, or open more cards only when deeper diagnostics are needed."
          : "Use this console as a steady watch surface and open deeper drawers only for audit or control-plane changes.",
        primary: {
          label: state.operatorFocusCriticalOnly ? "Show All Cards" : "Full Ops View",
          actionId: state.operatorFocusCriticalOnly ? "show_all_cards" : "full_ops_view",
        },
        secondary: isDemo && state.operatorFocusCriticalOnly
          ? {
              label: "Full Ops View",
              actionId: "full_ops_view",
              kind: "secondary",
            }
          : null,
      });
    }
  }

  const finalEntries = entries.length > 0
    ? entries
    : [{
        key: "queue_empty",
        tone: "neutral",
        kicker: "Waiting",
        title: "No active queue items yet",
        meta: "Refresh summary after live activity or drills to hydrate the next-action queue.",
        primary: {
          label: "Refresh Summary",
          actionId: "refresh_summary",
        },
        secondary: {
          label: "Open Quick Start",
          actionId: "open_quick_start",
          kind: "secondary",
        },
      }];

  let queueState = "neutral";
  for (const entry of finalEntries) {
    if (entry.tone === "fail") {
      queueState = "fail";
      break;
    }
    if (queueState !== "fail" && (entry.tone === "watch" || entry.tone === "stale")) {
      queueState = "watch";
    } else if (queueState === "neutral" && entry.tone === "ok") {
      queueState = "ok";
    }
  }
  if (el.operatorTriageSummary instanceof HTMLElement) {
    el.operatorTriageSummary.dataset.queueState = queueState;
  }

  const isDesktopQueue = typeof window !== "undefined"
    && typeof window.matchMedia === "function"
    && window.matchMedia("(min-width: 921px)").matches;
  const shouldCompactDesktopQueue = isDesktopQueue && finalEntries.length > 2;
  const visibleEntries = shouldCompactDesktopQueue ? finalEntries.slice(0, 2) : finalEntries;
  const overflowEntries = shouldCompactDesktopQueue ? finalEntries.slice(2) : [];

  el.operatorPriorityQueueList.innerHTML = "";
  for (const [index, entry] of visibleEntries.entries()) {
    const tone = entry.tone ?? "neutral";
    const queueDensity = isDesktopQueue ? "compact" : "default";
    const item = document.createElement("article");
    item.className = `operator-priority-queue-item is-${tone}`;
    item.dataset.queueDensity = queueDensity;

    const copy = document.createElement("div");
    copy.className = "operator-priority-queue-copy";

    const head = document.createElement("div");
    head.className = "operator-priority-queue-head";

    const rank = document.createElement("span");
    rank.className = `operator-priority-queue-rank is-${tone}`;
    rank.textContent = `P${index + 1}`;

    const kicker = document.createElement("p");
    kicker.className = "operator-priority-queue-kicker";
    kicker.textContent = entry.kicker ?? "Queue item";

    const title = document.createElement("h3");
    const titleText = entry.title ?? "Operator action";
    const visibleTitle = queueDensity === "compact"
      ? resolveOperatorPriorityQueueCompactTitle(entry)
      : titleText;
    title.textContent = visibleTitle;
    if (queueDensity === "compact" && visibleTitle !== titleText) {
      title.title = titleText;
    }

    const meta = document.createElement("p");
    meta.className = "operator-priority-queue-meta";
    const metaTitle = entry.meta ?? "No operator guidance is available yet.";
    meta.textContent = queueDensity === "compact" ? buildOperatorPriorityQueueCompactMeta(entry) : metaTitle;
    meta.title = metaTitle;

    head.append(rank, kicker);
    copy.append(head, title, meta);
    item.append(copy);

    const actionConfigs = [entry.primary, entry.secondary]
      .filter(Boolean)
      .map((config) => queueDensity === "compact"
        ? { ...config, shortLabel: resolveOperatorPriorityQueueCompactActionLabel(config) }
        : config);
    const actions = actionConfigs
      .map((config) => createOperatorPriorityQueueActionButton(config))
      .filter(Boolean);
    if (actions.length > 0) {
      const actionRow = document.createElement("div");
      actionRow.className = "operator-priority-queue-actions";
      for (const button of actions) {
        actionRow.append(button);
      }
      item.append(actionRow);
    }

    el.operatorPriorityQueueList.append(item);
  }
  if (el.operatorPriorityQueueOverflow instanceof HTMLElement) {
    const overflowLead = overflowEntries[0];
    const overflowTitle = overflowLead && typeof overflowLead.title === "string" ? overflowLead.title.trim() : "";
    const overflowCopy = overflowEntries.length === 0
      ? ""
      : overflowEntries.length === 1 && overflowTitle
        ? `1 more queued action remains: ${overflowTitle}.`
        : overflowEntries.length === 1
          ? "1 more queued action remains below the fold."
          : `${overflowEntries.length} more queued actions remain below the fold.`;
    el.operatorPriorityQueueOverflow.hidden = overflowCopy.length === 0;
    if (overflowCopy.length > 0) {
      el.operatorPriorityQueueOverflow.textContent = overflowCopy;
    }
  }
  syncOperatorActionCenter();
  syncOperatorEvidenceDrawer();
}

function getOperatorSignalStripEntries() {
  if (!(el.operatorSignalStrip instanceof HTMLElement)) {
    return [];
  }
  return Array.from(el.operatorSignalStrip.querySelectorAll(".operator-signal-card")).map((card, index) => {
    const statusNode = card.querySelector(".status-pill");
    const titleNode = card.querySelector("h3");
    const baseOrder = Number(card.dataset.baseOrder ?? Number.NaN);
    const resolvedBaseOrder = Number.isFinite(baseOrder) ? Math.floor(baseOrder) : index;
    const statusCode = getOperatorStatusCode(statusNode);
    const statusText = statusNode && typeof statusNode.textContent === "string" ? statusNode.textContent.trim() : "";
    card.dataset.baseOrder = String(resolvedBaseOrder);
    return {
      card,
      label: titleNode && typeof titleNode.textContent === "string" ? titleNode.textContent.trim() : `Lane ${index + 1}`,
      targetStatusId: typeof card.dataset.operatorSignalTarget === "string" ? card.dataset.operatorSignalTarget.trim() : "",
      statusCode,
      statusText,
      variant: readOperatorStatusVariant(statusNode),
      isPlaceholder: isOperatorUninitializedStatusText(statusCode),
      baseOrder: resolvedBaseOrder,
    };
  });
}

function createOperatorStableSignalChip(entry, tone) {
  if (!entry || typeof entry !== "object" || !(entry.card instanceof HTMLElement)) {
    return null;
  }
  const button = document.createElement("button");
  button.type = "button";
  button.className = `operator-signal-stable-chip is-${tone === "ok" ? "ok" : "dormant"}`;
  const displayStatus = resolveStatusPillDisplayText(resolveOperatorSignalMirrorText(entry.statusCode, entry.statusText));
  button.setAttribute("aria-label", `Jump to ${entry.label} lane (${displayStatus})`);
  button.addEventListener("click", () => {
    jumpToOperatorStatusCard(entry.targetStatusId ?? "");
  });

  const label = document.createElement("span");
  label.className = "operator-signal-stable-chip-label";
  label.textContent = entry.label;

  const status = document.createElement("span");
  status.className = "operator-signal-stable-chip-status";
  status.textContent = displayStatus;

  button.append(label, status);
  return button;
}

function shouldCompactOperatorQuietSignalStrip(primaryEntries, signalDensity) {
  return signalDensity === "quiet"
    && normalizeOperatorBoardMode(state.operatorBoardMode) === "demo"
    && typeof window !== "undefined"
    && typeof window.matchMedia === "function"
    && window.matchMedia("(min-width: 921px)").matches
    && Array.isArray(primaryEntries)
    && primaryEntries.length > 3;
}

function shouldCompactOperatorStandardSignalStrip(primaryEntries, signalDensity) {
  return signalDensity === "standard"
    && normalizeOperatorBoardMode(state.operatorBoardMode) === "demo"
    && typeof window !== "undefined"
    && typeof window.matchMedia === "function"
    && window.matchMedia("(min-width: 921px)").matches
    && Array.isArray(primaryEntries)
    && primaryEntries.length > 4;
}

function createOperatorSignalOverflowChip(hiddenCount, expanded) {
  const button = document.createElement("button");
  button.type = "button";
  button.className = "operator-signal-overflow-chip";
  button.style.order = "9999";
  button.setAttribute(
    "aria-label",
    expanded
      ? "Collapse lane radar to the highest-priority lanes"
      : `Show ${hiddenCount} more lanes in Lane Radar`,
  );
  button.title = expanded ? "Collapse Lane Radar" : `Show ${hiddenCount} more lanes`;
  button.addEventListener("click", () => {
    state.operatorSignalStripExpanded = !state.operatorSignalStripExpanded;
    syncOperatorSignalStripSurface();
  });

  const label = document.createElement("span");
  label.className = "operator-signal-overflow-chip-label";
  label.textContent = expanded ? "Collapse radar" : `${hiddenCount} more lanes`;

  const meta = document.createElement("span");
  meta.className = "operator-signal-overflow-chip-meta";
  meta.textContent = expanded ? "Show less" : "Show all";

  button.append(label, meta);
  return button;
}

function renderOperatorStableSignalStrip(entries) {
  if (!(el.operatorSignalStableStrip instanceof HTMLElement) || !(el.operatorSignalStableSurface instanceof HTMLElement)) {
    return;
  }
  el.operatorSignalStableStrip.innerHTML = "";
  const stableEntries = Array.isArray(entries) ? entries : [];
  for (const entry of stableEntries) {
    const tone = entry.variant === "ok" ? "ok" : "dormant";
    const chip = createOperatorStableSignalChip(entry, tone);
    if (chip) {
      el.operatorSignalStableStrip.append(chip);
    }
  }
  el.operatorSignalStableSurface.classList.toggle("is-hidden", el.operatorSignalStableStrip.childElementCount === 0);
}

function shouldShowOperatorQuickStartAfterRefresh() {
  const signals = getOperatorSummaryGuideSignals();
  return !signals.some((item) => {
    const statusCode = getOperatorStatusCode(item.node);
    if (item.variant === "fail" || statusCode === "summary_stale") {
      return true;
    }
    if (item.variant !== "neutral") {
      return false;
    }
    return !isOperatorUninitializedStatusText(statusCode);
  });
}

function syncOperatorSignalStripSurface() {
  if (!(el.operatorSignalStripSurface instanceof HTMLElement)) {
    return;
  }
  const activeSavedView = getActiveOperatorSavedViewConfig();
  const entries = getOperatorSignalStripEntries();
  if (entries.length === 0) {
    return;
  }

  const failEntries = entries.filter((entry) => entry.variant === "fail");
  const staleEntries = entries.filter((entry) => entry.statusCode === "summary_stale");
  const neutralEntries = entries.filter(
    (entry) => entry.variant === "neutral" && entry.statusCode !== "summary_stale" && !entry.isPlaceholder,
  );
  const okEntries = entries.filter((entry) => entry.variant === "ok");
  const dormantEntries = entries.filter((entry) => entry.isPlaceholder);
  const primaryEntries = [...failEntries, ...staleEntries, ...neutralEntries];
  const stableEntries = [...okEntries, ...dormantEntries].sort((left, right) => left.baseOrder - right.baseOrder);
  const signalDensity = failEntries.length > 0 ? "standard" : primaryEntries.length > 0 ? "quiet" : "shelf";

  let signalState = "neutral";
  let hint = "Jump to the lane that needs attention first.";
  let stableHint = "Nominal and dormant lanes stay compressed here until you need a deeper lane.";

  if (state.operatorLastRefreshState === "failed" && staleEntries.length > 0) {
    signalState = "stale";
    hint = "Summary fetch failed. Active lanes stay on top while nominal systems remain compressed below.";
    stableHint = "Refresh first, then reopen nominal lanes only if they still matter after the stale posture clears.";
  } else if (failEntries.length > 0) {
    signalState = "fail";
    hint = `Jump to ${formatOperatorSummaryGuideLabelList(failEntries, 2)} first. Stable systems stay compressed until the hot lane is cleared.`;
  } else if (neutralEntries.length > 0) {
    signalState = "neutral";
    hint = `Verify ${formatOperatorSummaryGuideLabelList(neutralEntries, 2)} before opening deeper diagnostics. Stable systems stay compressed below.`;
  } else if (okEntries.length > 0) {
    signalState = "ok";
    hint = "No hot lane is active. Stable systems stay compressed until you need deeper evidence.";
    stableHint = "Nominal lanes stay available here as quieter jump-links.";
  } else if (dormantEntries.length > 0) {
    hint = "No hot lane is active yet. Refresh once; dormant systems stay compressed until live evidence arrives.";
    stableHint = "Dormant lanes stay compressed here until the next refresh or scenario seed.";
  }

  if (activeSavedView && activeSavedView.id !== "incidents") {
    if (failEntries.length === 0 && neutralEntries.length === 0) {
      hint = activeSavedView.nominalHint ?? activeSavedView.contextNote ?? hint;
    } else if (signalState !== "stale") {
      hint = `${activeSavedView.label} posture active. ${hint}`;
    }
    stableHint = `Other nominal lanes stay compressed while ${activeSavedView.label.toLowerCase()} evidence stays in focus.`;
  }

  el.operatorSignalStripSurface.dataset.signalState = signalState;
  el.operatorSignalStripSurface.dataset.signalDensity = signalDensity;
  if (signalDensity === "quiet") {
    hint = signalState === "stale"
      ? "Stale lanes stay short here until fresh evidence lands."
      : "Watch lanes stay short here until deeper evidence is needed.";
    stableHint = "Other nominal lanes stay as quieter jump chips.";
  } else if (signalDensity === "shelf") {
    hint = state.operatorSummaryUserRefreshed === true
      ? "No hot lane is active. Keep nominal lanes on the shelf until needed."
      : "No hot lane yet. Refresh once, then open only the lane that changes.";
    stableHint = "Nominal lanes stay as quiet jump chips.";
  }
  if (el.operatorSignalStripHint instanceof HTMLElement) {
    el.operatorSignalStripHint.textContent = hint;
  }
  if (el.operatorSignalStableHint instanceof HTMLElement) {
    el.operatorSignalStableHint.textContent = stableHint;
  }
  if (el.operatorSignalPrimaryCount instanceof HTMLElement) {
    const primarySummary = primaryEntries.length > 0
      ? `Issues now ${primaryEntries.length}`
      : state.operatorSummaryUserRefreshed === true
        ? "Issues now clear"
        : "Issues now waiting";
    setText(el.operatorSignalPrimaryCount, primarySummary);
  }
  if (el.operatorSignalStableCount instanceof HTMLElement) {
    let stableSummary = `Stable systems ${okEntries.length}`;
    if (dormantEntries.length > 0) {
      stableSummary += ` · dormant ${dormantEntries.length}`;
    }
    setText(el.operatorSignalStableCount, normalizeOperatorUiCopy(stableSummary));
  }
  renderOperatorStableSignalStrip(stableEntries);

  const shouldCompactQuietSignals = shouldCompactOperatorQuietSignalStrip(primaryEntries, signalDensity);
  const shouldCompactStandardSignals = shouldCompactOperatorStandardSignalStrip(primaryEntries, signalDensity);
  const signalCompactLimit = shouldCompactQuietSignals ? 3 : shouldCompactStandardSignals ? 4 : 0;
  if (signalCompactLimit === 0) {
    state.operatorSignalStripExpanded = false;
  }
  const hiddenPrimaryEntries = signalCompactLimit > 0 ? primaryEntries.slice(signalCompactLimit) : [];
  const visiblePrimaryEntries = signalCompactLimit > 0 && !state.operatorSignalStripExpanded
    ? primaryEntries.slice(0, signalCompactLimit)
    : primaryEntries;
  const shouldCompactSignalPills = signalCompactLimit > 0 && !state.operatorSignalStripExpanded;
  el.operatorSignalStripSurface.dataset.signalCompact = signalCompactLimit > 0
    ? state.operatorSignalStripExpanded ? "expanded" : "collapsed"
    : "all";
  if (el.operatorSignalStrip instanceof HTMLElement) {
    el.operatorSignalStrip.querySelectorAll(".operator-signal-overflow-chip").forEach((node) => node.remove());
  }

  for (const entry of entries) {
    const orderBucket =
      entry.variant === "fail"
        ? 0
        : entry.statusCode === "summary_stale"
          ? 1
          : entry.variant === "neutral" && !entry.isPlaceholder
            ? 2
            : entry.variant === "ok"
              ? 3
              : 4;
    entry.card.style.order = String(orderBucket * 100 + entry.baseOrder);
    const shouldShowAsCard = visiblePrimaryEntries.includes(entry);
    entry.card.hidden = !shouldShowAsCard;
    entry.card.dataset.signalTier = shouldShowAsCard ? "active" : entry.variant === "ok" ? "stable" : "dormant";
    const statusNode = entry.card.querySelector(".status-pill");
    if (statusNode instanceof HTMLElement) {
      const fullSignalLabel = resolveStatusPillDisplayText(
        resolveOperatorSignalMirrorText(entry.statusCode, entry.statusText),
      );
      const compactSignalLabel = shouldCompactSignalPills
        ? resolveOperatorSignalStripPillText(entry.statusCode, entry.statusText)
        : fullSignalLabel;
      statusNode.textContent = compactSignalLabel;
      if (shouldCompactSignalPills && compactSignalLabel !== fullSignalLabel) {
        statusNode.title = fullSignalLabel;
        statusNode.setAttribute("aria-label", fullSignalLabel);
      } else {
        statusNode.removeAttribute("title");
        statusNode.removeAttribute("aria-label");
      }
    }
  }
  if (el.operatorSignalStrip instanceof HTMLElement && signalCompactLimit > 0 && hiddenPrimaryEntries.length > 0) {
    el.operatorSignalStrip.append(createOperatorSignalOverflowChip(hiddenPrimaryEntries.length, state.operatorSignalStripExpanded));
  }
  syncOperatorEvidenceDrawer();
}

function syncOperatorBoardModeButtons() {
  const mode = normalizeOperatorBoardMode(state.operatorBoardMode);
  const isDemo = mode === "demo";
  if (el.operatorDemoViewBtn) {
    el.operatorDemoViewBtn.classList.toggle("is-active", isDemo);
    el.operatorDemoViewBtn.setAttribute("aria-pressed", isDemo ? "true" : "false");
    el.operatorDemoViewBtn.setAttribute("aria-label", "Demo View");
    el.operatorDemoViewBtn.title = "Demo View";
    el.operatorDemoViewBtn.textContent = "Demo";
  }
  if (el.operatorFullOpsViewBtn) {
    el.operatorFullOpsViewBtn.classList.toggle("is-active", !isDemo);
    el.operatorFullOpsViewBtn.setAttribute("aria-pressed", !isDemo ? "true" : "false");
    el.operatorFullOpsViewBtn.setAttribute("aria-label", "Full Ops View");
    el.operatorFullOpsViewBtn.title = "Full Ops View";
    el.operatorFullOpsViewBtn.textContent = "Full Ops";
  }
  if (el.operatorHealthBoard) {
    el.operatorHealthBoard.classList.toggle("is-demo-view", isDemo);
    el.operatorHealthBoard.classList.toggle("is-full-ops-view", !isDemo);
  }
  if (el.operatorBoardModeHint) {
    el.operatorBoardModeHint.textContent = isDemo
      ? "Judge walkthrough. Highest-signal lanes stay up front."
      : "Deep triage. Every lane stays visible.";
  }
  if (el.operatorModeBanner) {
    el.operatorModeBanner.classList.toggle("is-demo", isDemo);
    el.operatorModeBanner.classList.toggle("is-full-ops", !isDemo);
  }
  if (el.operatorDemoSummaryStrip) {
    el.operatorDemoSummaryStrip.classList.toggle("is-hidden", !isDemo);
  }
  setStatusPill(el.operatorModeBadge, isDemo ? "Demo view" : "Full ops", isDemo ? "ok" : "neutral");
  if (el.operatorModeCopy) {
    el.operatorModeCopy.textContent = isDemo
      ? "Judge-first view."
      : "Deep triage view.";
  }
  syncOperatorSupportPanels();
  syncOperatorSummaryGuide();
  syncOperatorSignalStripSurface();
}

function getOperatorGroupByKey(key) {
  if (typeof key !== "string" || key.trim().length === 0) {
    return null;
  }
  return document.querySelector(`.operator-health-group[data-operator-group="${key.trim()}"]`);
}

function getOperatorGroupLabel(group) {
  if (!(group instanceof HTMLElement)) {
    return "Lane";
  }
  const titleNode = group.querySelector(".operator-health-group-title-copy h3");
  if (titleNode instanceof HTMLElement && typeof titleNode.textContent === "string" && titleNode.textContent.trim().length > 0) {
    return titleNode.textContent.trim();
  }
  return "Lane";
}

function resolveOperatorGroupFocusStatusId(group) {
  if (!(group instanceof HTMLElement)) {
    return "";
  }
  const cards = Array.from(group.querySelectorAll(".operator-health-card"));
  const entries = [];
  for (const card of cards) {
    if (!(card instanceof HTMLElement) || card.classList.contains("operator-health-card-hidden")) {
      continue;
    }
    const statusNode = card.querySelector(".status-pill");
    if (!(statusNode instanceof HTMLElement) || typeof statusNode.id !== "string" || statusNode.id.trim().length === 0) {
      continue;
    }
    entries.push({
      id: statusNode.id.trim(),
      variant: readOperatorStatusVariant(statusNode),
      statusCode: getOperatorStatusCode(statusNode),
    });
  }
  const pick = (predicate) => entries.find(predicate)?.id ?? "";
  return (
    pick((item) => item.variant === "fail") ||
    pick((item) => item.statusCode === "summary_stale") ||
    pick(
      (item) =>
        item.variant === "neutral"
        && item.statusCode !== "summary_stale"
        && !isOperatorUninitializedStatusText(item.statusCode),
    ) ||
    pick((item) => item.variant === "ok") ||
    pick((item) => isOperatorUninitializedStatusText(item.statusCode))
  );
}

function flashOperatorGroup(group) {
  if (!(group instanceof HTMLElement)) {
    return;
  }
  group.classList.remove("operator-health-group-focus-flash");
  void group.offsetWidth;
  group.classList.add("operator-health-group-focus-flash");
  window.setTimeout(() => {
    group.classList.remove("operator-health-group-focus-flash");
  }, OPERATOR_SIGNAL_FLASH_MS);
}

function getActiveOperatorSavedViewConfig() {
  const activeView = normalizeOperatorSavedView(state.operatorSavedView);
  if (!activeView) {
    return null;
  }
  const config = OPERATOR_SAVED_VIEWS[activeView];
  return config ? { ...config, id: activeView } : null;
}

function getOperatorGroupKeyByStatusId(statusId) {
  const card = getOperatorCardByStatusId(statusId);
  const group = card instanceof HTMLElement ? card.closest(".operator-health-group") : null;
  return group instanceof HTMLElement ? group.getAttribute("data-operator-group") ?? "" : "";
}

function resolveOperatorSavedViewEvidenceStatusId(config, signals) {
  if (!config || !Array.isArray(signals) || signals.length === 0) {
    return "";
  }
  const groupKey = typeof config.groupKey === "string" ? config.groupKey.trim() : "";
  const targetStatusId = typeof config.targetStatusId === "string" ? config.targetStatusId.trim() : "";
  const scopedSignals = groupKey
    ? signals.filter((item) => getOperatorGroupKeyByStatusId(item.id) === groupKey)
    : signals;
  const findScopedSignalId = (predicate) => {
    const match = scopedSignals.find(predicate);
    return match && typeof match.id === "string" ? match.id : "";
  };
  return (
    findScopedSignalId((item) => item.variant === "fail") ||
    findScopedSignalId((item) => item.statusCode === "summary_stale") ||
    findScopedSignalId(
      (item) =>
        item.variant === "neutral" && item.statusCode !== "summary_stale" && !isOperatorUninitializedStatusText(item.statusCode),
    ) ||
    (targetStatusId && getOperatorCardByStatusId(targetStatusId) instanceof HTMLElement ? targetStatusId : "") ||
    findScopedSignalId((item) => item.variant === "ok") ||
    findScopedSignalId((item) => isOperatorUninitializedStatusText(item.statusCode))
  );
}

function syncOperatorSavedViewContext() {
  if (
    !(el.operatorSummaryGuideContext instanceof HTMLElement) ||
    !(el.operatorSummaryGuideViewPill instanceof HTMLElement) ||
    !(el.operatorSummaryGuideViewNote instanceof HTMLElement)
  ) {
    return;
  }
  const activeConfig = getActiveOperatorSavedViewConfig();
  const shouldShow = !!activeConfig;
  el.operatorSummaryGuideContext.classList.toggle("is-hidden", !shouldShow);
  if (!activeConfig) {
    delete el.operatorSummaryGuideContext.dataset.savedView;
  }
  if (!activeConfig) {
    return;
  }
  el.operatorSummaryGuideContext.dataset.savedView = activeConfig.id;
  el.operatorSummaryGuideViewPill.textContent = activeConfig.contextLabel ?? `${activeConfig.label} posture`;
  el.operatorSummaryGuideViewNote.textContent =
    activeConfig.contextNote ?? "Saved views keep one operator posture active without rebuilding filters and lane expansion.";
}

function syncOperatorConsoleEntry() {
  if (
    !(el.operatorConsoleEntry instanceof HTMLElement) ||
    !(el.operatorConsoleEntryStatus instanceof HTMLElement) ||
    !(el.operatorConsoleEntryTitle instanceof HTMLElement) ||
    !(el.operatorConsoleEntryHint instanceof HTMLElement)
  ) {
    return;
  }

  const activeConfig = getActiveOperatorSavedViewConfig();
  const hasManualRefresh = state.operatorSummaryUserRefreshed === true;
  const hasWorkspace = !!activeConfig;
  const isComplete = hasManualRefresh || hasWorkspace;

  el.operatorConsoleEntry.dataset.entryState = isComplete ? "complete" : "active";

  if (!isComplete) {
    setStatusPill(el.operatorConsoleEntryStatus, "entry active", "neutral");
    el.operatorConsoleEntryStatus.dataset.statusCode = "handoff_waiting";
    el.operatorConsoleEntryTitle.textContent = "Continue deeper operator work here";
    el.operatorConsoleEntryHint.textContent =
      "Use this console for the full queue, deeper runtime diagnostics, recovery tools, and audit evidence after the live case workspace handoff.";
    if (el.operatorConsoleEntryApprovalsBtn instanceof HTMLButtonElement) {
      el.operatorConsoleEntryApprovalsBtn.textContent = "Approvals";
      el.operatorConsoleEntryApprovalsBtn.dataset.entryActionState = "jump";
      el.operatorConsoleEntryApprovalsBtn.setAttribute("aria-pressed", "false");
    }
    if (el.operatorConsoleEntryRuntimeBtn instanceof HTMLButtonElement) {
      el.operatorConsoleEntryRuntimeBtn.textContent = "Runtime";
      el.operatorConsoleEntryRuntimeBtn.dataset.entryActionState = "jump";
      el.operatorConsoleEntryRuntimeBtn.setAttribute("aria-pressed", "false");
    }
    if (el.operatorConsoleEntryAuditBtn instanceof HTMLButtonElement) {
      el.operatorConsoleEntryAuditBtn.textContent = "Audit";
      el.operatorConsoleEntryAuditBtn.dataset.entryActionState = "jump";
      el.operatorConsoleEntryAuditBtn.setAttribute("aria-pressed", "false");
    }
    return;
  }

  setStatusPill(el.operatorConsoleEntryStatus, "handoff complete", "ok");
  el.operatorConsoleEntryStatus.dataset.statusCode = "handoff_complete";

  if (activeConfig && activeConfig.id !== "incidents") {
    el.operatorConsoleEntryTitle.textContent = `${activeConfig.label} workspace is active`;
    el.operatorConsoleEntryHint.textContent =
      "The operator handoff is already complete. Keep using Choose workspace below to switch areas, or use these quick paths when you need another direct jump.";
  } else {
    el.operatorConsoleEntryTitle.textContent = "Operator handoff complete";
    el.operatorConsoleEntryHint.textContent =
      "The board is already hydrated. Use Choose workspace below for the next focused area instead of restarting from the entry card.";
  }

  const workspaceButtons = [
    { button: el.operatorConsoleEntryApprovalsBtn, id: "approvals", label: "Approvals" },
    { button: el.operatorConsoleEntryRuntimeBtn, id: "runtime", label: "Runtime" },
    { button: el.operatorConsoleEntryAuditBtn, id: "audit", label: "Audit" },
  ];
  for (const item of workspaceButtons) {
    if (!(item.button instanceof HTMLButtonElement)) {
      continue;
    }
    const isCurrentWorkspace = activeConfig?.id === item.id;
    item.button.dataset.entryActionState = isCurrentWorkspace ? "current" : "jump";
    item.button.textContent = isCurrentWorkspace ? `${item.label} current` : item.label;
    item.button.setAttribute("aria-pressed", isCurrentWorkspace ? "true" : "false");
  }
}

function syncOperatorSummaryGuidePreview(activeSavedView, presentation) {
  if (
    !(el.operatorSummaryGuidePreview instanceof HTMLElement) ||
    !(el.operatorSummaryGuidePreviewFocusBtn instanceof HTMLButtonElement) ||
    !(el.operatorSummaryGuidePreviewFocusValue instanceof HTMLElement) ||
    !(el.operatorSummaryGuidePreviewOpenBtn instanceof HTMLButtonElement) ||
    !(el.operatorSummaryGuidePreviewOpenValue instanceof HTMLElement) ||
    !(el.operatorSummaryGuidePreviewRecoverBtn instanceof HTMLButtonElement) ||
    !(el.operatorSummaryGuidePreviewRecoverValue instanceof HTMLElement)
  ) {
    return;
  }

  const workspaceId = activeSavedView?.id ?? presentation?.normalizedView ?? "incidents";
  const workspaceLabel = presentation?.routeFacts?.label ?? activeSavedView?.label ?? "Overview";
  const workspaceTone = presentation?.tone ?? "neutral";
  const hasManualRefresh = presentation?.hasManualRefresh === true;
  const signalLabel = typeof presentation?.signal?.label === "string" && presentation.signal.label.trim().length > 0
    ? presentation.signal.label.trim()
    : workspaceLabel;
  const inspectSignal = presentation?.signal && typeof presentation.signal === "object" ? presentation.signal : null;

  let focusValue = presentation?.routeFacts?.focus ?? "Fail + watch lanes";
  let openValue = !hasManualRefresh ? "Refresh Summary" : `${workspaceLabel} workspace`;

  if (hasManualRefresh && workspaceTone === "fail") {
    openValue = `Inspect ${signalLabel}`;
  } else if (hasManualRefresh && workspaceTone === "neutral") {
    openValue = `Review ${signalLabel}`;
  } else if (hasManualRefresh && workspaceId === "incidents") {
    openValue = "Open incident workspace";
  }

  el.operatorSummaryGuidePreview.dataset.workspace = workspaceId;
  el.operatorSummaryGuidePreview.dataset.workspaceState = workspaceTone;
  el.operatorSummaryGuidePreviewFocusBtn.dataset.guidePreviewAction = "refresh_summary";
  delete el.operatorSummaryGuidePreviewFocusBtn.dataset.guidePreviewTargetStatusId;
  delete el.operatorSummaryGuidePreviewFocusBtn.dataset.guidePreviewSavedView;

  const openAction = !hasManualRefresh
    ? "refresh_summary"
    : activeSavedView?.id && activeSavedView.id !== "incidents"
      ? "inspect_saved_view"
      : inspectSignal ? "inspect_status" : "refresh_summary";
  el.operatorSummaryGuidePreviewOpenBtn.dataset.guidePreviewAction = openAction;
  if (openAction === "inspect_status" && inspectSignal?.id) {
    el.operatorSummaryGuidePreviewOpenBtn.dataset.guidePreviewTargetStatusId = inspectSignal.id;
  } else {
    delete el.operatorSummaryGuidePreviewOpenBtn.dataset.guidePreviewTargetStatusId;
  }
  if (openAction === "inspect_saved_view" && activeSavedView?.id) {
    el.operatorSummaryGuidePreviewOpenBtn.dataset.guidePreviewSavedView = activeSavedView.id;
  } else {
    delete el.operatorSummaryGuidePreviewOpenBtn.dataset.guidePreviewSavedView;
  }

  const recoverAction = !hasManualRefresh || workspaceTone === "neutral"
    ? "open_quick_start"
    : "open_playbook";
  const recoverValue = recoverAction === "open_quick_start" ? "Quick Start" : "Recovery Playbook";
  el.operatorSummaryGuidePreviewRecoverBtn.dataset.guidePreviewAction = recoverAction;
  delete el.operatorSummaryGuidePreviewRecoverBtn.dataset.guidePreviewTargetStatusId;
  delete el.operatorSummaryGuidePreviewRecoverBtn.dataset.guidePreviewSavedView;

  el.operatorSummaryGuidePreviewFocusValue.textContent = focusValue;
  el.operatorSummaryGuidePreviewOpenValue.textContent = openValue;
  el.operatorSummaryGuidePreviewRecoverValue.textContent = recoverValue;
  el.operatorSummaryGuidePreviewFocusBtn.setAttribute("aria-label", `Focus preview card. ${focusValue}.`);
  el.operatorSummaryGuidePreviewOpenBtn.setAttribute("aria-label", `Open preview card. ${openValue}.`);
  el.operatorSummaryGuidePreviewRecoverBtn.setAttribute("aria-label", `Recover preview card. ${recoverValue}.`);
}

function syncOperatorWorkspaceChooser() {
  if (!(el.operatorWorkspaceChooserStatus instanceof HTMLElement) || !(el.operatorWorkspaceChooserMeta instanceof HTMLElement)) {
    return;
  }
  const activeConfig = getActiveOperatorSavedViewConfig();
  const returnToOverviewVisible = activeConfig?.id && activeConfig.id !== "incidents";
  if (el.operatorWorkspaceChooser instanceof HTMLElement) {
    if (activeConfig?.id) {
      el.operatorWorkspaceChooser.dataset.activeWorkspace = activeConfig.id;
    } else {
      delete el.operatorWorkspaceChooser.dataset.activeWorkspace;
    }
  }
  if (!activeConfig) {
    setStatusPill(el.operatorWorkspaceChooserStatus, "overview", "neutral");
    el.operatorWorkspaceChooserStatus.dataset.statusCode = "overview";
    el.operatorWorkspaceChooserMeta.textContent =
      "No workspace pinned yet. Use Approvals, Runtime, or Audit to jump deeper without scanning the full board.";
    if (el.operatorWorkspaceReturnBtn instanceof HTMLButtonElement) {
      el.operatorWorkspaceReturnBtn.hidden = true;
      el.operatorWorkspaceReturnBtn.setAttribute("aria-hidden", "true");
    }
    return;
  }
  const activeLabel = activeConfig.id === "incidents" ? "overview active" : `${activeConfig.label} active`;
  setStatusPill(el.operatorWorkspaceChooserStatus, activeLabel, activeConfig.id === "incidents" ? "neutral" : "ok");
  el.operatorWorkspaceChooserStatus.dataset.statusCode = activeConfig.id;
  el.operatorWorkspaceChooserMeta.textContent =
    activeConfig.id === "incidents"
      ? "Overview keeps broad fail, stale, and watch lanes in one scan path before deeper workspace work."
      : `${activeConfig.hint ?? "Saved view is active for deeper operator work."} Use Back to Overview to reopen the broader board.`;
  if (el.operatorWorkspaceReturnBtn instanceof HTMLButtonElement) {
    el.operatorWorkspaceReturnBtn.hidden = !returnToOverviewVisible;
    el.operatorWorkspaceReturnBtn.setAttribute("aria-hidden", returnToOverviewVisible ? "false" : "true");
  }
}

function getOperatorWorkspaceCardTargets() {
  return {
    incidents: {
      button: el.operatorWorkspaceOverviewBtn,
      status: el.operatorWorkspaceOverviewStatus,
      meta: el.operatorWorkspaceOverviewMeta,
      focusValue: el.operatorWorkspaceOverviewFocusValue,
      openValue: el.operatorWorkspaceOverviewOpenValue,
      modeValue: el.operatorWorkspaceOverviewModeValue,
      viewValue: el.operatorWorkspaceOverviewViewValue,
      nextValue: el.operatorWorkspaceOverviewNextValue,
      signal: el.operatorWorkspaceOverviewSignal,
      signalValue: el.operatorWorkspaceOverviewSignalValue,
      signalSource: el.operatorWorkspaceOverviewSignalSource,
      signalFreshness: el.operatorWorkspaceOverviewSignalFreshness,
      marker: el.operatorWorkspaceOverviewMarker,
    },
    approvals: {
      button: el.operatorWorkspaceApprovalsBtn,
      status: el.operatorWorkspaceApprovalsStatus,
      meta: el.operatorWorkspaceApprovalsMeta,
      focusValue: el.operatorWorkspaceApprovalsFocusValue,
      openValue: el.operatorWorkspaceApprovalsOpenValue,
      modeValue: el.operatorWorkspaceApprovalsModeValue,
      viewValue: el.operatorWorkspaceApprovalsViewValue,
      nextValue: el.operatorWorkspaceApprovalsNextValue,
      signal: el.operatorWorkspaceApprovalsSignal,
      signalValue: el.operatorWorkspaceApprovalsSignalValue,
      signalSource: el.operatorWorkspaceApprovalsSignalSource,
      signalFreshness: el.operatorWorkspaceApprovalsSignalFreshness,
      marker: el.operatorWorkspaceApprovalsMarker,
    },
    runtime: {
      button: el.operatorWorkspaceRuntimeBtn,
      status: el.operatorWorkspaceRuntimeStatus,
      meta: el.operatorWorkspaceRuntimeMeta,
      focusValue: el.operatorWorkspaceRuntimeFocusValue,
      openValue: el.operatorWorkspaceRuntimeOpenValue,
      modeValue: el.operatorWorkspaceRuntimeModeValue,
      viewValue: el.operatorWorkspaceRuntimeViewValue,
      nextValue: el.operatorWorkspaceRuntimeNextValue,
      signal: el.operatorWorkspaceRuntimeSignal,
      signalValue: el.operatorWorkspaceRuntimeSignalValue,
      signalSource: el.operatorWorkspaceRuntimeSignalSource,
      signalFreshness: el.operatorWorkspaceRuntimeSignalFreshness,
      marker: el.operatorWorkspaceRuntimeMarker,
    },
    audit: {
      button: el.operatorWorkspaceAuditBtn,
      status: el.operatorWorkspaceAuditStatus,
      meta: el.operatorWorkspaceAuditMeta,
      focusValue: el.operatorWorkspaceAuditFocusValue,
      openValue: el.operatorWorkspaceAuditOpenValue,
      modeValue: el.operatorWorkspaceAuditModeValue,
      viewValue: el.operatorWorkspaceAuditViewValue,
      nextValue: el.operatorWorkspaceAuditNextValue,
      signal: el.operatorWorkspaceAuditSignal,
      signalValue: el.operatorWorkspaceAuditSignalValue,
      signalSource: el.operatorWorkspaceAuditSignalSource,
      signalFreshness: el.operatorWorkspaceAuditSignalFreshness,
      marker: el.operatorWorkspaceAuditMarker,
    },
  };
}

function resolveOperatorWorkspaceCardViewLabel(presentation) {
  const workspaceId = normalizeOperatorSavedView(presentation?.normalizedView) || "incidents";
  const variant = !presentation?.hasManualRefresh
    ? "dormant"
    : presentation?.tone === "fail"
      ? "fail"
      : presentation?.tone === "ok"
        ? "ok"
        : "neutral";
  const defaultViewId = resolveOperatorEvidenceDrawerDefaultView({
    activeSavedViewId: workspaceId,
    variant,
  });
  return resolveOperatorEvidenceDrawerWorkspaceTabLabel(defaultViewId, {
    activeSavedViewId: workspaceId,
    variant,
  });
}

function resolveOperatorWorkspaceLeadSignalPresentation(presentation) {
  const signalValue =
    presentation?.signal?.text?.trim().length
      ? presentation.signal.text.trim()
      : presentation?.signal?.label?.trim().length
        ? presentation.signal.label.trim()
        : `${typeof presentation?.routeFacts?.label === "string" && presentation.routeFacts.label.trim().length > 0
            ? presentation.routeFacts.label.trim()
            : "Workspace"} signal pending`;
  const signalState = presentation?.signal?.variant ?? (presentation?.tone === "ok" ? "steady" : "dormant");
  return {
    value: signalValue,
    state: signalState,
  };
}

function resolveOperatorWorkspaceLeadSignalSourcePresentation(presentation) {
  const signalSource =
    typeof presentation?.signal?.label === "string" && presentation.signal.label.trim().length > 0
      ? presentation.signal.label.trim()
      : typeof presentation?.routeFacts?.label === "string" && presentation.routeFacts.label.trim().length > 0
        ? presentation.routeFacts.label.trim()
        : "Workspace";
  return `Source: ${signalSource}`;
}

function resolveOperatorWorkspaceCardLeadSignalSourceValue(presentation) {
  if (typeof presentation?.signal?.label === "string" && presentation.signal.label.trim().length > 0) {
    return presentation.signal.label.trim();
  }
  if (typeof presentation?.routeFacts?.label === "string" && presentation.routeFacts.label.trim().length > 0) {
    return presentation.routeFacts.label.trim();
  }
  return "Workspace";
}

function resolveOperatorWorkspaceFreshnessPresentation() {
  if (state.operatorSummaryUserRefreshed !== true) {
    return {
      value: "Freshness: awaiting refresh",
      state: "dormant",
    };
  }

  const refreshLabel = getOperatorEvidenceDrawerRefreshLabel();
  const refreshStamp = getOperatorEvidenceDrawerRefreshStamp(refreshLabel);

  if (state.operatorLastRefreshState === "failed") {
    return {
      value: "Freshness: refresh failed",
      state: "fail",
    };
  }

  return {
    value: `Freshness: ${refreshStamp || "awaiting refresh"}`,
    state: "steady",
  };
}

function resolveOperatorWorkspaceCardFreshnessValue() {
  if (state.operatorSummaryUserRefreshed !== true) {
    return {
      value: "awaiting refresh",
      state: "dormant",
    };
  }

  const refreshLabel = getOperatorEvidenceDrawerRefreshLabel();
  const refreshStamp = getOperatorEvidenceDrawerRefreshStamp(refreshLabel);

  if (state.operatorLastRefreshState === "failed") {
    return {
      value: "refresh failed",
      state: "fail",
    };
  }

  return {
    value: refreshStamp || "awaiting refresh",
    state: "steady",
  };
}

function setOperatorWorkspaceCardMetaValue(node, value) {
  if (!(node instanceof HTMLElement)) {
    return;
  }
  const valueNode = node.querySelector(".operator-workspace-card-signal-meta-value");
  if (valueNode instanceof HTMLElement) {
    valueNode.textContent = value;
    return;
  }
  node.textContent = value;
}

function buildOperatorWorkspaceCardSignalSummary(sourceValue, freshnessValue) {
  const source = typeof sourceValue === "string" ? sourceValue.trim() : "";
  const freshness = typeof freshnessValue === "string" ? freshnessValue.trim() : "";
  if (source && freshness) {
    return `${source} · ${freshness}`;
  }
  return source || freshness || "Awaiting signal";
}

function buildOperatorWorkspaceCardCompactSignalSummary(sourceValue, freshnessValue) {
  const source = typeof sourceValue === "string" ? sourceValue.trim() : "";
  const freshness = typeof freshnessValue === "string" ? freshnessValue.trim() : "";
  if (source && freshness) {
    return `${source} | ${freshness}`;
  }
  return source || freshness || "Awaiting signal";
}

function buildOperatorWorkspaceCardJumpSummary(presentation) {
  const parts = [
    presentation?.routeFacts?.focus,
    presentation?.routeFacts?.modeLabel,
    presentation?.next,
  ]
    .filter((value) => typeof value === "string" && value.trim().length > 0)
    .map((value) => value.trim());
  return parts.length > 0 ? parts.join(" · ") : "Awaiting workspace summary";
}

function buildOperatorWorkspaceCardCompactMeta(presentation) {
  const workspaceLabel =
    typeof presentation?.routeFacts?.label === "string" && presentation.routeFacts.label.trim().length > 0
      ? presentation.routeFacts.label.trim().toLowerCase()
      : "workspace";
  // Legacy chooser copy tokens kept in-source for alignment tests:
  // Next: inspect
  // Next: review
  // Next: keep
  if (presentation?.hasManualRefresh !== true) {
    return `Refresh ${workspaceLabel} evidence.`;
  }
  if (presentation?.tone === "fail") {
    return `Inspect ${workspaceLabel} signal.`;
  }
  if (presentation?.tone === "neutral") {
    return `Review ${workspaceLabel} signal.`;
  }
  return `Keep ${workspaceLabel} steady.`;
}

function buildOperatorWorkspaceCardCompactHint(presentation) {
  const workspaceLabel =
    typeof presentation?.routeFacts?.label === "string" && presentation.routeFacts.label.trim().length > 0
      ? presentation.routeFacts.label.trim().toLowerCase()
      : "workspace";
  if (presentation?.hasManualRefresh !== true) {
    return `Jump here after refreshing ${workspaceLabel} evidence.`;
  }
  if (presentation?.tone === "fail") {
    return `Jump here to inspect ${workspaceLabel} attention.`;
  }
  if (presentation?.tone === "neutral") {
    return `Jump here to review ${workspaceLabel}.`;
  }
  return `Jump here when you need ${workspaceLabel} evidence.`;
}

function buildOperatorWorkspaceHeaderCompactSignalMeta(leadSignalSource, freshnessValue) {
  const sourceText =
    typeof leadSignalSource === "string" && leadSignalSource.trim().length > 0
      ? leadSignalSource.trim()
      : "Source: workspace";
  const freshnessText =
    typeof freshnessValue === "string" && freshnessValue.trim().length > 0
      ? freshnessValue.trim()
      : "Freshness: awaiting refresh";
  return `${sourceText} | ${freshnessText}`;
}

function readOperatorWorkspaceHeaderSignal(viewId, config) {
  if (viewId === "incidents") {
    const signals = getOperatorSummaryGuideSignals();
    return signals.find((item) => item.variant === "fail")
      ?? signals.find((item) => item.variant === "neutral")
      ?? signals.find((item) => item.variant === "ok")
      ?? null;
  }
  const statusId = typeof config?.targetStatusId === "string" ? config.targetStatusId.trim() : "";
  if (!statusId) {
    return null;
  }
  const node = document.getElementById(statusId);
  if (!(node instanceof HTMLElement)) {
    return null;
  }
  return {
    label: config.label,
    text: typeof node.textContent === "string" ? node.textContent.trim() : "",
    statusCode: getOperatorStatusCode(node),
    variant: readOperatorStatusVariant(node),
  };
}

function getOperatorWorkspacePresentationState(viewId = state.operatorSavedView) {
  const normalizedView = normalizeOperatorSavedView(viewId) || "incidents";
  const config = OPERATOR_SAVED_VIEWS[normalizedView] ?? OPERATOR_SAVED_VIEWS.incidents;
  const routeFacts = OPERATOR_WORKSPACE_ROUTE_FACTS[normalizedView] ?? OPERATOR_WORKSPACE_ROUTE_FACTS.incidents;
  const hasManualRefresh = state.operatorSummaryUserRefreshed === true;
  const signal = hasManualRefresh ? readOperatorWorkspaceHeaderSignal(normalizedView, config) : null;

  let tone = hasManualRefresh ? "ok" : "neutral";
  let title = config.hydrateTitle ?? `${routeFacts.label} workspace`;
  let hint = config.hydrateHint ?? config.hint;
  let next = "Refresh Summary";

  if (hasManualRefresh && signal?.variant === "fail") {
    tone = "fail";
    title = `${routeFacts.label} needs attention`;
    hint = `${signal.label}: ${signal.text || "Attention required"}. ${config.contextNote ?? config.hint}`;
    next = signal.label ? `Inspect ${signal.label}` : "Inspect highlighted signal";
  } else if (hasManualRefresh && signal?.variant === "neutral") {
    tone = "neutral";
    title = `${routeFacts.label} needs review`;
    hint = `${signal.label}: ${signal.text || "Review recommended"}. ${config.contextNote ?? config.hint}`;
    next = signal.label ? `Review ${signal.label}` : "Review highlighted signal";
  } else if (hasManualRefresh) {
    tone = normalizedView === "incidents" ? "neutral" : "ok";
    title = config.nominalTitle ?? `${routeFacts.label} workspace is active`;
    hint = config.nominalHint ?? config.contextNote ?? config.hint;
    next = routeFacts.nominalNext;
  }

  return {
    normalizedView,
    config,
    routeFacts,
    hasManualRefresh,
    signal,
    tone,
    title,
    hint,
    next,
  };
}

function syncOperatorWorkspaceCards() {
  const activeView = normalizeOperatorSavedView(state.operatorSavedView) || "incidents";
  const cardTargets = getOperatorWorkspaceCardTargets();
  const hasManualRefresh = state.operatorSummaryUserRefreshed === true;
  const markerViewId = activeView !== "incidents"
    ? activeView
    : hasManualRefresh
      ? "incidents"
      : "approvals";
  const markerVariant = activeView !== "incidents" || hasManualRefresh ? "current" : "recommended-next";
  const markerLabel = markerVariant === "current" ? "Current workspace" : "Recommended next";
  for (const [viewId, target] of Object.entries(cardTargets)) {
    if (!(target.button instanceof HTMLButtonElement)) {
      continue;
    }
    const presentation = getOperatorWorkspacePresentationState(viewId);
    const isActive = viewId === activeView;
    const leadSignalSource = resolveOperatorWorkspaceCardLeadSignalSourceValue(presentation);
    const freshness = resolveOperatorWorkspaceCardFreshnessValue();
    target.button.dataset.workspaceState = presentation.tone;
    target.button.dataset.workspaceActive = isActive ? "true" : "false";
    target.button.dataset.workspaceCurrent = isActive ? "true" : "false";
    const hintNode = target.button.querySelector(".operator-workspace-card-hint");
    if (hintNode instanceof HTMLElement) {
      hintNode.textContent = isActive ? presentation.hint : buildOperatorWorkspaceCardCompactHint(presentation);
      hintNode.dataset.hintDensity = isActive ? "full" : "compact";
    }
    if (target.status instanceof HTMLElement) {
      const cardLabel =
        isActive
          ? "Current"
          : !presentation.hasManualRefresh
            ? "Hydrate"
          : presentation.tone === "fail"
            ? "Attention"
            : presentation.tone === "neutral"
              ? "Review"
              : "Steady";
      setStatusPill(target.status, cardLabel, presentation.tone);
      target.status.dataset.statusCode = viewId;
    }
    if (target.meta instanceof HTMLElement) {
      target.meta.textContent =
        !presentation.hasManualRefresh
          ? isActive
            ? `Current workspace. Refresh once to hydrate ${presentation.routeFacts.label.toLowerCase()} evidence.`
            : buildOperatorWorkspaceCardCompactMeta(presentation)
          : isActive
            ? presentation.tone === "fail"
              ? `Current workspace. Inspect the flagged ${presentation.routeFacts.label.toLowerCase()} signal before switching lanes.`
              : presentation.tone === "neutral"
                ? `Current workspace. Review ${presentation.routeFacts.label.toLowerCase()} before reopening broader triage.`
                : `Current workspace. Stay here unless fresher proof is needed elsewhere.`
            : buildOperatorWorkspaceCardCompactMeta(presentation);
      target.meta.dataset.metaDensity = isActive ? "full" : "compact";
    }
    const workspaceSummary = buildOperatorWorkspaceCardJumpSummary(presentation);
    const focusSection =
      target.focusValue instanceof HTMLElement
        ? target.focusValue.closest(".operator-workspace-card-focus")
        : null;
    const focusLabel =
      focusSection instanceof HTMLElement
        ? focusSection.querySelector(".operator-workspace-card-focus-label")
        : null;
    const modeSection =
      target.modeValue instanceof HTMLElement
        ? target.modeValue.closest(".operator-workspace-card-mode")
        : null;
    const openSection =
      target.openValue instanceof HTMLElement
        ? target.openValue.closest(".operator-workspace-card-open")
        : null;
    const viewSection =
      target.viewValue instanceof HTMLElement
        ? target.viewValue.closest(".operator-workspace-card-view")
        : null;
    const viewLabel =
      viewSection instanceof HTMLElement
        ? viewSection.querySelector(".operator-workspace-card-view-label")
        : null;
    const nextSection =
      target.nextValue instanceof HTMLElement
        ? target.nextValue.closest(".operator-workspace-card-next")
        : null;
    target.button.dataset.workspaceSummaryDensity = isActive ? "full" : "compact";
    if (focusSection instanceof HTMLElement) {
      focusSection.dataset.summaryDensity = isActive ? "full" : "compact";
    }
    if (focusLabel instanceof HTMLElement) {
      focusLabel.textContent = isActive ? "Focus" : "Workspace";
    }
    if (target.focusValue instanceof HTMLElement) {
      target.focusValue.textContent = isActive ? presentation.routeFacts.focus : workspaceSummary;
    }
    if (openSection instanceof HTMLElement) {
      openSection.hidden = isActive;
      openSection.setAttribute("aria-hidden", isActive ? "true" : "false");
    }
    if (target.openValue instanceof HTMLElement) {
      target.openValue.textContent = resolveOperatorWorkspaceCardViewLabel(presentation);
    }
    if (modeSection instanceof HTMLElement) {
      modeSection.hidden = !isActive;
      modeSection.setAttribute("aria-hidden", isActive ? "false" : "true");
    }
    if (target.modeValue instanceof HTMLElement) {
      target.modeValue.textContent = presentation.routeFacts.modeLabel;
    }
    if (viewLabel instanceof HTMLElement) {
      viewLabel.textContent = "View";
    }
    if (viewSection instanceof HTMLElement) {
      viewSection.hidden = !isActive;
      viewSection.setAttribute("aria-hidden", isActive ? "false" : "true");
    }
    if (target.viewValue instanceof HTMLElement) {
      target.viewValue.textContent = resolveOperatorWorkspaceCardViewLabel(presentation);
    }
    if (nextSection instanceof HTMLElement) {
      nextSection.hidden = !isActive;
      nextSection.setAttribute("aria-hidden", isActive ? "false" : "true");
    }
    if (target.nextValue instanceof HTMLElement) {
      target.nextValue.textContent = presentation.next;
    }
    const leadSignal = resolveOperatorWorkspaceLeadSignalPresentation(presentation);
    if (target.signal instanceof HTMLElement) {
      target.signal.dataset.signalState = leadSignal.state;
      target.signal.dataset.freshnessState = freshness.state;
      target.signal.dataset.signalRole = isActive ? "current" : "jump";
      target.signal.dataset.signalDensity = isActive ? "full" : "compact";
    }
    if (target.signalValue instanceof HTMLElement) {
      target.signalValue.textContent = leadSignal.value;
    }
    if (target.signalSource instanceof HTMLElement) {
      setOperatorWorkspaceCardMetaValue(
        target.signalSource,
        isActive ? leadSignalSource : buildOperatorWorkspaceCardCompactSignalSummary(leadSignalSource, freshness.value),
      );
    }
    if (target.signalFreshness instanceof HTMLElement) {
      target.signalFreshness.dataset.freshnessState = freshness.state;
      target.signalFreshness.hidden = !isActive;
      target.signalFreshness.setAttribute("aria-hidden", isActive ? "false" : "true");
      setOperatorWorkspaceCardMetaValue(target.signalFreshness, freshness.value);
    }
    if (target.marker instanceof HTMLElement) {
      const shouldShowMarker = viewId === markerViewId;
      target.marker.hidden = !shouldShowMarker;
      if (shouldShowMarker) {
        target.marker.textContent = markerLabel;
        target.button.dataset.workspaceMarker = markerVariant;
      } else {
        target.marker.textContent = "";
        delete target.button.dataset.workspaceMarker;
      }
    }
  }
}

function syncOperatorWorkspaceHeader() {
  if (
    !(el.operatorWorkspaceHeader instanceof HTMLElement)
    || !(el.operatorWorkspaceHeaderBadge instanceof HTMLElement)
    || !(el.operatorWorkspaceHeaderTitle instanceof HTMLElement)
    || !(el.operatorWorkspaceHeaderHint instanceof HTMLElement)
    || !(el.operatorWorkspaceHeaderFocusValue instanceof HTMLElement)
    || !(el.operatorWorkspaceHeaderNextValue instanceof HTMLElement)
    || !(el.operatorWorkspaceHeaderModeValue instanceof HTMLElement)
    || !(el.operatorWorkspaceHeaderStatusValue instanceof HTMLElement)
    || !(el.operatorWorkspaceHeaderViewValue instanceof HTMLElement)
    || !(el.operatorWorkspaceHeaderLeadFact instanceof HTMLElement)
    || !(el.operatorWorkspaceHeaderLeadValue instanceof HTMLElement)
    || !(el.operatorWorkspaceHeaderLeadSource instanceof HTMLElement)
    || !(el.operatorWorkspaceHeaderLeadFreshness instanceof HTMLElement)
  ) {
    return;
  }

  const presentation = getOperatorWorkspacePresentationState();
  const { normalizedView, routeFacts, tone, title, hint, next } = presentation;
  const leadSignalValue = resolveOperatorWorkspaceLeadSignalPresentation(presentation);
  const leadSignal = leadSignalValue;
  const leadSignalSource = resolveOperatorWorkspaceLeadSignalSourcePresentation(presentation);
  const freshness = resolveOperatorWorkspaceFreshnessPresentation();
  const useCompactLeadSignalMeta = leadSignal.state === "dormant" || freshness.state === "dormant";
  const workspaceStatus = !presentation.hasManualRefresh
    ? "Hydrate"
    : tone === "fail"
      ? "Attention"
      : tone === "neutral"
        ? "Review"
        : "Steady";

  el.operatorWorkspaceHeader.dataset.workspace = normalizedView;
  el.operatorWorkspaceHeader.dataset.workspaceState = tone;
  el.operatorWorkspaceHeader.dataset.workspaceSignal = leadSignal.state;
  setStatusPill(el.operatorWorkspaceHeaderBadge, routeFacts.label, tone);
  el.operatorWorkspaceHeaderBadge.dataset.statusCode = normalizedView;
  el.operatorWorkspaceHeaderTitle.textContent = title;
  el.operatorWorkspaceHeaderHint.textContent = hint;
  el.operatorWorkspaceHeaderFocusValue.textContent = routeFacts.focus;
  el.operatorWorkspaceHeaderNextValue.textContent = next;
  el.operatorWorkspaceHeaderModeValue.textContent = routeFacts.modeLabel;
  el.operatorWorkspaceHeaderStatusValue.textContent = workspaceStatus;
  el.operatorWorkspaceHeaderViewValue.textContent = resolveOperatorWorkspaceCardViewLabel(presentation);
  el.operatorWorkspaceHeaderLeadFact.dataset.signalState = leadSignal.state;
  el.operatorWorkspaceHeaderLeadFact.dataset.freshnessState = freshness.state;
  el.operatorWorkspaceHeaderLeadFact.dataset.signalDensity = useCompactLeadSignalMeta ? "compact" : "full";
  el.operatorWorkspaceHeaderLeadValue.textContent = leadSignal.value;
  el.operatorWorkspaceHeaderLeadSource.textContent = useCompactLeadSignalMeta
    ? buildOperatorWorkspaceHeaderCompactSignalMeta(leadSignalSource, freshness.value)
    : leadSignalSource;
  el.operatorWorkspaceHeaderLeadFreshness.textContent = freshness.value;
  el.operatorWorkspaceHeaderLeadFreshness.hidden = useCompactLeadSignalMeta;
  el.operatorWorkspaceHeaderLeadFreshness.setAttribute("aria-hidden", useCompactLeadSignalMeta ? "true" : "false");
}

function syncOperatorToolbarWorkspaceMode() {
  const presentation = getOperatorWorkspacePresentationState();
  const workspaceFocus = presentation.normalizedView !== "incidents" ? presentation.normalizedView : "overview";
  if (el.operatorToolbar instanceof HTMLElement) {
    el.operatorToolbar.dataset.workspaceFocus = workspaceFocus;
  }
  if (el.operatorToolbarAdvancedControls instanceof HTMLDetailsElement) {
    el.operatorToolbarAdvancedControls.dataset.workspaceFocus = workspaceFocus;
    el.operatorToolbarAdvancedControls.open = workspaceFocus === "overview";
  }
  if (el.operatorToolbarAdvancedSummary instanceof HTMLElement) {
    el.operatorToolbarAdvancedSummary.setAttribute(
      "aria-label",
      workspaceFocus === "overview"
        ? "Advanced board controls are open for overview triage"
        : "Advanced board controls are available on demand while a focused workspace is active",
    );
  }
  if (el.operatorToolbarAdvancedTitle instanceof HTMLElement) {
    el.operatorToolbarAdvancedTitle.textContent =
      presentation.normalizedView === "incidents" ? "Advanced board controls" : `Advanced ${presentation.routeFacts.label.toLowerCase()} controls`;
  }
  if (el.operatorToolbarAdvancedHint instanceof HTMLElement) {
    el.operatorToolbarAdvancedHint.textContent =
      presentation.normalizedView === "incidents"
        ? "Board mode and filters for broader console triage."
        : !presentation.hasManualRefresh
          ? `Hydrate ${presentation.routeFacts.label.toLowerCase()} first, then open broader board controls only if you need cross-lane triage.`
          : presentation.tone === "fail"
            ? `Focused ${presentation.routeFacts.label.toLowerCase()} signals need attention. Open broader board controls only if you need wider triage.`
            : presentation.tone === "neutral"
              ? `Keep ${presentation.routeFacts.label.toLowerCase()} in review. Open broader board controls only if you need cross-lane comparison.`
              : `Keep ${presentation.routeFacts.label.toLowerCase()} focused. Open broader board controls only when you need broader proof.`;
  }
  if (el.operatorToolbarAdvancedPill instanceof HTMLElement) {
    el.operatorToolbarAdvancedPill.textContent =
      presentation.normalizedView === "incidents" ? "Board" : presentation.routeFacts.label;
  }
  if (el.operatorRefreshBtn instanceof HTMLButtonElement) {
    const refreshLabel =
      presentation.normalizedView === "incidents" ? "Refresh Overview" : `Refresh ${presentation.routeFacts.label}`;
    el.operatorRefreshBtn.textContent = refreshLabel;
    el.operatorRefreshBtn.setAttribute("aria-label", refreshLabel);
    el.operatorRefreshBtn.title = refreshLabel;
  }
  if (el.operatorToolbarRefreshMeta instanceof HTMLElement) {
    el.operatorToolbarRefreshMeta.textContent =
      !presentation.hasManualRefresh
        ? presentation.config.hydrateMeta ?? "Refresh once to load current workspace evidence."
        : presentation.tone === "fail"
          ? `Refresh after recovery or when new ${presentation.routeFacts.label.toLowerCase()} evidence lands.`
          : presentation.tone === "neutral"
            ? `Refresh again while ${presentation.routeFacts.label.toLowerCase()} still needs confirmation.`
            : `Refresh only when you need fresher ${presentation.routeFacts.label.toLowerCase()} proof.`;
  }
}

function syncOperatorSavedViewButtons() {
  const activeView = normalizeOperatorSavedView(state.operatorSavedView);
  const defaultHint = "Choose one saved view to jump the board into an incidents, runtime, approvals, or audit posture.";
  if (el.operatorSavedViewHint instanceof HTMLElement) {
    el.operatorSavedViewHint.textContent =
      activeView && activeView !== "incidents"
        ? `${OPERATOR_SAVED_VIEWS[activeView].label} workspace is active. Open Advanced board controls only if you need broader triage filters.`
        : activeView
          ? OPERATOR_SAVED_VIEWS[activeView].hint
          : defaultHint;
  }
  const savedViewButtons = document.querySelectorAll("[data-operator-saved-view]");
  for (const button of savedViewButtons) {
    if (!(button instanceof HTMLButtonElement)) {
      continue;
    }
    const viewId = normalizeOperatorSavedView(button.dataset.operatorSavedView);
    const isActive = activeView.length > 0 && viewId === activeView;
    button.classList.toggle("is-active", isActive);
    button.setAttribute("aria-pressed", isActive ? "true" : "false");
  }
  syncOperatorSavedViewContext();
  syncOperatorConsoleEntry();
  syncOperatorWorkspaceChooser();
  syncOperatorWorkspaceCards();
  syncOperatorWorkspaceHeader();
  syncOperatorToolbarWorkspaceMode();
}

function clearOperatorSavedView(options = {}) {
  state.operatorSavedView = "";
  state.operatorEvidenceDrawerView = "";
  state.operatorFocusedEvidencePinned = false;
  state.operatorFocusedGroupKey = "";
  const persist = options && options.persist === false ? false : true;
  if (persist) {
    try {
      window.localStorage?.removeItem(OPERATOR_SAVED_VIEW_STORAGE_KEY);
    } catch {
      /* no-op on storage failures */
    }
  }
  syncOperatorSavedViewButtons();
  syncOperatorSavedViewFocusState();
  renderOperatorLaneFocusRail();
}

function expandOperatorSavedViewGroups(expandGroups) {
  const groups = Array.isArray(expandGroups) ? expandGroups.filter((item) => typeof item === "string" && item.trim().length > 0) : [];
  const metas = syncOperatorGroupPriorities();
  if (metas.length === 0 || groups.length === 0) {
    syncOperatorCollapseActionButtons();
    return;
  }
  const expandKeys = new Set(groups.map((item) => item.trim()));
  for (const meta of metas) {
    setOperatorGroupCollapsed(meta.group, !expandKeys.has(meta.key));
  }
  syncOperatorCollapseActionButtons();
}

function scrollOperatorElementIntoView(elementId) {
  if (typeof elementId !== "string" || elementId.trim().length === 0) {
    return;
  }
  const node = document.getElementById(elementId.trim());
  if (node instanceof HTMLElement) {
    node.scrollIntoView({ behavior: "smooth", block: "start", inline: "nearest" });
  }
}

function flashOperatorStatusCard(statusId) {
  const normalizedStatusId = typeof statusId === "string" ? statusId.trim() : "";
  if (!normalizedStatusId) {
    return;
  }
  const card = getOperatorCardByStatusId(normalizedStatusId);
  if (!(card instanceof HTMLElement)) {
    return;
  }
  card.classList.remove("operator-health-card-flash");
  card.classList.add("operator-health-card-flash");
  setTimeout(() => {
    card.classList.remove("operator-health-card-flash");
  }, OPERATOR_SIGNAL_FLASH_MS);
}

function syncOperatorSavedViewFocusState() {
  const focusedNodes = document.querySelectorAll(".operator-saved-view-focus");
  for (const node of focusedNodes) {
    node.classList.remove("operator-saved-view-focus");
  }
  const activeView = normalizeOperatorSavedView(state.operatorSavedView);
  if (!activeView) {
    return;
  }
  const config = OPERATOR_SAVED_VIEWS[activeView];
  const targetId = typeof config.targetElementId === "string" ? config.targetElementId.trim() : "";
  if (!targetId) {
    return;
  }
  const targetNode = document.getElementById(targetId);
  if (targetNode instanceof HTMLElement) {
    targetNode.classList.add("operator-saved-view-focus");
  }
}

function renderOperatorLaneFocusRail() {
  if (!(el.operatorLaneFocusRail instanceof HTMLElement) || !(el.operatorLaneFocusRailList instanceof HTMLElement)) {
    return;
  }
  const collapsedGroups = getVisibleOperatorGroups().filter((group) => group.classList.contains("is-collapsed"));
  const shouldShow = collapsedGroups.length > 0 && state.operatorSummaryUserRefreshed === true;
  const shouldUseInlineMode = collapsedGroups.length === 1;
  el.operatorLaneFocusRail.classList.toggle("is-hidden", !shouldShow);
  el.operatorLaneFocusRail.classList.toggle("is-inline", shouldShow && shouldUseInlineMode);
  el.operatorLaneFocusRailList.replaceChildren();
  if (el.operatorLaneFocusRailHint instanceof HTMLElement) {
    el.operatorLaneFocusRailHint.textContent = shouldShow
      ? shouldUseInlineMode
        ? "One parked lane stays here as a quiet reopen chip."
        : "Collapsed lanes stay here as quiet reopen chips."
      : "Quiet reopen chips for collapsed lanes.";
  }
  if (!shouldShow) {
    return;
  }

  const fragment = document.createDocumentFragment();
  for (const group of collapsedGroups) {
    const key = group.getAttribute("data-operator-group") ?? "";
    if (!key) {
      continue;
    }
    const tone = group.dataset.operatorGroupFocusState ?? group.dataset.operatorGroupState ?? "muted";
    const title = getOperatorGroupLabel(group);
    const stateLabel = group.dataset.operatorGroupFocusLabel ?? "Lane";
    const focusValue = group.dataset.operatorGroupFocusValue ?? "Awaiting refresh";
    const scopeValue = group.dataset.operatorGroupScopeValue ?? "Awaiting signal";
    const button = document.createElement("button");
    button.type = "button";
    button.className = `operator-lane-focus-chip is-${tone}`;
    if (shouldUseInlineMode) {
      button.classList.add("is-inline");
    }
    if (state.operatorFocusedGroupKey === key) {
      button.classList.add("is-active");
      button.setAttribute("aria-pressed", "true");
    } else {
      button.setAttribute("aria-pressed", "false");
    }
    button.setAttribute("data-operator-group-focus", key);
    button.setAttribute("role", "listitem");
    button.setAttribute("aria-label", `${title}. ${stateLabel}. ${focusValue}. ${scopeValue}.`);

    const titleNode = document.createElement("span");
    titleNode.className = "operator-lane-focus-chip-title";
    titleNode.textContent = title;

    const metaNode = document.createElement("span");
    metaNode.className = "operator-lane-focus-chip-meta";
    metaNode.textContent = `${stateLabel} · ${focusValue}`;

    const scopeNode = document.createElement("span");
    scopeNode.className = "operator-lane-focus-chip-scope";
    scopeNode.textContent = scopeValue;

    button.append(titleNode, metaNode, scopeNode);
    button.addEventListener("click", () => {
      focusOperatorGroup(key);
    });
    fragment.append(button);
  }

  el.operatorLaneFocusRailList.append(fragment);
}

function focusOperatorGroup(groupKey, options = {}) {
  const normalizedKey = typeof groupKey === "string" ? groupKey.trim() : "";
  if (!normalizedKey) {
    return;
  }
  const group = getOperatorGroupByKey(normalizedKey);
  if (!(group instanceof HTMLElement)) {
    return;
  }
  const activeSavedView = getActiveOperatorSavedViewConfig();
  if (activeSavedView && activeSavedView.groupKey !== normalizedKey && options.clearSavedView !== false) {
    clearOperatorSavedView();
  }
  state.operatorFocusedGroupKey = normalizedKey;
  if (state.operatorIssuesOnly && group.classList.contains("operator-health-group-hidden")) {
    setOperatorIssuesOnlyMode(false);
  }
  setOperatorGroupCollapsed(group, false);
  syncOperatorCollapseActionButtons();

  const statusId = resolveOperatorGroupFocusStatusId(group);
  if (statusId) {
    state.operatorFocusedEvidenceStatusId = statusId;
    state.operatorFocusedEvidencePinned = true;
    state.operatorEvidenceDrawerView = "";
    syncOperatorEvidenceDrawer();
    flashOperatorStatusCard(statusId);
  }

  flashOperatorGroup(group);
  group.scrollIntoView({ behavior: "smooth", block: "start", inline: "nearest" });
  renderOperatorLaneFocusRail();
}

function focusOperatorSavedViewSurface(viewId) {
  const normalizedView = normalizeOperatorSavedView(viewId);
  if (!normalizedView) {
    return;
  }
  const config = OPERATOR_SAVED_VIEWS[normalizedView];
  if (normalizedView === "incidents") {
    state.operatorFocusedEvidencePinned = false;
    state.operatorFocusedEvidenceStatusId = resolveOperatorFocusedEvidenceStatusId();
    syncOperatorEvidenceDrawer();
  } else if (typeof config.targetStatusId === "string" && config.targetStatusId.trim().length > 0) {
    flashOperatorStatusCard(config.targetStatusId);
  }
  if (typeof config.targetElementId === "string" && config.targetElementId.trim().length > 0) {
    scrollOperatorElementIntoView(config.targetElementId);
    return;
  }
  if (typeof config.targetStatusId === "string" && config.targetStatusId.trim().length > 0) {
    jumpToOperatorStatusCard(config.targetStatusId);
    return;
  }
  scrollOperatorElementIntoView("operatorHealthBoard");
}

function setOperatorSavedView(viewId, options = {}) {
  const normalizedView = normalizeOperatorSavedView(viewId);
  if (!normalizedView) {
    clearOperatorSavedView(options);
    return;
  }
  const config = OPERATOR_SAVED_VIEWS[normalizedView];
  const persist = options && options.persist === false ? false : true;
  const shouldScroll = options && options.scroll === false ? false : true;
  state.operatorSavedView = normalizedView;
  state.operatorSignalStripExpanded = false;
  state.operatorFocusedGroupKey = "";
  state.operatorEvidenceDrawerView = "";
  state.operatorFocusedEvidencePinned = false;
  if (persist) {
    try {
      window.localStorage?.setItem(OPERATOR_SAVED_VIEW_STORAGE_KEY, normalizedView);
    } catch {
      /* no-op on storage failures */
    }
  }
  setOperatorBoardMode(config.mode, { syncPresets: false, persist: true });
  setOperatorIssuesOnlyMode(config.issuesOnly === true);
  setOperatorFocusCriticalMode(config.focusCritical === true);
  expandOperatorSavedViewGroups(config.expandGroups);
  if (normalizedView === "incidents") {
    state.operatorFocusedEvidenceStatusId = resolveOperatorFocusedEvidenceStatusId();
  } else if (typeof config.targetStatusId === "string") {
    state.operatorFocusedEvidenceStatusId = config.targetStatusId.trim();
  }
  syncOperatorSavedViewButtons();
  syncOperatorSavedViewFocusState();
  syncOperatorEvidenceDrawer();
  renderOperatorLaneFocusRail();
  if (shouldScroll) {
    focusOperatorSavedViewSurface(normalizedView);
  }
}

function focusOperatorConsoleEntry(targetId = "operatorConsoleEntry") {
  const preferredTarget =
    typeof targetId === "string" && targetId.trim().length > 0 ? document.getElementById(targetId.trim()) : null;
  const fallbackTarget = el.operatorConsoleEntry instanceof HTMLElement ? el.operatorConsoleEntry : el.operatorRefreshBtn;
  const focusTarget = preferredTarget instanceof HTMLElement ? preferredTarget : fallbackTarget;
  if (!(focusTarget instanceof HTMLElement)) {
    return;
  }
  if (focusTarget.id) {
    scrollOperatorElementIntoView(focusTarget.id);
  } else {
    scrollOperatorElementIntoView("operatorConsoleEntry");
  }
  scheduleDeferredFocus(() => {
    focusTarget.focus({ preventScroll: true });
  }, LIVE_CONTEXT_KEYBOARD_HANDOFF_DELAYS);
}

function openOperatorConsoleFromLive(options = {}) {
  const savedView = normalizeOperatorSavedView(options?.savedView ?? "");
  const focusId =
    typeof options?.focusId === "string" && options.focusId.trim().length > 0
      ? options.focusId.trim()
      : "operatorConsoleEntry";
  setActiveLiveContextPanel(null, { force: true });
  setActiveTab("operator");
  window.setTimeout(() => {
    if (savedView) {
      setOperatorSavedView(savedView);
      return;
    }
    scrollOperatorElementIntoView("operatorConsoleEntry");
  }, 0);
  focusOperatorConsoleEntry(focusId);
}

function syncOperatorSummaryGuide() {
  if (!(el.operatorSummaryGuide instanceof HTMLElement)) {
    return;
  }
  const activeSavedView = getActiveOperatorSavedViewConfig();
  const workspacePresentation = getOperatorWorkspacePresentationState(activeSavedView?.id);
  const isDemo = normalizeOperatorBoardMode(state.operatorBoardMode) === "demo";
  const hasManualRefresh = state.operatorSummaryUserRefreshed === true;
  const signals = getOperatorSummaryGuideSignals();
  const failSignals = signals.filter((item) => item.variant === "fail");
  const neutralSignals = signals.filter((item) => item.variant === "neutral");
  const okSignals = signals.filter((item) => item.variant === "ok");
  let nextVariant = "neutral";
  let nextStatusText = "waiting";
  let nextTitle = isDemo ? "Start with one refresh" : "Hydrate diagnostics first";
  let nextHint = isDemo
    ? "Refresh once, then follow the highlighted workspace instead of scanning the full board."
    : "Refresh once, then open only the workspace that still needs deeper diagnostics.";
  let nextMeta = "Next: hydrate the overview workspace.";
  let nextWatchItems = [];

  el.operatorSummaryGuide.classList.remove("is-hidden");
  el.operatorSummaryGuide.classList.toggle("is-full-ops", !isDemo);

  if (!hasManualRefresh && activeSavedView) {
    nextTitle = activeSavedView.hydrateTitle ?? nextTitle;
    nextHint = activeSavedView.hydrateHint ?? nextHint;
    nextMeta = activeSavedView.hydrateMeta ?? nextMeta;
    nextWatchItems = [];
  } else if (hasManualRefresh && failSignals.length > 0) {
    nextVariant = "fail";
    nextStatusText = failSignals.length > 1 ? `${failSignals.length} alerts` : "attention";
    nextTitle = failSignals.length > 1
      ? `${failSignals.length} critical lanes need attention`
      : `${failSignals[0].label} needs attention`;
    nextHint = `Risk is concentrated in ${formatOperatorSummaryGuideLabelList(failSignals, 2)}. Open that lane before any deeper diagnostics.`;
    nextMeta = `Next: open ${failSignals[0].label}.`;
    if (activeSavedView && activeSavedView.id !== "incidents") {
      nextMeta = `${nextMeta} ${activeSavedView.contextNote ?? ""}`.trim();
    }
    nextWatchItems = failSignals.concat(neutralSignals).slice(0, 4);
  } else if (hasManualRefresh && neutralSignals.length > 0) {
    nextVariant = state.operatorLastRefreshState === "failed" ? "fail" : "neutral";
    nextStatusText = state.operatorLastRefreshState === "failed" ? "refresh failed" : "watch";
    nextTitle = activeSavedView
      ? `${activeSavedView.label} posture still needs confirmation`
      : neutralSignals.length > 1
        ? `${neutralSignals.length} lanes still need confirmation`
        : `${neutralSignals[0].label} is still unverified`;
    nextHint = state.operatorLastRefreshState === "failed"
      ? `Summary refresh failed. Recheck ${formatOperatorSummaryGuideLabelList(neutralSignals, 2)} once the runtime lane is reachable.`
      : activeSavedView
        ? `${activeSavedView.contextNote ?? activeSavedView.hint} Refresh once more or run one targeted scenario if this posture still looks incomplete.`
        : `${formatOperatorSummaryGuideLabelList(neutralSignals, 2)} still need fresh evidence or one targeted run.`;
    nextMeta = state.operatorLastRefreshState === "failed"
      ? "Next: retry refresh or reseed the lane."
      : activeSavedView
        ? activeSavedView.hydrateMeta ?? "Next: refresh summary or run one targeted scenario."
        : "Next: refresh or run one targeted scenario.";
    nextWatchItems = neutralSignals.slice(0, 4);
  } else if (hasManualRefresh && okSignals.length > 0) {
    nextVariant = "ok";
    nextStatusText = "nominal";
    nextTitle = activeSavedView?.nominalTitle ?? "Critical lanes look nominal";
    nextHint = activeSavedView?.nominalHint ?? (isDemo
      ? "First-line operator signals are nominal. Open deeper runtime evidence only when you need it."
      : "Runtime, queue, and control-plane lanes are nominal. Open deeper drawers only for replay, overrides, or audit work.");
    nextMeta = activeSavedView?.nominalMeta ?? (isDemo
      ? "Next: switch to Full Ops View only if you need deeper diagnostics."
      : "Next: inspect deeper drawers only for replay or control-plane changes.");
    nextWatchItems = [];
  } else {
    nextWatchItems = [];
  }

  el.operatorSummaryGuide.dataset.operatorVariant = nextVariant;
  setStatusPill(
    el.operatorSummaryGuideStatus,
    nextStatusText,
    nextVariant === "ok" ? "ok" : nextVariant === "fail" ? "fail" : "neutral",
  );
  if (el.operatorSummaryGuideTitle) {
    el.operatorSummaryGuideTitle.textContent = nextTitle;
  }
  if (el.operatorSummaryGuideHint) {
    el.operatorSummaryGuideHint.textContent = nextHint;
  }
  if (el.operatorSummaryGuideMeta) {
    el.operatorSummaryGuideMeta.textContent = nextMeta;
  }
  syncOperatorConsoleEntry();
  syncOperatorSummaryGuidePreview(activeSavedView, workspacePresentation);
  syncOperatorSummaryGuidePath({
    activeSavedView,
    hasManualRefresh,
    refreshFailed: state.operatorLastRefreshState === "failed",
    failSignals,
    neutralSignals,
    okSignals,
  });
  renderOperatorSummaryGuideWatchlist(nextWatchItems, hasManualRefresh ? "No active watch items" : "Refresh summary first");
  syncOperatorWorkspaceCards();
  syncOperatorWorkspaceHeader();
  syncOperatorPriorityQueue();
  syncOperatorSupportPanels();
  syncOperatorSignalStripSurface();
  syncOperatorEvidenceDrawer();
}

function syncOperatorSupportPanels() {
  const isDemo = normalizeOperatorBoardMode(state.operatorBoardMode) === "demo";
  const hasManualRefresh = state.operatorSummaryUserRefreshed === true;
  const canAutoMinimize = isDemo && hasManualRefresh;
  const showSupportPanels = !canAutoMinimize || state.operatorSupportPanelsPinned === true;
  const showQuickStart = !canAutoMinimize || (state.operatorSupportPanelsPinned === true && shouldShowOperatorQuickStartAfterRefresh());

  if (el.operatorQuickStart instanceof HTMLDetailsElement) {
    el.operatorQuickStart.classList.toggle("is-minimized", !showQuickStart);
    if (!showQuickStart) {
      el.operatorQuickStart.open = false;
    }
  }

  // Support-panel parity tokens: operatorRuntimeDrills, el.operatorWorkflowControl] / operatorWorkflowControl]
  const supportPanels = [
    el.operatorAdvancedControlSurfaces,
    el.operatorLanePlaybook,
    el.operatorRuntimeDrills,
    el.operatorWorkflowControl,
    el.operatorBootstrapDoctorControl,
    el.operatorSessionOpsControl,
    el.operatorBrowserWorkerControl,
  ];
  for (const panel of supportPanels) {
    if (!(panel instanceof HTMLDetailsElement)) {
      continue;
    }
    panel.classList.toggle("is-minimized", !showSupportPanels);
    if (!showSupportPanels) {
      panel.open = false;
    }
  }

  if (!(el.operatorGuideToggleBtn instanceof HTMLButtonElement)) {
    return;
  }
  el.operatorGuideToggleBtn.hidden = !canAutoMinimize;
  if (!canAutoMinimize) {
    el.operatorGuideToggleBtn.classList.remove("is-active");
    el.operatorGuideToggleBtn.setAttribute("aria-pressed", "false");
    el.operatorGuideToggleBtn.textContent = "Show Setup Panels";
    return;
  }
  el.operatorGuideToggleBtn.classList.toggle("is-active", showSupportPanels);
  el.operatorGuideToggleBtn.setAttribute("aria-pressed", showSupportPanels ? "true" : "false");
  el.operatorGuideToggleBtn.textContent = showSupportPanels ? "Hide Setup Panels" : "Show Setup Panels";
}

function formatOperatorRefreshTime(value = new Date()) {
  const date = value instanceof Date ? value : new Date(value);
  if (!Number.isFinite(date.getTime())) {
    return "n/a";
  }
  return date.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit", hour12: false });
}

function setOperatorLastRefreshState(nextState, timestamp = new Date()) {
  if (!(el.operatorLastRefresh instanceof HTMLElement)) {
    return;
  }
  const resolved = nextState === "success" || nextState === "failed" ? nextState : "pending";
  state.operatorLastRefreshState = resolved;
  state.operatorSignalStripExpanded = false;
  el.operatorLastRefresh.dataset.refreshState = resolved;
  el.operatorLastRefresh.classList.toggle("is-pending", resolved === "pending");
  el.operatorLastRefresh.classList.toggle("is-ok", resolved === "success");
  el.operatorLastRefresh.classList.toggle("is-fail", resolved === "failed");

  if (resolved === "success") {
    el.operatorLastRefresh.textContent = `Last refresh: ${formatOperatorRefreshTime(timestamp)}`;
    renderDashboardWorkspace();
    syncOperatorSummaryGuide();
    syncOperatorSignalStripSurface();
    return;
  }
  if (resolved === "failed") {
    el.operatorLastRefresh.textContent = `Last refresh failed: ${formatOperatorRefreshTime(timestamp)}`;
    renderDashboardWorkspace();
    syncOperatorSummaryGuide();
    syncOperatorSignalStripSurface();
    return;
  }
  el.operatorLastRefresh.textContent = "Last refresh: waiting";
  renderDashboardWorkspace();
  syncOperatorSummaryGuide();
  syncOperatorSignalStripSurface();
}

function setOperatorBoardMode(mode, options = {}) {
  const nextMode = normalizeOperatorBoardMode(mode);
  const syncPresets = options && options.syncPresets === false ? false : true;
  const persist = options && options.persist === false ? false : true;
  state.operatorBoardMode = nextMode;
  state.operatorSignalStripExpanded = false;
  if (nextMode !== "demo") {
    state.operatorSupportPanelsPinned = true;
  } else if (state.operatorSummaryUserRefreshed !== true) {
    state.operatorSupportPanelsPinned = false;
  }
  if (persist) {
    try {
      window.localStorage?.setItem(OPERATOR_BOARD_MODE_STORAGE_KEY, nextMode);
    } catch {
      /* no-op on storage failures */
    }
  }
  syncOperatorBoardModeButtons();

  if (!syncPresets) {
    return;
  }

  setOperatorCardsCollapsed(false);
  setOperatorIssuesOnlyMode(false);
  setOperatorFocusCriticalMode(nextMode === "demo");

  if (nextMode === "demo") {
    applyOperatorDemoGroupPreset();
  } else {
    setAllOperatorGroupsCollapsed(false);
    syncOperatorCollapseActionButtons();
  }
  applyOperatorCardsVisibility();
}

function readOperatorStatusVariant(statusNode) {
  if (!(statusNode instanceof HTMLElement)) {
    return "neutral";
  }
  if (statusNode.classList.contains("status-fail")) {
    return "fail";
  }
  if (statusNode.classList.contains("status-ok")) {
    return "ok";
  }
  return "neutral";
}

function formatOperatorDemoSummaryKpi(fail, neutral, ok) {
  return `F ${fail} | N ${neutral} | O ${ok}`;
}

function formatOperatorDemoSummaryKpiMarkup(fail, neutral, ok) {
  return [
    `<span class="operator-demo-summary-kpi-token operator-demo-summary-kpi-fail">F ${fail}</span>`,
    `<span class="operator-demo-summary-kpi-token operator-demo-summary-kpi-neutral">N ${neutral}</span>`,
    `<span class="operator-demo-summary-kpi-token operator-demo-summary-kpi-ok">O ${ok}</span>`,
  ].join("");
}

function summarizeOperatorDemoSummaryNoteText(value) {
  const normalized = normalizeOperatorUiCopy(value);
  if (!normalized) {
    return "";
  }
  const firstSentenceMatch = normalized.match(/^[^.!?]+[.!?]?/u);
  const firstSentence = firstSentenceMatch && typeof firstSentenceMatch[0] === "string"
    ? firstSentenceMatch[0].trim()
    : normalized;
  if (firstSentence.length <= 90) {
    return firstSentence;
  }
  return `${firstSentence.slice(0, 87).trimEnd()}...`;
}

function buildOperatorDemoSummaryNote(statusNode) {
  if (!(statusNode instanceof HTMLElement)) {
    return "Awaiting signal. Refresh or run one targeted scenario.";
  }

  const statusCode = getOperatorStatusCode(statusNode);
  const normalizedStatusCode = typeof statusCode === "string" ? statusCode.trim().toLowerCase() : "";
  if (normalizedStatusCode === "summary_stale") {
    return "Stale. Refresh summary before trusting this lane.";
  }

  const sourceCard = statusNode.closest(".operator-health-card");
  const hintNode = sourceCard instanceof HTMLElement ? sourceCard.querySelector(".operator-health-hint") : null;
  const noteFromHint = summarizeOperatorDemoSummaryNoteText(hintNode && typeof hintNode.textContent === "string" ? hintNode.textContent : "");
  if (noteFromHint) {
    return noteFromHint;
  }

  const variant = readOperatorStatusVariant(statusNode);
  if (variant === "fail") {
    return "Action needed. Open this lane before deeper diagnostics.";
  }
  if (variant === "ok") {
    return "Stable. Keep compressed unless related work changes.";
  }
  if (!isOperatorUninitializedStatusText(statusCode)) {
    return "Watch. Confirm this lane before deeper diagnostics.";
  }
  return "Awaiting signal. Refresh or run one targeted scenario.";
}

function isOperatorDemoSummaryQuietStatus(statusNode) {
  if (!(statusNode instanceof HTMLElement)) {
    return false;
  }
  const statusCode = getOperatorStatusCode(statusNode);
  const normalizedStatusCode = typeof statusCode === "string" ? statusCode.trim().toLowerCase() : "";
  if (!normalizedStatusCode) {
    return false;
  }
  if (readOperatorStatusVariant(statusNode) === "fail") {
    return false;
  }
  return (
    normalizedStatusCode === "summary_stale"
    || normalizedStatusCode === "awaiting_refresh"
    || normalizedStatusCode === "no_data"
    || normalizedStatusCode === "summary_error"
    || normalizedStatusCode === "idle"
    || normalizedStatusCode.includes("state=unknown")
    || normalizedStatusCode.includes("no_approvals")
    || normalizedStatusCode.includes("no_nodes")
    || normalizedStatusCode.includes("idle total=0")
    || isOperatorUninitializedStatusText(statusCode)
  );
}

function resolveOperatorDemoSummaryPillText(statusCode, fallbackText) {
  const isRu = state.languageMode === "ru";
  const mirrorText = resolveOperatorSignalMirrorText(statusCode, fallbackText);
  const fullLabel = resolveStatusPillDisplayText(mirrorText);
  const normalizedStatus = typeof statusCode === "string" ? statusCode.trim().toLowerCase() : "";
  const normalizedLabel = typeof fullLabel === "string" ? fullLabel.trim().toLowerCase() : "";

  const blockingMatch = normalizedStatus.match(/^critical total=(\d+)\s+blocking=(\d+)$/u);
  if (blockingMatch) {
    return isRu ? `\u0431\u043b\u043e\u043a ${blockingMatch[2]}` : `blocking ${blockingMatch[2]}`;
  }
  if (normalizedLabel === "waiting for request") {
    return isRu ? "\u0436\u0434\u0451\u0442 \u0437\u0430\u043f\u0440\u043e\u0441" : "request wait";
  }
  if (normalizedLabel === "waiting for approval") {
    return isRu ? "\u0436\u0434\u0451\u0442 \u0430\u043f\u043f\u0440\u0443\u0432" : "approval wait";
  }
  if (normalizedLabel === "waiting for node") {
    return isRu ? "\u0436\u0434\u0451\u0442 \u0443\u0437\u0435\u043b" : "node wait";
  }
  if (normalizedLabel === "needs refresh") {
    return isRu ? "\u043e\u0431\u043d\u043e\u0432\u0438\u0442\u044c" : "refresh";
  }
  if (normalizedLabel === "queue empty") {
    return isRu ? "\u0442\u0438\u0445\u043e" : "quiet";
  }
  return fullLabel;
}

function resolveOperatorSignalStripPillText(statusCode, fallbackText) {
  const isRu = state.languageMode === "ru";
  const mirrorText = resolveOperatorSignalMirrorText(statusCode, fallbackText);
  const fullLabel = resolveStatusPillDisplayText(mirrorText);
  const normalizedStatus = typeof statusCode === "string" ? statusCode.trim().toLowerCase() : "";
  const normalizedLabel = typeof fullLabel === "string" ? fullLabel.trim().toLowerCase() : "";

  const blockingMatch = normalizedStatus.match(/^critical total=(\d+)\s+blocking=(\d+)$/u);
  if (blockingMatch) {
    return isRu ? `\u0431\u043b\u043e\u043a ${blockingMatch[2]}` : `blocking ${blockingMatch[2]}`;
  }
  if (normalizedLabel === "waiting for request") {
    return isRu ? "\u0436\u0434\u0451\u0442 \u0437\u0430\u043f\u0440\u043e\u0441" : "request wait";
  }
  if (normalizedLabel === "waiting for approval") {
    return isRu ? "\u0436\u0434\u0451\u0442 \u0430\u043f\u043f\u0440\u0443\u0432" : "approval wait";
  }
  if (normalizedLabel === "waiting for node") {
    return isRu ? "\u0436\u0434\u0451\u0442 \u0443\u0437\u0435\u043b" : "node wait";
  }
  if (normalizedLabel === "needs proof") {
    return isRu ? "\u043d\u0443\u0436\u043d\u043e \u0434\u043e\u043a." : "proof";
  }
  if (normalizedLabel === "override active") {
    return isRu ? "\u0435\u0441\u0442\u044c \u043e\u0432\u0435\u0440\u0440\u0430\u0439\u0434" : "override";
  }
  if (normalizedLabel === "needs refresh") {
    return isRu ? "\u043e\u0431\u043d\u043e\u0432\u0438\u0442\u044c" : "refresh";
  }
  if (normalizedLabel === "queue empty") {
    return isRu ? "\u0442\u0438\u0445\u043e" : "quiet";
  }
  return fullLabel;
}

function syncOperatorDemoSummaryDensity() {
  if (!(el.operatorDemoSummaryStrip instanceof HTMLElement)) {
    return;
  }
  const summaryCards = Array.from(el.operatorDemoSummaryStrip.querySelectorAll(".operator-demo-summary-card"));
  let quietCount = 0;
  for (const summaryCard of summaryCards) {
    const statusNode = summaryCard.querySelector(".status-pill");
    const isQuiet = isOperatorDemoSummaryQuietStatus(statusNode);
    summaryCard.classList.toggle("is-quiet", isQuiet);
    summaryCard.classList.toggle("is-hot", !isQuiet);
    if (isQuiet) {
      quietCount += 1;
    }
  }
  const allQuiet = summaryCards.length > 0 && quietCount === summaryCards.length;
  const hasQuiet = quietCount > 0;
  el.operatorDemoSummaryStrip.dataset.summaryDensity = allQuiet ? "quiet" : hasQuiet ? "mixed" : "standard";
}

function syncOperatorDemoSummaryNote(statusNode) {
  if (!(statusNode instanceof HTMLElement)) {
    return;
  }
  const noteId = OPERATOR_DEMO_SUMMARY_NOTE_IDS[statusNode.id];
  if (typeof noteId !== "string") {
    return;
  }
  const noteNode = el[noteId];
  if (!(noteNode instanceof HTMLElement)) {
    return;
  }
  noteNode.textContent = buildOperatorDemoSummaryNote(statusNode);
}

function animateOperatorDemoSummaryKpi(kpiNode) {
  if (!(kpiNode instanceof HTMLElement)) {
    return;
  }
  kpiNode.classList.remove("is-updated");
  // Force reflow so repeated summary updates can retrigger the pulse.
  void kpiNode.offsetWidth;
  kpiNode.classList.add("is-updated");
}

function syncOperatorDemoSummaryKpi(statusNode) {
  if (!(statusNode instanceof HTMLElement)) {
    return;
  }
  const kpiId = OPERATOR_DEMO_SUMMARY_KPI_IDS[statusNode.id];
  if (typeof kpiId !== "string") {
    return;
  }
  const kpiNode = el[kpiId];
  if (!(kpiNode instanceof HTMLElement)) {
    return;
  }

  const sourceCard = statusNode.closest(".operator-health-card");
  const sourceGroup = sourceCard instanceof HTMLElement ? sourceCard.closest(".operator-health-group") : null;

  let fail = 0;
  let neutral = 0;
  let ok = 0;

  if (sourceGroup instanceof HTMLElement) {
    const groupCards = Array.from(sourceGroup.querySelectorAll(".operator-health-card"));
    const visibleCards = groupCards.filter((card) => !card.classList.contains("operator-health-card-hidden"));
    for (const card of visibleCards) {
      const cardStatus = card.querySelector(".status-pill");
      const variant = readOperatorStatusVariant(cardStatus);
      if (variant === "fail") {
        fail += 1;
      } else if (variant === "ok") {
        ok += 1;
      } else {
        neutral += 1;
      }
    }
  } else {
    const variant = readOperatorStatusVariant(statusNode);
    if (variant === "fail") {
      fail = 1;
    } else if (variant === "ok") {
      ok = 1;
    } else {
      neutral = 1;
    }
  }

  const nextLabel = formatOperatorDemoSummaryKpi(fail, neutral, ok);
  const isAlreadyRendered = kpiNode.querySelector(".operator-demo-summary-kpi-token") !== null;
  if (kpiNode.dataset.kpiLabel === nextLabel && isAlreadyRendered) {
    return;
  }

  kpiNode.dataset.kpiLabel = nextLabel;
  kpiNode.setAttribute("aria-label", `Fail ${fail}, Neutral ${neutral}, Ok ${ok}`);
  kpiNode.title = nextLabel;
  kpiNode.innerHTML = formatOperatorDemoSummaryKpiMarkup(fail, neutral, ok);
  animateOperatorDemoSummaryKpi(kpiNode);
}

function refreshOperatorDemoSummaryKpis() {
  for (const sourceStatusId of Object.keys(OPERATOR_DEMO_SUMMARY_KPI_IDS)) {
    const statusNode = document.getElementById(sourceStatusId);
    if (statusNode instanceof HTMLElement) {
      syncOperatorDemoSummaryKpi(statusNode);
      syncOperatorDemoSummaryNote(statusNode);
    }
  }
  syncOperatorDemoSummaryDensity();
}

function refreshOperatorTriageSummary() {
  const cards = Array.from(document.querySelectorAll(".operator-health-card"));
  let visible = 0;
  let hidden = 0;
  let fail = 0;
  let neutral = 0;
  let ok = 0;

  for (const card of cards) {
    const group = card.closest(".operator-health-group");
    const isGroupHidden = group instanceof HTMLElement && group.classList.contains("operator-health-group-hidden");
    const isHidden = card.classList.contains("operator-health-card-hidden") || isGroupHidden;
    if (isHidden) {
      hidden += 1;
      continue;
    }

    visible += 1;
    const statusNode = card.querySelector(".status-pill");
    const variant = readOperatorStatusVariant(statusNode);
    if (variant === "fail") {
      fail += 1;
      continue;
    }
    if (variant === "ok") {
      ok += 1;
      continue;
    }
    neutral += 1;
  }

  setText(el.operatorTriageTotal, String(cards.length));
  setText(el.operatorTriageVisible, String(visible));
  setText(el.operatorTriageFail, String(fail));
  setText(el.operatorTriageNeutral, String(neutral));
  setText(el.operatorTriageOk, String(ok));
  setText(el.operatorTriageHidden, String(hidden));
  syncOperatorPriorityQueue();
}

function formatOperatorGroupPreviewLabels(items, maxItems = 2) {
  const labels = Array.isArray(items)
    ? items
        .slice(0, Math.max(1, maxItems))
        .map((item) => (item && typeof item.title === "string" ? item.title.trim() : ""))
        .filter((label) => label.length > 0)
    : [];
  if (labels.length === 0) {
    return "this lane";
  }
  if (labels.length === 1) {
    return labels[0];
  }
  if (labels.length === 2) {
    return `${labels[0]} and ${labels[1]}`;
  }
  return `${labels.slice(0, -1).join(", ")}, and ${labels.at(-1)}`;
}

function formatOperatorGroupMetricsMarkup(visible, fail, neutral, ok, hidden) {
  return [
    { label: "Visible", value: visible, tone: "visible" },
    { label: "Fail", value: fail, tone: "fail" },
    { label: "Neutral", value: neutral, tone: "neutral" },
    { label: "Ok", value: ok, tone: "ok" },
    { label: "Hidden", value: hidden, tone: "hidden" },
  ]
    .map(
      (item) =>
        `<span class="operator-group-metric-pill is-${item.tone}"><span class="operator-group-metric-pill-label">${item.label}</span><strong>${item.value}</strong></span>`,
    )
    .join("");
}

function getOperatorGroupSummaryConfig(groupKey) {
  if (typeof groupKey !== "string" || groupKey.trim().length === 0) {
    return [];
  }
  const items = OPERATOR_GROUP_SUMMARY_STRIPS[groupKey.trim()];
  return Array.isArray(items) ? items : [];
}

function resolveOperatorGroupSummaryState(statusNode) {
  const statusCode = getOperatorStatusCode(statusNode);
  const variant = readOperatorStatusVariant(statusNode);
  if (statusCode === "summary_error" || variant === "fail") {
    return "fail";
  }
  if (statusCode === "summary_stale") {
    return "watch";
  }
  if (isOperatorUninitializedStatusText(statusCode)) {
    return "dormant";
  }
  if (variant === "ok") {
    return "ok";
  }
  return "watch";
}

function formatOperatorGroupSummaryStatusValue(statusNode) {
  const statusCode = getOperatorStatusCode(statusNode);
  const variant = readOperatorStatusVariant(statusNode);
  const displayText = statusNode instanceof HTMLElement && typeof statusNode.textContent === "string"
    ? statusNode.textContent.replace(/\s+/g, " ").trim()
    : "";
  const normalizedDisplayText = displayText.toLowerCase();
  const compactMatchText = `${statusCode} ${normalizedDisplayText}`;
  if (statusCode === "summary_error") {
    return "Refresh failed";
  }
  if (statusCode === "summary_stale") {
    return "Stale";
  }
  if (isOperatorUninitializedStatusText(statusCode)) {
    return "Awaiting";
  }
  if (normalizedDisplayText.includes("queue empty")) {
    return "Queue empty";
  }
  if (normalizedDisplayText.includes("no approvals")) {
    return "No approvals";
  }
  if (normalizedDisplayText.includes("no nodes")) {
    return "No nodes";
  }
  if (compactMatchText.includes("no_evidence")) {
    return "No evidence";
  }
  if (compactMatchText.includes("workflow_ready")) {
    return "Ready";
  }
  if (compactMatchText.includes("validated")) {
    return "Validated";
  }
  if (compactMatchText.includes("healthy")) {
    return "Healthy";
  }
  if (compactMatchText.includes("partial")) {
    return "Partial";
  }
  if (compactMatchText.includes("degraded")) {
    return "Degraded";
  }
  if (compactMatchText.includes("blocked")) {
    return "Blocked";
  }
  if (compactMatchText.includes("draining")) {
    return "Draining";
  }
  if (compactMatchText.includes("idle")) {
    return "Idle";
  }
  if (compactMatchText.includes("ready")) {
    return "Ready";
  }
  if (displayText.length > 0 && displayText.length <= 18) {
    return displayText;
  }
  if (variant === "ok") {
    return "Nominal";
  }
  if (variant === "fail") {
    return "Action needed";
  }
  return "Watching";
}

function createOperatorGroupSummaryChip(item) {
  const chip = document.createElement("span");
  chip.className = `operator-health-group-summary-chip is-${item.state}`;
  chip.dataset.statusId = item.statusId;

  const label = document.createElement("span");
  label.className = "operator-health-group-summary-chip-label";
  label.textContent = item.label;

  const value = document.createElement("strong");
  value.className = "operator-health-group-summary-chip-value";
  value.textContent = item.value;

  chip.append(label, value);
  return chip;
}

function createOperatorGroupCollapsedPreviewPill(config) {
  const tone = typeof config?.tone === "string" && config.tone.trim().length > 0 ? config.tone.trim() : "muted";
  const labelText = typeof config?.label === "string" && config.label.trim().length > 0 ? config.label.trim() : "Lane";
  const valueText = typeof config?.value === "string" && config.value.trim().length > 0
    ? config.value.trim()
    : "Awaiting refresh";

  const pill = document.createElement("span");
  pill.className = `operator-health-group-collapsed-pill is-${tone}`;

  const label = document.createElement("span");
  label.className = "operator-health-group-collapsed-pill-label";
  label.textContent = labelText;

  const value = document.createElement("strong");
  value.className = "operator-health-group-collapsed-pill-value";
  value.textContent = valueText;

  pill.append(label, value);
  return pill;
}

function syncOperatorGroupCollapsedPreview(group, config) {
  if (!(group instanceof HTMLElement)) {
    return;
  }
  const previewNode = group.querySelector("[data-operator-group-collapsed-preview]");
  if (!(previewNode instanceof HTMLElement)) {
    return;
  }

  const fragment = document.createDocumentFragment();
  const items = Array.isArray(config?.items) ? config.items.filter(Boolean).slice(0, 3) : [];
  if (items.length === 0) {
    fragment.append(
      createOperatorGroupCollapsedPreviewPill({
        label: "Lane",
        value: "Awaiting refresh",
        tone: "muted",
      }),
    );
  } else {
    for (const item of items) {
      fragment.append(createOperatorGroupCollapsedPreviewPill(item));
    }
  }

  previewNode.replaceChildren(fragment);
}

function syncOperatorGroupSummaryStrip(group) {
  if (!(group instanceof HTMLElement)) {
    return;
  }
  const summaryStripNode = group.querySelector("[data-operator-group-summary-strip]");
  if (!(summaryStripNode instanceof HTMLElement)) {
    return;
  }
  const groupKey = group.getAttribute("data-operator-group") ?? "";
  const items = getOperatorGroupSummaryConfig(groupKey);
  const fragment = document.createDocumentFragment();

  if (items.length === 0) {
    fragment.append(
      createOperatorGroupSummaryChip({
        statusId: "",
        label: "Lane summary",
        value: "Awaiting refresh",
        state: "dormant",
      }),
    );
  } else {
    for (const item of items) {
      const statusNode = document.getElementById(item.statusId);
      fragment.append(
        createOperatorGroupSummaryChip({
          statusId: item.statusId,
          label: item.label,
          value: formatOperatorGroupSummaryStatusValue(statusNode),
          state: resolveOperatorGroupSummaryState(statusNode),
        }),
      );
    }
  }

  summaryStripNode.replaceChildren(fragment);
}

function refreshOperatorGroupMetrics() {
  const activeSavedView = getActiveOperatorSavedViewConfig();
  const groups = Array.from(document.querySelectorAll(".operator-health-group"));
  for (const group of groups) {
    const metricsNode = group.querySelector("[data-operator-group-metrics]");
    const previewNode = group.querySelector("[data-operator-group-preview]");
    if (!(metricsNode instanceof HTMLElement)) {
      continue;
    }
    syncOperatorGroupSummaryStrip(group);

    const cards = Array.from(group.querySelectorAll(".operator-health-card"));
    const isGroupHidden = group.classList.contains("operator-health-group-hidden");
    const activeCards = [];
    let visible = 0;
    let hidden = 0;
    let fail = 0;
    let neutral = 0;
    let ok = 0;

    for (const card of cards) {
      const isHidden = isGroupHidden || card.classList.contains("operator-health-card-hidden");
      if (isHidden) {
        hidden += 1;
        continue;
      }
      visible += 1;
      const statusNode = card.querySelector(".status-pill");
      const titleNode = card.querySelector("h3");
      const variant = readOperatorStatusVariant(statusNode);
      const statusCode = getOperatorStatusCode(statusNode);
      activeCards.push({
        title: titleNode && typeof titleNode.textContent === "string" ? titleNode.textContent.trim() : "lane card",
        variant,
        statusCode,
      });
      if (variant === "fail") {
        fail += 1;
        continue;
      }
      if (variant === "ok") {
        ok += 1;
        continue;
      }
      neutral += 1;
    }

    metricsNode.setAttribute("aria-label", `visible ${visible}, fail ${fail}, neutral ${neutral}, ok ${ok}, hidden ${hidden}`);
    metricsNode.innerHTML = formatOperatorGroupMetricsMarkup(visible, fail, neutral, ok, hidden);
    metricsNode.classList.toggle("is-has-fail", fail > 0);
    metricsNode.classList.toggle("is-all-ok", fail === 0 && neutral === 0 && ok > 0);

    if (!(previewNode instanceof HTMLElement)) {
      continue;
    }
    const groupKey = group.getAttribute("data-operator-group") ?? "";
    const isActiveSavedViewGroup = !!activeSavedView && activeSavedView.groupKey === groupKey;
    const failCards = activeCards.filter((card) => card.variant === "fail");
    const staleCards = activeCards.filter((card) => card.statusCode === "summary_stale");
    const watchCards = activeCards.filter(
      (card) =>
        card.variant === "neutral"
        && card.statusCode !== "summary_stale"
        && !isOperatorUninitializedStatusText(card.statusCode),
    );
    const neutralCards = watchCards;
    const dormantCards = activeCards.filter((card) => isOperatorUninitializedStatusText(card.statusCode));
    let previewText = "Preview updates after refresh.";
    let previewState = "neutral";
    if (failCards.length > 0) {
      previewText = `Act first: ${formatOperatorGroupPreviewLabels(failCards)}.`;
      previewState = "fail";
    } else if (staleCards.length > 0) {
      previewText = `Refresh first: ${formatOperatorGroupPreviewLabels(staleCards)}.`;
      previewState = "stale";
    } else if (neutralCards.length > 0) {
      previewText = `Check next: ${formatOperatorGroupPreviewLabels(neutralCards)}.`;
      previewState = "neutral";
    } else if (ok > 0) {
      previewText = `Steady: ${ok} visible ${ok === 1 ? "check" : "checks"}.`;
      previewState = "ok";
    } else if (isActiveSavedViewGroup && typeof activeSavedView.groupPreviewText === "string") {
      previewText = activeSavedView.groupPreviewText;
      previewState = "muted";
    } else if (hidden === cards.length && cards.length > 0) {
      previewText = "Hidden by current filters.";
      previewState = "muted";
    } else if (dormantCards.length > 0) {
      previewText = "Awaiting signal after the next refresh.";
      previewState = "muted";
    }
    previewNode.textContent = previewText;
    previewNode.classList.toggle("is-has-fail", previewState === "fail");
    previewNode.classList.toggle("is-stale", previewState === "stale");
    previewNode.classList.toggle("is-all-ok", previewState === "ok");
    previewNode.classList.toggle("is-muted", previewState === "muted");

    let collapsedStateTone = "muted";
    let collapsedStateLabel = "Dormant";
    let collapsedFocusTone = "muted";
    let collapsedFocusValue = "Awaiting refresh";

    if (failCards.length > 0) {
      collapsedStateTone = "fail";
      collapsedStateLabel = "Critical";
      collapsedFocusTone = "fail";
      collapsedFocusValue = formatOperatorGroupPreviewLabels(failCards, 1);
    } else if (staleCards.length > 0) {
      collapsedStateTone = "stale";
      collapsedStateLabel = "Stale";
      collapsedFocusTone = "stale";
      collapsedFocusValue = formatOperatorGroupPreviewLabels(staleCards, 1);
    } else if (watchCards.length > 0) {
      collapsedStateTone = "watch";
      collapsedStateLabel = "Watch";
      collapsedFocusTone = "watch";
      collapsedFocusValue = formatOperatorGroupPreviewLabels(watchCards, 1);
    } else if (ok > 0) {
      collapsedStateTone = "ok";
      collapsedStateLabel = "Steady";
      collapsedFocusTone = "ok";
      collapsedFocusValue = `${ok} ${ok === 1 ? "check" : "checks"} steady`;
    } else if (hidden === cards.length && cards.length > 0) {
      collapsedStateTone = "muted";
      collapsedStateLabel = "Filtered";
      collapsedFocusTone = "muted";
      collapsedFocusValue = "Hidden by filters";
    } else if (isActiveSavedViewGroup && typeof activeSavedView.contextLabel === "string") {
      collapsedStateTone = "muted";
      collapsedStateLabel = "Focused";
      collapsedFocusTone = "muted";
      collapsedFocusValue = activeSavedView.contextLabel;
    }

    const collapsedScopeValue = visible > 0
      ? `${visible} visible${hidden > 0 ? ` / ${hidden} hidden` : ""}`
      : hidden > 0
        ? `${hidden} hidden`
        : "Awaiting signal";
    group.dataset.operatorGroupFocusState = collapsedStateTone;
    group.dataset.operatorGroupFocusLabel = collapsedStateLabel;
    group.dataset.operatorGroupFocusValue = collapsedFocusValue;
    group.dataset.operatorGroupScopeValue = collapsedScopeValue;
    syncOperatorGroupCollapsedPreview(group, {
      items: [
        { label: "Status", value: collapsedStateLabel, tone: collapsedStateTone },
        { label: "Focus", value: collapsedFocusValue, tone: collapsedFocusTone },
        {
          label: "Coverage",
          value: collapsedScopeValue,
          tone: hidden > 0 ? "muted" : collapsedStateTone === "ok" ? "ok" : "muted",
        },
      ],
    });
  }
  syncOperatorGroupPriorities();
  renderOperatorLaneFocusRail();
}

function resetOperatorBoardView(options = {}) {
  const requestedMode = normalizeOperatorBoardMode(options.mode);
  const persistMode = options && options.persistMode === false ? false : true;
  setOperatorBoardMode(requestedMode, { syncPresets: false, persist: persistMode });
  setOperatorCardsCollapsed(false);
  setOperatorIssuesOnlyMode(false);
  setOperatorFocusCriticalMode(requestedMode === "demo");
  if (requestedMode === "demo") {
    applyOperatorDemoGroupPreset();
  } else {
    setAllOperatorGroupsCollapsed(false);
    syncOperatorCollapseActionButtons();
  }
  applyOperatorCardsVisibility();
}

function getOperatorCardByStatusId(statusId) {
  if (typeof statusId !== "string" || statusId.trim().length === 0) {
    return null;
  }
  const statusNode = document.getElementById(statusId.trim());
  if (!(statusNode instanceof HTMLElement)) {
    return null;
  }
  const card = statusNode.closest(".operator-health-card");
  return card instanceof HTMLElement ? card : null;
}

function getOperatorStatusIdFromCard(card) {
  if (!(card instanceof HTMLElement)) {
    return "";
  }
  const statusNode = card.querySelector(".status-pill[id]");
  return statusNode instanceof HTMLElement && typeof statusNode.id === "string" ? statusNode.id.trim() : "";
}

function isOperatorDesktopCompactionViewport() {
  return typeof window !== "undefined"
    && typeof window.matchMedia === "function"
    && window.matchMedia("(min-width: 921px)").matches;
}

function resolveOperatorCompactCardTitle(card, fallbackTitle = "") {
  const statusId = getOperatorStatusIdFromCard(card);
  if (statusId && Object.prototype.hasOwnProperty.call(OPERATOR_COMPACT_CARD_TITLES, statusId)) {
    return OPERATOR_COMPACT_CARD_TITLES[statusId] || fallbackTitle;
  }
  const normalizedFallbackTitle = typeof fallbackTitle === "string" ? fallbackTitle.replace(/\s+/g, " ").trim() : "";
  if (
    normalizedFallbackTitle
    && Object.prototype.hasOwnProperty.call(OPERATOR_COMPACT_CARD_TITLES_BY_TITLE, normalizedFallbackTitle)
  ) {
    return OPERATOR_COMPACT_CARD_TITLES_BY_TITLE[normalizedFallbackTitle] || fallbackTitle;
  }
  return fallbackTitle;
}

function shouldUseOperatorCompactCardTitle(card) {
  if (!(card instanceof HTMLElement)) {
    return false;
  }
  const group = card.closest(".operator-health-group");
  return Boolean(
    normalizeOperatorBoardMode(state.operatorBoardMode) === "demo"
      && isOperatorDesktopCompactionViewport()
      && !card.classList.contains("operator-health-card-hidden")
      && (card.classList.contains("operator-health-card-lead") || card.classList.contains("operator-health-card-supporting"))
      && group instanceof HTMLElement
      && !group.classList.contains("is-collapsed")
      && !group.classList.contains("operator-health-group-hidden"),
  );
}

function syncOperatorCardPresentationTitle(card) {
  if (!(card instanceof HTMLElement)) {
    return;
  }
  const titleNode = card.querySelector("h3");
  if (!(titleNode instanceof HTMLElement)) {
    return;
  }
  const currentTitle = typeof titleNode.textContent === "string" ? titleNode.textContent.replace(/\s+/g, " ").trim() : "";
  const originalTitle = card.dataset.operatorCardOriginalTitle || currentTitle;
  if (!card.dataset.operatorCardOriginalTitle && originalTitle) {
    card.dataset.operatorCardOriginalTitle = originalTitle;
  }
  if (!originalTitle) {
    return;
  }
  const compactTitle = resolveOperatorCompactCardTitle(card, originalTitle);
  const shouldUseCompactTitle = shouldUseOperatorCompactCardTitle(card) && compactTitle !== originalTitle;
  titleNode.textContent = shouldUseCompactTitle ? compactTitle : originalTitle;
  titleNode.classList.toggle("is-compact-title", shouldUseCompactTitle);
  titleNode.title = originalTitle;
  if (shouldUseCompactTitle) {
    titleNode.setAttribute("aria-label", originalTitle);
  } else {
    titleNode.removeAttribute("aria-label");
  }
}

function syncOperatorBoardCardPresentationTitles() {
  const cards = document.querySelectorAll(".operator-health-card");
  for (const card of cards) {
    syncOperatorCardPresentationTitle(card);
  }
}

function focusOperatorStatusCard(statusId, options = {}) {
  const normalizedStatusId = typeof statusId === "string" ? statusId.trim() : "";
  if (!normalizedStatusId) {
    return;
  }
  if (state.operatorIssuesOnly) {
    setOperatorIssuesOnlyMode(false);
  }
  const card = getOperatorCardByStatusId(normalizedStatusId);
  state.operatorFocusedEvidenceStatusId = normalizedStatusId;
  state.operatorFocusedEvidencePinned = options.pin !== false;
  state.operatorEvidenceDrawerView = "";
  if (!(card instanceof HTMLElement)) {
    syncOperatorEvidenceDrawer();
    return;
  }
  const group = card.closest(".operator-health-group");
  if (group instanceof HTMLElement) {
    state.operatorFocusedGroupKey = group.getAttribute("data-operator-group") ?? "";
    setOperatorGroupCollapsed(group, false);
    syncOperatorCollapseActionButtons();
  }
  syncOperatorEvidenceDrawer();
  if (options.flash !== false) {
    card.classList.remove("operator-health-card-flash");
    card.classList.add("operator-health-card-flash");
    setTimeout(() => {
      card.classList.remove("operator-health-card-flash");
    }, OPERATOR_SIGNAL_FLASH_MS);
  }
  if (options.scroll !== false) {
    card.scrollIntoView({ behavior: "smooth", block: "center", inline: "nearest" });
  }
  if (options.focusCard === true) {
    card.focus({ preventScroll: true });
  }
}

function jumpToOperatorStatusCard(statusId) {
  focusOperatorStatusCard(statusId, {
    flash: true,
    scroll: true,
  });
}

function openOperatorSupportPanel(panel, focusTarget = null) {
  if (!(panel instanceof HTMLDetailsElement)) {
    return;
  }
  if (normalizeOperatorBoardMode(state.operatorBoardMode) === "demo" && state.operatorSupportPanelsPinned !== true) {
    state.operatorSupportPanelsPinned = true;
    syncOperatorSupportPanels();
  }
  const parentControlSurfaces = panel.closest(".operator-control-surfaces-body")?.parentElement;
  if (parentControlSurfaces instanceof HTMLDetailsElement) {
    parentControlSurfaces.open = true;
  }
  panel.open = true;
  panel.scrollIntoView({ behavior: "smooth", block: "center", inline: "nearest" });
  if (focusTarget instanceof HTMLElement && typeof window !== "undefined") {
    window.requestAnimationFrame(() => {
      focusTarget.focus();
    });
  }
}

function isOperatorPlaceholderStatusText(value) {
  if (typeof value !== "string") {
    return false;
  }
  const normalized = value.trim().toLowerCase();
  return normalized === "no_data" || normalized === "summary_error";
}

function getOperatorStatusCode(statusNode) {
  if (!(statusNode instanceof HTMLElement)) {
    return "";
  }
  const raw = typeof statusNode.dataset.statusCode === "string" && statusNode.dataset.statusCode.trim().length > 0
    ? statusNode.dataset.statusCode
    : statusNode.textContent ?? "";
  return typeof raw === "string" ? raw.trim().toLowerCase() : "";
}

function isOperatorUninitializedStatusText(value) {
  if (typeof value !== "string") {
    return false;
  }
  const normalized = value.trim().toLowerCase();
  return (
    normalized === "no_data" ||
    normalized === "summary_error" ||
    normalized === "awaiting_refresh" ||
    normalized === "refresh_failed" ||
    normalized === "unknown" ||
    normalized === "pending" ||
    normalized === "n/a" ||
    normalized === "-"
  );
}

function shouldHideOperatorDemoNeutralCard(card, statusNode) {
  if (!(card instanceof HTMLElement) || !(statusNode instanceof HTMLElement)) {
    return false;
  }
  if (normalizeOperatorBoardMode(state.operatorBoardMode) !== "demo") {
    return false;
  }
  if (!statusNode.classList.contains("status-neutral")) {
    return false;
  }
  if (!isOperatorUninitializedStatusText(getOperatorStatusCode(statusNode))) {
    return false;
  }
  if (state.operatorFocusCriticalOnly === true) {
    return true;
  }
  return !isOperatorDemoEssentialCard(card);
}

function shouldCondenseOperatorDemoNeutralCard(card, statusNode) {
  if (!(card instanceof HTMLElement) || !(statusNode instanceof HTMLElement)) {
    return false;
  }
  if (normalizeOperatorBoardMode(state.operatorBoardMode) !== "demo") {
    return false;
  }
  if (!statusNode.classList.contains("status-neutral")) {
    return false;
  }
  return isOperatorUninitializedStatusText(getOperatorStatusCode(statusNode));
}

function runOperatorEmptyStateAction(actionId) {
  if (actionId === "refresh_summary") {
    void refreshOperatorSummary({ markUserRefresh: true });
    return;
  }
  switch (actionId) {
    case "run_negotiation":
      applyIntentTemplateFromActiveTasks("negotiation", ACTIVE_TASK_NEGOTIATION_PROMPT);
      return;
    case "run_story":
      applyIntentTemplateFromActiveTasks("story", STORY_EMPTY_STATE_PROMPT);
      return;
    case "run_ui_task":
      applyIntentTemplateFromActiveTasks("ui_task", ACTIVE_TASK_UI_TASK_PROMPT);
      return;
    case "open_device_nodes":
      openDeviceNodesFromOperatorQuickStart();
      return;
    default:
      return;
  }
}

function ensureOperatorCardEmptyActions(card, statusNode) {
  if (!(card instanceof HTMLElement) || !(statusNode instanceof HTMLElement)) {
    return;
  }
  const cardStatusId = typeof statusNode.id === "string" ? statusNode.id : "";
  const actionConfig = OPERATOR_EMPTY_STATE_ACTIONS[cardStatusId];
  const hintCopy = OPERATOR_EMPTY_STATE_COPY[cardStatusId];
  const shouldShowActions = shouldCondenseOperatorDemoNeutralCard(card, statusNode) && Boolean(actionConfig);
  let actionRow = card.querySelector(".operator-health-empty-actions");
  if (!shouldShowActions) {
    card.classList.remove("operator-health-card-empty");
    if (actionRow instanceof HTMLElement) {
      actionRow.remove();
    }
    return;
  }

  card.classList.add("operator-health-card-empty");
  if (!(actionRow instanceof HTMLElement)) {
    actionRow = document.createElement("div");
    actionRow.className = "operator-health-empty-actions";

    const cue = document.createElement("span");
    cue.className = "operator-health-empty-cue";
    cue.textContent = "Awaiting signal";

    const primaryButton = document.createElement("button");
    primaryButton.type = "button";
    primaryButton.className = "button-muted operator-health-empty-action operator-health-empty-action-primary";
    primaryButton.dataset.emptyActionRole = "primary";
    primaryButton.addEventListener("click", () => {
      const actionId = primaryButton.dataset.emptyActionId;
      if (typeof actionId === "string" && actionId.length > 0) {
        runOperatorEmptyStateAction(actionId);
      }
    });

    const refreshButton = document.createElement("button");
    refreshButton.type = "button";
    refreshButton.className = "button-muted operator-health-empty-action operator-health-empty-action-refresh";
    refreshButton.textContent = "Refresh Summary";
    refreshButton.addEventListener("click", () => {
      runOperatorEmptyStateAction("refresh_summary");
    });

    const copy = document.createElement("p");
    copy.className = "operator-health-empty-copy";
    copy.dataset.emptyActionRole = "copy";

    actionRow.append(cue, copy, primaryButton, refreshButton);
    card.append(actionRow);
  }

  const primaryButton = actionRow.querySelector("[data-empty-action-role='primary']");
  if (primaryButton instanceof HTMLButtonElement && actionConfig) {
    primaryButton.dataset.emptyActionId = actionConfig.action;
    primaryButton.textContent = actionConfig.label;
  }

  const copyNode = actionRow.querySelector("[data-empty-action-role='copy']");
  if (copyNode instanceof HTMLElement) {
    copyNode.textContent =
      typeof hintCopy === "string" && hintCopy.trim().length > 0
        ? hintCopy
        : "Run one recovery action, then refresh summary to hydrate this lane.";
  }
}

function resolveStatusPillDisplayText(value) {
  if (typeof value !== "string") {
    return value;
  }
  const isRu = state.languageMode === "ru";
  const normalized = value.trim().toLowerCase();
  const exactOperatorMap = isRu
    ? {
        pending: "\u043e\u0436\u0438\u0434\u0430\u0435\u0442",
        review: "\u043f\u0440\u043e\u0432\u0435\u0440\u043a\u0430",
        timeouts: "\u0442\u0430\u0439\u043c\u0430\u0443\u0442\u044b",
        critical: "\u043a\u0440\u0438\u0442\u0438\u0447\u043d\u043e",
        degraded: "\u0440\u0438\u0441\u043a",
        elevated: "\u043f\u043e\u0432\u044b\u0448\u0435\u043d\u043e",
        stable: "\u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e",
        covered: "\u043f\u043e\u043a\u0440\u044b\u0442\u043e",
        warnings: "\u043f\u0440\u0435\u0434\u0443\u043f\u0440\u0435\u0436\u0434\u0435\u043d\u0438\u044f",
        unhealthy: "\u0441\u0431\u043e\u0439",
        coverage_incomplete: "\u043e\u0445\u0432\u0430\u0442 \u043d\u0435\u043f\u043e\u043b\u043d\u044b\u0439",
        assistive_missing_key: "assistive \u0431\u0435\u0437 \u043a\u043b\u044e\u0447\u0430",
        override_active: "override \u0430\u043a\u0442\u0438\u0432\u0435\u043d",
        last_known_good: "\u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u0439 \u0432\u0430\u043b\u0438\u0434\u043d\u044b\u0439",
        workflow_error: "\u043e\u0448\u0438\u0431\u043a\u0430 workflow",
        offline_nodes: "\u0443\u0437\u043b\u044b \u043e\u0444\u043b\u0430\u0439\u043d",
        no_runs: "\u043d\u0435\u0442 \u0437\u0430\u043f\u0443\u0441\u043a\u043e\u0432",
        no_events: "\u043d\u0435\u0442 \u0441\u043e\u0431\u044b\u0442\u0438\u0439",
        error_heavy: "\u043c\u043d\u043e\u0433\u043e \u043e\u0448\u0438\u0431\u043e\u043a",
        draining_active: "\u0434\u0440\u0435\u0439\u043d \u0430\u043a\u0442\u0438\u0432\u0435\u043d",
        unknown_state: "\u0441\u0442\u0430\u0442\u0443\u0441 \u043d\u0435\u044f\u0441\u0435\u043d",
      }
    : {
        pending: "pending",
        review: "review",
        timeouts: "timeouts",
        critical: "critical",
        degraded: "watch",
        elevated: "elevated",
        stable: "stable",
        covered: "covered",
        warnings: "warnings",
        unhealthy: "unhealthy",
        coverage_incomplete: "needs proof",
        assistive_missing_key: "assistive key missing",
        override_active: "override active",
        last_known_good: "last known good",
        workflow_error: "workflow error",
        offline_nodes: "offline nodes",
        no_runs: "no runs",
        no_events: "no events",
        error_heavy: "error-heavy",
        draining_active: "draining",
        unknown_state: "unknown state",
      };
  const localizedMap = isRu
    ? {
        disconnected: "не подключено",
        connected: "подключено",
        offline: "не в сети",
        online: "в сети",
        translation: "перевод",
        conversation: "диалог",
        negotiation: "переговоры",
        research: "поиск ответа",
        story: "история",
        ui_task: "UI-задача",
        voice: "голос",
        "text-fallback": "текст",
        idle: "ожидание",
        "ptt=off": "выкл",
        "ptt=on": "вкл",
      }
    : {
        disconnected: "offline",
        connected: "connected",
        offline: "offline",
        online: "online",
        translation: "translation",
        conversation: "conversation",
        negotiation: "negotiation",
        research: "research",
        story: "story",
        ui_task: "UI task",
        voice: "voice",
        "text-fallback": "text",
        idle: "idle",
        "ptt=off": "off",
        "ptt=on": "on",
      };
  if (localizedMap[normalized]) {
    return localizedMap[normalized];
  }
  if (exactOperatorMap[normalized]) {
    return exactOperatorMap[normalized];
  }
  if (normalized === "no_data") {
    return isRu ? "нужно обновить" : "needs refresh";
  }
  if (normalized === "summary_error") {
    return isRu ? "ошибка обновления" : "refresh failed";
  }
  if (normalized === "summary_stale") {
    return isRu ? "\u0443\u0441\u0442\u0430\u0440\u0435\u043b\u043e" : "stale";
  }
  if (normalized === "unknown" || normalized === "n/a" || normalized === "-") {
    return isRu ? "ждёт запрос" : "waiting for request";
  }
  if (normalized.includes("state=unknown")) {
    return isRu ? "ждёт запрос" : "waiting for request";
  }
  if (normalized.includes("no_approvals")) {
    return isRu ? "нет согласований" : "no approvals";
  }
  if (normalized.includes("no_nodes")) {
    return isRu ? "нет узлов" : "no nodes";
  }
  if (normalized.includes("no_evidence")) {
    return isRu ? "нет данных" : "no evidence";
  }
  if (normalized.includes("idle total=0")) {
    return isRu ? "очередь пуста" : "queue empty";
  }
  if (normalized.includes("awaiting_signal")) {
    return isRu ? "ждёт запрос" : "waiting for request";
  }
  if (normalized.includes("awaiting_refresh")) {
    return isRu ? "ждёт обновление" : "needs refresh";
  }
  if (normalized.includes("awaiting_approvals")) {
    return isRu ? "ждёт согласование" : "waiting for approval";
  }
  if (normalized.includes("awaiting_nodes")) {
    return isRu ? "ждёт узел" : "waiting for node";
  }
  if (normalized.includes("idle_queue=0")) {
    return isRu ? "очередь пуста" : "queue empty";
  }
  if (normalized.includes("workflow_ready")) {
    return isRu ? "готово" : "ready";
  }
  if (normalized.includes("validated")) {
    return isRu ? "проверено" : "validated";
  }
  if (normalized.includes("healthy")) {
    return isRu ? "норма" : "healthy";
  }
  if (normalized.includes("partial")) {
    return isRu ? "частично" : "partial";
  }
  const criticalSignalsMatch = normalized.match(/^critical signals=(\d+)$/);
  if (criticalSignalsMatch) {
    return isRu ? `\u043a\u0440\u0438\u0442\u0438\u0447\u043d\u043e x${criticalSignalsMatch[1]}` : `critical x${criticalSignalsMatch[1]}`;
  }
  const degradedSignalsMatch = normalized.match(/^degraded signals=(\d+)$/);
  if (degradedSignalsMatch) {
    return isRu ? `\u0440\u0438\u0441\u043a x${degradedSignalsMatch[1]}` : `watch x${degradedSignalsMatch[1]}`;
  }
  const healthySignalsMatch = normalized.match(/^healthy signals=(\d+)$/);
  if (healthySignalsMatch) {
    return isRu ? "\u043d\u043e\u0440\u043c\u0430" : "healthy";
  }
  const storyStatusText = formatStoryTimelineStatusText(value, isRu);
  if (storyStatusText !== value) {
    return storyStatusText;
  }
  return value;
}

function isOperatorDemoEssentialCard(card) {
  return card instanceof HTMLElement && card.hasAttribute("data-operator-demo-essential");
}

function clearOperatorGroupCardHierarchy(card) {
  if (!(card instanceof HTMLElement)) {
    return;
  }
  clearOperatorLeadCardSummary(card);
  card.classList.remove("operator-health-card-lead");
  card.classList.remove("operator-health-card-supporting");
  card.classList.remove("operator-health-card-selectable");
  card.classList.remove("is-evidence-active");
  card.removeAttribute("data-operator-card-status-id");
  card.removeAttribute("tabindex");
  card.removeAttribute("role");
  card.removeAttribute("aria-pressed");
  const note = card.querySelector("[data-operator-card-drilldown-note]");
  if (note instanceof HTMLElement) {
    note.hidden = true;
  }
}

function resolveOperatorCardHierarchyScore(card) {
  if (!(card instanceof HTMLElement)) {
    return Number.NEGATIVE_INFINITY;
  }
  const statusNode = card.querySelector(".status-pill");
  const variant = readOperatorStatusVariant(statusNode);
  const statusCode = statusNode instanceof HTMLElement
    ? (statusNode.dataset.statusCode ?? statusNode.textContent ?? "").trim().toLowerCase()
    : "";
  let score = 0;
  if (variant === "fail") {
    score += 40;
  } else if (statusCode === "summary_stale") {
    score += 30;
  } else if (variant === "neutral" && !isOperatorUninitializedStatusText(statusCode)) {
    score += 22;
  } else if (variant === "ok") {
    score += 8;
  } else {
    score += 4;
  }
  if (isOperatorCriticalCard(card)) {
    score += 18;
  }
  if (isOperatorDemoEssentialCard(card)) {
    score += 10;
  }
  if (statusCode.includes("blocking") || statusCode.includes("degraded")) {
    score += 4;
  }
  return score;
}

function resolveOperatorGroupLeadCard(group, visibleCards) {
  if (!(group instanceof HTMLElement) || !Array.isArray(visibleCards) || visibleCards.length === 0) {
    return null;
  }
  const focusedCard = getOperatorCardByStatusId(state.operatorFocusedEvidenceStatusId);
  if (focusedCard instanceof HTMLElement && visibleCards.includes(focusedCard) && focusedCard.closest(".operator-health-group") === group) {
    return focusedCard;
  }
  const criticalVisibleCards = visibleCards.filter((card) => isOperatorCriticalCard(card));
  const candidates = criticalVisibleCards.length > 0 ? criticalVisibleCards : visibleCards;
  return candidates
    .slice()
    .sort((left, right) => resolveOperatorCardHierarchyScore(right) - resolveOperatorCardHierarchyScore(left))[0] ?? null;
}

function ensureOperatorCardDrilldownNote(card) {
  if (!(card instanceof HTMLElement)) {
    return null;
  }
  const existing = card.querySelector("[data-operator-card-drilldown-note]");
  if (existing instanceof HTMLElement) {
    return existing;
  }
  const note = document.createElement("p");
  note.className = "operator-health-card-drilldown-note";
  note.setAttribute("data-operator-card-drilldown-note", "true");
  note.hidden = true;
  card.append(note);
  return note;
}

function ensureOperatorLeadCardSummary(card) {
  if (!(card instanceof HTMLElement)) {
    return null;
  }
  const existing = card.querySelector("[data-operator-lead-summary]");
  if (existing instanceof HTMLElement) {
    return existing;
  }
  const summary = document.createElement("div");
  summary.className = "operator-health-card-lead-summary";
  summary.setAttribute("data-operator-lead-summary", "true");
  summary.hidden = true;
  const hintNode = card.querySelector(".operator-health-hint");
  if (hintNode instanceof HTMLElement) {
    card.insertBefore(summary, hintNode);
  } else {
    card.append(summary);
  }
  return summary;
}

function clearOperatorLeadCardSummary(card) {
  if (!(card instanceof HTMLElement)) {
    return;
  }
  card.classList.remove("has-lead-summary");
  card.removeAttribute("data-operator-lead-summary-count");
  delete card.dataset.operatorLeadSummaryDensity;
  const summary = card.querySelector("[data-operator-lead-summary]");
  if (summary instanceof HTMLElement) {
    summary.hidden = true;
    summary.replaceChildren();
  }
}

function collectOperatorLeadCardSummaryFacts(card) {
  if (!(card instanceof HTMLElement)) {
    return [];
  }
  const statusNode = card.querySelector(".status-pill");
  const variant = readOperatorStatusVariant(statusNode);
  const targetCount = variant === "fail" ? 3 : 2;
  const facts = collectOperatorEvidenceDrawerFacts(card);
  if (facts.length === 0) {
    return [];
  }
  const summaryFacts = [];
  for (const fact of facts.filter((item) => item && item.isPlaceholder !== true)) {
    pushOperatorEvidenceDrawerFact(summaryFacts, fact, targetCount);
  }
  for (const fact of facts.filter((item) => item && item.isPlaceholder === true)) {
    pushOperatorEvidenceDrawerFact(summaryFacts, fact, targetCount);
  }
  return summaryFacts.slice(0, targetCount);
}

function shouldUseOperatorCompactLeadSummary(card) {
  if (!(card instanceof HTMLElement)) {
    return false;
  }
  const group = card.closest(".operator-health-group");
  const supportsCompactLeadShell = Boolean(
    group instanceof HTMLElement &&
      (group.classList.contains("has-supporting-ledger-layout") || group.classList.contains("has-single-lead-layout")),
  );
  return Boolean(
    normalizeOperatorBoardMode(state.operatorBoardMode) === "demo" &&
      isOperatorDesktopCompactionViewport() &&
      card.classList.contains("operator-health-card-lead") &&
      !card.classList.contains("operator-health-card-hidden") &&
      supportsCompactLeadShell &&
      !group.classList.contains("is-collapsed") &&
      !group.classList.contains("operator-health-group-hidden"),
  );
}

function normalizeOperatorLeadSummaryLabel(value) {
  const normalized = normalizeOperatorUiCopy(value);
  if (!normalized) {
    return "";
  }
  const compactMap = {
    "last event": "Event",
    "last event at": "Seen",
    healthy: "Health",
    "blocking services": "Blocking",
    "browser workers": "Workers",
    "device nodes": "Nodes",
    "recovery path": "Path",
    "total active": "Active",
  };
  return compactMap[normalized.toLowerCase()] ?? normalized;
}

function normalizeOperatorLeadSummaryValue(label, value, isPlaceholder = false) {
  const normalizedLabel = normalizeOperatorUiCopy(label).toLowerCase();
  const normalizedValue = normalizeOperatorUiCopy(value);
  if (!normalizedValue) {
    return "";
  }
  if (normalizedValue === "Awaiting signal") {
    if (normalizedLabel === "last event") {
      return "No signal";
    }
    return "Awaiting";
  }
  if (normalizedLabel === "healthy" && /^healthy$/iu.test(normalizedValue)) {
    return "OK";
  }
  if (normalizedLabel === "recovery path" && /refresh summary/iu.test(normalizedValue)) {
    return "Refresh";
  }
  if (isPlaceholder && /refresh summary/iu.test(normalizedValue)) {
    return "Refresh";
  }
  const compactSentence = summarizeOperatorDemoSummaryNoteText(normalizedValue).replace(/[.!?]+$/u, "").trim();
  if (!compactSentence) {
    return normalizedValue;
  }
  if (compactSentence.length <= 20) {
    return compactSentence;
  }
  return `${compactSentence.slice(0, 17).trimEnd()}...`;
}

function resolveOperatorCompactLeadActionLabel(actionLabel = "") {
  const normalized = normalizeOperatorUiCopy(actionLabel);
  if (!normalized) {
    return "";
  }
  const compactMap = {
    "run ui task": "UI Task",
    "refresh summary": "Refresh",
    "open quick start": "Quick Start",
    "open playbook": "Playbook",
    "open lane": "Lane",
    "open device nodes": "Nodes",
    "device tab": "Nodes",
    "workflow control": "Workflow",
    "run path": "Path",
  };
  return compactMap[normalized.toLowerCase()] ?? normalized;
}

function syncOperatorLeadCardSummary(card) {
  if (!(card instanceof HTMLElement)) {
    return;
  }
  const group = card.closest(".operator-health-group");
  const shouldShow = Boolean(
    normalizeOperatorBoardMode(state.operatorBoardMode) === "demo" &&
      card.classList.contains("operator-health-card-lead") &&
      !card.classList.contains("operator-health-card-hidden") &&
      group instanceof HTMLElement &&
      !group.classList.contains("is-collapsed") &&
      !group.classList.contains("operator-health-group-hidden"),
  );
  if (!shouldShow) {
    clearOperatorLeadCardSummary(card);
    return;
  }
  const summary = ensureOperatorLeadCardSummary(card);
  if (!(summary instanceof HTMLElement)) {
    clearOperatorLeadCardSummary(card);
    return;
  }
  const facts = collectOperatorLeadCardSummaryFacts(card);
  if (facts.length === 0) {
    clearOperatorLeadCardSummary(card);
    return;
  }
  const useCompactSummary = shouldUseOperatorCompactLeadSummary(card);
  const summaryItems = facts.map((fact, index) => {
    const item = document.createElement("article");
    item.className = "operator-health-card-lead-summary-item";
    if (index === 0) {
      item.classList.add("is-primary");
    }
    if (fact.isPlaceholder === true) {
      item.classList.add("is-placeholder");
    }

    const label = document.createElement("span");
    label.className = "operator-health-card-lead-summary-label";
    const fullLabel = normalizeOperatorUiCopy(fact.label);
    label.textContent = useCompactSummary ? normalizeOperatorLeadSummaryLabel(fullLabel) : fullLabel;

    const value = document.createElement("strong");
    value.className = "operator-health-card-lead-summary-value";
    const fullValue = normalizeOperatorUiCopy(fact.value);
    value.textContent = useCompactSummary ? normalizeOperatorLeadSummaryValue(fullLabel, fullValue, fact.isPlaceholder === true) : fullValue;
    item.title = fullLabel && fullValue ? `${fullLabel}: ${fullValue}` : fullValue || fullLabel;

    item.append(label, value);
    return item;
  });
  summary.replaceChildren(...summaryItems);
  summary.hidden = false;
  card.classList.add("has-lead-summary");
  card.dataset.operatorLeadSummaryCount = String(facts.length);
  card.dataset.operatorLeadSummaryDensity = useCompactSummary ? "compact" : "default";
}

function shouldUseOperatorCompactLeadHint(card) {
  if (!(card instanceof HTMLElement)) {
    return false;
  }
  const group = card.closest(".operator-health-group");
  return Boolean(
    normalizeOperatorBoardMode(state.operatorBoardMode) === "demo" &&
      isOperatorDesktopCompactionViewport() &&
      card.classList.contains("operator-health-card-lead") &&
      card.classList.contains("has-lead-summary") &&
      !card.classList.contains("operator-health-card-hidden") &&
      group instanceof HTMLElement &&
      !group.classList.contains("is-collapsed") &&
      !group.classList.contains("operator-health-group-hidden"),
  );
}

function resolveOperatorCompactLeadHintText(card, fallbackText = "") {
  if (!(card instanceof HTMLElement)) {
    return "";
  }
  const normalizedFallback = normalizeOperatorUiCopy(fallbackText);
  const hintNode = card.querySelector(".operator-health-hint");
  const statusNode = card.querySelector(".status-pill");
  const statusCode = getOperatorStatusCode(statusNode);
  const statusId = getOperatorStatusIdFromCard(card);
  const group = card.closest(".operator-health-group");
  const useCompactSummary = shouldUseOperatorCompactLeadSummary(card);
  const actionLabel =
    OPERATOR_EMPTY_STATE_ACTIONS[statusId]?.label ??
    OPERATOR_PRIORITY_QUEUE_ACTIONS[statusId]?.supportLabel ??
    "";
  const compactActionLabel = resolveOperatorCompactLeadActionLabel(actionLabel);
  const preferredActionLabel = useCompactSummary ? compactActionLabel || actionLabel : actionLabel;
  const isSingleLeadLayout = Boolean(
    group instanceof HTMLElement &&
      group.classList.contains("has-single-lead-layout") &&
      !group.classList.contains("has-supporting-ledger-layout"),
  );
  const isQuietAwaitingState = Boolean(
    isOperatorPlaceholderStatusText(statusCode) ||
      isOperatorUninitializedStatusText(statusCode) ||
      /waiting for request|awaiting signal/iu.test(normalizeOperatorUiCopy(statusCode)) ||
      /not initialized|first traffic|live session/iu.test(normalizedFallback),
  );
  const prefersActionFirstHint = Boolean(
    useCompactSummary &&
      actionLabel &&
      (isQuietAwaitingState || /^refresh summary to inspect\b/iu.test(normalizedFallback)),
  );
  if (prefersActionFirstHint) {
    return `${preferredActionLabel} first.`;
  }
  if (statusCode === "summary_stale") {
    if (useCompactSummary && isSingleLeadLayout && preferredActionLabel) {
      return `${preferredActionLabel} first.`;
    }
    return useCompactSummary ? "Refresh first." : "Next: Refresh Summary.";
  }
  if (
    isOperatorPlaceholderStatusText(statusCode) ||
    isOperatorUninitializedStatusText(statusCode) ||
    (hintNode instanceof HTMLElement && hintNode.classList.contains("operator-health-hint-neutral"))
  ) {
    if (useCompactSummary) {
      return preferredActionLabel ? `${preferredActionLabel} first.` : "Refresh first.";
    }
    return actionLabel ? `Next: ${actionLabel}, then Refresh Summary.` : "Next: Refresh Summary.";
  }
  if (hintNode instanceof HTMLElement && hintNode.classList.contains("operator-health-hint-ok")) {
    if (useCompactSummary) {
      return "Monitor on change.";
    }
    return "Next: monitor this lane only if related work changes.";
  }
  if (
    hintNode instanceof HTMLElement &&
    (hintNode.classList.contains("operator-health-hint-warn") || hintNode.classList.contains("operator-health-hint-fail"))
  ) {
    return normalizedFallback;
  }
  const shortHint = summarizeOperatorDemoSummaryNoteText(normalizedFallback);
  if (!shortHint) {
    return "";
  }
  const compactHint = shortHint.replace(/^next:\s*/i, "").replace(/\.$/, "").trim();
  return compactHint ? `Next: ${compactHint}.` : shortHint;
}

function syncOperatorLeadCardHint(card) {
  if (!(card instanceof HTMLElement)) {
    return;
  }
  const shouldUseCompactShell = shouldUseOperatorCompactLeadSummary(card);
  const hintNode = card.querySelector(".operator-health-hint");
  if (!(hintNode instanceof HTMLElement)) {
    card.classList.toggle("has-compact-lead-shell", shouldUseCompactShell);
    return;
  }
  const currentText = typeof hintNode.textContent === "string" ? hintNode.textContent.replace(/\s+/g, " ").trim() : "";
  const originalText = card.dataset.operatorLeadHintOriginalText || currentText;
  if (!card.dataset.operatorLeadHintOriginalText && originalText) {
    card.dataset.operatorLeadHintOriginalText = originalText;
  }
  if (!originalText) {
    card.classList.toggle("has-compact-lead-shell", shouldUseCompactShell);
    return;
  }
  const compactText = resolveOperatorCompactLeadHintText(card, originalText);
  const shouldUseCompactHint = shouldUseOperatorCompactLeadHint(card) && compactText && compactText !== originalText;
  hintNode.textContent = shouldUseCompactHint ? compactText : originalText;
  hintNode.classList.toggle("is-compact-lead-hint", shouldUseCompactHint);
  card.classList.toggle("has-compact-lead-shell", shouldUseCompactShell || shouldUseCompactHint);
  hintNode.title = originalText;
}

function ensureOperatorSupportingCardSummary(card) {
  if (!(card instanceof HTMLElement)) {
    return null;
  }
  let summary = card.querySelector(".operator-health-card-supporting-summary");
  if (summary instanceof HTMLElement) {
    return summary;
  }
  summary = document.createElement("div");
  summary.className = "operator-health-card-supporting-summary";
  summary.hidden = true;
  const note = card.querySelector(".operator-health-card-drilldown-note");
  if (note instanceof HTMLElement) {
    card.insertBefore(summary, note);
  } else {
    card.append(summary);
  }
  return summary;
}

function clearOperatorSupportingCardSummary(card) {
  if (!(card instanceof HTMLElement)) {
    return;
  }
  const summary = card.querySelector(".operator-health-card-supporting-summary");
  if (summary instanceof HTMLElement) {
    summary.hidden = true;
    summary.replaceChildren();
  }
  card.classList.remove("has-supporting-summary");
  delete card.dataset.operatorSupportingSummaryCount;
}

function collectOperatorSupportingCardSummaryFacts(card) {
  if (!(card instanceof HTMLElement)) {
    return [];
  }
  const facts = collectOperatorEvidenceDrawerFacts(card);
  if (facts.length === 0) {
    return [];
  }
  const summaryFacts = [];
  const preferredFacts = facts.filter((item) => item && item.isPlaceholder !== true);
  const placeholderFacts = facts.filter((item) => item && item.isPlaceholder === true);
  const targetCount = preferredFacts.length > 0 ? 2 : 1;
  for (const fact of preferredFacts) {
    pushOperatorEvidenceDrawerFact(summaryFacts, fact, targetCount);
  }
  for (const fact of placeholderFacts) {
    pushOperatorEvidenceDrawerFact(summaryFacts, fact, targetCount);
  }
  return summaryFacts.slice(0, targetCount);
}

function normalizeOperatorSupportingSummaryLabel(value) {
  const normalized = normalizeOperatorUiCopy(value);
  if (!normalized) {
    return "";
  }
  const compactMap = {
    "blocking services": "Blocking",
    "recovery path": "Path",
    "top signal": "Top",
    "total active": "Active",
  };
  return compactMap[normalized.toLowerCase()] ?? normalized;
}

function normalizeOperatorSupportingSummaryValue(label, value, isPlaceholder = false) {
  const normalizedLabel = normalizeOperatorUiCopy(label).toLowerCase();
  const normalizedValue = normalizeOperatorUiCopy(value);
  if (!normalizedValue) {
    return "";
  }
  if (normalizedValue === "Awaiting signal") {
    return normalizedLabel === "recovery path" ? "Refresh needed" : "Awaiting";
  }
  if (normalizedLabel === "recovery path" && /refresh summary/i.test(normalizedValue)) {
    return "Refresh needed";
  }
  if (isPlaceholder && /refresh summary/i.test(normalizedValue)) {
    return "Refresh first";
  }
  const compactSentence = summarizeOperatorDemoSummaryNoteText(normalizedValue).replace(/[.!?]+$/u, "").trim();
  if (!compactSentence) {
    return normalizedValue;
  }
  if (compactSentence.length <= 28) {
    return compactSentence;
  }
  return `${compactSentence.slice(0, 25).trimEnd()}...`;
}

function syncOperatorSupportingCardSummary(card) {
  if (!(card instanceof HTMLElement)) {
    return;
  }
  const group = card.closest(".operator-health-group");
  const shouldShow = Boolean(
    normalizeOperatorBoardMode(state.operatorBoardMode) === "demo" &&
      isOperatorDesktopCompactionViewport() &&
      card.classList.contains("operator-health-card-supporting") &&
      !card.classList.contains("operator-health-card-hidden") &&
      group instanceof HTMLElement &&
      group.classList.contains("has-supporting-ledger-layout") &&
      !group.classList.contains("is-collapsed") &&
      !group.classList.contains("operator-health-group-hidden"),
  );
  if (!shouldShow) {
    clearOperatorSupportingCardSummary(card);
    return;
  }
  const summary = ensureOperatorSupportingCardSummary(card);
  if (!(summary instanceof HTMLElement)) {
    clearOperatorSupportingCardSummary(card);
    return;
  }
  const facts = collectOperatorSupportingCardSummaryFacts(card);
  if (facts.length === 0) {
    clearOperatorSupportingCardSummary(card);
    return;
  }
  const items = facts.map((fact) => {
    const item = document.createElement("span");
    item.className = "operator-health-card-supporting-summary-item";
    if (fact.isPlaceholder === true) {
      item.classList.add("is-placeholder");
    }
    const label = document.createElement("span");
    label.className = "operator-health-card-supporting-summary-label";
    label.textContent = normalizeOperatorSupportingSummaryLabel(fact.label);
    const value = document.createElement("strong");
    value.className = "operator-health-card-supporting-summary-value";
    value.textContent = normalizeOperatorSupportingSummaryValue(fact.label, fact.value, fact.isPlaceholder === true);
    item.append(label, value);
    return item;
  });
  summary.replaceChildren(...items);
  summary.hidden = false;
  card.classList.add("has-supporting-summary");
  card.dataset.operatorSupportingSummaryCount = String(facts.length);
}

function syncOperatorCardDrilldownState(card) {
  if (!(card instanceof HTMLElement)) {
    return;
  }
  const statusId = getOperatorStatusIdFromCard(card);
  const group = card.closest(".operator-health-group");
  const note = ensureOperatorCardDrilldownNote(card);
  const shouldEnable = Boolean(
    statusId &&
      normalizeOperatorBoardMode(state.operatorBoardMode) === "demo" &&
      !card.classList.contains("operator-health-card-hidden") &&
      group instanceof HTMLElement &&
      !group.classList.contains("is-collapsed") &&
      !group.classList.contains("operator-health-group-hidden"),
  );
  card.classList.toggle("operator-health-card-selectable", shouldEnable);
  if (!shouldEnable) {
    card.classList.remove("is-evidence-active");
    card.removeAttribute("data-operator-card-status-id");
    card.removeAttribute("tabindex");
    card.removeAttribute("role");
    card.removeAttribute("aria-pressed");
    if (note instanceof HTMLElement) {
      note.hidden = true;
    }
    syncOperatorLeadCardSummary(card);
    syncOperatorLeadCardHint(card);
    syncOperatorSupportingCardSummary(card);
    return;
  }
  const isActive = state.operatorFocusedEvidenceStatusId.trim() === statusId;
  card.classList.toggle("is-evidence-active", isActive);
  card.dataset.operatorCardStatusId = statusId;
  card.tabIndex = 0;
  card.setAttribute("role", "button");
  card.setAttribute("aria-pressed", isActive ? "true" : "false");
  if (note instanceof HTMLElement) {
    const isSupporting = card.classList.contains("operator-health-card-supporting");
    note.hidden = !isSupporting;
    note.textContent = isActive ? "Focused" : "Inspect";
  }
  syncOperatorLeadCardSummary(card);
  syncOperatorLeadCardHint(card);
  syncOperatorSupportingCardSummary(card);
}

function getOperatorCardSortOrder(card, fallbackIndex = 0) {
  if (!(card instanceof HTMLElement)) {
    return fallbackIndex;
  }
  const currentValue = Number.parseInt(card.dataset.operatorCardOrder ?? "", 10);
  if (Number.isFinite(currentValue)) {
    return currentValue;
  }
  card.dataset.operatorCardOrder = String(fallbackIndex);
  return fallbackIndex;
}

function ensureOperatorSupportingLedger(group) {
  if (!(group instanceof HTMLElement)) {
    return null;
  }
  let ledger = group.querySelector("[data-operator-supporting-ledger]");
  if (ledger instanceof HTMLElement) {
    return ledger;
  }
  ledger = document.createElement("section");
  ledger.className = "operator-health-supporting-ledger";
  ledger.setAttribute("data-operator-supporting-ledger", "true");
  ledger.hidden = true;

  const head = document.createElement("div");
  head.className = "operator-health-supporting-ledger-head";

  const title = document.createElement("span");
  title.className = "operator-health-supporting-ledger-title";
  title.textContent = "Other evidence";

  const count = document.createElement("strong");
  count.className = "operator-health-supporting-ledger-count";
  count.setAttribute("data-operator-supporting-ledger-count", "true");
  count.textContent = "0 signals";

  const copy = document.createElement("p");
  copy.className = "operator-health-supporting-ledger-copy";
  copy.textContent = "Select a supporting signal to inspect it in the focused drawer without reopening a deeper surface.";

  const list = document.createElement("div");
  list.className = "operator-health-supporting-ledger-list";
  list.setAttribute("data-operator-supporting-ledger-list", "true");

  head.append(title, count);
  ledger.append(head, copy, list);
  return ledger;
}

function syncOperatorGroupSupportingLedger(group) {
  if (!(group instanceof HTMLElement)) {
    return;
  }
  const body = group.querySelector(".operator-health-group-body");
  if (!(body instanceof HTMLElement)) {
    return;
  }
  group.classList.remove("has-supporting-ledger-layout", "has-single-supporting-ledger-layout");
  const orderedCards = Array.from(group.querySelectorAll(".operator-health-card"))
    .filter((card) => card instanceof HTMLElement)
    .sort((left, right) => getOperatorCardSortOrder(left) - getOperatorCardSortOrder(right));
  if (orderedCards.length === 0) {
    return;
  }
  orderedCards.forEach((card, index) => {
    if (!(card instanceof HTMLElement)) {
      return;
    }
    getOperatorCardSortOrder(card, index);
  });

  const ledger = ensureOperatorSupportingLedger(group);
  const list = ledger?.querySelector("[data-operator-supporting-ledger-list]");
  const countNode = ledger?.querySelector("[data-operator-supporting-ledger-count]");
  const useLedger = Boolean(
    ledger instanceof HTMLElement &&
      list instanceof HTMLElement &&
      normalizeOperatorBoardMode(state.operatorBoardMode) === "demo" &&
      !group.classList.contains("is-collapsed") &&
      !group.classList.contains("operator-health-group-hidden"),
  );

  if (!useLedger) {
    body.classList.remove("has-supporting-ledger");
    body.classList.remove("has-single-supporting-ledger");
    body.replaceChildren(...orderedCards);
    if (ledger instanceof HTMLElement) {
      ledger.classList.remove("is-single-signal");
      ledger.hidden = true;
    }
    return;
  }

  const leadCards = orderedCards.filter(
    (card) => !card.classList.contains("operator-health-card-hidden") && card.classList.contains("operator-health-card-lead"),
  );
  const supportingCards = orderedCards.filter(
    (card) => !card.classList.contains("operator-health-card-hidden") && card.classList.contains("operator-health-card-supporting"),
  );
  const trailingCards = orderedCards.filter(
    (card) => !leadCards.includes(card) && !supportingCards.includes(card),
  );

  if (supportingCards.length === 0) {
    body.classList.remove("has-supporting-ledger");
    body.classList.remove("has-single-supporting-ledger");
    body.replaceChildren(...orderedCards);
    ledger.classList.remove("is-single-signal");
    ledger.hidden = true;
    return;
  }

  body.classList.add("has-supporting-ledger");
  body.classList.toggle("has-single-supporting-ledger", supportingCards.length === 1);
  group.classList.add("has-supporting-ledger-layout");
  group.classList.toggle("has-single-supporting-ledger-layout", supportingCards.length === 1);
  ledger.classList.toggle("is-single-signal", supportingCards.length === 1);
  if (countNode instanceof HTMLElement) {
    countNode.textContent = supportingCards.length === 1 ? "1 signal" : `${supportingCards.length} signals`;
  }
  list.replaceChildren(...supportingCards);
  ledger.hidden = false;

  const fragment = document.createDocumentFragment();
  for (const card of leadCards) {
    fragment.append(card);
  }
  fragment.append(ledger);
  for (const card of trailingCards) {
    fragment.append(card);
  }
  body.replaceChildren(fragment);
}

function syncOperatorGroupCardHierarchy(group) {
  if (!(group instanceof HTMLElement)) {
    return;
  }
  const body = group.querySelector(".operator-health-group-body");
  if (body instanceof HTMLElement) {
    body.classList.remove("has-single-lead-card");
  }
  group.classList.remove("has-single-lead-layout");
  const cards = Array.from(group.querySelectorAll(".operator-health-card"));
  for (const card of cards) {
    clearOperatorGroupCardHierarchy(card);
  }
  if (
    normalizeOperatorBoardMode(state.operatorBoardMode) !== "demo" ||
    group.classList.contains("is-collapsed") ||
    group.classList.contains("operator-health-group-hidden")
  ) {
    syncOperatorGroupSupportingLedger(group);
    for (const card of cards) {
      syncOperatorCardDrilldownState(card);
    }
    return;
  }
  const visibleCards = cards.filter((card) => !card.classList.contains("operator-health-card-hidden"));
  if (visibleCards.length === 0) {
    syncOperatorGroupSupportingLedger(group);
    for (const card of cards) {
      syncOperatorCardDrilldownState(card);
    }
    return;
  }
  const hasSingleVisibleCard = visibleCards.length === 1;
  group.classList.toggle("has-single-lead-layout", hasSingleVisibleCard);
  if (body instanceof HTMLElement) {
    body.classList.toggle("has-single-lead-card", hasSingleVisibleCard);
  }
  const leadCard = resolveOperatorGroupLeadCard(group, visibleCards) ?? visibleCards[0];
  for (const card of visibleCards) {
    const isLead = card === leadCard;
    card.classList.toggle("operator-health-card-lead", isLead);
    card.classList.toggle("operator-health-card-supporting", !isLead);
    syncOperatorCardDrilldownState(card);
  }
  syncOperatorGroupSupportingLedger(group);
  for (const card of cards) {
    syncOperatorCardDrilldownState(card);
  }
}

function syncOperatorBoardCardHierarchy() {
  const groups = document.querySelectorAll(".operator-health-group");
  for (const group of groups) {
    syncOperatorGroupCardHierarchy(group);
  }
  syncOperatorBoardCardPresentationTitles();
}

function applyOperatorCardVisibility(card) {
  if (!card) {
    return;
  }
  const statusNode = card.querySelector(".status-pill");
  if (!statusNode) {
    card.classList.remove("operator-health-card-hidden");
    card.classList.remove("operator-health-card-condensed");
    return;
  }
  const shouldCondense = shouldCondenseOperatorDemoNeutralCard(card, statusNode);
  card.classList.toggle("operator-health-card-condensed", shouldCondense);
  ensureOperatorCardEmptyActions(card, statusNode);
  const shouldHide =
    state.operatorSummaryUserRefreshed !== true &&
    isOperatorPlaceholderStatusText(
      statusNode instanceof HTMLElement ? (statusNode.dataset.statusCode ?? statusNode.textContent ?? "") : statusNode.textContent ?? "",
    );
  if (state.operatorFocusCriticalOnly === true && !isOperatorCriticalCard(card)) {
    card.classList.toggle("operator-health-card-hidden", true);
    return;
  }
  if (state.operatorIssuesOnly && statusNode.classList.contains("status-ok")) {
    card.classList.toggle("operator-health-card-hidden", true);
    return;
  }

  if (shouldHideOperatorDemoNeutralCard(card, statusNode)) {
    card.classList.toggle("operator-health-card-hidden", true);
    return;
  }

  if (state.operatorBoardMode === "demo" && state.operatorFocusCriticalOnly === true && !isOperatorDemoEssentialCard(card)) {
    const variant = readOperatorStatusVariant(statusNode);
    if (variant !== "fail") {
      card.classList.toggle("operator-health-card-hidden", true);
      return;
    }
  }

  card.classList.toggle("operator-health-card-hidden", shouldHide);
}

function applyOperatorGroupVisibility(group) {
  if (!group) {
    return;
  }
  const cards = Array.from(group.querySelectorAll(".operator-health-card"));
  const hasVisibleCards = cards.some((card) => !card.classList.contains("operator-health-card-hidden"));
  group.classList.toggle("operator-health-group-hidden", !hasVisibleCards);
}

function applyOperatorCardsVisibility() {
  const cards = document.querySelectorAll(".operator-health-card");
  for (const card of cards) {
    applyOperatorCardVisibility(card);
  }
  const groups = document.querySelectorAll(".operator-health-group");
  for (const group of groups) {
    applyOperatorGroupVisibility(group);
  }
  applyOperatorDefaultGroupFocus();
  syncOperatorBoardCardHierarchy();
  syncOperatorCollapseActionButtons();
  refreshOperatorTriageSummary();
  refreshOperatorGroupMetrics();
  refreshOperatorDemoSummaryKpis();
  syncOperatorSummaryGuide();
}

function toConversationScope(value) {
  return value === "none" ? "none" : "default";
}

function toEnvelopeOptions(runOrOptions) {
  if (typeof runOrOptions === "string" || runOrOptions === null || runOrOptions === undefined) {
    return {
      runId: runOrOptions ?? state.runId,
      conversation: "default",
      metadata: {},
    };
  }
  if (typeof runOrOptions !== "object") {
    return {
      runId: state.runId,
      conversation: "default",
      metadata: {},
    };
  }

  const runId =
    typeof runOrOptions.runId === "string" || runOrOptions.runId === null || runOrOptions.runId === undefined
      ? runOrOptions.runId
      : state.runId;
  const conversation = toConversationScope(runOrOptions.conversation);
  const metadata =
    runOrOptions.metadata && typeof runOrOptions.metadata === "object" && !Array.isArray(runOrOptions.metadata)
      ? runOrOptions.metadata
      : {};

  return {
    runId: runId ?? state.runId,
    conversation,
    metadata,
  };
}

function isRealtimeSocketConnected() {
  return Boolean(state.ws && state.ws.readyState === WebSocket.OPEN);
}

function isEphemeralSessionState(text) {
  const normalized = typeof text === "string" ? text.trim().toLowerCase() : "";
  return normalized === "live_forwarded";
}

function shouldRenderSessionState(text) {
  return !isEphemeralSessionState(text);
}

function shouldUseMicTranslationCapture(intent = getCurrentLiveIntentValue()) {
  return typeof intent === "string" && intent.trim().toLowerCase() === "translation";
}

function shouldForwardMicAudioToLiveRuntime(intent = state.micCaptureIntent) {
  return !shouldUseMicTranslationCapture(intent ?? getCurrentLiveIntentValue());
}

function setMicSpeechUiPhase(phase, detail = null) {
  state.micSpeechUiPhase = typeof phase === "string" && phase.trim().length > 0 ? phase.trim() : "ready";
  state.micSpeechUiDetail = detail;
  syncMicSpeechComposerStatus();
}

function getMicSpeechComposerStatus(intent = getCurrentLiveIntentValue()) {
  if (!shouldUseMicTranslationCapture(intent)) {
    return {
      visible: false,
      code: "hidden",
      toneClass: "status-neutral",
      label: "",
      hint: "",
    };
  }

  const isRu = state.languageMode === "ru";
  const transcript = resolveMicSpeechCaptureTranscript();
  const translationMicActive =
    shouldUseMicTranslationCapture(state.micCaptureIntent)
    && (Boolean(state.micSpeechRecognition) || (Boolean(state.micProcessor) && Boolean(state.micSpeechSource)));

  let phase = typeof state.micSpeechUiPhase === "string" && state.micSpeechUiPhase.trim().length > 0
    ? state.micSpeechUiPhase.trim().toLowerCase()
    : "ready";
  if (state.micSpeechDispatchPending === true) {
    phase = "sending";
  } else if (translationMicActive) {
    phase = transcript.length > 0 ? "recognized" : "listening";
  }

  const errorDetail =
    typeof state.micSpeechUiDetail === "string" && state.micSpeechUiDetail.trim().length > 0
      ? state.micSpeechUiDetail.trim().toLowerCase()
      : typeof state.micSpeechError === "string" && state.micSpeechError.trim().length > 0
        ? state.micSpeechError.trim().toLowerCase()
        : "";

  const copy = {
    ready: {
      toneClass: "status-neutral",
      label: isRu ? "Мик готов" : "Mic ready",
      hint: isRu
        ? "Нажми Start mic, чтобы продиктовать короткую фразу для перевода."
        : "Start mic to dictate a short phrase for translation.",
    },
    listening: {
      toneClass: "status-neutral",
      label: isRu ? "Слушаю" : "Listening",
      hint: isRu
        ? "Говори исходную фразу на выбранном языке речи."
        : "Speak the source phrase in the selected speech language.",
    },
    recognized: {
      toneClass: "status-neutral",
      label: isRu ? "Распознано" : "Recognized",
      hint: isRu
        ? "Фраза захвачена. Короткая пауза должна отправить её автоматически."
        : "Phrase captured. A short pause should send it automatically.",
    },
    sending: {
      toneClass: "status-neutral",
      label: isRu ? "Отправляем" : "Sending",
      hint: isRu
        ? "Распознанная фраза уходит на перевод."
        : "Sending the recognized phrase for translation.",
    },
    sent: {
      toneClass: "status-ok",
      label: isRu ? "Отправлено" : "Sent",
      hint: isRu
        ? "Голосовая фраза отправлена. Перевод появится справа."
        : "Voice phrase sent. The translation will appear on the right.",
    },
  };

  if (phase === "error") {
    if (errorDetail === "unsupported") {
      return {
        visible: true,
        code: "unsupported",
        toneClass: "status-fail",
        label: isRu ? "Мик недоступен" : "Mic unavailable",
        hint: isRu
          ? "SpeechRecognition недоступен. Используй Chrome/Edge на localhost или введи текст вручную."
          : "SpeechRecognition is unavailable. Use Chrome/Edge on localhost or type the text manually.",
      };
    }
    if (errorDetail === "no-speech" || errorDetail === "empty") {
      return {
        visible: true,
        code: "no_speech",
        toneClass: "status-fail",
        label: isRu ? "Речь не поймана" : "No speech",
        hint: isRu
          ? "Чёткая фраза не распознана. Повтори её или введи текст вручную."
          : "No clear phrase was captured. Try again or type the text manually.",
      };
    }
    return {
      visible: true,
      code: "error",
      toneClass: "status-fail",
      label: isRu ? "Ошибка микрофона" : "Mic error",
      hint: isRu
        ? "Голосовой ввод завершился ошибкой. Попробуй ещё раз или используй текст."
        : "Voice capture failed. Try again or use text input.",
    };
  }

  const resolved = copy[phase] ?? copy.ready;
  return {
    visible: true,
    code: phase,
    toneClass: resolved.toneClass,
    label: resolved.label,
    hint: resolved.hint,
  };
}

function syncMicSpeechComposerStatus(intent = getCurrentLiveIntentValue()) {
  const status = getMicSpeechComposerStatus(intent);
  const hasHTMLElementCtor = typeof HTMLElement !== "undefined";
  if (!hasHTMLElementCtor || !(el.micComposerStatus instanceof HTMLElement)) {
    return status;
  }
  el.micComposerStatus.hidden = !status.visible;
  el.micComposerStatus.setAttribute("aria-hidden", status.visible ? "false" : "true");
  el.micComposerStatus.dataset.statusCode = status.code;
  if (el.micComposerStatusPill instanceof HTMLElement) {
    el.micComposerStatusPill.textContent = status.label;
    el.micComposerStatusPill.className = `status-pill ${status.toneClass} live-compose-mic-status-pill`;
    el.micComposerStatusPill.dataset.statusCode = status.code;
  }
  if (el.micComposerStatusHint instanceof HTMLElement) {
    el.micComposerStatusHint.textContent = status.hint;
  }
  return status;
}

function normalizeMicSpeechTranscript(value) {
  return typeof value === "string" ? value.replace(/\s+/g, " ").trim() : "";
}

function getMicSpeechRecognitionCtor(scope = globalThis) {
  if (!scope || (typeof scope !== "object" && typeof scope !== "function")) {
    return null;
  }
  if (typeof scope.SpeechRecognition === "function") {
    return scope.SpeechRecognition;
  }
  if (typeof scope.webkitSpeechRecognition === "function") {
    return scope.webkitSpeechRecognition;
  }
  return null;
}

function resolveMicSpeechRecognitionLocale() {
  return (
    state.micCaptureSpeechLanguage ??
    (typeof getLiveSpeechLanguageValue === "function" ? getLiveSpeechLanguageValue() : "auto")
  );
}

function formatMicSpeechTranscriptForCompose(value, options = {}) {
  const normalized = normalizeMicSpeechTranscript(value);
  if (normalized.length === 0) {
    return "";
  }
  const hasInterim = options && options.hasInterim === true;
  const speechLanguage =
    typeof options.speechLanguage === "string" && options.speechLanguage.trim().length > 0
      ? options.speechLanguage.trim()
      : resolveMicSpeechRecognitionLocale();
  let formatted = normalized.charAt(0).toUpperCase() + normalized.slice(1);
  if (hasInterim) {
    return formatted;
  }

  const normalizedLanguage = speechLanguage.toLowerCase();
  if (normalizedLanguage.startsWith("ru")) {
    formatted = formatted
      .replace(
        /^((?:Привет|Здравствуй(?:те)?|Доброе утро|Добрый день|Добрый вечер))\s+(?=(?:как|что|где|когда|почему|зачем|кто|сколько|какой|какая|какие|чем|куда|откуда|можешь|можете)(?:\s|$))/iu,
        "$1, ",
      )
      .replace(/(как дела)\s+/iu, "$1, ");
  } else if (normalizedLanguage.startsWith("en")) {
    formatted = formatted
      .replace(
        /^((?:Hello|Hi|Hey|Good morning|Good afternoon|Good evening))\s+(?=(?:who|what|when|where|why|how|is|are|do|does|did|can|could|would|will)(?:\s|$))/iu,
        "$1, ",
      )
      .replace(/(how are you)\s+/iu, "$1, ");
  }

  if (!/[.!?…]$/u.test(formatted)) {
    const lowerText = formatted.toLowerCase();
    const firstWord = lowerText.split(/\s+/u)[0] ?? "";
    const isQuestion = normalizedLanguage.startsWith("ru")
      ? [
          "как",
          "что",
          "где",
          "когда",
          "почему",
          "зачем",
          "кто",
          "сколько",
          "какой",
          "какая",
          "какие",
          "чем",
          "куда",
          "откуда",
          "можешь",
          "можете",
        ].includes(firstWord) || lowerText.includes("как дела") || lowerText.includes("чем занимаешься")
      : [
          "who",
          "what",
          "when",
          "where",
          "why",
          "how",
          "is",
          "are",
          "do",
          "does",
          "did",
          "can",
          "could",
          "would",
          "will",
        ].includes(firstWord) || lowerText.includes("how are you");
    formatted = `${formatted}${isQuestion ? "?" : "."}`;
  }

  return formatted.replace(/\s+,/gu, ",").replace(/\s+([?!.:;])/gu, "$1");
}

function clearMicSpeechAutoStopTimer() {
  if (state.micSpeechAutoStopTimer !== null && typeof clearTimeout === "function") {
    clearTimeout(state.micSpeechAutoStopTimer);
  }
  state.micSpeechAutoStopTimer = null;
}

function clearMicSpeechStopFinalizeTimer() {
  if (state.micSpeechStopFinalizeTimer !== null && typeof clearTimeout === "function") {
    clearTimeout(state.micSpeechStopFinalizeTimer);
  }
  state.micSpeechStopFinalizeTimer = null;
}

function shouldAutoSubmitMicTranslationOnPause(source = state.micSpeechSource) {
  return source === "mic" && shouldUseMicTranslationCapture(state.micCaptureIntent) && state.pttEnabled !== true;
}

function scheduleMicSpeechAutoStop() {
  const transcript = resolveMicSpeechCaptureTranscript();
  if (!shouldAutoSubmitMicTranslationOnPause() || transcript.length === 0 || state.micSpeechDispatchPending) {
    return;
  }
  clearMicSpeechAutoStopTimer();
  if (typeof setTimeout !== "function") {
    return;
  }
  state.micSpeechAutoStopTimer = setTimeout(() => {
    state.micSpeechAutoStopTimer = null;
    state.micSpeechAutoPauseNoticePending = true;
    endMicSpeechCapture({
      dispatchTranslation: true,
      source: "mic",
    });
  }, 900);
}

function resetMicSpeechCapture(options = {}) {
  const preserveTranscript = options && options.preserveTranscript === true;
  clearMicSpeechAutoStopTimer();
  clearMicSpeechStopFinalizeTimer();
  state.micSpeechRecognition = null;
  state.micSpeechAutoPauseNoticePending = false;
  state.micSpeechDispatchPending = false;
  state.micSpeechSource = null;
  state.micSpeechError = null;
  if (!preserveTranscript) {
    state.micSpeechTranscript = "";
    state.micSpeechInterimTranscript = "";
  }
}

function resolveMicSpeechCaptureTranscript() {
  const finalText = normalizeMicSpeechTranscript(state.micSpeechTranscript);
  const interimText = normalizeMicSpeechTranscript(state.micSpeechInterimTranscript);
  if (finalText.length > 0 && interimText.length > 0) {
    return normalizeMicSpeechTranscript(`${finalText} ${interimText}`);
  }
  return finalText || interimText;
}

function resolveMicSpeechComposerField() {
  if (!el.message || typeof el.message !== "object") {
    return null;
  }
  return typeof el.message.value === "string" ? el.message : null;
}

function snapshotMicSpeechComposerDraft(intent = state.micCaptureIntent) {
  const messageField = resolveMicSpeechComposerField();
  if (!messageField || !shouldUseMicTranslationCapture(intent)) {
    state.micSpeechDraftBeforeCapture = "";
    return;
  }
  state.micSpeechDraftBeforeCapture = messageField.value;
}

function syncMicSpeechComposerPreview(transcript = resolveMicSpeechCaptureTranscript()) {
  const messageField = resolveMicSpeechComposerField();
  if (!messageField || !shouldUseMicTranslationCapture(state.micCaptureIntent)) {
    return;
  }
  messageField.value = formatMicSpeechTranscriptForCompose(transcript, {
    hasInterim: normalizeMicSpeechTranscript(state.micSpeechInterimTranscript).length > 0,
  });
}

function clearMicSpeechComposerDraft(options = {}) {
  const restoreDraft = options && options.restoreDraft === true;
  const messageField = resolveMicSpeechComposerField();
  if (restoreDraft && messageField) {
    messageField.value = state.micSpeechDraftBeforeCapture;
  }
  state.micSpeechDraftBeforeCapture = "";
}

function finalizeMicTranslationFromTranscript(transcript, options = {}) {
  const normalizedTranscript = formatMicSpeechTranscriptForCompose(transcript, {
    speechLanguage:
      state.micCaptureSpeechLanguage ??
      (typeof getLiveSpeechLanguageValue === "function" ? getLiveSpeechLanguageValue() : "auto"),
  });
  const speechLanguage =
    state.micCaptureSpeechLanguage ??
    (typeof getLiveSpeechLanguageValue === "function" ? getLiveSpeechLanguageValue() : "auto");
  if (normalizedTranscript.length === 0) {
    clearMicSpeechComposerDraft({ restoreDraft: true });
    setMicSpeechUiPhase("error", state.micSpeechError ?? "empty");
    if (options.reportEmpty !== false) {
      appendTranscript(
        "error",
        state.languageMode === "ru"
          ? "Голосовой ввод не распознан. Повтори фразу или введи текст вручную."
          : "No speech was captured for translation. Try a longer phrase, pick the correct speech language, or use the text field.",
      );
    }
    return false;
  }

  const messageField = resolveMicSpeechComposerField();
  if (messageField) {
    messageField.value = normalizedTranscript;
  }

  sendIntentRequest({
    intent: "translation",
    message: normalizedTranscript,
    keepMessage: true,
    targetLanguage:
      typeof options.targetLanguage === "string" && options.targetLanguage.trim().length > 0
        ? options.targetLanguage.trim()
        : getLiveTargetLanguageValue(),
      metadata: {
        ...(options.metadata && typeof options.metadata === "object" && !Array.isArray(options.metadata)
          ? options.metadata
          : {}),
        inputMode: "voice_mic_translation",
        source: options.source === "ptt" ? "ptt" : "mic",
        speechRecognition: true,
        speechLanguage,
      },
    });
  clearMicSpeechComposerDraft();
  setMicSpeechUiPhase("sent", options.source === "ptt" ? "ptt" : "mic");
  return true;
}

function finalizePendingMicSpeechCapture(options = {}) {
  const shouldDispatch = options && options.dispatchTranslation === true;
  const transcript = resolveMicSpeechCaptureTranscript();
  const targetLanguage =
    typeof options.targetLanguage === "string" && options.targetLanguage.trim().length > 0
      ? options.targetLanguage.trim()
      : state.micCaptureTargetLanguage;
  const source = options.source === "ptt" ? "ptt" : state.micSpeechSource;
  const speechError = state.micSpeechError;
  const shouldTearDownMic = options && options.teardownMic === true;
  const shouldAppendAutoPauseNotice =
    (options && options.appendAutoPauseNotice === true) || state.micSpeechAutoPauseNoticePending === true;
  clearMicSpeechStopFinalizeTimer();
  resetMicSpeechCapture();

  let dispatched = false;
  if (shouldDispatch) {
    if (transcript.length === 0 && typeof speechError === "string" && speechError.length > 0) {
      clearMicSpeechComposerDraft({ restoreDraft: true });
    } else {
      dispatched = finalizeMicTranslationFromTranscript(transcript, {
        targetLanguage,
        source,
      });
    }
  } else {
    clearMicSpeechComposerDraft({ restoreDraft: true });
  }

  if (shouldTearDownMic) {
    teardownMicStreamResources();
    state.micCaptureIntent = null;
    state.micCaptureTargetLanguage = null;
    state.micCaptureSpeechLanguage = null;
    syncLiveControlButtonStates();
  }

  if (shouldAppendAutoPauseNotice && dispatched) {
    appendTranscript(
      "system",
      state.languageMode === "ru"
        ? "Пауза в речи распознана. Перевод отправлен, микрофон остановлен автоматически."
        : "Speech pause detected. Translation sent and mic stopped automatically.",
    );
  }

  return dispatched;
}

function beginMicSpeechCapture(options = {}) {
  const intent = typeof options.intent === "string" && options.intent.trim().length > 0
    ? options.intent.trim()
    : getCurrentLiveIntentValue();
  if (!shouldUseMicTranslationCapture(intent)) {
    return false;
  }

  const SpeechRecognitionCtor = getMicSpeechRecognitionCtor(globalThis);
  if (!SpeechRecognitionCtor) {
    state.micSpeechError = "unsupported";
    setMicSpeechUiPhase("error", "unsupported");
    if (!state.micSpeechUnavailableNotified) {
      appendTranscript(
        "error",
        state.languageMode === "ru"
          ? "Голосовой перевод требует SpeechRecognition в браузере. Используй Chrome/Edge на localhost или введи текст вручную."
          : "Voice translation requires browser SpeechRecognition support. Use Chrome/Edge on localhost or type the text manually.",
      );
      state.micSpeechUnavailableNotified = true;
    }
    return false;
  }

  if (state.micSpeechRecognition && typeof state.micSpeechRecognition.stop === "function") {
    try {
      state.micSpeechRecognition.stop();
    } catch {
      /* ignore stale speech-recognition instances */
    }
  }

  clearMicSpeechAutoStopTimer();
  clearMicSpeechStopFinalizeTimer();
  state.micSpeechTranscript = "";
  state.micSpeechInterimTranscript = "";
  state.micSpeechAutoPauseNoticePending = false;
  state.micSpeechDispatchPending = false;
  state.micSpeechSource = options.source === "ptt" ? "ptt" : "mic";
  state.micSpeechError = null;
  state.micCaptureIntent = intent;
  state.micCaptureTargetLanguage =
    typeof options.targetLanguage === "string" && options.targetLanguage.trim().length > 0
      ? options.targetLanguage.trim()
      : getLiveTargetLanguageValue();
  state.micCaptureSpeechLanguage =
    typeof options.speechLanguage === "string" && options.speechLanguage.trim().length > 0
      ? options.speechLanguage.trim()
      : getLiveSpeechLanguageValue();
  snapshotMicSpeechComposerDraft(intent);
  syncMicSpeechComposerPreview("");

  const recognition = new SpeechRecognitionCtor();
  recognition.lang = resolveMicSpeechRecognitionLocale();
  recognition.continuous = state.micSpeechSource === "ptt";
  recognition.interimResults = true;
  recognition.maxAlternatives = 1;
  recognition.onresult = (event) => {
    if (!event || !event.results) {
      return;
    }
    const finalParts = [];
    const interimParts = [];
    const startIndex = Number.isInteger(event.resultIndex) ? event.resultIndex : 0;
    for (let index = startIndex; index < event.results.length; index += 1) {
      const result = event.results[index];
      const alternative = result && result[0];
      const transcriptPart = normalizeMicSpeechTranscript(alternative && alternative.transcript);
      if (transcriptPart.length === 0) {
        continue;
      }
      if (result.isFinal) {
        finalParts.push(transcriptPart);
      } else {
        interimParts.push(transcriptPart);
      }
    }
    if (finalParts.length > 0) {
      state.micSpeechTranscript = normalizeMicSpeechTranscript(`${state.micSpeechTranscript} ${finalParts.join(" ")}`);
    }
    state.micSpeechInterimTranscript = normalizeMicSpeechTranscript(interimParts.join(" "));
    syncMicSpeechComposerPreview();
    setMicSpeechUiPhase(resolveMicSpeechCaptureTranscript().length > 0 ? "recognized" : "listening");
    scheduleMicSpeechAutoStop();
  };
  recognition.onspeechend = () => {
    scheduleMicSpeechAutoStop();
  };
  recognition.onaudioend = () => {
    scheduleMicSpeechAutoStop();
  };
  recognition.onerror = (event) => {
    const errorCode =
      event && typeof event.error === "string" && event.error.trim().length > 0 ? event.error.trim() : "unknown";
    state.micSpeechError = errorCode;
    if (errorCode === "aborted") {
      return;
    }
    if (errorCode === "no-speech" && state.micSpeechDispatchPending) {
      return;
    }
    setMicSpeechUiPhase("error", errorCode);
    appendTranscript(
      errorCode === "no-speech" ? "system" : "error",
      state.languageMode === "ru"
        ? `Голосовой перевод: ${errorCode === "no-speech" ? "речь не обнаружена" : `ошибка распознавания (${errorCode})`}.`
        : `Voice translation ${errorCode === "no-speech" ? "did not detect speech" : `speech-recognition error (${errorCode})`}.`,
    );
  };
  recognition.onend = () => {
    clearMicSpeechStopFinalizeTimer();
    const transcript = resolveMicSpeechCaptureTranscript();
    const targetLanguage = state.micCaptureTargetLanguage;
    const source = state.micSpeechSource;
    const shouldTearDownMic =
      source === "mic"
      && shouldUseMicTranslationCapture(state.micCaptureIntent)
      && (state.micSpeechDispatchPending === true || transcript.length > 0);
    const shouldAutoDispatch =
      state.micSpeechDispatchPending !== true
      && source === "mic"
      && shouldUseMicTranslationCapture(state.micCaptureIntent)
      && transcript.length > 0;
    const shouldDispatch = state.micSpeechDispatchPending || shouldAutoDispatch;
    finalizePendingMicSpeechCapture({
      dispatchTranslation: shouldDispatch,
      targetLanguage,
      source,
      teardownMic: shouldTearDownMic,
      appendAutoPauseNotice: shouldAutoDispatch || state.micSpeechAutoPauseNoticePending === true,
    });
  };

  try {
    recognition.start();
    state.micSpeechRecognition = recognition;
    setMicSpeechUiPhase("listening");
    return true;
  } catch (error) {
    clearMicSpeechComposerDraft({ restoreDraft: true });
    resetMicSpeechCapture();
    setMicSpeechUiPhase("error", "start_failed");
    appendTranscript("error", `Voice translation start failed: ${String(error)}`);
    return false;
  }
}

function endMicSpeechCapture(options = {}) {
  const shouldDispatch = options && options.dispatchTranslation === true;
  const source = options.source === "ptt" ? "ptt" : state.micSpeechSource;
  if (shouldDispatch) {
    setMicSpeechUiPhase("sending", source);
  } else if (shouldUseMicTranslationCapture(state.micCaptureIntent ?? getCurrentLiveIntentValue())) {
    setMicSpeechUiPhase("ready");
  }
  clearMicSpeechAutoStopTimer();
  if (state.micSpeechRecognition && typeof state.micSpeechRecognition.stop === "function") {
    state.micSpeechDispatchPending = shouldDispatch;
    clearMicSpeechStopFinalizeTimer();
    if (shouldDispatch && typeof setTimeout === "function") {
      state.micSpeechStopFinalizeTimer = setTimeout(() => {
        state.micSpeechStopFinalizeTimer = null;
        if (state.micSpeechDispatchPending !== true) {
          return;
        }
        finalizePendingMicSpeechCapture({
          dispatchTranslation: true,
          targetLanguage: state.micCaptureTargetLanguage,
          source,
          teardownMic: source === "mic" && shouldUseMicTranslationCapture(state.micCaptureIntent),
          appendAutoPauseNotice: state.micSpeechAutoPauseNoticePending === true,
        });
      }, 1200);
    }
    try {
      state.micSpeechRecognition.stop();
      return;
    } catch {
      /* fall through to direct finalize/reset */
    }
  }

  return finalizePendingMicSpeechCapture({
    dispatchTranslation: shouldDispatch,
    targetLanguage: state.micCaptureTargetLanguage,
    source,
    teardownMic: source === "mic" && shouldUseMicTranslationCapture(state.micCaptureIntent),
    appendAutoPauseNotice: state.micSpeechAutoPauseNoticePending === true,
  });
}

function teardownMicStreamResources() {
  const hadActiveMic = Boolean(state.micProcessor);
  if (state.micProcessor) {
    state.micProcessor.disconnect();
    state.micProcessor.onaudioprocess = null;
    state.micProcessor = null;
  }
  if (state.micGain) {
    state.micGain.disconnect();
    state.micGain = null;
  }
  if (state.micStream) {
    for (const track of state.micStream.getTracks()) {
      track.stop();
    }
    state.micStream = null;
  }
  if (state.micContext) {
    state.micContext.close();
    state.micContext = null;
  }
  return hadActiveMic;
}

function syncLiveControlButtonStates() {
  const socketConnected = isRealtimeSocketConnected();
  const micActive = Boolean(state.micProcessor);
  const micIntent = state.micCaptureIntent ?? getCurrentLiveIntentValue();
  const translationMicCapture = shouldUseMicTranslationCapture(micIntent);

  if (el.startMicBtn instanceof HTMLButtonElement) {
    el.startMicBtn.disabled = micActive || (!socketConnected && !translationMicCapture);
    el.startMicBtn.classList.toggle("is-active", micActive);
  }

  if (el.stopMicBtn instanceof HTMLButtonElement) {
    el.stopMicBtn.disabled = !micActive;
    el.stopMicBtn.classList.toggle("is-active", micActive);
  }

  if (el.pttToggleBtn instanceof HTMLButtonElement) {
    el.pttToggleBtn.disabled = !socketConnected;
    el.pttToggleBtn.classList.toggle("is-active", state.pttEnabled);
  }

  if (el.pttHoldBtn instanceof HTMLButtonElement) {
    const canHold = socketConnected && state.pttEnabled;
    el.pttHoldBtn.disabled = !canHold;
    el.pttHoldBtn.classList.toggle("is-active", canHold && state.pttPressed);
  }

  if (el.fallbackBtn instanceof HTMLButtonElement) {
    const fallbackEnabled = state.mode === "text-fallback";
    el.fallbackBtn.textContent = fallbackEnabled ? t("live.controls.returnToVoice") : t("live.controls.textFallback");
    el.fallbackBtn.classList.toggle("is-active", fallbackEnabled);
  }
}

function setConnectionStatus(text) {
  const normalized = typeof text === "string" ? text : "disconnected";
  state.connectionStatus = normalized;
  let variant = "neutral";
  if (normalized === "connected") {
    variant = "ok";
  } else if (normalized === "disconnected" || normalized === "error") {
    variant = "fail";
  }
  setStatusPill(el.connectionStatus, normalized, variant);
  renderAssistantActivityStatus();
  syncLiveControlButtonStates();
  renderLiveContextDock();
  renderDashboardWorkspace();
}

function resolveSessionStateVariant(text) {
  const normalized = typeof text === "string" ? text.trim().toLowerCase() : "";
  if (!normalized || normalized === "-" || normalized === "idle" || normalized === "unknown") {
    return "neutral";
  }
  if (
    normalized.includes("ready") ||
    normalized.includes("active") ||
    normalized.includes("running") ||
    normalized.includes("connected")
  ) {
    return "ok";
  }
  if (
    normalized.includes("error") ||
    normalized.includes("fail") ||
    normalized.includes("disconnect") ||
    normalized.includes("timeout") ||
    normalized.includes("drain")
  ) {
    return "fail";
  }
  return "neutral";
}

function setSessionState(text) {
  const normalized = typeof text === "string" && text.trim().length > 0 ? text.trim() : "-";
  state.sessionState = normalized;
  setStatusPill(el.sessionState, normalized, resolveSessionStateVariant(normalized));
  renderDashboardWorkspace();
}

function resolveModeStatusVariant(mode) {
  const normalized = typeof mode === "string" ? mode.trim().toLowerCase() : "";
  if (normalized === "voice") {
    return "ok";
  }
  return "neutral";
}

function setMode(mode) {
  const normalized = typeof mode === "string" && mode.trim().length > 0 ? mode.trim() : "voice";
  state.mode = normalized;
  setStatusPill(el.modeStatus, normalized, resolveModeStatusVariant(normalized));
  syncLiveControlButtonStates();
}

function setPttStatus(text, variant = "neutral") {
  if (!el.pttStatus) {
    return;
  }
  setStatusPill(el.pttStatus, text, variant);
}

function setStatusTextValue(node, text, fallback = "-") {
  if (!(node instanceof HTMLElement)) {
    return;
  }
  const normalized = typeof text === "string" && text.trim().length > 0 ? text.trim() : fallback;
  node.textContent = normalized;
  node.title = normalized === fallback ? "" : normalized;
}

function resetPlaybackTracking() {
  state.assistantPlaybackTurnId = null;
  state.assistantPlaybackStartedAtMs = null;
  state.assistantPlaybackScheduledMs = 0;
}

function estimateAssistantPlaybackMs() {
  if (!state.assistantPlaybackStartedAtMs || state.assistantPlaybackScheduledMs <= 0) {
    return 0;
  }
  const elapsedMs = Math.max(0, Date.now() - state.assistantPlaybackStartedAtMs);
  return Math.min(Math.floor(elapsedMs), Math.floor(state.assistantPlaybackScheduledMs));
}

function normalizeApiBaseUrl(value) {
  if (typeof value !== "string") {
    return state.apiBaseUrl;
  }
  const trimmed = value.trim();
  if (trimmed.length === 0) {
    return state.apiBaseUrl;
  }
  return trimmed.replace(/\/+$/, "");
}

async function loadRuntimeConfig() {
  try {
    const response = await fetch("/config.json", {
      method: "GET",
      cache: "no-store",
    });
    if (!response.ok) {
      return null;
    }
    const payload = await response.json();
    const runtime = payload && typeof payload.runtime === "object" ? payload.runtime : null;
    if (!runtime) {
      return null;
    }
    const wsUrl = typeof runtime.wsUrl === "string" && runtime.wsUrl.trim().length > 0 ? runtime.wsUrl.trim() : null;
    const apiBaseUrl =
      typeof runtime.apiBaseUrl === "string" && runtime.apiBaseUrl.trim().length > 0 ? runtime.apiBaseUrl.trim() : null;
    if (!wsUrl && !apiBaseUrl) {
      return null;
    }
    return {
      wsUrl,
      apiBaseUrl,
    };
  } catch {
    return null;
  }
}

function toOptionalText(value) {
  return typeof value === "string" && value.trim().length > 0 ? value.trim() : null;
}

function normalizeDeviceNode(value) {
  if (!value || typeof value !== "object") {
    return null;
  }
  const nodeId = toOptionalText(value.nodeId);
  if (!nodeId) {
    return null;
  }
  const status = toOptionalText(value.status) ?? "online";
  const kind = toOptionalText(value.kind) ?? "desktop";
  const displayName = toOptionalText(value.displayName) ?? nodeId;
  const capabilities = Array.isArray(value.capabilities)
    ? value.capabilities.filter((item) => typeof item === "string" && item.trim().length > 0)
    : [];
  return {
    nodeId,
    displayName,
    kind,
    platform: toOptionalText(value.platform) ?? "unknown",
    executorUrl: toOptionalText(value.executorUrl),
    status,
    trustLevel: toOptionalText(value.trustLevel) ?? "reviewed",
    version: typeof value.version === "number" ? value.version : null,
    lastSeenAt: toOptionalText(value.lastSeenAt),
    updatedAt: toOptionalText(value.updatedAt),
    capabilities,
  };
}

function parseCapabilitiesCsv(value) {
  if (typeof value !== "string") {
    return [];
  }
  const seen = new Set();
  const deduped = [];
  for (const item of value.split(",")) {
    const normalized = item.trim().toLowerCase();
    if (!normalized || seen.has(normalized)) {
      continue;
    }
    seen.add(normalized);
    deduped.push(normalized);
  }
  return deduped;
}

function parseOptionalMetadataJson(value) {
  if (typeof value !== "string" || value.trim().length === 0) {
    return null;
  }
  return JSON.parse(value);
}

function appendEntry(container, kind, title, message, options = {}) {
  const entry = document.createElement("div");
  entry.className = `entry ${kind}`;
  const titleNode = document.createElement("small");
  titleNode.className = "entry-meta";
  const roleNode = document.createElement("span");
  roleNode.className = "entry-role";
  roleNode.textContent = title;
  const timeNode = document.createElement("span");
  timeNode.className = "entry-time";
  const timestampLabel =
    options && typeof options.timestampLabel === "string" && options.timestampLabel.trim().length > 0
      ? options.timestampLabel.trim()
      : nowLabel();
  timeNode.textContent = timestampLabel;
  titleNode.append(roleNode, timeNode);
  const bodyNode = document.createElement("div");
  bodyNode.className = "entry-body";
  bodyNode.textContent = message;
  entry.appendChild(titleNode);
  entry.appendChild(bodyNode);
  container.prepend(entry);
  return entry;
}

function getLiveConversationRoleLabel(role) {
  const normalized = typeof role === "string" ? role.trim().toLowerCase() : "";
  const isRu = state.languageMode === "ru";
  if (normalized === "assistant") {
    return isRu ? "\u0410\u0433\u0435\u043d\u0442" : "Agent";
  }
  if (normalized === "user") {
    return isRu ? "\u0422\u044b" : "You";
  }
  if (normalized === "error") {
    return isRu ? "\u041e\u0448\u0438\u0431\u043a\u0430" : "Error";
  }
  return role;
}

function normalizeLiveConversationIntent(value) {
  const normalized = typeof value === "string" ? value.trim() : "";
  if (LIVE_INTENT_PRIMARY_CARD_ORDER.includes(normalized) || LIVE_INTENT_SECONDARY_CARD_ORDER.includes(normalized)) {
    return normalized;
  }
  return "conversation";
}

function resolveLiveConversationIntent(intent = null) {
  if (typeof intent === "string" && intent.trim().length > 0) {
    return normalizeLiveConversationIntent(intent);
  }
  return normalizeLiveConversationIntent(getCurrentLiveIntentValue());
}

function filterLiveConversationHistoryByIntent(history, intent) {
  const normalizedIntent = normalizeLiveConversationIntent(intent);
  if (!Array.isArray(history)) {
    return [];
  }
  return history.filter((entry) => {
    if (!entry || typeof entry !== "object") {
      return false;
    }
    if (typeof entry.text !== "string" || entry.text.trim().length <= 0) {
      return false;
    }
    return normalizeLiveConversationIntent(entry.intent) === normalizedIntent;
  });
}

function renderConversationHistory() {
  if (!(el.conversationHistory instanceof HTMLElement)) {
    return;
  }
  el.conversationHistory.replaceChildren();
  const currentIntent = normalizeLiveConversationIntent(getCurrentLiveIntentValue());
  const visibleEntries = filterLiveConversationHistoryByIntent(state.liveConversationHistory, currentIntent);
  for (const entry of visibleEntries) {
    const role = entry.role === "assistant" || entry.role === "user" ? entry.role : "error";
    const displayText =
      role === "assistant"
        ? rewriteUiTaskDraftDemoResponseText(currentIntent, null, entry.text)
        : entry.text;
    appendEntry(el.conversationHistory, role, getLiveConversationRoleLabel(role), displayText, {
      timestampLabel: entry.timestampLabel,
    });
  }
}

function resetLiveConversationHistory() {
  state.liveConversationHistory = [];
  renderConversationHistory();
}

function resolveLivePendingSubmitCopy(intent, phase = "awaiting_response") {
  const normalizedIntent = resolveLiveConversationIntent(intent);
  const isRu = state.languageMode === "ru";
  if (phase === "connecting") {
    return {
      label: isRu ? "\u041f\u043e\u0434\u043a\u043b\u044e\u0447\u0430\u0435\u043c..." : "Connecting...",
      hint: isRu
        ? "\u041e\u0442\u043a\u0440\u044b\u0432\u0430\u0435\u043c live-\u0441\u0435\u0441\u0441\u0438\u044e \u0438 \u043e\u0442\u043f\u0440\u0430\u0432\u0438\u043c \u0437\u0430\u043f\u0440\u043e\u0441 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438."
        : "Opening the live session and sending automatically.",
    };
  }
  if (normalizedIntent === "translation") {
    return {
      label: isRu ? "\u041f\u0435\u0440\u0435\u0432\u043e\u0434\u0438\u043c..." : "Translating...",
      hint: isRu
        ? "\u0422\u0435\u043a\u0441\u0442 \u0443\u0436\u0435 \u043e\u0442\u043f\u0440\u0430\u0432\u043b\u0435\u043d. \u0416\u0434\u0435\u043c \u043d\u043e\u0432\u044b\u0439 \u043f\u0435\u0440\u0435\u0432\u043e\u0434 \u0441\u043f\u0440\u0430\u0432\u0430."
        : "The text was sent. Wait for the fresh translation on the right.",
    };
  }
  if (normalizedIntent === "negotiation") {
    return {
      label: isRu ? "\u0413\u043e\u0442\u043e\u0432\u0438\u043c \u043e\u0442\u0432\u0435\u0442..." : "Preparing reply...",
      hint: isRu
        ? "\u041e\u0444\u0444\u0435\u0440 \u043e\u0442\u043f\u0440\u0430\u0432\u043b\u0435\u043d. \u0416\u0434\u0435\u043c \u043e\u0442\u0432\u0435\u0442 \u043d\u0430 \u043f\u0435\u0440\u0435\u0433\u043e\u0432\u043e\u0440\u044b."
        : "The offer was sent. Waiting for the negotiation reply.",
    };
  }
  if (normalizedIntent === "research") {
    return {
      label: isRu ? "\u0418\u0449\u0435\u043c \u043e\u0442\u0432\u0435\u0442..." : "Researching...",
      hint: isRu
        ? "\u0417\u0430\u043f\u0440\u043e\u0441 \u043e\u0442\u043f\u0440\u0430\u0432\u043b\u0435\u043d. \u041a\u043e\u0433\u0434\u0430 \u043e\u0442\u0432\u0435\u0442 \u0431\u0443\u0434\u0435\u0442 \u0433\u043e\u0442\u043e\u0432, \u043e\u043d \u043f\u043e\u044f\u0432\u0438\u0442\u0441\u044f \u0441\u043f\u0440\u0430\u0432\u0430."
        : "The request was sent. The sourced answer will appear on the right.",
    };
  }
  if (normalizedIntent === "story") {
    return {
      label: isRu ? "\u0421\u043e\u0431\u0438\u0440\u0430\u0435\u043c \u0438\u0441\u0442\u043e\u0440\u0438\u044e..." : "Building story...",
      hint: isRu
        ? "\u0417\u0430\u043f\u0440\u043e\u0441 \u043d\u0430 \u0438\u0441\u0442\u043e\u0440\u0438\u044e \u0443\u0436\u0435 \u043e\u0442\u043f\u0440\u0430\u0432\u043b\u0435\u043d. \u041f\u043e\u0434\u043e\u0436\u0434\u0438 \u043d\u043e\u0432\u044b\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442."
        : "The story request was sent. Wait for the new result.",
    };
  }
  if (normalizedIntent === "ui_task") {
    return {
      label: isRu ? "\u0413\u043e\u0442\u043e\u0432\u0438\u043c \u043f\u043b\u0430\u043d..." : "Preparing plan...",
      hint: isRu
        ? "\u0417\u0430\u0434\u0430\u0447\u0430 \u0443\u0436\u0435 \u043e\u0442\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0430. \u0416\u0434\u0435\u043c \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u044b\u0439 \u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0438\u0439 \u0448\u0430\u0433."
        : "The task was sent. Waiting for the safe next step.",
    };
  }
  return {
    label: isRu ? "\u0416\u0434\u0435\u043c \u043e\u0442\u0432\u0435\u0442..." : "Waiting for reply...",
    hint: isRu
      ? "\u0417\u0430\u043f\u0440\u043e\u0441 \u0443\u0436\u0435 \u043e\u0442\u043f\u0440\u0430\u0432\u043b\u0435\u043d. \u041f\u043e\u0434\u043e\u0436\u0434\u0438 \u043e\u0442\u0432\u0435\u0442 \u0430\u0433\u0435\u043d\u0442\u0430."
      : "The request was sent. Wait for the agent reply.",
  };
}

function resolveLivePendingRequest() {
  if (!state.livePendingRequest || typeof state.livePendingRequest !== "object") {
    return null;
  }
  return {
    intent: resolveLiveConversationIntent(state.livePendingRequest.intent),
    phase: state.livePendingRequest.phase === "connecting" ? "connecting" : "awaiting_response",
    runId:
      typeof state.livePendingRequest.runId === "string" && state.livePendingRequest.runId.trim().length > 0
        ? state.livePendingRequest.runId.trim()
        : null,
    requestedAt:
      typeof state.livePendingRequest.requestedAt === "string" && state.livePendingRequest.requestedAt.trim().length > 0
        ? state.livePendingRequest.requestedAt.trim()
        : null,
  };
}

function syncLiveIntentSubmitState(composeConfig = null) {
  const currentIntent = resolveLiveConversationIntent(getCurrentLiveIntentValue());
  const currentConfig = composeConfig ?? getLiveIntentComposerConfig(currentIntent);
  const pendingRequest = resolveLivePendingRequest();
  const isPending = pendingRequest !== null;
  const pendingCopy = isPending
    ? resolveLivePendingSubmitCopy(pendingRequest.intent, pendingRequest.phase)
    : null;

  if (el.sendBtn instanceof HTMLButtonElement) {
    el.sendBtn.textContent = pendingCopy ? pendingCopy.label : currentConfig.sendLabel;
    el.sendBtn.disabled = isPending;
    el.sendBtn.classList.toggle("is-pending", isPending);
    el.sendBtn.setAttribute("aria-busy", isPending ? "true" : "false");
    if (isPending) {
      el.sendBtn.dataset.pendingPhase = pendingRequest.phase;
    } else {
      delete el.sendBtn.dataset.pendingPhase;
    }
  }
  if (el.sendBtnHint instanceof HTMLElement) {
    el.sendBtnHint.textContent = pendingCopy ? pendingCopy.hint : currentConfig.sendHint;
    el.sendBtnHint.classList.toggle("is-pending", isPending);
  }
}

function setLivePendingRequest(intent, options = {}) {
  const requestedAt = toIsoNow();
  state.liveLastRequestAt = requestedAt;
  state.livePendingRequest = {
    intent: resolveLiveConversationIntent(intent),
    phase: options.phase === "connecting" ? "connecting" : "awaiting_response",
    runId: typeof options.runId === "string" && options.runId.trim().length > 0 ? options.runId.trim() : null,
    requestedAt,
  };
  renderLiveIntentExperience();
  showThinkingIndicator();
}

function clearLivePendingRequest() {
  state.livePendingRequest = null;
  renderLiveIntentExperience();
  hideThinkingIndicator();
}

function hasLiveRequestInFlight() {
  if (resolveLivePendingRequest() !== null) {
    return true;
  }
  return Boolean(
    state.pendingIntentRequest &&
      typeof state.pendingIntentRequest === "object" &&
      state.pendingIntentRequest.conversation !== "none",
  );
}

function resolveLiveRuntimeFailureCopy(kind = "transport") {
  const normalizedKind = typeof kind === "string" ? kind.trim().toLowerCase() : "transport";
  if (state.languageMode === "ru") {
    if (normalizedKind === "gateway") {
      return "Live runtime вернул ошибку. Проверь системный лог и попробуй запрос еще раз.";
    }
    if (normalizedKind === "protocol") {
      return "Live runtime прислал некорректный ответ. Проверь системный лог и повтори запрос.";
    }
    return "Соединение с Live runtime потеряно. Переподключи сессию и отправь запрос еще раз.";
  }
  if (normalizedKind === "gateway") {
    return "The live runtime returned an error. Check the system log, then try the request again.";
  }
  if (normalizedKind === "protocol") {
    return "The live runtime returned an invalid response. Check the system log, then try again.";
  }
  return "The connection to the live runtime was lost. Reconnect the session and send the request again.";
}

function reportLiveRuntimeFailure(kind, technicalMessage, options = {}) {
  const technicalText =
    typeof technicalMessage === "string" && technicalMessage.trim().length > 0
      ? technicalMessage.trim()
      : "Live runtime failure";
  appendTranscript("error", technicalText, { exposeInLiveResult: false });
  if (options.surfaceInResult === false) {
    return;
  }
  const intent =
    typeof options.intent === "string" && options.intent.trim().length > 0
      ? options.intent.trim()
      : state.lastRequestedIntent;
  const userMessage =
    typeof options.userMessage === "string" && options.userMessage.trim().length > 0
      ? options.userMessage.trim()
      : resolveLiveRuntimeFailureCopy(kind);
  setLiveResult("error", userMessage, {
    intent,
    streaming: false,
  });
}

function focusPrimaryLiveFieldForIntent(intent) {
  const focusTarget = el.message instanceof HTMLTextAreaElement ? el.message : null;
  if (!(focusTarget instanceof HTMLElement)) {
    return;
  }
  window.requestAnimationFrame(() => {
    focusTarget.focus();
    if (focusTarget instanceof HTMLTextAreaElement) {
      const caret = focusTarget.value.length;
      focusTarget.setSelectionRange(caret, caret);
    }
  });
}

function renderLiveIntentCards() {
  if (!(el.liveIntentCards instanceof HTMLElement)) {
    return;
  }
  const currentIntent =
    el.intent instanceof HTMLSelectElement && typeof el.intent.value === "string" && el.intent.value.trim().length > 0
      ? el.intent.value.trim()
      : "conversation";
  const definitions = getLiveIntentCardDefinitions();
  const isRu = state.languageMode === "ru";
  el.liveIntentCards.replaceChildren();
  if (el.liveIntentSecondaryActions instanceof HTMLElement) {
    el.liveIntentSecondaryActions.replaceChildren();
  }
  el.liveIntentCards.setAttribute(
    "aria-label",
    isRu ? "\u041e\u0441\u043d\u043e\u0432\u043d\u044b\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044f \u0436\u0438\u0432\u043e\u0433\u043e \u0434\u0438\u0430\u043b\u043e\u0433\u0430" : "Primary live actions",
  );
  if (el.liveIntentSecondaryActions instanceof HTMLElement) {
    el.liveIntentSecondaryActions.setAttribute(
      "aria-label",
      isRu ? "\u0412\u0442\u043e\u0440\u0438\u0447\u043d\u044b\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044f \u0436\u0438\u0432\u043e\u0433\u043e \u0434\u0438\u0430\u043b\u043e\u0433\u0430" : "Secondary live actions",
    );
  }

  const renderIntentButton = (intentKey, container, variant = "primary") => {
    if (!(container instanceof HTMLElement)) {
      return;
    }
    const cardConfig = definitions[intentKey];
    if (!cardConfig) {
      return;
    }
    const button = document.createElement("button");
    button.type = "button";
    button.className = variant === "secondary" ? "live-intent-option live-intent-option-secondary" : "live-intent-option";
    button.dataset.intentCard = intentKey;
    button.setAttribute("aria-pressed", intentKey === currentIntent ? "true" : "false");
    if (intentKey === currentIntent) {
      button.classList.add("is-active");
    }

    const label = document.createElement("span");
    label.className = "live-intent-option-label";
    label.textContent = cardConfig.label;

    const title = document.createElement("span");
    title.className = "live-intent-option-title";
    title.textContent = cardConfig.title;

    button.append(label, title);
    if (variant !== "secondary") {
      const hint = document.createElement("span");
      hint.className = "live-intent-option-hint";
      hint.textContent = cardConfig.hint;
      button.append(hint);
    }
    button.addEventListener("click", () => {
      if (el.intent instanceof HTMLSelectElement) {
        if (el.intent.value !== intentKey) {
          el.intent.value = intentKey;
        }
        if (
          intentKey === "translation" &&
          (el.targetLanguage instanceof HTMLInputElement || el.targetLanguage instanceof HTMLSelectElement) &&
          el.targetLanguage.value.trim().length === 0
        ) {
          el.targetLanguage.value = "en";
          if (el.targetLanguage instanceof HTMLSelectElement) {
            syncCustomSelectControl(el.targetLanguage);
          }
        }
        setUiTaskFieldsVisibility();
      } else {
        renderLiveIntentExperience();
      }
      focusPrimaryLiveFieldForIntent(intentKey);
    });
    container.append(button);
  };

  for (const intentKey of LIVE_INTENT_PRIMARY_CARD_ORDER) {
    renderIntentButton(intentKey, el.liveIntentCards, "primary");
  }
  if (el.liveIntentSecondaryActions instanceof HTMLElement) {
    for (const intentKey of LIVE_INTENT_SECONDARY_CARD_ORDER) {
      renderIntentButton(intentKey, el.liveIntentSecondaryActions, "secondary");
    }
  }
}

function renderLiveIntentExperience() {
  const intent = el.intent instanceof HTMLSelectElement ? el.intent.value : state.lastRequestedIntent;
  const normalizedIntent = typeof intent === "string" && intent.trim().length > 0 ? intent.trim() : "conversation";
  const config = getResolvedLiveIntentExperienceConfig(intent);
  const composeConfig = getLiveIntentComposerConfig(intent);
  if (el.liveIntentStageLabel instanceof HTMLElement) {
    el.liveIntentStageLabel.textContent =
      state.languageMode === "ru" ? "\u041e\u0441\u043d\u043e\u0432\u043d\u044b\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044f" : "Main actions";
  }
  if (el.liveIntentStageHint instanceof HTMLElement) {
    el.liveIntentStageHint.textContent =
      state.languageMode === "ru"
        ? "\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0432\u044b\u0431\u0435\u0440\u0438 \u0433\u043b\u0430\u0432\u043d\u043e\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435. \u0421\u043b\u0443\u0436\u0435\u0431\u043d\u044b\u0435 \u0441\u043b\u043e\u0438 \u043e\u0441\u0442\u0430\u044e\u0442\u0441\u044f \u0432\u044b\u0448\u0435."
        : "Choose the main action first. Main compose stays here; tools open below.";
  }
  if (el.liveIntentSecondaryLabel instanceof HTMLElement) {
    el.liveIntentSecondaryLabel.textContent = t("live.compose.secondaryTitle", null, "Workflow tools");
  }
  if (el.liveIntentSecondaryHint instanceof HTMLElement) {
    el.liveIntentSecondaryHint.textContent = t(
      "live.compose.secondaryHint",
      null,
      "Open when the case needs a browser task or a story run.",
    );
  }
  renderLiveIntentCards();
  renderLiveContextDock();
  if (el.liveSupportPanelTitle instanceof HTMLElement) {
    el.liveSupportPanelTitle.textContent = config.panelTitle;
  }
  if (el.liveSupportPanelIntro instanceof HTMLElement) {
    el.liveSupportPanelIntro.textContent = config.panelIntro;
  }
  if (el.liveResultKicker instanceof HTMLElement) {
    el.liveResultKicker.textContent = state.languageMode === "ru" ? "\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0447\u0438\u0442\u0430\u0439" : "Read first";
  }
  if (el.conversationHistoryKicker instanceof HTMLElement) {
    el.conversationHistoryKicker.textContent = state.languageMode === "ru" ? "\u0420\u0435\u043f\u043b\u0438\u043a\u0438" : "Turns";
  }
  if (el.conversationHistoryTitle instanceof HTMLElement) {
    el.conversationHistoryTitle.textContent = config.conversationTitle;
  }
  if (el.conversationHistoryHint instanceof HTMLElement) {
    el.conversationHistoryHint.textContent = config.conversationHint;
  }
  if (el.conversationHistory instanceof HTMLElement) {
    el.conversationHistory.setAttribute(
      "data-empty-text",
      state.languageMode === "ru" ? "История диалога пока пуста." : "No conversation turns yet.",
    );
  }
  if (el.conversationHistory instanceof HTMLElement) {
    el.conversationHistory.setAttribute("data-empty-text", config.historyEmpty ?? "No conversation turns yet.");
  }
  if (el.liveTechnicalTimelineTitle instanceof HTMLElement) {
    el.liveTechnicalTimelineTitle.textContent = config.technicalTitle;
  }
  if (el.liveTechnicalTimelineHint instanceof HTMLElement) {
    el.liveTechnicalTimelineHint.textContent = config.technicalHint;
  }
  if (el.kpiPanel instanceof HTMLElement) {
    el.kpiPanel.hidden = !config.showKpi;
    el.kpiPanel.setAttribute("aria-hidden", config.showKpi ? "false" : "true");
  }
  if (el.liveComposeModeChip instanceof HTMLElement) {
    el.liveComposeModeChip.textContent = composeConfig.modeChip;
  }
  if (el.liveComposeHelper instanceof HTMLElement) {
    el.liveComposeHelper.textContent = composeConfig.helper;
  }
  const composeGuidanceShell =
    el.liveComposeModeChip instanceof HTMLElement ? el.liveComposeModeChip.closest(".live-compose-guidance") : null;
  if (composeGuidanceShell instanceof HTMLElement) {
    const showComposeGuidance = composeConfig.showComposeGuidance !== false;
    composeGuidanceShell.hidden = !showComposeGuidance;
    composeGuidanceShell.setAttribute("aria-hidden", showComposeGuidance ? "false" : "true");
  }
  if (el.messageFieldLabel instanceof HTMLElement) {
    el.messageFieldLabel.textContent = composeConfig.messageLabel;
  }
  if (el.messageFieldHint instanceof HTMLElement) {
    el.messageFieldHint.textContent = composeConfig.messageHint;
  }
  if (el.message instanceof HTMLTextAreaElement) {
    el.message.placeholder = composeConfig.messagePlaceholder;
  }
  if (el.intentLanguageField instanceof HTMLElement) {
    el.intentLanguageField.hidden = !composeConfig.showTargetLanguage;
    el.intentLanguageField.setAttribute("aria-hidden", composeConfig.showTargetLanguage ? "false" : "true");
  }
  if (el.targetLanguageLabel instanceof HTMLElement) {
    el.targetLanguageLabel.textContent = composeConfig.targetLanguageLabel;
  }
  if (el.targetLanguageHint instanceof HTMLElement) {
    el.targetLanguageHint.textContent = composeConfig.targetLanguageHint;
  }
  if (el.speechLanguageField instanceof HTMLElement) {
    el.speechLanguageField.hidden = !composeConfig.showSpeechLanguage;
    el.speechLanguageField.setAttribute("aria-hidden", composeConfig.showSpeechLanguage ? "false" : "true");
  }
  if (el.speechLanguageLabel instanceof HTMLElement) {
    el.speechLanguageLabel.textContent = composeConfig.speechLanguageLabel;
  }
  if (el.speechLanguageHint instanceof HTMLElement) {
    el.speechLanguageHint.textContent = composeConfig.speechLanguageHint;
  }
  syncLiveTranslationDirectionSummary(normalizedIntent);
  if (el.translationDirectionSummary instanceof HTMLElement) {
    const showDirectionSummary = composeConfig.showDirectionSummary === true;
    el.translationDirectionSummary.hidden = !showDirectionSummary;
    el.translationDirectionSummary.setAttribute("aria-hidden", showDirectionSummary ? "false" : "true");
  }
  syncMicSpeechComposerStatus(normalizedIntent);
  /* Show/hide negotiate structured fields vs textarea */
  const isNegotiate = normalizedIntent === "negotiation";
  const negotiateFields = document.getElementById("negotiateOfferFields");
  const messageField = document.querySelector(".intent-field-message");
  if (negotiateFields) {
    negotiateFields.hidden = !isNegotiate;
  }
  if (messageField instanceof HTMLElement) {
    messageField.hidden = isNegotiate;
  }

  const latestResult = state.liveResult;
  const pendingRequest = resolveLivePendingRequest();
  const awaitingFreshResponse =
    pendingRequest !== null && resolveLiveConversationIntent(pendingRequest.intent) === normalizedIntent;
  const hasIntentMatchedResult =
    latestResult &&
    typeof latestResult.text === "string" &&
    latestResult.text.trim().length > 0 &&
    latestResult.intent === intent;
  const summaryConfig = getLiveResultSummaryConfig(intent, latestResult, hasIntentMatchedResult);

  renderCaseWorkspaceSummary(intent, latestResult, pendingRequest, awaitingFreshResponse, summaryConfig);
  renderCaseWorkspaceFlow(awaitingFreshResponse);

  if (el.liveResultLabel instanceof HTMLElement) {
    el.liveResultLabel.textContent = config.resultLabel;
  }
  if (el.liveResultBody instanceof HTMLElement) {
    const displayLatestResultText =
      hasIntentMatchedResult && latestResult.role === "assistant"
        ? rewriteUiTaskDraftDemoResponseText(normalizedIntent, null, latestResult.text)
        : latestResult?.text;
    el.liveResultBody.textContent = hasIntentMatchedResult
      ? displayLatestResultText
      : awaitingFreshResponse
        ? (config.pendingResult ?? config.emptyResult)
        : config.emptyResult;
  }
  if (el.liveResultCard instanceof HTMLElement) {
    el.liveResultCard.classList.toggle("is-empty", !hasIntentMatchedResult);
    el.liveResultCard.classList.toggle("is-pending", !hasIntentMatchedResult && awaitingFreshResponse);
    el.liveResultCard.classList.toggle("is-error", hasIntentMatchedResult && latestResult.role === "error");
    el.liveResultCard.classList.toggle("is-streaming", hasIntentMatchedResult && latestResult.streaming === true);
    el.liveResultCard.classList.toggle("is-ready", hasIntentMatchedResult && latestResult.role !== "error" && latestResult.streaming !== true);
    el.liveResultCard.dataset.intent = intent;
  }
  if (el.liveResultMeta instanceof HTMLElement) {
    const metaText = hasIntentMatchedResult
      ? latestResult.streaming === true
        ? (config.streamingMeta ?? (state.languageMode === "ru" ? "Ассистент печатает..." : "Assistant is streaming..."))
        : config.resultMeta
      : awaitingFreshResponse
        ? (config.pendingMeta ?? config.resultMeta)
        : config.resultMeta;
    setStatusPill(
      el.liveResultMeta,
      metaText,
      hasIntentMatchedResult
        ? latestResult.streaming === true
          ? "ok"
          : (latestResult.role === "error" ? "fail" : "ok")
        : (awaitingFreshResponse ? "neutral" : "neutral"),
    );
  }
  if (el.liveResultActionBtn instanceof HTMLButtonElement) {
    const actionConfig = getLiveResultActionConfig(intent, latestResult, hasIntentMatchedResult);
    if (actionConfig) {
      el.liveResultActionBtn.hidden = false;
      el.liveResultActionBtn.textContent = actionConfig.label;
      el.liveResultActionBtn.dataset.action = actionConfig.action;
    } else {
      el.liveResultActionBtn.hidden = true;
      el.liveResultActionBtn.textContent = "";
      delete el.liveResultActionBtn.dataset.action;
    }
  }
  if (el.liveResultSummary instanceof HTMLElement) {
    el.liveResultSummary.hidden = !summaryConfig;
    el.liveResultSummary.setAttribute("aria-hidden", summaryConfig ? "false" : "true");
    if (el.liveResultSummaryTitle instanceof HTMLElement) {
      el.liveResultSummaryTitle.textContent = summaryConfig?.title ?? "";
    }
    if (el.liveResultSummaryList instanceof HTMLElement) {
      el.liveResultSummaryList.replaceChildren();
      for (const item of summaryConfig?.items ?? []) {
        const row = document.createElement("div");
        row.className = "live-result-summary-item";

        const label = document.createElement("span");
        label.className = "live-result-summary-label";
        label.textContent = item.label;

        const value = document.createElement("span");
        value.className = "live-result-summary-value";
        value.textContent = item.value;

        row.append(label, value);
        el.liveResultSummaryList.append(row);
      }
    }
    if (el.liveResultSummaryHandoff instanceof HTMLElement) {
      if (summaryConfig?.handoff) {
        el.liveResultSummaryHandoff.hidden = false;
        el.liveResultSummaryHandoff.textContent = `${summaryConfig.handoff.label}: ${summaryConfig.handoff.value}`;
      } else {
        el.liveResultSummaryHandoff.hidden = true;
        el.liveResultSummaryHandoff.textContent = "";
      }
    }
    if (el.liveResultSummaryCopyBtn instanceof HTMLButtonElement) {
      if (summaryConfig) {
        el.liveResultSummaryCopyBtn.hidden = false;
        el.liveResultSummaryCopyBtn.disabled = false;
        el.liveResultSummaryCopyBtn.textContent = summaryConfig.copyLabel ?? t("live.result.visaSummaryCopy", null, "Copy operator summary");
      } else {
        el.liveResultSummaryCopyBtn.hidden = true;
        el.liveResultSummaryCopyBtn.disabled = true;
        el.liveResultSummaryCopyBtn.textContent = "";
      }
    }
  }
  if (el.conversationHistory instanceof HTMLElement) {
    el.conversationHistory.setAttribute(
      "data-empty-text",
      awaitingFreshResponse ? (config.historyPending ?? config.historyEmpty ?? "No conversation turns yet.") : (config.historyEmpty ?? "No conversation turns yet."),
    );
    el.conversationHistory.classList.toggle("is-awaiting", awaitingFreshResponse);
  }
  renderConversationHistory();
  syncLiveIntentSubmitState(composeConfig);
  if (pendingRequest !== null) {
    showThinkingIndicator();
  } else {
    hideThinkingIndicator();
  }
  if (el.transcript instanceof HTMLElement) {
    el.transcript.setAttribute("data-empty-text", config.technicalEmpty ?? "Runtime and queue events appear here only when they matter.");
  }
}

function setLiveResult(role, text, options = {}) {
  const normalizedText = typeof text === "string" ? text.trim() : "";
  if (normalizedText.length === 0) {
    renderLiveIntentExperience();
    renderStoryStudioSurface();
    renderDashboardWorkspace();
    return;
  }
  const intent =
    typeof options.intent === "string" && options.intent.trim().length > 0
      ? options.intent.trim()
      : state.lastRequestedIntent;
  const displayText =
    role === "assistant"
      ? rewriteUiTaskDraftDemoResponseText(resolveLiveConversationIntent(intent), null, normalizedText)
      : normalizedText;
  state.liveResult = {
    intent,
    role,
    text: displayText,
    streaming: options.streaming === true,
    updatedAt: new Date().toISOString(),
  };
  if (intent === "story") {
    state.storyLatestResult = {
      role,
      text: displayText,
      streaming: options.streaming === true,
      updatedAt: toIsoNow(),
    };
    if (options.streaming !== true) {
      pushStoryLatestHistoryEntry(role, displayText, { updatedAt: state.storyLatestResult.updatedAt });
    }
  }
  renderLiveIntentExperience();
  renderStoryStudioSurface();
  renderDashboardWorkspace();
}

function appendConversationHistory(role, text, options = {}) {
  const normalizedText = typeof text === "string" ? text.trim() : "";
  if (normalizedText.length === 0) {
    return;
  }
  const normalizedRole = role === "assistant" || role === "user" ? role : "error";
  const normalizedIntent = resolveLiveConversationIntent(options.intent);
  const displayText =
    normalizedRole === "assistant"
      ? rewriteUiTaskDraftDemoResponseText(normalizedIntent, null, normalizedText)
      : normalizedText;
  state.liveConversationHistory.unshift({
    intent: normalizedIntent,
    role: normalizedRole,
    text: displayText,
    timestampLabel: nowLabel(),
    updatedAt: toIsoNow(),
  });
  if (state.liveConversationHistory.length > LIVE_VISIBLE_HISTORY_MAX_ENTRIES) {
    state.liveConversationHistory.length = LIVE_VISIBLE_HISTORY_MAX_ENTRIES;
  }
  renderConversationHistory();
}

function clearAssistantStreamFlushTimer() {
  if (state.assistantStreamFlushTimer === null) {
    return;
  }
  window.clearTimeout(state.assistantStreamFlushTimer);
  state.assistantStreamFlushTimer = null;
}

function clearAssistantSpeakingResetTimer() {
  if (state.assistantSpeakingResetTimer === null) {
    return;
  }
  window.clearTimeout(state.assistantSpeakingResetTimer);
  state.assistantSpeakingResetTimer = null;
}

function scheduleAssistantSpeakingReset() {
  clearAssistantSpeakingResetTimer();
  const audioContext = state.audioContext;
  if (!audioContext) {
    state.assistantIsSpeaking = false;
    renderAssistantActivityStatus();
    return;
  }

  const remainingMs = Math.max(0, (state.nextPlayTime - audioContext.currentTime) * 1000);
  if (remainingMs <= 10) {
    state.assistantIsSpeaking = false;
    renderAssistantActivityStatus();
    return;
  }

  const delayMs = Math.min(Math.max(Math.ceil(remainingMs + 30), 40), 2000);
  state.assistantSpeakingResetTimer = window.setTimeout(() => {
    state.assistantSpeakingResetTimer = null;
    scheduleAssistantSpeakingReset();
  }, delayMs);
}

function finalizeAssistantStreamEntry() {
  clearAssistantStreamFlushTimer();

  const entry = state.assistantStreamEntry;
  const body = state.assistantStreamBody;
  const text = state.assistantStreamText.trim();
  if (entry && body) {
    if (text.length > 0) {
      body.textContent = text;
    } else {
      entry.remove();
    }
  }

  state.assistantStreamEntry = null;
  state.assistantStreamBody = null;
  state.assistantStreamText = "";
  state.assistantIsStreaming = false;
  const nextLiveResult = settleStreamingResult(state.liveResult);
  const nextStoryResult = settleStreamingResult(state.storyLatestResult);
  const didSettleLiveResult = nextLiveResult !== state.liveResult;
  const didSettleStoryResult = nextStoryResult !== state.storyLatestResult;
  state.liveResult = nextLiveResult;
  state.storyLatestResult = nextStoryResult;
  renderAssistantActivityStatus();
  if (didSettleLiveResult || didSettleStoryResult) {
    renderLiveIntentExperience();
    renderStoryStudioSurface();
    renderDashboardWorkspace();
  }
}

function scheduleAssistantStreamFinalize(delayMs) {
  const finalDelayMs = Number.isFinite(delayMs) && delayMs > 0
    ? Math.floor(delayMs)
    : state.assistantStreamIdleFinalizeMs;
  clearAssistantStreamFlushTimer();
  state.assistantStreamFlushTimer = window.setTimeout(() => {
    finalizeAssistantStreamEntry();
  }, finalDelayMs);
}

function ensureAssistantStreamEntry() {
  if (
    state.assistantStreamEntry &&
    state.assistantStreamBody &&
    state.assistantStreamEntry.isConnected
  ) {
    return;
  }
  const entry = appendEntry(el.transcript, "system", "assistant", "");
  const body = entry.lastElementChild;
  if (!(body instanceof HTMLDivElement)) {
    return;
  }
  state.assistantStreamEntry = entry;
  state.assistantStreamBody = body;
  state.assistantStreamText = "";
}

function appendAssistantStreamingText(text) {
  if (typeof text !== "string" || text.length === 0) {
    return;
  }
  ensureAssistantStreamEntry();
  if (!state.assistantStreamBody) {
    return;
  }
  const chunk = prepareAssistantStreamChunk(state.assistantStreamText, text);
  if (chunk.length === 0) {
    return;
  }
  state.assistantStreamText += chunk;
  state.assistantIsStreaming = true;
  state.assistantStreamBody.textContent = state.assistantStreamText;
  setLiveResult("assistant", state.assistantStreamText, {
    intent: state.lastRequestedIntent,
    streaming: true,
  });
  renderAssistantActivityStatus();
  updateOfferFromText(chunk, false);
  evaluateConstraints();
  const finalizeDelayMs = resolveAssistantFinalizeDelay(
    chunk,
    state.assistantStreamIdleFinalizeMs,
    state.assistantStreamPunctuationFinalizeMs,
  );
  scheduleAssistantStreamFinalize(finalizeDelayMs);
}

function appendTranscript(role, text, options = {}) {
  finalizeAssistantStreamEntry();
  const transcriptIntent =
    typeof options.intent === "string" && options.intent.trim().length > 0 ? options.intent.trim() : null;
  if (role === "assistant" || role === "user") {
    appendConversationHistory(role, text, { intent: transcriptIntent });
  }
  const exposeInLiveResult = options.exposeInLiveResult !== false;
  if (role === "assistant" || (role === "error" && exposeInLiveResult)) {
    setLiveResult(role, text, {
      intent: transcriptIntent ?? state.lastRequestedIntent,
      streaming: false,
    });
  } else {
    renderLiveIntentExperience();
  }
  appendEntry(el.transcript, role === "error" ? "error" : "system", role, text);
}

function appendEvent(type, text) {
  appendEntry(el.events, "system", type, text);
}

function resolveExportStatusKind(statusText) {
  const normalized = typeof statusText === "string" ? statusText.trim().toLowerCase() : "";
  if (normalized.startsWith("markdown exported")) {
    return "markdown";
  }
  if (normalized.startsWith("json exported")) {
    return "json";
  }
  if (normalized.startsWith("audio exported")) {
    return "audio";
  }
  if (normalized.startsWith("audio export skipped")) {
    return "skipped";
  }
  if (normalized === "idle") {
    return "idle";
  }
  return "other";
}

function resolveExportMenuSummaryLabel(statusText) {
  return t("live.connection.exportSession");
}

function resolveExportMenuSummaryIcon(statusText) {
  const kind = resolveExportStatusKind(statusText);
  if (kind === "markdown") {
    return "MD";
  }
  if (kind === "json") {
    return "JS";
  }
  if (kind === "audio") {
    return "WAV";
  }
  if (kind === "skipped") {
    return "SKIP";
  }
  return "DL";
}

function resolveExportStatusStripLabel(statusText) {
  const kind = resolveExportStatusKind(statusText);
  if (kind === "markdown") {
    return t("export.status.markdown");
  }
  if (kind === "json") {
    return t("export.status.json");
  }
  if (kind === "audio") {
    return t("export.status.audio");
  }
  if (kind === "skipped") {
    return t("export.status.skipped");
  }
  if (kind === "idle") {
    return t("export.status.idle");
  }
  const normalized = typeof statusText === "string" ? statusText.trim() : "";
  if (normalized.length === 0) {
    return t("export.status.idle");
  }
  return normalized.length > 42 ? `${normalized.slice(0, 39)}...` : normalized;
}

function shouldTrackExportStatus(statusText) {
  const kind = resolveExportStatusKind(statusText);
  return kind === "markdown" || kind === "json" || kind === "audio" || kind === "skipped";
}

function extractExportHistoryFileLabel(statusText) {
  if (typeof statusText !== "string") {
    return "";
  }
  const match = statusText.match(/\(([^()]+)\)\s*$/);
  if (!match || typeof match[1] !== "string") {
    return "";
  }
  return match[1].trim();
}

function formatExportHistoryTime(value) {
  const date = value instanceof Date ? value : new Date(value);
  if (!(date instanceof Date) || !Number.isFinite(date.getTime())) {
    return "--:--:--";
  }
  return date.toLocaleTimeString([], {
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false,
  });
}

function renderExportMenuHistory() {
  if (!(el.exportMenuHistory instanceof HTMLElement)) {
    return;
  }
  el.exportMenuHistory.innerHTML = "";
  const history = Array.isArray(state.exportHistory) ? state.exportHistory : [];
  if (history.length === 0) {
    const emptyItem = document.createElement("li");
    emptyItem.className = "export-menu-history-empty";
    emptyItem.textContent = t("live.connection.noExportsYet");
    el.exportMenuHistory.appendChild(emptyItem);
    return;
  }
  for (const item of history.slice(0, EXPORT_HISTORY_LIMIT)) {
    const historyItem = document.createElement("li");
    historyItem.className = "export-menu-history-item";
    if (typeof item.kind === "string" && item.kind.trim().length > 0) {
      historyItem.classList.add("is-" + item.kind);
    }

    const badge = document.createElement("span");
    badge.className = "export-menu-history-badge";
    badge.textContent = typeof item.badge === "string" && item.badge.trim().length > 0 ? item.badge : "LOG";
    historyItem.appendChild(badge);

    const main = document.createElement("div");
    main.className = "export-menu-history-main";

    const fileLabel = document.createElement("span");
    fileLabel.className = "export-menu-history-file";
    fileLabel.textContent =
      typeof item.label === "string" && item.label.trim().length > 0 ? item.label : t("export.history.defaultLabel");

    const timeLabel = document.createElement("span");
    timeLabel.className = "export-menu-history-time";
    timeLabel.textContent = formatExportHistoryTime(item.recordedAt);

    main.append(fileLabel, timeLabel);
    historyItem.appendChild(main);
    el.exportMenuHistory.appendChild(historyItem);
  }
}

function pushExportHistory(statusText) {
  if (!shouldTrackExportStatus(statusText)) {
    return;
  }
  const normalized = typeof statusText === "string" ? statusText.trim() : "";
  if (normalized.length === 0) {
    return;
  }
  const last = Array.isArray(state.exportHistory) && state.exportHistory.length > 0 ? state.exportHistory[0] : null;
  if (last && typeof last.status === "string" && last.status === normalized) {
    return;
  }
  const kind = resolveExportStatusKind(normalized);
  const badge =
    kind === "markdown" ? "MD" : kind === "json" ? "JS" : kind === "audio" ? "WAV" : kind === "skipped" ? "SKIP" : "LOG";
  const label = extractExportHistoryFileLabel(normalized) || normalized;
  state.exportHistory = [
    {
      kind,
      badge,
      label,
      status: normalized,
      recordedAt: Date.now(),
    },
    ...state.exportHistory,
  ].slice(0, EXPORT_HISTORY_LIMIT);
  renderExportMenuHistory();
}

function setExportStatus(text) {
  const normalized = typeof text === "string" && text.trim().length > 0 ? text.trim() : "idle";
  if (!el.exportStatus) {
    return;
  }
  const stripLabel = resolveExportStatusStripLabel(normalized);
  let variant = "neutral";
  const exportKind = resolveExportStatusKind(normalized);
  if (exportKind === "markdown" || exportKind === "json" || exportKind === "audio") {
    variant = "ok";
  }
  setStatusPill(el.exportStatus, stripLabel, variant);
  el.exportStatus.title = normalized;
  if (el.exportMenuSummaryIcon) {
    el.exportMenuSummaryIcon.textContent = resolveExportMenuSummaryIcon(normalized);
    el.exportMenuSummaryIcon.setAttribute("data-export-kind", exportKind);
  }
  if (el.exportMenuSummaryLabel) {
    el.exportMenuSummaryLabel.textContent = resolveExportMenuSummaryLabel(normalized);
  }
  if (el.exportMenuMeta) {
    el.exportMenuMeta.textContent = t("live.connection.exportMeta", { status: stripLabel });
    el.exportMenuMeta.title = normalized;
  }
  pushExportHistory(normalized);
  renderLiveContextDock();
}

function normalizeStoryTimelineSegment(value, fallbackIndex) {
  if (!value || typeof value !== "object") {
    return null;
  }
  const rawIndex =
    typeof value.index === "number" && Number.isFinite(value.index) ? Math.floor(value.index) : fallbackIndex + 1;
  const index = Math.max(1, rawIndex);
  const text = toOptionalText(value.text) ?? "";
  return {
    index,
    text,
    imageRef: toOptionalText(value.imageRef),
    videoRef: toOptionalText(value.videoRef),
    videoStatus: toOptionalText(value.videoStatus),
    audioRef: toOptionalText(value.audioRef),
  };
}

function getStoryTimelineSelectedSegment() {
  const count = state.storyTimelineSegments.length;
  if (count === 0) {
    return null;
  }
  const selected =
    typeof state.storyTimelineSelectedIndex === "number" && Number.isFinite(state.storyTimelineSelectedIndex)
      ? Math.max(1, Math.min(count, Math.floor(state.storyTimelineSelectedIndex)))
      : 1;
  state.storyTimelineSelectedIndex = selected;
  return state.storyTimelineSegments[selected - 1] ?? null;
}

function compactStoryAssetRef(ref) {
  if (typeof ref !== "string") {
    return "";
  }
  const value = ref.trim();
  if (value.length <= 42) {
    return value;
  }
  return `${value.slice(0, 39)}...`;
}

function formatStoryAssetPillText(kind, ref, isRu = state.languageMode === "ru") {
  const safeRef = typeof ref === "string" ? ref : "";
  if (!safeRef) {
    return safeRef;
  }
  const labels = isRu
    ? { image: "Изображение", video: "Видео", audio: "Звук" }
    : { image: "Image", video: "Video", audio: "Audio" };
  const label = labels[kind] ?? kind;
  return `${label}: ${safeRef}`;
}

function formatStoryVideoStatusText(videoStatus, isRu = state.languageMode === "ru") {
  const value = toOptionalText(videoStatus);
  if (!value) {
    return value;
  }
  const lowered = value.toLowerCase();
  if (lowered.includes("ready") || lowered.includes("complete") || lowered.includes("done")) {
    return isRu ? "Видео готово" : "Video ready";
  }
  if (lowered.includes("pending") || lowered.includes("queue") || lowered.includes("render")) {
    return isRu ? "Видео рендерится" : "Video rendering";
  }
  if (lowered.includes("fail") || lowered.includes("error")) {
    return isRu ? "Ошибка видео" : "Video error";
  }
  return isRu ? `Видео: ${value}` : `Video: ${value}`;
}

function compactStorySceneCopy(value, maxLength = 156) {
  if (typeof value !== "string") {
    return "";
  }
  const normalized = value.replace(/\s+/g, " ").trim();
  if (!normalized) {
    return "";
  }
  if (!Number.isFinite(maxLength) || maxLength < 24 || normalized.length <= maxLength) {
    return normalized;
  }
  return `${normalized.slice(0, Math.max(0, Math.floor(maxLength) - 3)).trimEnd()}...`;
}

