      characterTabFallback: "\u0413\u0435\u0440\u043e\u0439 \u0438 \u043f\u043e\u0434\u0430\u0447\u0430",
      mediaTabFallback: "\u0410\u0441\u0441\u0435\u0442\u044b \u0438 \u043e\u0447\u0435\u0440\u0435\u0434\u044c",
