function syncStoryCompactTextMeta(node, visibleText = "", fullText = "") {
  if (!(node instanceof HTMLElement)) {
    return;
  }
  const normalizedVisibleText = typeof visibleText === "string" ? visibleText.trim() : "";
  const normalizedFullText = typeof fullText === "string" ? fullText.trim() : "";
  node.textContent = normalizedVisibleText;
  if (normalizedFullText && normalizedVisibleText && normalizedVisibleText !== normalizedFullText) {
    node.title = normalizedFullText;
  } else {
    node.removeAttribute("title");
  }
}

