function resolveStoryDesktopTimelinePositionText(count, selectedIndex, pendingJobs, runtimeState, fallback = "") {
  const isRu = state.languageMode === "ru";
  const safeCount = Math.max(0, Number.isFinite(count) ? Math.floor(count) : 0);
  const safePending = Math.max(0, Number.isFinite(pendingJobs) ? Math.floor(pendingJobs) : 0);
  const safeIndex = Math.max(0, Number.isFinite(selectedIndex) ? Math.floor(selectedIndex) : 0);
  const resolvedIndex = safeCount > 0 ? Math.min(Math.max(safeIndex, 1), safeCount) : 0;
  if (safeCount > 0) {
    return `${resolvedIndex}/${safeCount}`;
  }
  if (runtimeState === "error") {
    return isRu ? "Повтор" : "Retry";
  }
  if (safePending > 0) {
    return isRu ? "Ждём" : "Awaiting";
  }
  return fallback;
}

function syncStoryTimelineControlUtilityDensity(count, pendingJobs, runtimeState) {
  const safeCount = Math.max(0, Number.isFinite(count) ? Math.floor(count) : 0);
  const safePending = Math.max(0, Number.isFinite(pendingJobs) ? Math.floor(pendingJobs) : 0);
  const useUtilityDensity =
    isStoryDesktopRuntimeQuietViewport() && (safeCount > 0 || (safePending > 0 && runtimeState !== "idle"));

  for (const node of [el.storyTimelineControls, el.storyTimelineControlsGrid]) {
    if (!(node instanceof HTMLElement)) {
      continue;
    }
    node.dataset.storyControlDensity = useUtilityDensity ? "utility" : "default";
  }

  if (!(el.storyTimelineControlsGrid instanceof HTMLElement)) {
    return;
  }

  const fieldLabels = Array.from(el.storyTimelineControlsGrid.querySelectorAll(".field > span"));
  const controlMeta = [
    ["scrubber", el.storyTimelineScrubber],
    ["selector", el.storyTimelineSelect],
    ["position", el.storyTimelinePosition],
  ];

  for (let index = 0; index < controlMeta.length; index += 1) {
    const labelNode = fieldLabels[index];
    const [kind, controlNode] = controlMeta[index];
    if (!(labelNode instanceof HTMLElement)) {
      continue;
    }
    const fullLabel =
      typeof labelNode.dataset.storyFullLabel === "string" && labelNode.dataset.storyFullLabel.trim().length > 0
        ? labelNode.dataset.storyFullLabel.trim()
        : (labelNode.textContent ?? "").trim();
    if (!fullLabel) {
      continue;
    }
    labelNode.dataset.storyFullLabel = fullLabel;
    const visibleLabel = useUtilityDensity ? resolveStoryDesktopTimelineControlLabel(kind, fullLabel) : fullLabel;
    syncStoryCompactTextMeta(labelNode, visibleLabel, fullLabel);
    if (controlNode instanceof HTMLElement) {
      controlNode.setAttribute("aria-label", fullLabel);
      if (useUtilityDensity && visibleLabel !== fullLabel) {
        controlNode.title = fullLabel;
      } else {
        controlNode.removeAttribute("title");
      }
    }
  }
}

function resolveStoryDesktopOutputDisplaySummary(descriptor, totalRefs, fallback = "") {
  const isRu = state.languageMode === "ru";
  const sceneCount = Math.max(0, Math.floor(state.storyTimelineSegments.length));
  const safeTotalRefs = Math.max(0, Number.isFinite(totalRefs) ? Math.floor(totalRefs) : 0);
  const pendingJobs = Math.max(
    0,
    Number.isFinite(descriptor?.pendingJobs) ? Math.floor(descriptor.pendingJobs) : Math.floor(state.storyTimelinePendingJobs ?? 0),
  );
  if (pendingJobs > 0) {
    return isRu
      ? `${Math.max(sceneCount, 1)} сцен, ${pendingJobs} рендер в очереди.`
      : `${Math.max(sceneCount, 1)} scenes, ${pendingJobs} render pending.`;
  }
  if (sceneCount > 0 || safeTotalRefs > 0) {
    return isRu
      ? `${Math.max(sceneCount, 1)} сцен, ${safeTotalRefs} refs ready.`
      : `${Math.max(sceneCount, 1)} scenes, ${safeTotalRefs} refs ready.`;
  }
  return fallback;
}

function resolveStoryDesktopAtlasSummary(kind, value, fallback = "") {
  const fullText = typeof value === "string" ? value.trim() : "";
  if (!fullText) {
    return fallback;
  }
  switch (kind) {
    case "character":
      return compactStoryReferenceValue(fullText, 7, 58);
    case "media":
      return compactStorySignalValue(fullText, 52);
    case "world":
    default:
      return compactStoryReferenceValue(fullText, 8, 64);
  }
}

function resolveStoryDesktopAtlasMeta(kind, value, fallback = "") {
  const fullText = typeof value === "string" ? value.trim() : "";
  if (!fullText) {
    return fallback;
  }
  switch (kind) {
    case "media":
      return compactStorySignalValue(fullText, 48);
    case "character":
    case "world":
    default:
      return compactStorySignalValue(fullText, 54);
  }
}

function resolveStoryDesktopAtlasShellHeading(activePanel, pendingJobs, totalRefs, fallback = "") {
  const isRu = state.languageMode === "ru";
  const safePending = Math.max(0, Number.isFinite(pendingJobs) ? Math.floor(pendingJobs) : 0);
  const safeRefs = Math.max(0, Number.isFinite(totalRefs) ? Math.floor(totalRefs) : 0);
  switch (normalizeStoryAtlasPanel(activePanel)) {
    case "character":
      return isRu ? "Опора героя" : "Lead notes";
    case "media":
      if (safePending > 0) {
        return isRu ? "Медиа очередь" : "Media queue";
      }
      if (safeRefs > 0) {
        return isRu ? "Медиа стек" : "Media stack";
      }
      return isRu ? "План медиа" : "Media plan";
    case "world":
    default:
      return isRu ? "Опора мира" : "World notes";
  }
}

function resolveStoryDesktopAtlasShellIntro(activePanel, pendingJobs, totalRefs, fallback = "") {
  const isRu = state.languageMode === "ru";
  const safePending = Math.max(0, Number.isFinite(pendingJobs) ? Math.floor(pendingJobs) : 0);
  const safeRefs = Math.max(0, Number.isFinite(totalRefs) ? Math.floor(totalRefs) : 0);
  switch (normalizeStoryAtlasPanel(activePanel)) {
    case "character":
      return isRu ? "Герой, голос и подача." : "Lead, voice, and delivery.";
    case "media":
      if (safePending > 0) {
        return isRu ? "Ассеты и очередь." : "Assets and queue.";
      }
      if (safeRefs > 0) {
        return isRu ? "Готовые референсы и счётчики." : "Ready refs and counts.";
      }
      return isRu ? "Медиа план ещё пуст." : "Media plan is still empty.";
    case "world":
    default:
      return isRu ? "Тон, место и ритм." : "Tone, place, and rhythm.";
  }
}

function resolveStoryDesktopAtlasPanelHeading(kind, hasValue, pendingJobs = 0, totalRefs = 0, fallback = "") {
  const isRu = state.languageMode === "ru";
  switch (kind) {
    case "character":
      return hasValue ? (isRu ? "Фокус героя" : "Lead focus") : fallback;
    case "media":
      if (pendingJobs > 0) {
        return isRu ? "Медиа очередь" : "Media queue";
      }
      if (totalRefs > 0) {
        return isRu ? "Медиа стек" : "Media stack";
      }
      return isRu ? "План медиа" : "Media plan";
    case "world":
      return hasValue ? (isRu ? "Опора мира" : "World anchor") : fallback;
    default:
      return fallback;
  }
}

function resolveStoryDesktopOutputDossierText(kind, value, fallback = "") {
  const fullText = typeof value === "string" ? value.trim() : "";
  if (!fullText) {
    return fallback;
  }
  switch (kind) {
    case "title":
      return compactStoryReferenceValue(fullText, 7, 58);
    case "note":
    default:
      return compactStoryReferenceValue(fullText, 11, 92);
  }
}

function resolveStoryDesktopOutputVariantText(kind, value, fallback = "") {
  const fullText = typeof value === "string" ? value.trim() : "";
  if (!fullText) {
    return fallback;
  }
  switch (kind) {
    case "title":
      return compactStoryReferenceValue(fullText, 7, 54);
    case "meta":
      return compactStorySignalValue(fullText, 42);
    case "note":
    default:
      return compactStoryReferenceValue(fullText, 10, 76);
  }
}

function resolveStoryDesktopOutputVariantOverflowText(hiddenCount, fallback = "") {
  const isRu = state.languageMode === "ru";
  const safeHiddenCount = Math.max(0, Number.isFinite(hiddenCount) ? Math.floor(hiddenCount) : 0);
  if (safeHiddenCount <= 0) {
    return fallback;
  }
  return isRu
    ? `Ещё ${safeHiddenCount} ${safeHiddenCount === 1 ? "версия" : "версии"} выше в истории.`
    : `${safeHiddenCount} more ${safeHiddenCount === 1 ? "pass" : "passes"} remain in history.`;
}

function resolveStoryDesktopSceneCardStatusLabel(videoStatus, fallback = "") {
  const isRu = state.languageMode === "ru";
  const normalized = toOptionalText(videoStatus)?.toLowerCase() ?? "";
  if (!normalized) {
    return isRu ? "без видео" : "no video";
  }
  if (normalized.includes("queue")) {
    return isRu ? "в очереди" : "queued";
  }
  if (normalized.includes("pending") || normalized.includes("render")) {
    return isRu ? "рендер" : "rendering";
  }
  if (normalized.includes("ready") || normalized.includes("done") || normalized.includes("complete")) {
    return isRu ? "готово" : "ready";
  }
  if (normalized.includes("fail") || normalized.includes("error")) {
    return isRu ? "повторить" : "retry";
  }
  return compactStorySignalValue(fallback, 22);
}

function resolveStoryDesktopSceneMediaLabel(segment, fallback = "") {
  const isRu = state.languageMode === "ru";
  const readyItems = [];
  if (segment?.imageRef) {
    readyItems.push(isRu ? "кадр" : "image");
  }
  if (segment?.audioRef) {
    readyItems.push(isRu ? "звук" : "audio");
  }
  if (segment?.videoRef) {
    readyItems.push(isRu ? "видео" : "video");
  }
  if (readyItems.length > 0) {
    return readyItems.join(" · ");
  }
  return isRu ? "только текст" : "text only";
}

function resolveStoryDesktopSceneAssetsOverflowText(hiddenCount, fallback = "") {
  const isRu = state.languageMode === "ru";
  const safeHiddenCount = Math.max(0, Number.isFinite(hiddenCount) ? Math.floor(hiddenCount) : 0);
  if (safeHiddenCount <= 0) {
    return fallback;
  }
  return isRu ? `+${safeHiddenCount} ещё` : `+${safeHiddenCount} more`;
}

function resolveStoryDesktopSceneCardSummary(value, fallback = "") {
  const fullText = typeof value === "string" ? value.trim() : "";
  if (!fullText) {
    return fallback;
  }
  return compactStorySceneCopy(fullText, 104);
}

function resolveStoryCompactModeTitle(mode, fallbackTitle = "") {
  const isRu = state.languageMode === "ru";
  switch (normalizeStoryComposerMode(mode)) {
    case "cinematic":
      return isRu ? "Трейлер" : "Trailer";
    case "scenes":
      return isRu ? "Сцены" : "Scenes";
    case "character":
      return isRu ? "Арка" : "Character";
    case "world":
      return isRu ? "Мир" : "World";
    default:
      return fallbackTitle;
  }
}

function resolveStoryDesktopQuietModeTitle(mode, fallbackTitle = "") {
  const isRu = state.languageMode === "ru";
  switch (normalizeStoryComposerMode(mode)) {
    case "cinematic":
      return isRu ? "Трейлер" : "Trailer";
    case "scenes":
      return isRu ? "Сцены" : "Scenes";
    case "character":
      return isRu ? "Арка" : "Arc";
    case "world":
      return isRu ? "Мир" : "World";
    default:
      return fallbackTitle;
  }
}

function resolveStoryCompactDeliveryLabel(mediaMixValue, narrationStyleValue, fallbackLabel = "") {
  const isRu = state.languageMode === "ru";
  const mediaLabel = (() => {
    switch ((mediaMixValue || "").trim()) {
      case "balanced":
        return isRu ? "Микс" : "Mixed";
      case "image-heavy":
        return isRu ? "Кадры" : "Images";
      case "cinematic-video":
        return isRu ? "Видео" : "Video";
      case "voiceover-led":
        return isRu ? "Озвучка" : "Voice";
      default:
        return "";
    }
  })();
  const narrationLabel = (() => {
    switch ((narrationStyleValue || "").trim()) {
      case "concise":
        return isRu ? "Кратко" : "Brief";
      case "lush":
        return isRu ? "Насыщ." : "Rich";
      case "scripted":
        return isRu ? "Озвучка" : "VO";
      default:
        return "";
    }
  })();
  const compactLabel = [mediaLabel, narrationLabel].filter(Boolean).join(" · ");
  return compactLabel || compactStorySignalValue(fallbackLabel, 18);
}

function resolveStoryCompactScopeLabel(sceneTargetValue, toneValue, fallbackLabel = "") {
  const isRu = state.languageMode === "ru";
  const sceneLabel = (() => {
    switch ((sceneTargetValue || "").trim()) {
      case "3":
        return isRu ? "3 сц." : "3 sc.";
      case "4":
        return isRu ? "4 сц." : "4 sc.";
      case "6":
        return isRu ? "6 сц." : "6 sc.";
      default:
        return "";
    }
  })();
  const toneLabel = (() => {
    switch ((toneValue || "").trim()) {
      case "editorial":
        return isRu ? "Ред." : "Ed.";
      case "hopeful":
        return isRu ? "Свет." : "Hope";
      case "mythic":
        return isRu ? "Миф." : "Myth";
      case "tense":
        return isRu ? "Напр." : "Tense";
      default:
        return "";
    }
  })();
  const compactLabel = [sceneLabel, toneLabel].filter(Boolean).join(" · ");
  return compactLabel || compactStorySignalValue(fallbackLabel, 16);
}

function formatStoryTraySummary(parts, maxLength = 96) {
  const text = (Array.isArray(parts) ? parts : [])
    .map((part) => (typeof part === "string" ? part.replace(/\s+/g, " ").trim() : ""))
    .filter(Boolean)
    .join(" • ");
  return compactStorySignalValue(text, maxLength);
}

function renderStoryTagList(container, items) {
  if (!(container instanceof HTMLElement)) {
    return;
  }
  container.replaceChildren();
  for (const item of items) {
    const text = typeof item === "string" ? item.trim() : "";
    if (!text) {
      continue;
    }
    const tag = document.createElement("span");
    tag.className = "story-atlas-tag";
    tag.textContent = compactStorySignalValue(text, 34);
    container.append(tag);
  }
}

function appendStoryOutputCardTags(container, items) {
  if (!(container instanceof HTMLElement)) {
    return;
  }
  for (const item of Array.isArray(items) ? items : []) {
    const text = typeof item === "string" ? item.trim() : "";
    if (!text) {
      continue;
    }
    const tag = document.createElement("span");
    tag.className = "story-output-card-tag";
    tag.textContent = text;
    container.append(tag);
  }
}

function buildStoryOutputMetrics(metrics, compact = false) {
  const outputCopy = getStoryOutputPresentationCopy();
  const metricGrid = document.createElement("div");
  metricGrid.className = "story-output-metrics";
  metricGrid.classList.toggle("is-compact", compact);

  for (const metric of Array.isArray(metrics) ? metrics : []) {
    const labelText = typeof metric?.label === "string" ? metric.label.trim() : "";
    const valueText = typeof metric?.value === "string" ? metric.value.trim() : "";
    if (!labelText || !valueText) {
      continue;
    }
    const metricCard = document.createElement("article");
    metricCard.className = "story-output-metric";

    const metricLabel = document.createElement("span");
    if (labelText === "scenes") {
      metricLabel.textContent = outputCopy.metricScenes;
    } else if (labelText === "img") {
      metricLabel.textContent = outputCopy.metricImages;
    } else if (labelText === "vid") {
      metricLabel.textContent = outputCopy.metricVideo;
    } else if (labelText === "aud") {
      metricLabel.textContent = outputCopy.metricAudio;
    } else {
      metricLabel.textContent = labelText;
    }

    const metricValue = document.createElement("strong");
    metricValue.textContent = valueText;
    metricCard.append(metricLabel, metricValue);
    metricGrid.append(metricCard);
  }

  return metricGrid;
}

function buildStoryOutputDossierSection(detail) {
  const section = document.createElement("div");
  section.className = "story-output-dossier-section";

  const label = document.createElement("span");
  label.className = "story-output-dossier-label";
  label.textContent = detail?.label ?? "";

  const title = document.createElement("strong");
  title.className = "story-output-dossier-title";
  title.textContent = detail?.title ?? "";

  const note = document.createElement("p");
  note.className = "story-output-dossier-note";
  note.textContent = detail?.note ?? "";

  section.append(label, title, note);

  if (Array.isArray(detail?.tags) && detail.tags.length > 0) {
    const tags = document.createElement("div");
    tags.className = "story-output-card-tags";
    appendStoryOutputCardTags(tags, detail.tags);
    section.append(tags);
  }

  if (Array.isArray(detail?.metrics) && detail.metrics.length > 0) {
    section.append(buildStoryOutputMetrics(detail.metrics, true));
  }

  return section;
}

function buildStoryOutputSupportCard(detail) {
  const card = document.createElement("article");
  card.className = "story-output-support-card";

  const label = document.createElement("span");
  label.className = "story-output-support-label";
  label.textContent = detail?.label ?? "";

  const title = document.createElement("strong");
  title.className = "story-output-support-title";
  title.textContent = detail?.title ?? "";

  card.append(label, title);

  if (typeof detail?.note === "string" && detail.note.trim().length > 0) {
    const note = document.createElement("p");
    note.className = "story-output-support-note";
    note.textContent = detail.note.trim();
    card.append(note);
  }

  if (Array.isArray(detail?.tags) && detail.tags.length > 0) {
    const tags = document.createElement("div");
    tags.className = "story-output-card-tags story-output-card-tags-compact";
    appendStoryOutputCardTags(tags, detail.tags);
    card.append(tags);
  }

  return card;
}

function buildStoryComposerPrompt() {
  const copy = getStoryComposerCopy();
  const modeConfig = getStoryComposerModeConfig();
  const basePrompt = resolveStoryComposerPromptText().replace(/^story:\s*/i, "").trim();
  const safePrompt = basePrompt.length > 0 ? basePrompt : modeConfig.prompt.replace(/^story:\s*/i, "").trim();
  const sceneTargetLabel = resolveStoryComposerSelectionLabel("storySceneTarget", modeConfig.defaults.sceneTarget);
  const toneLabel = resolveStoryComposerSelectionLabel("storyTone", modeConfig.defaults.tone);
  const mediaMixLabel = resolveStoryComposerSelectionLabel("storyMediaMix", modeConfig.defaults.mediaMix);
  const narrationLabel = resolveStoryComposerSelectionLabel("storyNarrationStyle", modeConfig.defaults.narrationStyle);
  const characterFocus = readStoryComposerControlValue(el.storyCharacterFocus) || modeConfig.defaults.characterFocus;
  const worldFocus = readStoryComposerControlValue(el.storyWorldFocus) || modeConfig.defaults.worldFocus;
  const desktopQuietDeliverySignal = compactStorySignalValue(
    [mediaMixLabel, narrationLabel].filter(Boolean).join(" · "),
    36,
  );
  const desktopQuietScopeSignal = compactStorySignalValue(
    [sceneTargetLabel, toneLabel].filter(Boolean).join(" · "),
    28,
  );
  const editorialNotes = readStoryComposerControlValue(el.storyEditorialNotes) || modeConfig.defaults.editorialNotes;
  const details = [
    `${copy.modeKicker}: ${modeConfig.badge}`,
    `${copy.sceneTargetLabel}: ${sceneTargetLabel}`,
    `${copy.storyCharacterFocusLabel}: ${characterFocus}`,
    `${copy.storyWorldFocusLabel}: ${worldFocus}`,
    `${copy.toneLabel}: ${toneLabel}`,
    `${copy.mediaMixLabel}: ${mediaMixLabel}`,
    `${copy.narrationStyleLabel}: ${narrationLabel}`,
  ];
  if (editorialNotes) {
    details.push(`${copy.storyEditorialNotesLabel}: ${editorialNotes}`);
  }
  return [`story: ${safePrompt}`, "", `${copy.promptPayloadHeading}:`, ...details.map((item) => `- ${item}`)].join("\n");
}

function seedLiveNegotiatorWithStoryPrompt(message = buildStoryComposerPrompt()) {
  const safeMessage = typeof message === "string" ? message.trim() : "";
  if (el.intent instanceof HTMLSelectElement) {
    el.intent.value = "story";
    syncCustomSelectControl(el.intent);
    setUiTaskFieldsVisibility();
  }
  if (el.message instanceof HTMLTextAreaElement && safeMessage.length > 0) {
    el.message.value = safeMessage;
  }
}

function renderStoryModeRail() {
  if (!(el.storyModeRail instanceof HTMLElement)) {
    return;
  }
  const isCompactMobile = isStoryCompactMobileViewport();
  const useDesktopQuietCompose = !hasStoryRunActivity() && isStoryDesktopComposeQuietViewport();
  const copy = getStoryComposerCopy();
  el.storyModeRail.setAttribute("aria-label", copy.modeRailLabel);
  for (const button of Array.from(el.storyModeRail.querySelectorAll("[data-story-mode]"))) {
    if (!(button instanceof HTMLButtonElement)) {
      continue;
    }
    const mode = normalizeStoryComposerMode(button.dataset.storyMode);
    const modeConfig = getStoryComposerModeConfig(mode);
    button.classList.toggle("is-active", mode === state.storyComposerMode);
    button.setAttribute("aria-pressed", mode === state.storyComposerMode ? "true" : "false");
    const kicker = button.querySelector(".story-mode-kicker");
    const title = button.querySelector(".story-mode-title");
    const hint = button.querySelector(".story-mode-hint");
    if (kicker instanceof HTMLElement) {
      kicker.textContent = copy.modeKicker;
    }
    if (title instanceof HTMLElement) {
      const visibleTitle =
        isCompactMobile && mode !== state.storyComposerMode
          ? resolveStoryCompactModeTitle(mode, modeConfig.railTitle)
          : modeConfig.railTitle;
      title.textContent =
        visibleTitle;
      title.title = modeConfig.railTitle;
    }
    if (hint instanceof HTMLElement) {
      hint.textContent = modeConfig.railHint;
      hint.title = modeConfig.railHint;
    }
    button.title = `${modeConfig.railTitle}. ${modeConfig.railHint}`;
    button.setAttribute("aria-label", `${modeConfig.railTitle}. ${modeConfig.railHint}`);
  }
}

function renderStorySignalStrip() {
  const copy = getStoryComposerCopy();
  const modeConfig = getStoryComposerModeConfig();
  const isCompactMobile = isStoryCompactMobileViewport();
  const useDesktopQuietCompose = !hasStoryRunActivity() && isStoryDesktopComposeQuietViewport();
  const sceneTargetValue = readStoryComposerControlValue(el.storySceneTarget) || modeConfig.defaults.sceneTarget;
  const toneValue = readStoryComposerControlValue(el.storyTone) || modeConfig.defaults.tone;
  const mediaMixValue = readStoryComposerControlValue(el.storyMediaMix) || modeConfig.defaults.mediaMix;
  const narrationStyleValue =
    readStoryComposerControlValue(el.storyNarrationStyle) || modeConfig.defaults.narrationStyle;
  const sceneTargetLabel = resolveStoryComposerSelectionLabel("storySceneTarget", modeConfig.defaults.sceneTarget);
  const toneLabel = resolveStoryComposerSelectionLabel("storyTone", modeConfig.defaults.tone);
  const mediaMixLabel = resolveStoryComposerSelectionLabel("storyMediaMix", modeConfig.defaults.mediaMix);
  const narrationLabel = resolveStoryComposerSelectionLabel("storyNarrationStyle", modeConfig.defaults.narrationStyle);
  const characterFocus = readStoryComposerControlValue(el.storyCharacterFocus) || modeConfig.defaults.characterFocus;
  const worldFocus = readStoryComposerControlValue(el.storyWorldFocus) || modeConfig.defaults.worldFocus;
  const desktopQuietDeliverySignal = compactStorySignalValue(
    [mediaMixLabel, narrationLabel].filter(Boolean).join(" · "),
    36,
  );
  const desktopQuietScopeSignal = compactStorySignalValue(
    [sceneTargetLabel, toneLabel].filter(Boolean).join(" · "),
    28,
  );
  const leadSignal = isCompactMobile
    ? compactStorySignalValue(characterFocus, 22)
    : useDesktopQuietCompose
      ? compactStoryReferenceValue(characterFocus, 6, 36)
      : compactStoryReferenceValue(characterFocus, 4, 28);
  const worldSignal = isCompactMobile
    ? compactStorySignalValue(worldFocus, 20)
    : useDesktopQuietCompose
      ? compactStoryReferenceValue(worldFocus, 6, 38)
      : compactStoryReferenceValue(worldFocus, 4, 26);
  const deliverySignal = useDesktopQuietCompose
    ? desktopQuietDeliverySignal
    : resolveStoryCompactDeliveryLabel(
    mediaMixValue,
    narrationStyleValue,
    `${mediaMixLabel} · ${narrationLabel}`,
  );
  const scopeSignal = useDesktopQuietCompose
    ? desktopQuietScopeSignal
    : resolveStoryCompactScopeLabel(sceneTargetValue, toneValue, `${sceneTargetLabel} · ${toneLabel}`);

  setText(el.storySignalLeadLabel, copy.signalLeadLabel);
  setText(el.storySignalLeadValue, leadSignal);
  if (el.storySignalLeadValue instanceof HTMLElement) {
    el.storySignalLeadValue.title = characterFocus;
  }
  setText(el.storySignalWorldLabel, copy.signalWorldLabel);
  setText(el.storySignalWorldValue, worldSignal);
  if (el.storySignalWorldValue instanceof HTMLElement) {
    el.storySignalWorldValue.title = worldFocus;
  }
  setText(el.storySignalDeliveryLabel, copy.signalDeliveryLabel);
  setText(el.storySignalDeliveryValue, deliverySignal);
  if (el.storySignalDeliveryValue instanceof HTMLElement) {
    el.storySignalDeliveryValue.title = `${mediaMixLabel}. ${narrationLabel}`;
  }
  setText(el.storySignalScopeLabel, copy.signalScopeLabel);
  setText(el.storySignalScopeValue, scopeSignal);
  if (el.storySignalScopeValue instanceof HTMLElement) {
    el.storySignalScopeValue.title = `${sceneTargetLabel}. ${toneLabel}`;
  }
}

function renderStoryLatestOutput() {
  const copy = getStoryComposerCopy();
  const outputCopy = getStoryOutputPresentationCopy();
  const latest = state.storyLatestResult ?? {};
  const text = typeof latest.text === "string" ? latest.text.trim() : "";
  const useDesktopQuietRuntime = hasStoryRunActivity() && isStoryDesktopRuntimeQuietViewport();
  const shell =
    el.storyLatestOutput instanceof HTMLElement ? el.storyLatestOutput.closest(".story-latest-output-shell") : null;
  const awaitingFreshResponse = resolveStoryLatestResponsePhase(latest) === "awaiting";
  const timeLabel = formatStoryComposerTimeLabel(awaitingFreshResponse ? state.storyLatestRequestAt : latest.updatedAt);

  setText(el.storyOutputChip, copy.outputChip);
  setText(el.storyOutputHeading, copy.outputHeading);
  setText(el.storyOutputIntro, copy.outputIntro);

  if (el.storyLatestOutputMeta instanceof HTMLElement) {
    if (awaitingFreshResponse) {
      el.storyLatestOutputMeta.textContent = copy.outputMetaPending(timeLabel);
    } else if (text.length > 0) {
      el.storyLatestOutputMeta.textContent = copy.outputMetaReady(latest.role, timeLabel, latest.streaming === true);
    } else {
      el.storyLatestOutputMeta.textContent = copy.outputMetaIdle;
    }
  }

  if (el.storyLatestOutput instanceof HTMLElement) {
    el.storyLatestOutput.replaceChildren();
    const descriptor = getStoryLatestOutputDescriptorData();
    const narrative = deriveStoryLatestOutputNarrative(text);
    const isErrorStory = text.length > 0 && latest.role === "error";
    const errorPresentation = isErrorStory ? parseStoryRuntimeError(text) : null;
    const totalRefs =
      descriptor.assetCounts.images + descriptor.assetCounts.video + descriptor.assetCounts.audio;
    const hasReadyStory = text.length > 0 && !isErrorStory;
    const displayTitle = hasReadyStory ? resolveStoryLatestOutputDisplayTitle(narrative) : narrative.title;
    const displaySummary = hasReadyStory
      ? buildStoryLatestOutputDisplaySummary(descriptor, totalRefs) || narrative.summary
      : isErrorStory && errorPresentation
        ? errorPresentation.summary
      : narrative.summary;
    const visibleDisplaySummary =
      useDesktopQuietRuntime && hasReadyStory
        ? resolveStoryDesktopOutputDisplaySummary(descriptor, totalRefs, displaySummary)
        : displaySummary;
    const shouldCondenseBody = hasReadyStory && shouldCondenseStoryLatestOutputBody(narrative, displayTitle, displaySummary);
    const condensedBodyPreview = shouldCondenseBody ? compactStorySceneCopy(narrative.body, 236) : "";

    const stage = document.createElement("div");
    stage.className = "story-output-stage";
    stage.classList.toggle("story-output-stage-idle", text.length === 0);

    const main = document.createElement("div");
    main.className = "story-output-main";
    main.classList.toggle("is-empty", text.length === 0);
    main.classList.toggle("is-error", isErrorStory);
    main.classList.toggle("is-compact", shouldCondenseBody);

    const kickerRow = document.createElement("div");
    kickerRow.className = "story-output-kicker-row";

    const kicker = document.createElement("span");
    kicker.className = "story-output-kicker";
    if (awaitingFreshResponse) {
      kicker.textContent = outputCopy.stagePending;
    } else if (text.length === 0) {
      kicker.textContent = outputCopy.stageIdle;
    } else if (latest.role === "error") {
      kicker.textContent = outputCopy.stageError;
    } else {
      kicker.textContent = outputCopy.stageReady;
    }
    kickerRow.append(kicker);

    const title = document.createElement("h4");
    title.className = "story-output-title";
    title.textContent = isErrorStory ? outputCopy.errorTitle : displayTitle;

    const summary = document.createElement("p");
    summary.className = "story-output-summary";
    summary.classList.toggle("is-display-meta", hasReadyStory);
    syncStoryCompactTextMeta(summary, visibleDisplaySummary, displaySummary);

    const side = document.createElement("aside");
    side.className = "story-output-side";

    const productionTitleText =
      descriptor.pendingJobs > 0
        ? outputCopy.productionPending(descriptor.pendingJobs)
        : totalRefs > 0
          ? outputCopy.productionReady(totalRefs)
          : outputCopy.productionIdle;
    const productionNoteText =
      totalRefs > 0
        ? outputCopy.assetsReady(
            descriptor.assetCounts.images,
            descriptor.assetCounts.video,
            descriptor.assetCounts.audio,
          )
        : outputCopy.assetsIdle;
    const productionMetrics = [
      { label: "scenes", value: String(state.storyTimelineSegments.length) },
      { label: "img", value: String(descriptor.assetCounts.images) },
      { label: "vid", value: String(descriptor.assetCounts.video) },
      { label: "aud", value: String(descriptor.assetCounts.audio) },
    ];
    if (text.length === 0) {
      const idleSupportDetails = [
        {
          label: outputCopy.briefLabel,
          title: descriptor.modeLabel,
          note: `${descriptor.toneLabel} \u2022 ${descriptor.sceneTargetLabel}`,
          tags: [descriptor.sceneTargetLabel],
        },
        {
          label: outputCopy.deliveryLabel,
          title: descriptor.mediaMixLabel,
          note: descriptor.narrationLabel,
          tags: [descriptor.mediaMixLabel],
        },
        {
          label: outputCopy.productionLabel,
          title: productionTitleText,
          note:
            descriptor.pendingJobs > 0
              ? outputCopy.idleSupportQueue(state.storyTimelineSegments.length, descriptor.pendingJobs)
              : outputCopy.idleSupportCounts(state.storyTimelineSegments.length, totalRefs),
        },
      ];
      const bodyCard = document.createElement("article");
      bodyCard.className = "story-output-body-card story-output-body-card-muted";
      const bodyLabel = document.createElement("span");
      bodyLabel.className = "story-output-body-label";
      bodyLabel.textContent = outputCopy.bodyLabel;
      const bodyText = document.createElement("div");
      bodyText.className = "story-output-body-text";
      bodyText.textContent = awaitingFreshResponse ? copy.outputMetaPending(timeLabel) : copy.outputEmpty;
      bodyCard.append(bodyLabel, bodyText);
      main.append(kickerRow, title, summary, bodyCard);

      const supportStrip = document.createElement("div");
      supportStrip.className = "story-output-support-strip";
      for (const detail of idleSupportDetails) {
        supportStrip.append(buildStoryOutputSupportCard(detail));
      }

      side.append(supportStrip);
      stage.append(main, side);
      el.storyLatestOutput.append(stage);
    } else {
      const cueItems = narrative.highlights.filter((item) => {
        const normalizedItem = normalizeComparableStoryText(item);
        if (!normalizedItem) {
          return false;
        }
        if (!shouldCondenseBody) {
          return true;
        }
        const normalizedTitle = normalizeComparableStoryText(displayTitle);
        const normalizedBody = normalizeComparableStoryText(text);
        if (normalizedTitle && normalizedItem.includes(normalizedTitle)) {
          return false;
        }
        if (normalizedBody && (normalizedItem === normalizedBody || normalizedBody.includes(normalizedItem))) {
          return false;
        }
        return true;
      });
      const cueStrip = document.createElement("div");
      cueStrip.className = "story-output-cue-strip";
      for (const item of cueItems) {
        const cuePill = document.createElement("span");
        cuePill.className = "story-output-cue-pill";
        cuePill.textContent = item;
        cueStrip.append(cuePill);
      }
      if (isErrorStory && errorPresentation) {
        main.append(kickerRow, title, summary);
        if (cueStrip.childElementCount > 0) {
          main.append(cueStrip);
        }
        const bodyCard = document.createElement("article");
        bodyCard.className = "story-output-body-card story-output-body-card-main story-output-body-card-error";
        const bodyText = document.createElement("div");
        bodyText.className = "story-output-body-text";
        bodyText.textContent = errorPresentation.body;
        bodyCard.append(bodyText);
        if (errorPresentation.traceNote) {
          const footnote = document.createElement("p");
          footnote.className = "story-output-body-footnote";
          footnote.textContent = errorPresentation.traceNote;
          bodyCard.append(footnote);
        }
        main.append(bodyCard);
      } else if (shouldCondenseBody) {
        main.append(kickerRow, title, summary);
        if (cueStrip.childElementCount > 0) {
          main.append(cueStrip);
        }
        if (condensedBodyPreview) {
          const bodyCard = document.createElement("article");
          bodyCard.className = "story-output-body-card story-output-body-card-main story-output-body-card-compact";
          const bodyText = document.createElement("div");
          bodyText.className = "story-output-body-text";
          bodyText.textContent = condensedBodyPreview;
          bodyCard.append(bodyText);
          main.append(bodyCard);
        }
      } else {
        const bodyCard = document.createElement("article");
        bodyCard.className = "story-output-body-card story-output-body-card-main";
        const bodyText = document.createElement("div");
        bodyText.className = "story-output-body-text";
        bodyText.textContent = text;
        if (cueStrip.childElementCount > 0) {
          bodyCard.append(cueStrip);
        }
        bodyCard.append(bodyText);
        main.append(kickerRow, title, summary, bodyCard);
      }

      const deliveryContext = [descriptor.narrationLabel];
      if (descriptor.editorialNotes) {
        deliveryContext.push(compactStorySceneCopy(descriptor.editorialNotes, 88));
      }
      const detailCards = [
        {
          label: outputCopy.briefLabel,
          title: descriptor.modeLabel,
          note: `${descriptor.toneLabel} \u00b7 ${descriptor.sceneTargetLabel}`,
          tags: [descriptor.sceneTargetLabel, descriptor.toneLabel],
        },
        {
          label: outputCopy.deliveryLabel,
          title: descriptor.mediaMixLabel,
          note: deliveryContext.filter(Boolean).join(" \u00b7 "),
          tags: [descriptor.mediaMixLabel, descriptor.narrationLabel].filter(Boolean),
        },
        {
          label: outputCopy.productionLabel,
          title: productionTitleText,
          note: productionNoteText,
          metrics: productionMetrics,
        },
      ];

      const dossierCard = document.createElement("article");
      dossierCard.className = "story-output-side-card story-output-side-card-dossier";
      for (const detail of detailCards) {
        dossierCard.append(buildStoryOutputDossierSection(detail));
      }
      if (useDesktopQuietRuntime) {
        for (const dossierTitle of Array.from(dossierCard.querySelectorAll(".story-output-dossier-title"))) {
          if (dossierTitle instanceof HTMLElement) {
            const fullText = dossierTitle.textContent ?? "";
            syncStoryCompactTextMeta(
              dossierTitle,
              resolveStoryDesktopOutputDossierText("title", fullText, fullText),
              fullText,
            );
          }
        }
        for (const dossierNote of Array.from(dossierCard.querySelectorAll(".story-output-dossier-note"))) {
          if (dossierNote instanceof HTMLElement) {
            const fullText = dossierNote.textContent ?? "";
            syncStoryCompactTextMeta(
              dossierNote,
              resolveStoryDesktopOutputDossierText("note", fullText, fullText),
              fullText,
            );
          }
        }
      }

      side.append(dossierCard);
      stage.append(main, side);
      el.storyLatestOutput.append(stage);

      const previousEntries = Array.isArray(state.storyLatestHistory)
        ? state.storyLatestHistory.slice(1, 3)
        : [];
      if (previousEntries.length > 0) {
        const visiblePreviousEntries = useDesktopQuietRuntime ? previousEntries.slice(0, 1) : previousEntries;
        const hiddenVariantCount = Math.max(0, previousEntries.length - visiblePreviousEntries.length);
        const variants = document.createElement("section");
        variants.className = "story-output-variants";
        const variantsHead = document.createElement("div");
        variantsHead.className = "story-output-variants-head";
        const variantsLabel = document.createElement("span");
        variantsLabel.className = "story-output-body-label";
        variantsLabel.textContent = outputCopy.variantsLabel;
        variantsHead.append(variantsLabel);
        variants.append(variantsHead);
        const grid = document.createElement("div");
        grid.className = "story-output-variants-grid";
        for (const entry of visiblePreviousEntries) {
          const entryNarrative =
            entry.role === "error" ? parseStoryRuntimeError(entry.text) : deriveStoryLatestOutputNarrative(entry.text);
          const card = document.createElement("article");
          card.className = "story-output-variant-card";
          card.classList.toggle("is-error", entry.role === "error");

          const variantKicker = document.createElement("span");
          variantKicker.className = "story-output-variant-kicker";
          variantKicker.textContent = outputCopy.previousVariant;

          const variantTitle = document.createElement("strong");
          variantTitle.className = "story-output-variant-title";
          const fullVariantTitle = entry.role === "error" ? copy.outputMetaVariantError : entryNarrative.title;
          const visibleVariantTitle = useDesktopQuietRuntime
            ? resolveStoryDesktopOutputVariantText("title", fullVariantTitle, fullVariantTitle)
            : fullVariantTitle;
          syncStoryCompactTextMeta(variantTitle, visibleVariantTitle, fullVariantTitle);

          const variantMeta = document.createElement("p");
          variantMeta.className = "story-output-variant-meta";
          const entryTime = formatStoryComposerTimeLabel(entry.updatedAt);
          const fullVariantMeta = [entry.modeLabel, entry.toneLabel, entryTime].filter(Boolean).join(" \u00b7 ");
          const visibleVariantMeta = useDesktopQuietRuntime
            ? resolveStoryDesktopOutputVariantText("meta", fullVariantMeta, fullVariantMeta)
            : fullVariantMeta;
          syncStoryCompactTextMeta(variantMeta, visibleVariantMeta, fullVariantMeta);

          const variantNote = document.createElement("p");
          variantNote.className = "story-output-variant-note";
          const fullVariantNote = entryNarrative.summary;
          const visibleVariantNote = useDesktopQuietRuntime
            ? resolveStoryDesktopOutputVariantText("note", fullVariantNote, fullVariantNote)
            : fullVariantNote;
          syncStoryCompactTextMeta(variantNote, visibleVariantNote, fullVariantNote);

          card.append(variantKicker, variantTitle, variantMeta, variantNote);
          grid.append(card);
        }
        variants.append(grid);
        if (hiddenVariantCount > 0) {
          const variantsMore = document.createElement("p");
          variantsMore.className = "story-output-variants-more";
          variantsMore.textContent = resolveStoryDesktopOutputVariantOverflowText(hiddenVariantCount);
          variants.append(variantsMore);
        }
        el.storyLatestOutput.append(variants);
      }
    }
  }

  if (shell instanceof HTMLElement) {
    shell.classList.toggle("is-empty", text.length === 0);
    shell.classList.toggle("is-pending", awaitingFreshResponse);
    shell.classList.toggle("is-error", text.length > 0 && latest.role === "error");
    shell.classList.toggle("is-ready", text.length > 0 && latest.role !== "error");
    shell.classList.toggle("is-streaming", text.length > 0 && latest.streaming === true);
  }
}

function renderStoryAtlasCards() {
  const isRu = state.languageMode === "ru";
  const copy = getStoryComposerCopy();
  const atlasCopy = getStoryAtlasPresentationCopy(isRu);
  const modeConfig = getStoryComposerModeConfig();
  const count = Math.max(0, Math.floor(state.storyTimelineSegments.length));
  const pendingJobs = Math.max(0, Math.floor(state.storyTimelinePendingJobs ?? 0));
  const counts = getStoryTimelineAssetCounts();
  const sceneTargetLabel = resolveStoryComposerSelectionLabel("storySceneTarget", modeConfig.defaults.sceneTarget);
  const toneLabel = resolveStoryComposerSelectionLabel("storyTone", modeConfig.defaults.tone);
  const mediaMixLabel = resolveStoryComposerSelectionLabel("storyMediaMix", modeConfig.defaults.mediaMix);
  const narrationLabel = resolveStoryComposerSelectionLabel("storyNarrationStyle", modeConfig.defaults.narrationStyle);
  const worldFocus = readStoryComposerControlValue(el.storyWorldFocus) || modeConfig.defaults.worldFocus;
  const characterFocus = readStoryComposerControlValue(el.storyCharacterFocus) || modeConfig.defaults.characterFocus;
  const totalRefs = counts.images + counts.video + counts.audio;
  const useDesktopQuietRuntime = (count > 0 || pendingJobs > 0 || hasStoryLatestOutputText()) && isStoryDesktopRuntimeQuietViewport();
  const preferredPanel = resolveStoryAtlasPreferredPanel({
    mode: state.storyComposerMode,
    pendingJobs,
    totalRefs,
  });
  const activePanel =
    typeof state.storyAtlasFocus === "string" && state.storyAtlasFocus.trim().length > 0
      ? normalizeStoryAtlasPanel(state.storyAtlasFocus)
      : preferredPanel;
  const worldCard = el.storyWorldHeading instanceof HTMLElement ? el.storyWorldHeading.closest(".story-atlas-card") : null;
  const characterCard =
    el.storyCharacterHeading instanceof HTMLElement ? el.storyCharacterHeading.closest(".story-atlas-card") : null;
  const mediaCard = el.storyMediaHeading instanceof HTMLElement ? el.storyMediaHeading.closest(".story-atlas-card") : null;

  setText(el.storyAtlasChip, atlasCopy.chip);
  const visibleAtlasHeading = useDesktopQuietRuntime
    ? resolveStoryDesktopAtlasShellHeading(activePanel, pendingJobs, totalRefs, atlasCopy.heading)
    : atlasCopy.heading;
  const visibleAtlasIntro = useDesktopQuietRuntime
    ? resolveStoryDesktopAtlasShellIntro(activePanel, pendingJobs, totalRefs, atlasCopy.intro)
    : atlasCopy.intro;
  syncStoryCompactTextMeta(el.storyAtlasHeading, visibleAtlasHeading, atlasCopy.heading);
  syncStoryCompactTextMeta(el.storyAtlasIntro, visibleAtlasIntro, atlasCopy.intro);
  if (el.storyAtlasRail instanceof HTMLElement) {
    el.storyAtlasRail.setAttribute("aria-label", atlasCopy.railLabel);
  }

  setText(el.storyWorldChip, copy.worldChip);
  const visibleWorldHeading = useDesktopQuietRuntime
    ? resolveStoryDesktopAtlasPanelHeading("world", worldFocus.trim().length > 0, pendingJobs, totalRefs, copy.worldHeading)
    : copy.worldHeading;
  syncStoryCompactTextMeta(el.storyWorldHeading, visibleWorldHeading, copy.worldHeading);
  const worldSummaryText = worldFocus || copy.worldSummaryFallback;
  const worldMetaText = worldFocus ? copy.worldMetaReady(toneLabel, sceneTargetLabel) : copy.worldMetaFallback;
  const visibleWorldSummary = useDesktopQuietRuntime
    ? resolveStoryDesktopAtlasSummary("world", worldSummaryText, worldSummaryText)
    : worldSummaryText;
  const visibleWorldMeta = useDesktopQuietRuntime
    ? resolveStoryDesktopAtlasMeta("world", worldMetaText, worldMetaText)
    : worldMetaText;
  syncStoryCompactTextMeta(el.storyWorldSummary, visibleWorldSummary, worldSummaryText);
  syncStoryCompactTextMeta(el.storyWorldMeta, visibleWorldMeta, worldMetaText);
  renderStoryTagList(el.storyWorldTags, [toneLabel, sceneTargetLabel]);
  if (worldCard instanceof HTMLElement) {
    worldCard.classList.toggle("is-shaped", worldFocus.trim().length > 0);
    worldCard.classList.toggle("is-empty", worldFocus.trim().length === 0);
  }

  setText(el.storyCharacterChip, copy.characterChip);
  const visibleCharacterHeading = useDesktopQuietRuntime
    ? resolveStoryDesktopAtlasPanelHeading(
        "character",
        characterFocus.trim().length > 0,
        pendingJobs,
        totalRefs,
        copy.characterHeading,
      )
    : copy.characterHeading;
  syncStoryCompactTextMeta(el.storyCharacterHeading, visibleCharacterHeading, copy.characterHeading);
  const characterSummaryText = characterFocus || copy.characterSummaryFallback;
  const characterMetaText = characterFocus
    ? copy.characterMetaReady(narrationLabel, modeConfig.badge)
    : copy.characterMetaFallback;
  const visibleCharacterSummary = useDesktopQuietRuntime
    ? resolveStoryDesktopAtlasSummary("character", characterSummaryText, characterSummaryText)
    : characterSummaryText;
  const visibleCharacterMeta = useDesktopQuietRuntime
    ? resolveStoryDesktopAtlasMeta("character", characterMetaText, characterMetaText)
    : characterMetaText;
  syncStoryCompactTextMeta(el.storyCharacterSummary, visibleCharacterSummary, characterSummaryText);
  syncStoryCompactTextMeta(el.storyCharacterMeta, visibleCharacterMeta, characterMetaText);
  renderStoryTagList(el.storyCharacterTags, [modeConfig.badge, narrationLabel]);
  if (characterCard instanceof HTMLElement) {
    characterCard.classList.toggle("is-shaped", characterFocus.trim().length > 0);
    characterCard.classList.toggle("is-empty", characterFocus.trim().length === 0);
  }

  setText(el.storyMediaChip, copy.mediaChip);
  const visibleMediaHeading = useDesktopQuietRuntime
    ? resolveStoryDesktopAtlasPanelHeading("media", totalRefs > 0, pendingJobs, totalRefs, copy.mediaHeading)
    : copy.mediaHeading;
  syncStoryCompactTextMeta(el.storyMediaHeading, visibleMediaHeading, copy.mediaHeading);
  const summarizedSceneCount = Math.max(count, 1);
  const mediaSummary =
    pendingJobs > 0
      ? isRu
        ? pendingJobs === 1
          ? "1 рендер всё ещё в очереди."
          : `${pendingJobs} рендеров всё ещё в очереди.`
        : copy.mediaSummaryPending(pendingJobs)
      : count > 0 || counts.images > 0 || counts.video > 0 || counts.audio > 0
        ? isRu
          ? `${totalRefs} референсов собрано на ${summarizedSceneCount} ${summarizedSceneCount === 1 ? "сцену" : summarizedSceneCount < 5 ? "сцены" : "сцен"}.`
          : copy.mediaSummaryReady(counts.images, counts.video, counts.audio, summarizedSceneCount)
        : isRu
          ? "Пока без ассетов. Первый прогон заполнит эту панель."
          : copy.mediaSummaryEmpty;
  const visibleMediaSummary = useDesktopQuietRuntime
    ? resolveStoryDesktopAtlasSummary("media", mediaSummary, mediaSummary)
    : mediaSummary;
  syncStoryCompactTextMeta(el.storyMediaSummary, visibleMediaSummary, mediaSummary);
  setText(el.storyMediaImageLabel, copy.mediaMetricImages);
  setText(el.storyMediaImageCount, String(counts.images));
  setText(el.storyMediaVideoLabel, copy.mediaMetricVideo);
  setText(el.storyMediaVideoCount, String(counts.video));
  setText(el.storyMediaAudioLabel, copy.mediaMetricAudio);
  setText(el.storyMediaAudioCount, String(counts.audio));
  const mediaMetricStates = [
    [el.storyMediaImageCount, counts.images, copy.mediaMetricImages],
    [el.storyMediaVideoCount, counts.video, copy.mediaMetricVideo],
    [el.storyMediaAudioCount, counts.audio, copy.mediaMetricAudio],
  ];
  for (const [valueNode, value, label] of mediaMetricStates) {
    const metricCard = valueNode instanceof HTMLElement ? valueNode.closest(".story-atlas-metric") : null;
    if (metricCard instanceof HTMLElement) {
      metricCard.classList.toggle("is-empty", value === 0);
      metricCard.classList.toggle("is-ready", value > 0);
      metricCard.setAttribute("aria-label", `${label}: ${value}`);
    }
  }
  renderStoryTagList(el.storyMediaTags, [
    mediaMixLabel,
    narrationLabel,
    pendingJobs > 0 ? copy.mediaTagQueued(pendingJobs) : totalRefs > 0 ? copy.mediaTagReady(totalRefs) : copy.mediaTagIdle,
  ]);
  if (mediaCard instanceof HTMLElement) {
    mediaCard.classList.remove("is-idle", "is-pending", "is-ready");
    if (pendingJobs > 0) {
      mediaCard.classList.add("is-pending");
    } else if (totalRefs > 0 || count > 0) {
      mediaCard.classList.add("is-ready");
    } else {
      mediaCard.classList.add("is-idle");
    }
  }

  syncStoryAtlasSurface(activePanel, {
    world: {
      label: copy.worldChip,
      hint:
        worldFocus && (toneLabel || sceneTargetLabel)
          ? compactStorySignalValue([toneLabel, sceneTargetLabel].filter(Boolean).join(" \u00b7 "), 26)
          : atlasCopy.worldTabFallback,
    },
    character: {
      label: copy.characterChip,
      hint: characterFocus ? compactStorySignalValue(narrationLabel || atlasCopy.characterTabFallback, 26) : atlasCopy.characterTabFallback,
    },
    media: {
      label: copy.mediaChip,
      hint:
        pendingJobs > 0
          ? copy.mediaTagQueued(pendingJobs)
          : totalRefs > 0
            ? copy.mediaTagReady(totalRefs)
            : atlasCopy.mediaTabFallback,
    },
  });

  setText(el.storyScenesChip, copy.scenesChip);
}

function renderStoryStudioSurface() {
  const copy = getStoryComposerCopy();
  const modeConfig = getStoryComposerModeConfig();
  const normalizedMode = normalizeStoryComposerMode(state.storyComposerMode);
  const count = Math.max(0, Math.floor(state.storyTimelineSegments.length));
  const pendingJobs = Math.max(0, Math.floor(state.storyTimelinePendingJobs ?? 0));
  const hasRunActivity = hasStoryRunActivity();
  const latestResponsePhase = resolveStoryLatestResponsePhase();
  const interactionState = resolveStoryComposerInteractionState({
    count,
    pendingJobs,
    hasRunActivity,
    latestResponsePhase,
  });
  const isBusyState = interactionState === "pending" || interactionState === "updating";
  const promptDraftValue = readStoryComposerControlValue(el.storyComposerPrompt);
  const promptValue = resolveStoryComposerPromptText();
  const normalizedPromptDraft = promptDraftValue.replace(/^story:\s*/i, "").replace(/\s+/g, " ").trim();
  const normalizedModePrompt = modeConfig.prompt.replace(/^story:\s*/i, "").replace(/\s+/g, " ").trim();
  const hasTypedPrompt = normalizedPromptDraft.length > 0 && normalizedPromptDraft !== normalizedModePrompt;
  const sceneTargetLabel = resolveStoryComposerSelectionLabel("storySceneTarget", modeConfig.defaults.sceneTarget);
  const toneLabel = resolveStoryComposerSelectionLabel("storyTone", modeConfig.defaults.tone);
  const mediaMixLabel = resolveStoryComposerSelectionLabel("storyMediaMix", modeConfig.defaults.mediaMix);
  const narrationLabel = resolveStoryComposerSelectionLabel("storyNarrationStyle", modeConfig.defaults.narrationStyle);
  const previewTextSource = (promptValue || modeConfig.prompt).replace(/^story:\s*/i, "").replace(/\s+/g, " ").trim();
  const previewLead = previewTextSource.length > 168 ? `${previewTextSource.slice(0, 165)}...` : previewTextSource;
  const previewDescriptor = [modeConfig.badge, sceneTargetLabel, mediaMixLabel].filter(Boolean).join(" · ");
  const compactPreview = previewDescriptor ? `${previewLead} · ${previewDescriptor}` : previewLead;
  const promptPreviewText = !hasRunActivity && !hasTypedPrompt ? previewDescriptor : compactPreview;
  const modeVariant = pendingJobs > 0 ? "neutral" : count > 0 ? "ok" : "neutral";
  const useDesktopQuietCompose = !hasRunActivity && isStoryDesktopComposeQuietViewport();
  const useDesktopPromptCompact = isStoryDesktopComposeQuietViewport();
  const useDesktopQuietRuntime = hasRunActivity && isStoryDesktopRuntimeQuietViewport();
  const timelineRuntimeState = resolveStoryTimelineRuntimeState({ count, pendingJobs });
  const characterFocus = readStoryComposerControlValue(el.storyCharacterFocus) || modeConfig.defaults.characterFocus;
  const worldFocus = readStoryComposerControlValue(el.storyWorldFocus) || modeConfig.defaults.worldFocus;
  const editorialNotes = readStoryComposerControlValue(el.storyEditorialNotes) || modeConfig.defaults.editorialNotes;

  renderStoryModeRail();
  renderStorySignalStrip();
  syncStoryStudioVisibility(count, pendingJobs);

  setText(el.storyComposeChip, copy.composeChip);
  setText(el.storyComposeHeading, modeConfig.heading);
  const visibleComposeIntro = useDesktopQuietCompose
    ? resolveStoryDesktopComposeIntro(normalizedMode, modeConfig.intro)
    : modeConfig.intro;
  setText(el.storyComposeIntro, visibleComposeIntro);
  if (el.storyComposeIntro instanceof HTMLElement) {
    el.storyComposeIntro.title = modeConfig.intro;
  }
  if (el.storyComposeModeBadge instanceof HTMLElement) {
    const visibleModeBadge = useDesktopQuietCompose
      ? resolveStoryDesktopComposeBadge(normalizedMode, modeConfig.badge)
      : modeConfig.badge;
    setStatusPill(el.storyComposeModeBadge, visibleModeBadge, modeVariant);
    el.storyComposeModeBadge.title = modeConfig.badge;
  }
  const composeStatusShell =
    el.storyComposeStatus instanceof HTMLElement ? el.storyComposeStatus.closest(".story-compose-status") : null;
  if (composeStatusShell instanceof HTMLElement) {
    composeStatusShell.dataset.storyComposeState = interactionState;
  }
  if (el.storyComposeStatus instanceof HTMLElement) {
    let composeStatusText = modeConfig.status;
    if (interactionState === "pending") {
      composeStatusText = copy.composeStatusSubmitting ?? copy.composeStatusPending?.(pendingJobs) ?? copy.composeStatusIdle;
    } else if (interactionState === "updating") {
      composeStatusText = copy.composeStatusUpdating ?? copy.composeStatusPending?.(pendingJobs) ?? copy.composeStatusReady(count);
    } else if (count > 0) {
      composeStatusText = copy.composeStatusReady(count);
    } else if (useDesktopQuietCompose) {
      composeStatusText = resolveStoryDesktopComposeStatus(normalizedMode, modeConfig.status);
    }
    el.storyComposeStatus.textContent = composeStatusText;
    el.storyComposeStatus.title = modeConfig.status;
  }

  setText(el.storyFlowStepOneTitle, copy.flowStepOneTitle);
  setText(el.storyFlowStepOneHint, copy.flowStepOneHint);
  setText(el.storyFlowStepTwoTitle, copy.flowStepTwoTitle);
  setText(el.storyFlowStepTwoHint, copy.flowStepTwoHint);
  setText(el.storyFlowStepThreeTitle, copy.flowStepThreeTitle);
  setText(el.storyFlowStepThreeHint, copy.flowStepThreeHint);

  const visiblePromptLabel = useDesktopPromptCompact ? resolveStoryDesktopPromptLabel(copy.promptLabel) : copy.promptLabel;
  setText(el.storyComposerPromptLabel, visiblePromptLabel);
  if (el.storyComposerPromptLabel instanceof HTMLElement) {
    if (visiblePromptLabel !== copy.promptLabel) {
      el.storyComposerPromptLabel.title = copy.promptLabel;
    } else {
      el.storyComposerPromptLabel.removeAttribute("title");
    }
  }
  const visiblePromptHint = useDesktopPromptCompact ? resolveStoryDesktopPromptHint(normalizedMode, copy.promptHint) : copy.promptHint;
  setText(el.storyComposerPromptHint, visiblePromptHint);
  if (el.storyComposerPromptHint instanceof HTMLElement) {
    el.storyComposerPromptHint.title = copy.promptHint;
  }
  if (el.storyComposerPrompt instanceof HTMLTextAreaElement) {
    el.storyComposerPrompt.placeholder = copy.promptPlaceholder;
  }
  if (el.storyComposerPromptPreview instanceof HTMLElement) {
    const fullPromptPreviewText = `${copy.promptPreviewPrefix}: ${promptPreviewText}`;
    const compactPromptPreviewText = `${resolveStoryDesktopPromptPreviewPrefix(copy.promptPreviewPrefix)} · ${promptPreviewText}`;
    const visiblePromptPreviewText = useDesktopPromptCompact ? compactPromptPreviewText : fullPromptPreviewText;
    el.storyComposerPromptPreview.hidden = !hasRunActivity && !hasTypedPrompt;
    el.storyComposerPromptPreview.textContent = visiblePromptPreviewText;
    if (visiblePromptPreviewText !== fullPromptPreviewText) {
      el.storyComposerPromptPreview.title = fullPromptPreviewText;
    } else {
      el.storyComposerPromptPreview.removeAttribute("title");
    }
  }
  const promptQuality = copy.promptQuality(promptValue.length);
  const fullPromptCount = copy.promptCount(promptValue.length);
  const visiblePromptCount = useDesktopPromptCompact
    ? resolveStoryDesktopPromptCount(promptValue.length, promptQuality, fullPromptCount)
    : fullPromptCount;
  setText(el.storyComposerPromptCount, visiblePromptCount);
  if (el.storyComposerPromptCount instanceof HTMLElement) {
    el.storyComposerPromptCount.setAttribute("data-quality", promptQuality);
    if (visiblePromptCount !== fullPromptCount) {
      el.storyComposerPromptCount.title = fullPromptCount;
    } else {
      el.storyComposerPromptCount.removeAttribute("title");
    }
  }
  const submitLabel =
    interactionState === "pending"
      ? copy.submitLabelPending ?? copy.submitLabel
      : interactionState === "updating"
        ? copy.submitLabelUpdating ?? copy.submitLabel
        : interactionState === "ready"
          ? copy.submitLabelReady ?? copy.submitLabel
          : copy.submitLabel;
  const templateLabel = isBusyState ? copy.templateLabelBusy ?? copy.templateLabel : copy.templateLabel;
  const openLiveLabel =
    interactionState === "pending" || interactionState === "updating"
      ? copy.openLiveLabelBusy ?? copy.openLiveLabel
      : interactionState === "ready"
        ? copy.openLiveLabelReady ?? copy.openLiveLabel
        : copy.openLiveLabel;
  const visibleSubmitLabel =
    useDesktopQuietCompose && interactionState === "idle"
      ? resolveStoryDesktopActionLabel("submit", submitLabel)
      : submitLabel;
  const visibleTemplateLabel =
    useDesktopQuietCompose && interactionState === "idle"
      ? resolveStoryDesktopActionLabel("template", templateLabel)
      : templateLabel;
  const visibleOpenLiveLabel =
    useDesktopQuietCompose && interactionState === "idle"
      ? resolveStoryDesktopActionLabel("live", openLiveLabel)
      : openLiveLabel;
  syncStoryActionButton(el.storyComposerSubmitBtn, {
    label: visibleSubmitLabel,
    disabled: isBusyState,
    busy: isBusyState,
    state: interactionState,
  });
  syncStoryActionButton(el.storyComposerTemplateBtn, {
    label: visibleTemplateLabel,
    disabled: isBusyState,
    state: interactionState,
  });
  syncStoryActionButton(el.storyComposerOpenLiveBtn, {
    label: visibleOpenLiveLabel,
    state: interactionState,
  });
  syncStoryActionButtonMeta(el.storyComposerSubmitBtn, submitLabel);
  syncStoryActionButtonMeta(el.storyComposerTemplateBtn, templateLabel);
  syncStoryActionButtonMeta(el.storyComposerOpenLiveBtn, openLiveLabel);
  const composeActions =
    el.storyComposerSubmitBtn instanceof HTMLButtonElement ? el.storyComposerSubmitBtn.closest(".story-compose-actions") : null;
  if (composeActions instanceof HTMLElement) {
    composeActions.dataset.storyComposeState = interactionState;
  }

  setText(el.storyCraftTrayTitle, copy.storyCraftTrayTitle);
  setText(el.storyCraftTrayHint, copy.storyCraftTrayHint);
  setText(el.storyCraftAnchorEyebrow, copy.storyCraftAnchorEyebrow);
  setText(el.storyCraftAnchorHint, copy.storyCraftAnchorHint);
  setText(el.storyCraftStructureEyebrow, copy.storyCraftStructureEyebrow);
  setText(el.storyCraftStructureHint, copy.storyCraftStructureHint);
  setText(el.storyCharacterFocusLabel, copy.storyCharacterFocusLabel);
  setText(el.storyWorldFocusLabel, copy.storyWorldFocusLabel);
  setText(el.storySceneTargetLabel, copy.sceneTargetLabel);
  if (el.storyCharacterFocus instanceof HTMLInputElement) {
    el.storyCharacterFocus.placeholder = copy.storyCharacterFocusPlaceholder;
  }
  if (el.storyWorldFocus instanceof HTMLInputElement) {
    el.storyWorldFocus.placeholder = copy.storyWorldFocusPlaceholder;
  }
  setStoryComposerSelectOptionLabels(el.storySceneTarget, copy.sceneTargetOptions);
  const craftTraySummaryFull = formatStoryTraySummary(
    [
      compactStoryReferenceValue(characterFocus, 2, 20),
      compactStoryReferenceValue(worldFocus, 3, 26),
    ],
    112,
  );
  const craftTraySummaryVisible = useDesktopQuietCompose
    ? resolveStoryDesktopCraftTraySummary(characterFocus, worldFocus, craftTraySummaryFull)
    : craftTraySummaryFull;
  syncStoryCompactTextMeta(el.storyCraftTraySummaryText, craftTraySummaryVisible, craftTraySummaryFull);
  renderStoryTagList(el.storyCraftTraySummaryMeta, [sceneTargetLabel]);

  setText(el.storyMediaTrayTitle, copy.storyMediaTrayTitle);
  setText(el.storyMediaTrayHint, copy.storyMediaTrayHint);
  setText(el.storyMediaDeliveryEyebrow, copy.storyMediaDeliveryEyebrow);
  setText(el.storyMediaDeliveryHint, copy.storyMediaDeliveryHint);
  setText(el.storyMediaVoiceEyebrow, copy.storyMediaVoiceEyebrow);
  setText(el.storyMediaVoiceHint, copy.storyMediaVoiceHint);
  setText(el.storyToneLabel, copy.toneLabel);
  setText(el.storyMediaMixLabel, copy.mediaMixLabel);
  setText(el.storyNarrationStyleLabel, copy.narrationStyleLabel);
  setStoryComposerSelectOptionLabels(el.storyTone, copy.toneOptions);
  setStoryComposerSelectOptionLabels(el.storyMediaMix, copy.mediaMixOptions);
  setStoryComposerSelectOptionLabels(el.storyNarrationStyle, copy.narrationStyleOptions);
  const mediaTraySummaryFull = formatStoryTraySummary(
    [
      compactStoryReferenceValue(mediaMixLabel, 4, 34),
      compactStoryReferenceValue(narrationLabel, 4, 36),
    ],
    92,
  );
  const mediaTraySummaryVisible = useDesktopQuietCompose
    ? resolveStoryDesktopMediaTraySummary(mediaMixLabel, narrationLabel, mediaTraySummaryFull)
    : mediaTraySummaryFull;
  syncStoryCompactTextMeta(el.storyMediaTraySummaryText, mediaTraySummaryVisible, mediaTraySummaryFull);
  renderStoryTagList(el.storyMediaTraySummaryMeta, [toneLabel]);

  setText(el.storyDirectionTrayTitle, copy.storyDirectionTrayTitle);
  setText(el.storyDirectionTrayHint, copy.storyDirectionTrayHint);
  setText(el.storyDirectionLeadEyebrow, copy.storyDirectionLeadEyebrow);
  setText(el.storyDirectionLeadHint, copy.storyDirectionLeadHint);
  setText(el.storyEditorialNotesLabel, copy.storyEditorialNotesLabel);
  if (el.storyEditorialNotes instanceof HTMLTextAreaElement) {
    el.storyEditorialNotes.placeholder = copy.storyEditorialNotesPlaceholder;
  }
  const directionTraySummaryFull = editorialNotes
    ? compactStoryReferenceValue(editorialNotes, 12, 108)
    : copy.storyDirectionTraySummaryEmpty;
  const directionTraySummaryVisible =
    useDesktopQuietCompose && editorialNotes
      ? resolveStoryDesktopDirectionTraySummary(editorialNotes, directionTraySummaryFull)
      : directionTraySummaryFull;
  syncStoryCompactTextMeta(el.storyDirectionTraySummaryText, directionTraySummaryVisible, directionTraySummaryFull);
  renderStoryTagList(el.storyDirectionTraySummaryMeta, []);

  setText(el.storyRunChip, copy.runChip);
  setText(el.storyRunHeading, copy.runHeading);
  setText(el.storyRunIntro, copy.runIntro);
  const guideTemplateLabel =
    isBusyState
      ? copy.guideRunActiveLabel ?? copy.generateLabel
      : interactionState === "ready"
        ? copy.submitLabelReady ?? copy.generateLabel
        : copy.generateLabel;
  const visibleGuideTemplateLabel = useDesktopQuietRuntime
    ? resolveStoryDesktopTimelineActionLabel("template", timelineRuntimeState, guideTemplateLabel)
    : guideTemplateLabel;
  const visibleGuideOpenLiveLabel = useDesktopQuietRuntime
    ? resolveStoryDesktopTimelineActionLabel("live", timelineRuntimeState, openLiveLabel)
    : openLiveLabel;
  syncStoryActionButton(el.storyTimelineGuideTemplateBtn, {
    label: visibleGuideTemplateLabel,
    disabled: isBusyState,
    state: interactionState,
  });
  syncStoryActionButton(el.storyTimelineGuideOpenLiveBtn, {
    label: visibleGuideOpenLiveLabel,
    state: interactionState,
  });
  syncStoryActionButtonMeta(el.storyTimelineGuideTemplateBtn, guideTemplateLabel);
  syncStoryActionButtonMeta(el.storyTimelineGuideOpenLiveBtn, openLiveLabel);
  const guidanceActions =
    el.storyTimelineGuideTemplateBtn instanceof HTMLButtonElement
      ? el.storyTimelineGuideTemplateBtn.closest(".story-guidance-actions")
      : null;
  if (guidanceActions instanceof HTMLElement) {
    guidanceActions.dataset.storyComposeState = interactionState;
  }

  renderStoryLatestOutput();
  renderStoryAtlasCards();
}

function applyStoryComposerMode(mode, options = {}) {
  const normalizedMode = normalizeStoryComposerMode(mode);
  const previousMode = normalizeStoryComposerMode(state.storyComposerMode);
  const previousConfig =
    options.previousConfig && typeof options.previousConfig === "object"
      ? options.previousConfig
      : getStoryComposerModeConfig(previousMode);
  state.storyComposerMode = normalizedMode;
  const modeConfig = getStoryComposerModeConfig(normalizedMode);
  const force = options.force === true;
  const focusPrompt = options.focusPrompt === true;

  const maybeApplyValue = (control, nextValue, previousValue = "") => {
    if (!(control instanceof HTMLInputElement || control instanceof HTMLTextAreaElement || control instanceof HTMLSelectElement)) {
      return;
    }
    const currentValue = readStoryComposerControlValue(control);
    const shouldReplace = force || currentValue.length === 0 || currentValue === previousValue;
    if (!shouldReplace || typeof nextValue !== "string") {
      if (control instanceof HTMLSelectElement) {
        syncCustomSelectControl(control);
      }
      return;
    }
    control.value = nextValue;
    if (control instanceof HTMLSelectElement) {
      syncCustomSelectControl(control);
    }
  };

  maybeApplyValue(el.storyComposerPrompt, modeConfig.prompt, previousConfig.prompt);
  maybeApplyValue(
    el.storyCharacterFocus,
    modeConfig.defaults.characterFocus,
    previousConfig.defaults?.characterFocus ?? "",
  );
  maybeApplyValue(
    el.storyWorldFocus,
    modeConfig.defaults.worldFocus,
    previousConfig.defaults?.worldFocus ?? "",
  );
  maybeApplyValue(
    el.storySceneTarget,
    modeConfig.defaults.sceneTarget,
    previousConfig.defaults?.sceneTarget ?? "",
  );
  maybeApplyValue(el.storyTone, modeConfig.defaults.tone, previousConfig.defaults?.tone ?? "");
  maybeApplyValue(el.storyMediaMix, modeConfig.defaults.mediaMix, previousConfig.defaults?.mediaMix ?? "");
  maybeApplyValue(
    el.storyNarrationStyle,
    modeConfig.defaults.narrationStyle,
    previousConfig.defaults?.narrationStyle ?? "",
  );
  maybeApplyValue(
    el.storyEditorialNotes,
    modeConfig.defaults.editorialNotes,
    previousConfig.defaults?.editorialNotes ?? "",
  );

  if (force || normalizedMode !== previousMode) {
    const counts = getStoryTimelineAssetCounts();
    const totalRefs = counts.images + counts.video + counts.audio;
    state.storyAtlasFocus = resolveStoryAtlasPreferredPanel({
      mode: normalizedMode,
      pendingJobs: state.storyTimelinePendingJobs,
      totalRefs,
    });
  }

  renderStoryStudioSurface();

  if (focusPrompt && el.storyComposerPrompt instanceof HTMLTextAreaElement) {
    window.requestAnimationFrame(() => {
      el.storyComposerPrompt.focus();
      const caret = el.storyComposerPrompt.value.length;
      el.storyComposerPrompt.setSelectionRange(caret, caret);
    });
  }
}

function submitStoryComposerRequest() {
  const builtPrompt = buildStoryComposerPrompt();
  state.storyLatestRequestAt = toIsoNow();
  seedLiveNegotiatorWithStoryPrompt(builtPrompt);
  renderStoryStudioSurface();
  sendIntentRequest({
    intent: "story",
    message: builtPrompt,
    metadata: {
      entrypoint: "storyteller_canvas",
      storyMode: state.storyComposerMode,
      sceneTarget: readStoryComposerControlValue(el.storySceneTarget),
      mediaMix: readStoryComposerControlValue(el.storyMediaMix),
      tone: readStoryComposerControlValue(el.storyTone),
    },
  });
}

function formatStoryTimelineStatusText(value, isRu = state.languageMode === "ru") {
  if (typeof value !== "string") {
    return value;
  }
  const normalized = value.trim().toLowerCase();
  if (!normalized) {
    return value;
  }

  if (normalized === "timeline_idle") {
    return isRu ? "ждёт первый запуск" : "waiting for first run";
  }
  if (normalized === "timeline_pending_video") {
    return isRu ? "идёт рендер" : "rendering";
  }
  if (normalized === "timeline_ready") {
    return isRu ? "готово к просмотру" : "ready to review";
  }
  if (normalized === "list_idle") {
    return isRu ? "карточки ждут запуск" : "cards waiting";
  }
  if (normalized === "list_pending") {
    return isRu ? "карточки готовятся" : "cards rendering";
  }
  if (normalized === "list_ready") {
    return isRu ? "карточки готовы" : "cards ready";
  }
  if (normalized === "assets=none") {
    return isRu ? "ассеты ещё не готовы" : "assets not ready";
  }
  if (normalized === "assets=queueing") {
    return isRu ? "ассеты прогреваются" : "assets warming up";
  }
  if (normalized === "progress=0%") {
    return isRu ? "прогресс: пусто" : "progress: empty";
  }
  if (normalized === "progress=queued") {
    return isRu ? "прогресс: очередь активна" : "progress: queued";
  }
  if (normalized === "queueing first segment") {
    return isRu ? "ждём первую сцену" : "waiting for first scene";
  }

  const progressMatch = normalized.match(/^(\d+)\/(\d+)\s+segments$/);
  if (progressMatch) {
    const [, current, total] = progressMatch;
    return isRu ? `${current} из ${total} сцен` : `${current} of ${total} scenes`;
  }

  const assetMatch = normalized.match(/^assets=i(\d+)\/v(\d+)\/a(\d+)$/);
  if (assetMatch) {
    const [, imageCount, videoCount, audioCount] = assetMatch;
    return isRu
      ? `${imageCount} изображ. / ${videoCount} видео / ${audioCount} звук`
      : `${imageCount} images / ${videoCount} video / ${audioCount} audio`;
  }

  return value;
}

function getStorySceneLaneStatusLabel(kind, isRu = state.languageMode === "ru") {
  switch (kind) {
    case "ready":
      return isRu ? "раскадровка готова" : "storyboard ready";
    case "pending":
      return isRu ? "раскадровка собирается" : "storyboard building";
    case "error":
      return isRu ? "ошибка прогона" : "run failed";
    case "idle":
    default:
      return isRu ? "ждём сцены" : "awaiting scenes";
  }
}

function getStoryTimelineNavigatorHint(kind, isRu = state.languageMode === "ru") {
  switch (kind) {
    case "error":
      return isRu
        ? "The latest run failed before the first scene landed. Review the output and retry from the same brief."
        : "The latest run failed before the first scene landed. Review the output and retry from the same brief.";
    case "pending":
      return isRu
        ? "Собираем первые сцены. Навигатор откроется, как только появится первая карточка."
        : "Building the first scenes. The navigator opens as soon as the first card lands.";
    case "updating":
      return isRu
        ? "Новые сцены ещё дорисовываются. Уже готовые можно листать."
        : "More scenes are still rendering. Ready beats stay browsable.";
    case "ready":
      return isRu
        ? "Навигатор готов: переключай сцену и смотри превью рядом."
        : "Navigator ready: jump scenes and review preview.";
    case "idle":
    default:
      return isRu
        ? "Навигатор включится после первого прогона из Story Studio выше."
        : "The navigator unlocks after the first Story Studio run.";
  }
}

