function createStoryTimelineEmptyStatusPill(text, variant = "neutral") {
  const pill = document.createElement("span");
  pill.className = "status-pill";
  pill.classList.add(variant === "ok" ? "status-ok" : variant === "fail" ? "status-fail" : "status-neutral");
  pill.textContent = formatStoryTimelineStatusText(text);
  return pill;
}

function renderStoryTimelineStateCard(
  count,
  pendingJobs,
  progressPercent,
  runtimeState = resolveStoryTimelineRuntimeState({ count, pendingJobs }),
) {
  const copy = getStoryTimelineCopy();
  if (el.storyTimelineProgressKpi) {
    el.storyTimelineProgressKpi.textContent = `${Math.max(0, Math.floor(progressPercent))}%`;
  }
  if (el.storyTimelineNextCue) {
    let fullCue = copy.nextCueIdle;
    if (runtimeState === "error") {
      fullCue = copy.nextCueError;
    } else if (count === 0 && pendingJobs > 0) {
      fullCue = copy.nextCuePending;
    } else if (count === 0) {
      fullCue = copy.nextCueIdle;
    } else if (pendingJobs > 0) {
      fullCue = copy.pendingJobLabel(pendingJobs);
    } else {
      fullCue = copy.nextCueReady;
    }
    const visibleCue = isStoryDesktopRuntimeQuietViewport()
      ? resolveStoryDesktopRunRailCue(count, pendingJobs, runtimeState, fullCue)
      : fullCue;
    syncStoryCompactTextMeta(el.storyTimelineNextCue, visibleCue, fullCue);
  }
  if (!(el.storyTimelineStateCard instanceof HTMLElement)) {
    return;
  }
  el.storyTimelineStateCard.classList.remove("is-idle", "is-pending", "is-ready", "is-error");
  if (runtimeState === "error") {
    el.storyTimelineStateCard.classList.add("is-error");
    return;
  }
  if (runtimeState === "pending") {
    el.storyTimelineStateCard.classList.add("is-pending");
    return;
  }
  if (runtimeState === "idle") {
    el.storyTimelineStateCard.classList.add("is-idle");
    return;
  }
  if (runtimeState === "updating") {
    el.storyTimelineStateCard.classList.add("is-pending");
    return;
  }
  el.storyTimelineStateCard.classList.add("is-ready");
}

function syncStoryTimelineControlState(
  count,
  pendingJobs,
  runtimeState = resolveStoryTimelineRuntimeState({ count, pendingJobs }),
) {
  const safeCount = Math.max(0, Number.isFinite(count) ? Math.floor(count) : 0);
  const isCollapsed = safeCount === 0;
  const controlNodes = [el.storyTimelineControls, el.storyTimelineControlsGrid];
  for (const node of controlNodes) {
    if (!(node instanceof HTMLElement)) {
      continue;
    }
    node.classList.toggle("is-idle", runtimeState === "idle");
    node.classList.toggle("is-pending", runtimeState === "pending" || runtimeState === "updating");
    node.classList.toggle("is-ready", runtimeState === "ready");
    node.classList.toggle("is-error", runtimeState === "error");
    node.classList.toggle("is-collapsed", isCollapsed);
  }
}

function renderStoryTimelineControlsHint(
  count,
  pendingJobs,
  runtimeState = resolveStoryTimelineRuntimeState({ count, pendingJobs }),
) {
  if (!(el.storyTimelineControlsHint instanceof HTMLElement)) {
    return;
  }
  el.storyTimelineControlsHint.classList.remove(
    "story-controls-hint-idle",
    "story-controls-hint-pending",
    "story-controls-hint-ready",
    "story-controls-hint-error",
  );

  const fullHint = getStoryTimelineNavigatorHint(runtimeState);
  const visibleHint = isStoryDesktopRuntimeQuietViewport()
    ? resolveStoryDesktopTimelineNavigatorHint(runtimeState, count, pendingJobs, fullHint)
    : fullHint;

  if (runtimeState === "error") {
    el.storyTimelineControlsHint.classList.add("story-controls-hint-error");
    syncStoryCompactTextMeta(el.storyTimelineControlsHint, visibleHint, fullHint);
    return;
  }

  if (runtimeState === "pending") {
    el.storyTimelineControlsHint.classList.add("story-controls-hint-pending");
    syncStoryCompactTextMeta(el.storyTimelineControlsHint, visibleHint, fullHint);
    return;
  }

  if (runtimeState === "idle") {
    el.storyTimelineControlsHint.classList.add("story-controls-hint-idle");
    syncStoryCompactTextMeta(el.storyTimelineControlsHint, visibleHint, fullHint);
    return;
  }

  if (runtimeState === "updating") {
    el.storyTimelineControlsHint.classList.add("story-controls-hint-pending");
    syncStoryCompactTextMeta(el.storyTimelineControlsHint, visibleHint, fullHint);
    return;
  }

  el.storyTimelineControlsHint.classList.add("story-controls-hint-ready");
  syncStoryCompactTextMeta(el.storyTimelineControlsHint, visibleHint, fullHint);
}

function renderStoryTimelineListHead(
  count,
  pendingJobs,
  runtimeState = resolveStoryTimelineRuntimeState({ count, pendingJobs }),
) {
  const copy = getStoryTimelineCopy();
  const safeCount = Math.max(0, Number.isFinite(count) ? Math.floor(count) : 0);
  const safePending = Math.max(0, Number.isFinite(pendingJobs) ? Math.floor(pendingJobs) : 0);
  const listHead =
    el.storyTimelineListSummary instanceof HTMLElement ? el.storyTimelineListSummary.closest(".story-list-head") : null;
  const listShell = el.storyTimelineList instanceof HTMLElement ? el.storyTimelineList.closest(".story-scenes-shell") : null;
  if (el.storyTimelineListSummary instanceof HTMLElement) {
    let fullSummary = copy.listIdle;
    if (runtimeState === "ready" || runtimeState === "updating") {
      fullSummary = copy.listLoaded(safeCount);
    } else if (runtimeState === "pending") {
      fullSummary = copy.listPending(safePending);
    } else if (runtimeState === "error") {
      fullSummary = copy.listError;
    }
    const visibleSummary = isStoryDesktopRuntimeQuietViewport()
      ? resolveStoryDesktopTimelineListSummary(runtimeState, safeCount, safePending, fullSummary)
      : fullSummary;
    syncStoryCompactTextMeta(el.storyTimelineListSummary, visibleSummary, fullSummary);
  }
  if (el.storyTimelineListState instanceof HTMLElement) {
    if (runtimeState === "ready") {
      setStatusPill(el.storyTimelineListState, getStorySceneLaneStatusLabel("ready"), "ok");
    } else if (runtimeState === "pending" || runtimeState === "updating") {
      setStatusPill(el.storyTimelineListState, getStorySceneLaneStatusLabel("pending"), "neutral");
    } else if (runtimeState === "error") {
      setStatusPill(el.storyTimelineListState, getStorySceneLaneStatusLabel("error"), "neutral");
    } else {
      setStatusPill(el.storyTimelineListState, getStorySceneLaneStatusLabel("idle"), "neutral");
    }
  }
  if (listHead instanceof HTMLElement) {
    listHead.classList.toggle("is-ready", runtimeState === "ready");
    listHead.classList.toggle("is-pending", runtimeState === "pending" || runtimeState === "updating");
    listHead.classList.toggle("is-idle", runtimeState === "idle");
    listHead.classList.toggle("is-error", runtimeState === "error");
  }
  if (listShell instanceof HTMLElement) {
    listShell.classList.toggle("is-ready", runtimeState === "ready");
    listShell.classList.toggle("is-pending", runtimeState === "pending" || runtimeState === "updating");
    listShell.classList.toggle("is-idle", runtimeState === "idle");
    listShell.classList.toggle("is-error", runtimeState === "error");
  }
}

function syncStoryTimelineStatusRow(
  count,
  pendingJobs,
  runtimeState = resolveStoryTimelineRuntimeState({ count, pendingJobs }),
) {
  const statusRow =
    el.storyTimelineMode instanceof HTMLElement ? el.storyTimelineMode.closest(".story-status-row") : null;
  if (!(statusRow instanceof HTMLElement)) {
    return;
  }
  statusRow.classList.toggle("is-idle", runtimeState === "idle");
  statusRow.classList.toggle("is-pending", runtimeState === "pending" || runtimeState === "updating");
  statusRow.classList.toggle("is-ready", runtimeState === "ready");
  statusRow.classList.toggle("is-error", runtimeState === "error");
}

function openLiveNegotiatorFromStoryEmptyState(options = {}) {
  const messageTemplate =
    typeof options.message === "string" && options.message.trim().length > 0
      ? options.message.trim()
      : buildStoryComposerPrompt();
  seedLiveNegotiatorWithStoryPrompt(messageTemplate);
  setActiveTab("live-negotiator");
  if (el.message instanceof HTMLElement) {
    window.requestAnimationFrame(() => {
      el.message.focus();
      if (el.message instanceof HTMLTextAreaElement) {
        const caret = el.message.value.length;
        el.message.setSelectionRange(caret, caret);
      }
    });
  }
}

function applyStoryPromptTemplateFromStoryEmptyState() {
  applyStoryComposerMode(state.storyComposerMode, { force: true, focusPrompt: true });
}

function openDeviceNodesFromOperatorQuickStart() {
  setActiveTab("device-nodes");
  if (el.deviceNodeId instanceof HTMLInputElement) {
    window.requestAnimationFrame(() => {
      el.deviceNodeId.focus();
    });
  }
}

function renderStoryTimelinePreviewEmptyState(
  pendingJobs = 0,
  runtimeState = resolveStoryTimelineRuntimeState({ pendingJobs }),
) {
  if (!el.storyTimelinePreview) {
    return;
  }
  const copy = getStoryTimelineCopy();
  const sceneCopy = getStoryScenePresentationCopy();
  const useDesktopQuietRuntime = hasStoryRunActivity() && isStoryDesktopRuntimeQuietViewport();
  const hasPendingJobs = runtimeState === "pending" || runtimeState === "updating";
  const hasError = runtimeState === "error";
  el.storyTimelinePreview.innerHTML = "";
  const wrapper = document.createElement("div");
  wrapper.className = "story-empty-state";
  wrapper.classList.toggle("is-pending", hasPendingJobs);
  wrapper.classList.toggle("is-error", hasError);

  const icon = document.createElement("span");
  icon.className = "story-empty-icon";
  if (hasPendingJobs) {
    icon.classList.add("is-pending");
  }
  if (hasError) {
    icon.classList.add("is-error");
  }
  icon.setAttribute("aria-hidden", "true");
  const iconGlyph = document.createElement("span");
  iconGlyph.className = "story-empty-icon-glyph";
  iconGlyph.textContent = hasPendingJobs ? "..." : hasError ? "!" : "ST";
  const iconLabel = document.createElement("span");
  iconLabel.className = "story-empty-icon-label";
  iconLabel.textContent = hasPendingJobs
    ? (state.languageMode === "ru" ? "Рендер" : "Rendering")
    : hasError
      ? "Retry"
      : (state.languageMode === "ru" ? "Раскадровка" : "Storyboard");
  icon.append(iconGlyph, iconLabel);

  const title = document.createElement("p");
  title.className = "story-empty-title";
  title.textContent = hasPendingJobs ? copy.previewPendingTitle : hasError ? copy.previewErrorTitle : copy.previewEmptyTitle;

  const lead = document.createElement("p");
  lead.className = "story-empty-lead";
  lead.textContent = hasPendingJobs ? copy.previewPendingLead : hasError ? copy.previewErrorLead : copy.previewEmptyLead;

  const hint = document.createElement("p");
  hint.className = "story-empty-hint";
  hint.append(
    hasPendingJobs ? copy.previewPendingHintPrefix : hasError ? copy.previewErrorHintPrefix : copy.previewEmptyHintPrefix,
  );
  const code = document.createElement("code");
  code.textContent = hasPendingJobs ? copy.previewPendingHintCode : hasError ? copy.previewErrorHintCode : copy.previewEmptyHintCode;
  hint.append(
    code,
    hasPendingJobs ? copy.previewPendingHintSuffix : hasError ? copy.previewErrorHintSuffix : copy.previewEmptyHintSuffix,
  );

  const intro = document.createElement("div");
  intro.className = "story-empty-intro";
  intro.append(icon, title, lead, hint);

  const kpis = document.createElement("div");
  kpis.className = "story-empty-kpis";
  kpis.setAttribute("aria-label", state.languageMode === "ru" ? "Ожидаемые результаты таймлайна истории" : "Story timeline expected outputs");

  const kpiItems = [
    { label: copy.kpiSegments, value: hasPendingJobs ? (state.languageMode === "ru" ? "в очереди" : "queued") : "3+" },
    {
      label: copy.kpiAssets,
      value: hasPendingJobs
        ? state.languageMode === "ru"
          ? "готовятся"
          : "preparing"
        : state.languageMode === "ru"
          ? "изображения / звук / видео"
          : "image / audio / video",
    },
    {
      label: copy.kpiRender,
      value: hasPendingJobs ? (state.languageMode === "ru" ? "очередь активна" : "queue active") : "< 60s target",
    },
  ];
  for (const kpiItem of kpiItems) {
    const card = document.createElement("article");
    card.className = "story-empty-kpi";
    const cardLabel = document.createElement("span");
    cardLabel.className = "story-empty-kpi-label";
    cardLabel.textContent = kpiItem.label;
    const cardValue = document.createElement("strong");
    cardValue.className = "story-empty-kpi-value";
    cardValue.textContent = kpiItem.value;
    card.append(cardLabel, cardValue);
    kpis.append(card);
  }
  while (kpis.childElementCount > 2) {
    kpis.lastElementChild?.remove();
  }

  const checklist = document.createElement("ul");
  checklist.className = "story-empty-checklist";
  checklist.setAttribute("aria-label", "Story timeline readiness checklist");
  const checklistItems = [
    hasPendingJobs ? copy.checklistPendingA : copy.checklistIdleA,
    hasPendingJobs ? copy.checklistPendingB : copy.checklistIdleB,
    hasPendingJobs ? copy.checklistPendingC : copy.checklistIdleC,
  ];
  for (const itemText of checklistItems) {
    const item = document.createElement("li");
    item.textContent = itemText;
    checklist.append(item);
  }
  while (checklist.childElementCount > 2) {
    checklist.lastElementChild?.remove();
  }

  const board = document.createElement("div");
  board.className = "story-empty-board story-empty-board-single";

  const readinessCard = document.createElement("article");
  readinessCard.className = "story-empty-board-card";
  const readinessKicker = document.createElement("span");
  readinessKicker.className = "story-empty-board-kicker";
  readinessKicker.textContent = sceneCopy.readinessLabel;
  const readinessNote = document.createElement("p");
  readinessNote.className = "story-empty-board-note";
  readinessNote.textContent = hasPendingJobs
    ? getStoryTimelineNavigatorHint("pending")
    : hasError
      ? getStoryTimelineNavigatorHint("error")
      : sceneCopy.storyboardLaneNote;
  readinessCard.append(readinessKicker, checklist, readinessNote);

  board.append(readinessCard);

  const ctaNote = document.createElement("p");
  ctaNote.className = "story-empty-cta-note";
  ctaNote.textContent = hasPendingJobs ? copy.ctaPending : hasError ? copy.ctaError : copy.ctaIdle;

  const support = document.createElement("div");
  support.className = "story-empty-support";
  support.append(kpis, board);

  wrapper.append(intro, support, ctaNote);
  el.storyTimelinePreview.append(wrapper);
}

function renderStoryTimelinePreview(segment) {
  if (!el.storyTimelinePreview) {
    return;
  }
  const previewShell = el.storyPreviewShell instanceof HTMLElement ? el.storyPreviewShell : null;
  const useDesktopQuietRuntime = isStoryDesktopRuntimeQuietViewport();
  el.storyTimelinePreview.classList.remove("is-pending", "is-ready", "is-error");
  if (!segment) {
    const runtimeState = resolveStoryTimelineRuntimeState();
    previewShell?.classList.remove("is-ready", "is-error");
    previewShell?.classList.add("is-empty");
    el.storyTimelinePreview.classList.add("story-timeline-preview-empty");
    el.storyTimelinePreview.classList.toggle("is-pending", runtimeState === "pending" || runtimeState === "updating");
    el.storyTimelinePreview.classList.toggle("is-error", runtimeState === "error");
    previewShell?.classList.toggle("is-error", runtimeState === "error");
    renderStoryTimelinePreviewEmptyState(state.storyTimelinePendingJobs, runtimeState);
    return;
  }
  const copy = getStoryTimelineCopy();
  const sceneCopy = getStoryScenePresentationCopy();
  previewShell?.classList.add("is-ready");
  previewShell?.classList.remove("is-empty", "is-error");
  el.storyTimelinePreview.classList.remove("story-timeline-preview-empty");
  const videoStatusVariant = segment.videoStatus ? resolveStoryVideoStatusVariant(segment.videoStatus) : "status-neutral";
  const normalizedVideoStatus = (toOptionalText(segment.videoStatus) ?? "").toLowerCase();
  const hasPendingRender =
    normalizedVideoStatus.includes("pending") ||
    normalizedVideoStatus.includes("queue") ||
    normalizedVideoStatus.includes("render");
  if (hasPendingRender || state.storyTimelinePendingJobs > 0) {
    el.storyTimelinePreview.classList.add("is-pending");
  } else if (videoStatusVariant === "status-ok") {
    el.storyTimelinePreview.classList.add("is-ready");
  }
  el.storyTimelinePreview.innerHTML = "";
  const narrative = deriveStorySceneNarrative(segment.text, segment.index);
  const displaySummary = buildStoryPreviewDisplaySummary(segment) || narrative.summary;
  const cueTags = getStorySceneCueTags(segment).slice(0, 2);

  const stage = document.createElement("div");
  stage.className = "story-preview-stage story-preview-stage-editorial";

  const copyColumn = document.createElement("div");
  copyColumn.className = "story-preview-copy";

  const head = document.createElement("div");
  head.className = "story-preview-head";

  const indexPill = document.createElement("span");
  indexPill.className = "story-preview-index";
  indexPill.textContent = copy.previewIndex(segment.index);
  head.appendChild(indexPill);

  if (segment.videoStatus) {
    const statusPill = document.createElement("span");
    statusPill.className = `status-pill story-preview-status ${videoStatusVariant}`;
    statusPill.textContent = formatStoryVideoStatusText(segment.videoStatus);
    head.appendChild(statusPill);
  }

  const title = document.createElement("h4");
  title.className = "story-preview-title";
  title.textContent = narrative.title;

  const summary = document.createElement("p");
  summary.className = "story-preview-summary story-preview-summary-meta";
  summary.textContent = displaySummary;

  const copyCard = document.createElement("article");
  copyCard.className = "story-preview-copy-card story-preview-copy-card-main";

  const text = segment.text.length > 0 ? segment.text : copy.emptySegmentText;
  const textNode = document.createElement("p");
  textNode.className = "story-preview-text";
  textNode.textContent = text;
  copyCard.append(textNode);

  const assets = document.createElement("div");
  assets.className = "story-preview-assets";
  const assetEntries = [];

  if (segment.imageRef) {
    assetEntries.push({
      text: formatStoryAssetPillText("image", compactStoryAssetRef(segment.imageRef)),
      tone: "is-image",
    });
  }
  if (segment.videoRef) {
    assetEntries.push({
      text: formatStoryAssetPillText("video", compactStoryAssetRef(segment.videoRef)),
      tone: "is-video",
    });
  }
  if (segment.audioRef) {
    assetEntries.push({
      text: formatStoryAssetPillText("audio", compactStoryAssetRef(segment.audioRef)),
      tone: "is-audio",
    });
  }
  const visibleAssetEntries = useDesktopQuietRuntime ? assetEntries.slice(0, 2) : assetEntries;
  for (const entry of visibleAssetEntries) {
    assets.appendChild(buildStoryAssetPill(entry.text, entry.tone));
  }
  const hiddenAssetEntries = useDesktopQuietRuntime ? assetEntries.slice(2) : [];
  if (hiddenAssetEntries.length > 0) {
    const overflowText = resolveStoryDesktopSceneAssetsOverflowText(hiddenAssetEntries.length, "");
    if (overflowText) {
      const overflowPill = buildStoryAssetPill(overflowText, "is-empty");
      const fullHiddenSummary = hiddenAssetEntries.map((entry) => entry.text).join(" • ");
      if (overflowPill instanceof HTMLElement && fullHiddenSummary) {
        overflowPill.title = fullHiddenSummary;
        overflowPill.setAttribute("aria-label", fullHiddenSummary);
      }
      assets.appendChild(overflowPill);
    }
  }
  if (assets.childElementCount === 0) {
    assets.appendChild(buildStoryAssetPill(copy.noAssets, "is-empty"));
  }

  const supportStrip = document.createElement("div");
  supportStrip.className = "story-preview-support-strip";

  const summaryCard = document.createElement("article");
  summaryCard.className = "story-preview-rail-card story-preview-support-card";

  const summaryGrid = document.createElement("div");
  summaryGrid.className = "story-preview-summary-grid";

  const mediaCard = document.createElement("div");
  mediaCard.className = "story-preview-summary-item";
  const mediaLabel = document.createElement("span");
  mediaLabel.textContent = sceneCopy.mediaLabel;
  const mediaValue = document.createElement("strong");
  const fullMediaSummary = formatStorySceneMediaSummary(segment);
  const visibleMediaSummary = useDesktopQuietRuntime
    ? resolveStoryDesktopSceneMediaLabel(segment, fullMediaSummary)
    : fullMediaSummary;
  syncStoryCompactTextMeta(mediaValue, visibleMediaSummary, fullMediaSummary);
  const mediaHint = document.createElement("p");
  mediaHint.textContent = cueTags.slice(1).join(" · ");
  mediaCard.append(mediaLabel, mediaValue, mediaHint);

  const statusCard = document.createElement("div");
  statusCard.className = "story-preview-summary-item";
  const statusLabel = document.createElement("span");
  statusLabel.textContent = sceneCopy.statusLabel;
  const statusValue = document.createElement("strong");
  const fullStatusSummary = formatStorySceneStatusSummary(segment);
  const visibleStatusSummary = useDesktopQuietRuntime
    ? resolveStoryDesktopSceneCardStatusLabel(segment.videoStatus, fullStatusSummary)
    : fullStatusSummary;
  syncStoryCompactTextMeta(statusValue, visibleStatusSummary, fullStatusSummary);
  const statusHint = document.createElement("p");
  statusHint.textContent = cueTags[0];
  statusCard.append(statusLabel, statusValue, statusHint);

  summaryGrid.append(mediaCard, statusCard);
  summaryCard.append(summaryGrid);

  const assetsCard = document.createElement("article");
  assetsCard.className = "story-preview-rail-card story-preview-support-card story-preview-support-card-assets";
  const assetsLabel = document.createElement("span");
  assetsLabel.textContent = sceneCopy.assetsLabel;
  assetsCard.append(assetsLabel, assets);

  supportStrip.append(summaryCard, assetsCard);
  copyColumn.append(head, title, summary, copyCard, supportStrip);
  stage.append(copyColumn);
  el.storyTimelinePreview.append(stage);
}

function renderStoryTimelineProgress(count, selectedIndex) {
  const safeCount = Math.max(0, Math.floor(count));
  const safeIndex = Math.max(0, Math.floor(selectedIndex));
  const resolvedIndex = safeCount > 0 ? Math.min(Math.max(safeIndex, 1), safeCount) : 0;
  const progressPercent = safeCount > 0 ? Math.round((resolvedIndex / safeCount) * 100) : 0;
  const hasPendingVideoJobs = Math.max(0, Math.floor(state.storyTimelinePendingJobs ?? 0)) > 0;

  if (el.storyTimelineProgressLabel) {
    el.storyTimelineProgressLabel.textContent = `${progressPercent}%`;
  }
  if (el.storyTimelineProgressBar) {
    el.storyTimelineProgressBar.style.width = `${progressPercent}%`;
  }
  if (el.storyTimelineProgressTrack) {
    el.storyTimelineProgressTrack.setAttribute("aria-valuenow", String(progressPercent));
    const valueText = safeCount > 0 ? `${resolvedIndex}/${safeCount}` : "0/0";
    el.storyTimelineProgressTrack.setAttribute("aria-valuetext", valueText);
    el.storyTimelineProgressTrack.classList.toggle("is-empty", safeCount === 0);
    el.storyTimelineProgressTrack.classList.toggle("is-pending", safeCount > 0 && hasPendingVideoJobs);
    el.storyTimelineProgressTrack.classList.toggle("is-active", safeCount > 0 && !hasPendingVideoJobs);
  }
  if (el.storyTimelineProgressHint) {
    const hintText =
      safeCount > 0
        ? `${resolvedIndex}/${safeCount} segments`
        : hasPendingVideoJobs
          ? state.languageMode === "ru"
            ? "ожидаем первую сцену"
            : "waiting for first scene"
          : "0/0 segments";
    const hintVariant = safeCount === 0 ? "neutral" : hasPendingVideoJobs ? "neutral" : "ok";
    setStatusPill(el.storyTimelineProgressHint, hintText, hintVariant);
  }
  return progressPercent;
}

function syncStoryTimelineGuidance(
  count,
  pendingJobs,
  runtimeState = resolveStoryTimelineRuntimeState({ count, pendingJobs }),
) {
  if (!(el.storyTimelineGuidance instanceof HTMLElement)) {
    return;
  }
  const copy = getStoryTimelineCopy();
  const isReady = runtimeState === "ready";
  const isUpdating = runtimeState === "updating";
  const isPending = runtimeState === "pending";
  const isError = runtimeState === "error";
  el.storyTimelineGuidance.classList.remove("is-hidden");
  el.storyTimelineGuidance.classList.toggle("is-idle", runtimeState === "idle");
  el.storyTimelineGuidance.classList.toggle("is-pending", isPending || isUpdating);
  el.storyTimelineGuidance.classList.toggle("is-ready", isReady);
  el.storyTimelineGuidance.classList.toggle("is-error", isError);
  if (el.storyTimelineGuidanceTitle) {
    const fullTitle = isReady
      ? copy.guidanceReadyTitle
      : isUpdating
        ? copy.guidanceUpdatingTitle
        : isPending
          ? copy.guidancePendingTitle
          : isError
            ? copy.guidanceErrorTitle
          : copy.guidanceIdleTitle;
    const visibleTitle = isStoryDesktopRuntimeQuietViewport()
      ? resolveStoryDesktopTimelineGuidanceTitle(runtimeState, fullTitle)
      : fullTitle;
    syncStoryCompactTextMeta(el.storyTimelineGuidanceTitle, visibleTitle, fullTitle);
  }
  if (el.storyTimelineGuidanceHint) {
    const fullHint = isReady
      ? copy.guidanceReadyHint
      : isUpdating
        ? copy.guidanceUpdatingHint
        : isPending
          ? copy.guidancePendingHint
          : isError
            ? copy.guidanceErrorHint
          : copy.guidanceIdleHint;
    const visibleHint = isStoryDesktopRuntimeQuietViewport()
      ? resolveStoryDesktopTimelineGuidanceHint(runtimeState, fullHint)
      : fullHint;
    el.storyTimelineGuidanceHint.innerHTML = visibleHint;
    if (visibleHint !== fullHint) {
      el.storyTimelineGuidanceHint.title = fullHint;
    } else {
      el.storyTimelineGuidanceHint.removeAttribute("title");
    }
  }
}

function renderStoryTimelineList() {
  if (!el.storyTimelineList) {
    return;
  }
  const copy = getStoryTimelineCopy();
  const sceneCopy = getStoryScenePresentationCopy();
  const useDesktopQuietRuntime = isStoryDesktopRuntimeQuietViewport();
  el.storyTimelineList.innerHTML = "";
  const segments = state.storyTimelineSegments;
  const pendingJobs = Math.max(0, Math.floor(state.storyTimelinePendingJobs ?? 0));
  const runtimeState = resolveStoryTimelineRuntimeState({ count: segments.length, pendingJobs });
  const hasPendingJobs = runtimeState === "pending" || runtimeState === "updating";
  const hasError = runtimeState === "error";
  if (segments.length === 0) {
    const empty = document.createElement("div");
    empty.className = "story-timeline-list-empty";
    empty.classList.toggle("is-pending", hasPendingJobs);
    empty.classList.toggle("is-error", hasError);
    const icon = document.createElement("span");
    icon.className = "story-timeline-list-empty-icon";
    if (hasPendingJobs) {
      icon.classList.add("is-pending");
    }
    if (hasError) {
      icon.classList.add("is-error");
    }
    icon.setAttribute("aria-hidden", "true");
    const iconGlyph = document.createElement("span");
    iconGlyph.className = "story-timeline-list-empty-icon-glyph";
    iconGlyph.textContent = hasPendingJobs ? "..." : hasError ? "!" : "TL";
    const iconLabel = document.createElement("span");
    iconLabel.className = "story-timeline-list-empty-icon-label";
    iconLabel.textContent = hasPendingJobs
      ? state.languageMode === "ru"
        ? "Сборка"
        : "Building"
      : hasError
        ? "Retry"
      : state.languageMode === "ru"
        ? "Раскадровка"
        : "Storyboard";
    icon.append(iconGlyph, iconLabel);

    const title = document.createElement("p");
    title.className = "story-timeline-list-empty-title";
    title.textContent = hasPendingJobs ? copy.listPendingTitle : hasError ? copy.listErrorTitle : copy.listEmptyTitle;

    const hint = document.createElement("p");
    hint.className = "story-timeline-list-empty-hint";
    hint.textContent = hasPendingJobs ? copy.listPendingHint : hasError ? copy.listErrorHint : copy.listEmptyHint;

    const main = document.createElement("div");
    main.className = "story-timeline-list-empty-main";
    main.append(icon, title, hint);

    const preview = document.createElement("div");
    preview.className = "story-timeline-list-empty-preview";
    preview.setAttribute("aria-hidden", "true");
    const sampleCards = [
      {
        kicker: sceneCopy.sampleHookKicker,
        title: copy.sampleSegment(1),
        hint: copy.sampleHook,
      },
      {
        kicker: sceneCopy.sampleConflictKicker,
        title: copy.sampleSegment(2),
        hint: copy.sampleConflict,
      },
      {
        kicker: sceneCopy.sampleResolutionKicker,
        title: copy.sampleSegment(3),
        hint: copy.sampleResolution,
      },
    ];
    for (const sampleCard of sampleCards) {
      const card = document.createElement("article");
      card.className = "story-timeline-list-empty-card";
      const cardKicker = document.createElement("span");
      cardKicker.className = "story-timeline-list-empty-card-kicker";
      cardKicker.textContent = sampleCard.kicker;
      const cardTitle = document.createElement("strong");
      cardTitle.textContent = sampleCard.title;
      const cardHint = document.createElement("span");
      cardHint.textContent = sampleCard.hint;
      card.append(cardKicker, cardTitle, cardHint);
      preview.append(card);
    }

    const board = document.createElement("div");
    board.className = "story-timeline-list-empty-board";
    const boardLabel = document.createElement("p");
    boardLabel.className = "story-timeline-list-empty-board-label";
    boardLabel.textContent = sceneCopy.storyboardLaneLabel;
    const boardNote = document.createElement("p");
    boardNote.className = "story-timeline-list-empty-board-note";
    boardNote.textContent = sceneCopy.storyboardLaneNote;
    board.append(boardLabel, preview, boardNote);

    const ctaNote = document.createElement("p");
    ctaNote.className = "story-timeline-list-empty-cta";
    ctaNote.textContent = hasPendingJobs ? copy.listCtaPending : hasError ? copy.listCtaError : copy.listCtaIdle;

    empty.append(main, board, ctaNote);
    el.storyTimelineList.append(empty);
    return;
  }
  const selectedIndex = state.storyTimelineSelectedIndex;
  for (let idx = 0; idx < segments.length; idx += 1) {
    const segment = segments[idx];
    const narrative = deriveStorySceneNarrative(segment.text, segment.index);
    const cueTags = getStorySceneCueTags(segment).slice(0, 2);

    const card = document.createElement("button");
    card.type = "button";
    card.className = "story-segment-card";
    card.setAttribute("aria-label", `${copy.sampleSegment(segment.index)}: ${narrative.title}`);
    card.dataset.segmentIndex = String(segment.index);
    if (segment.index === selectedIndex) {
      card.classList.add("is-selected");
    }
    card.addEventListener("click", () => {
      updateStoryTimelineSelection(segment.index);
    });

    const head = document.createElement("div");
    head.className = "story-segment-head";

    const index = document.createElement("span");
    index.className = "story-segment-index";
    index.textContent = copy.sampleSegment(segment.index);
    head.appendChild(index);

    const statePill = document.createElement("span");
    statePill.className = "status-pill story-segment-state";
    if (segment.videoStatus) {
      statePill.classList.add(resolveStoryVideoStatusVariant(segment.videoStatus));
      const fullStatusLabel = `${copy.videoPrefix}${segment.videoStatus}`;
      const visibleStatusLabel = useDesktopQuietRuntime
        ? resolveStoryDesktopSceneCardStatusLabel(segment.videoStatus, fullStatusLabel)
        : fullStatusLabel;
      statePill.textContent = visibleStatusLabel;
      if (visibleStatusLabel !== fullStatusLabel) {
        statePill.title = fullStatusLabel;
      }
    } else {
      statePill.classList.add("status-neutral");
      const visibleStatusLabel = useDesktopQuietRuntime
        ? resolveStoryDesktopSceneCardStatusLabel(null, copy.videoNone)
        : copy.videoNone;
      statePill.textContent = visibleStatusLabel;
      if (visibleStatusLabel !== copy.videoNone) {
        statePill.title = copy.videoNone;
      }
    }
    head.appendChild(statePill);

    const title = document.createElement("h4");
    title.className = "story-segment-title";
    title.textContent = narrative.title;

    const body = document.createElement("p");
    body.className = "story-segment-text";
    const fullSegmentSummary = narrative.summary;
    const visibleSegmentSummary = useDesktopQuietRuntime
      ? resolveStoryDesktopSceneCardSummary(fullSegmentSummary, fullSegmentSummary)
      : fullSegmentSummary;
    syncStoryCompactTextMeta(body, visibleSegmentSummary, fullSegmentSummary);

    const cueRow = document.createElement("div");
    cueRow.className = "story-segment-cues";
    for (const cue of cueTags) {
      const cueTag = document.createElement("span");
      cueTag.className = "story-segment-cue";
      cueTag.textContent = cue;
      cueRow.append(cueTag);
    }

    const footer = document.createElement("div");
    footer.className = "story-segment-footer";

    const meta = document.createElement("span");
    meta.className = "story-segment-meta";
    // meta.textContent = formatStorySceneMediaSummary(segment);
    const fullMediaLabel = formatStorySceneMediaSummary(segment);
    const visibleMediaLabel = useDesktopQuietRuntime
      ? resolveStoryDesktopSceneMediaLabel(segment, fullMediaLabel)
      : fullMediaLabel;
    meta.textContent = visibleMediaLabel;
    if (visibleMediaLabel !== fullMediaLabel) {
      meta.title = fullMediaLabel;
    }

    footer.append(cueRow, meta);

    card.append(head, title, body, footer);
    el.storyTimelineList.append(card);
  }
}

function renderStoryTimeline() {
  const copy = getStoryTimelineCopy();
  const segments = state.storyTimelineSegments;
  const count = segments.length;
  const pendingJobs = Math.max(0, Math.floor(state.storyTimelinePendingJobs ?? 0));
  const runtimeState = resolveStoryTimelineRuntimeState({ count, pendingJobs });
  const useDesktopQuietRuntime = isStoryDesktopRuntimeQuietViewport();
  const imageAssetCount = segments.filter((segment) => typeof segment.imageRef === "string").length;
  const videoAssetCount = segments.filter((segment) => typeof segment.videoRef === "string").length;
  const audioAssetCount = segments.filter((segment) => typeof segment.audioRef === "string").length;
  const totalAssetCount = imageAssetCount + videoAssetCount + audioAssetCount;
  const selectedForProgress = count > 0 ? state.storyTimelineSelectedIndex : 0;
  const progressPercent = count > 0 ? Math.round((Math.min(Math.max(selectedForProgress, 1), count) / count) * 100) : 0;
  const runRail = el.storyRunHeading instanceof HTMLElement ? el.storyRunHeading.closest(".story-run-rail") : null;
  if (runRail instanceof HTMLElement) {
    runRail.classList.remove("is-idle", "is-pending", "is-ready", "is-error");
    if (runtimeState === "error") {
      runRail.classList.add("is-error");
    } else if (runtimeState === "pending" || runtimeState === "updating") {
      runRail.classList.add("is-pending");
    } else if (runtimeState === "idle") {
      runRail.classList.add("is-idle");
    } else {
      runRail.classList.add("is-ready");
    }
  }
  const runCopy = getStoryComposerCopy();
  const visibleRunHeading = useDesktopQuietRuntime
    ? resolveStoryDesktopRunRailHeading(runtimeState, runCopy.runHeading)
    : runCopy.runHeading;
  const visibleRunIntro = useDesktopQuietRuntime
    ? resolveStoryDesktopRunRailIntro(runtimeState, pendingJobs, runCopy.runIntro)
    : runCopy.runIntro;
  syncStoryCompactTextMeta(el.storyRunHeading, visibleRunHeading, runCopy.runHeading);
  syncStoryCompactTextMeta(el.storyRunIntro, visibleRunIntro, runCopy.runIntro);
  const runTitleLabel = el.storyTimelineTitle instanceof HTMLElement ? el.storyTimelineTitle.previousElementSibling : null;
  const runTitleNote = el.storyTimelineTitle instanceof HTMLElement ? el.storyTimelineTitle.nextElementSibling : null;
  const runCountLabel = el.storyTimelineCount instanceof HTMLElement ? el.storyTimelineCount.previousElementSibling : null;
  const runQueueLabel = el.storyTimelinePendingJobs instanceof HTMLElement ? el.storyTimelinePendingJobs.previousElementSibling : null;
  const runStateLabel = el.storyTimelineProgressKpi instanceof HTMLElement ? el.storyTimelineProgressKpi.previousElementSibling : null;
  if (runTitleLabel instanceof HTMLElement) {
    syncStoryCompactTextMeta(
      runTitleLabel,
      resolveStoryDesktopRunRailLabel("title", runTitleLabel.textContent ?? ""),
      resolveStoryDesktopRunRailFullLabel("title", runTitleLabel.textContent ?? ""),
    );
  }
  if (runTitleNote instanceof HTMLElement) {
    syncStoryCompactTextMeta(
      runTitleNote,
      resolveStoryDesktopRunRailLabel("titleNote", runTitleNote.textContent ?? ""),
      resolveStoryDesktopRunRailFullLabel("titleNote", runTitleNote.textContent ?? ""),
    );
  }
  if (runCountLabel instanceof HTMLElement) {
    syncStoryCompactTextMeta(
      runCountLabel,
      resolveStoryDesktopRunRailLabel("count", runCountLabel.textContent ?? ""),
      resolveStoryDesktopRunRailFullLabel("count", runCountLabel.textContent ?? ""),
    );
  }
  if (runQueueLabel instanceof HTMLElement) {
    syncStoryCompactTextMeta(
      runQueueLabel,
      resolveStoryDesktopRunRailLabel("queue", runQueueLabel.textContent ?? ""),
      resolveStoryDesktopRunRailFullLabel("queue", runQueueLabel.textContent ?? ""),
    );
  }
  if (runStateLabel instanceof HTMLElement) {
    syncStoryCompactTextMeta(
      runStateLabel,
      resolveStoryDesktopRunRailLabel("state", runStateLabel.textContent ?? ""),
      resolveStoryDesktopRunRailFullLabel("state", runStateLabel.textContent ?? ""),
    );
  }
  const fullTimelineTitle = state.storyTimelineTitle ?? "-";
  const visibleTimelineTitle =
    useDesktopQuietRuntime && typeof fullTimelineTitle === "string"
      ? compactStorySceneCopy(fullTimelineTitle, 52) || fullTimelineTitle
      : fullTimelineTitle;
  syncStoryCompactTextMeta(el.storyTimelineTitle, visibleTimelineTitle, fullTimelineTitle);
  setText(el.storyTimelineCount, String(count));
  setText(el.storyTimelinePendingJobs, String(pendingJobs));
  syncStoryTimelineGuidance(count, pendingJobs, runtimeState);
  renderStoryTimelineStateCard(count, pendingJobs, progressPercent, runtimeState);
  syncStoryTimelineControlState(count, pendingJobs, runtimeState);
  syncStoryTimelineControlUtilityDensity(count, pendingJobs, runtimeState);
  renderStoryTimelineControlsHint(count, pendingJobs, runtimeState);
  renderStoryTimelineListHead(count, pendingJobs, runtimeState);

  if (runtimeState === "error") {
    setStatusPill(el.storyTimelineMode, "run_failed", "neutral");
  } else if (runtimeState === "pending" || runtimeState === "updating") {
    setStatusPill(
      el.storyTimelineMode,
      useDesktopQuietRuntime
        ? resolveStoryDesktopTimelineModePillLabel(runtimeState, "timeline_pending_video")
        : "timeline_pending_video",
      "neutral",
    );
  } else if (runtimeState === "idle") {
    setStatusPill(
      el.storyTimelineMode,
      useDesktopQuietRuntime ? resolveStoryDesktopTimelineModePillLabel("idle", "timeline_idle") : "timeline_idle",
      "neutral",
    );
  } else {
    setStatusPill(
      el.storyTimelineMode,
      useDesktopQuietRuntime ? resolveStoryDesktopTimelineModePillLabel("ready", "timeline_ready") : "timeline_ready",
      "ok",
    );
  }

  if (runtimeState === "error") {
    setStatusPill(el.storyTimelineAssetMix, copy.assetMixError, "neutral");
  } else if (count === 0) {
    setStatusPill(
      el.storyTimelineAssetMix,
      useDesktopQuietRuntime
        ? resolveStoryDesktopTimelineAssetMixPillLabel(0, pendingJobs, pendingJobs > 0 ? "assets=queueing" : "assets=none")
        : pendingJobs > 0
          ? "assets=queueing"
          : "assets=none",
      "neutral",
    );
  } else {
    const assetText = `assets=i${imageAssetCount}/v${videoAssetCount}/a${audioAssetCount}`;
    const hasAnyAssets = totalAssetCount > 0;
    setStatusPill(
      el.storyTimelineAssetMix,
      useDesktopQuietRuntime ? resolveStoryDesktopTimelineAssetMixPillLabel(totalAssetCount, pendingJobs, assetText) : assetText,
      hasAnyAssets ? "ok" : "neutral",
    );
  }

  if (el.storyTimelineScrubber) {
    el.storyTimelineScrubber.min = count > 0 ? "1" : "0";
    el.storyTimelineScrubber.max = count > 0 ? String(count) : "0";
    el.storyTimelineScrubber.value = count > 0 ? String(state.storyTimelineSelectedIndex) : "0";
    el.storyTimelineScrubber.disabled = count === 0;
  }

  if (el.storyTimelineSelect) {
    el.storyTimelineSelect.innerHTML = "";
    if (count === 0) {
      const option = document.createElement("option");
      option.value = "";
      option.textContent = copy.noSegmentsOption;
      el.storyTimelineSelect.append(option);
      el.storyTimelineSelect.disabled = true;
    } else {
      el.storyTimelineSelect.disabled = false;
      for (const segment of segments) {
        const option = document.createElement("option");
        option.value = String(segment.index);
        option.textContent = buildStoryTimelineSelectLabel(segment);
        option.title = typeof segment.text === "string" && segment.text.trim().length > 0 ? segment.text.trim() : copy.emptySegmentText;
        if (segment.index === state.storyTimelineSelectedIndex) {
          option.selected = true;
        }
        el.storyTimelineSelect.append(option);
      }
    }
  }

  if (el.storyTimelinePosition) {
    const fullPositionText =
      count === 0
        ? runtimeState === "error"
          ? copy.positionError
          : state.storyTimelinePendingJobs > 0
          ? copy.positionWaiting
          : "-"
        : `${state.storyTimelineSelectedIndex} / ${count}`;
    const visiblePositionText = useDesktopQuietRuntime
      ? resolveStoryDesktopTimelinePositionText(
          count,
          state.storyTimelineSelectedIndex,
          pendingJobs,
          runtimeState,
          fullPositionText,
        )
      : fullPositionText;
    syncStoryCompactTextMeta(el.storyTimelinePosition, visiblePositionText, fullPositionText);
    el.storyTimelinePosition.setAttribute("aria-label", fullPositionText);
  }

  renderStoryTimelineProgress(count, state.storyTimelineSelectedIndex);
  if (useDesktopQuietRuntime && el.storyTimelineProgressHint) {
    const fullProgressHint =
      count > 0
        ? `${state.storyTimelineSelectedIndex}/${count} segments`
        : pendingJobs > 0
          ? state.languageMode === "ru"
            ? "РѕР¶РёРґР°РµРј РїРµСЂРІСѓСЋ СЃС†РµРЅСѓ"
            : "waiting for first scene"
          : "0/0 segments";
    const visibleProgressHint = resolveStoryDesktopTimelineProgressPillLabel(
      count,
      state.storyTimelineSelectedIndex,
      pendingJobs,
      fullProgressHint,
    );
    const hintVariant = count === 0 ? "neutral" : pendingJobs > 0 ? "neutral" : "ok";
    setStatusPill(el.storyTimelineProgressHint, visibleProgressHint, hintVariant);
    if (el.storyTimelineProgressHint instanceof HTMLElement) {
      if (visibleProgressHint !== fullProgressHint) {
        el.storyTimelineProgressHint.title = fullProgressHint;
      } else {
        el.storyTimelineProgressHint.removeAttribute("title");
      }
    }
  }
  syncStoryTimelineStatusRow(count, pendingJobs, runtimeState);
  renderStoryTimelinePreview(getStoryTimelineSelectedSegment());
  renderStoryTimelineList();
  renderStoryStudioSurface();
  renderDashboardWorkspace();
}

function updateStoryTimelineSelection(nextIndex) {
  const total = state.storyTimelineSegments.length;
  if (total === 0) {
    state.storyTimelineSelectedIndex = 0;
    renderStoryTimeline();
    return;
  }
  const value =
    typeof nextIndex === "number" && Number.isFinite(nextIndex) ? Math.floor(nextIndex) : state.storyTimelineSelectedIndex;
  state.storyTimelineSelectedIndex = Math.min(Math.max(value, 1), total);
  renderStoryTimeline();
}

function setStoryTimelineData({ title = null, timeline = [], pendingVideoJobs = null } = {}) {
  const normalized = Array.isArray(timeline)
    ? timeline
        .map((segment, index) => normalizeStoryTimelineSegment(segment, index))
        .filter(Boolean)
        .sort((left, right) => left.index - right.index)
    : [];
  state.storyTimelineTitle = toOptionalText(title);
  state.storyTimelineSegments = normalized;
  const computedPending =
    typeof pendingVideoJobs === "number" && Number.isFinite(pendingVideoJobs)
      ? Math.max(0, Math.floor(pendingVideoJobs))
      : 0;
  state.storyTimelinePendingJobs = computedPending;

  if (normalized.length === 0) {
    state.storyTimelineSelectedIndex = 0;
  } else if (
    typeof state.storyTimelineSelectedIndex !== "number" ||
    !Number.isFinite(state.storyTimelineSelectedIndex) ||
    state.storyTimelineSelectedIndex < 1 ||
    state.storyTimelineSelectedIndex > normalized.length
  ) {
    state.storyTimelineSelectedIndex = 1;
  }

  renderStoryTimeline();
}

function toNodeText(node, fallback = "") {
  if (!node) {
    return fallback;
  }
  const text = typeof node.textContent === "string" ? node.textContent.trim() : "";
  return text.length > 0 ? text : fallback;
}

function sanitizeFileNamePart(value, fallback) {
  if (typeof value !== "string") {
    return fallback;
  }
  const normalized = value
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9_-]+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "");
  return normalized.length > 0 ? normalized.slice(0, 64) : fallback;
}

function collectEntryLane(container, lane) {
  if (!(container instanceof HTMLElement)) {
    return [];
  }
  const rows = Array.from(container.querySelectorAll(".entry"));
  const mapped = rows.map((entry) => {
    const titleNode = entry.querySelector("small");
    const bodyNode = entry.classList.contains("task-entry")
      ? entry.querySelector(".task-entry-export")
      : entry.querySelector("div");
    return {
      lane,
      title: toNodeText(titleNode, lane),
      message: toNodeText(bodyNode, ""),
    };
  });
  return mapped.reverse();
}

function toIsoNow() {
  return new Date().toISOString();
}

function syncExportControlAvailability() {
  const chunks = Array.isArray(state.assistantAudioChunks) ? state.assistantAudioChunks : [];
  const totalBytes = typeof state.assistantAudioBytesTotal === "number" && Number.isFinite(state.assistantAudioBytesTotal)
    ? Math.max(0, state.assistantAudioBytesTotal)
    : 0;
  const uniqueTurns = new Set(
    chunks
      .map((chunk) => (chunk && typeof chunk.turnId === "string" ? chunk.turnId.trim() : ""))
      .filter((turnId) => turnId.length > 0),
  ).size;
  const hasAudioEvidence =
    totalBytes > 0 &&
    chunks.length > 0;
  if (el.exportAudioBtn instanceof HTMLButtonElement) {
    el.exportAudioBtn.disabled = !hasAudioEvidence;
    el.exportAudioBtn.setAttribute("aria-disabled", hasAudioEvidence ? "false" : "true");
    if (!hasAudioEvidence) {
      el.exportAudioBtn.title =
        state.languageMode === "ru" ? "Аудио ассистента пока недоступно" : "Assistant audio is not available yet";
    } else {
      const turnsLabel = formatLocalizedTurnCount(uniqueTurns);
      const sizeLabel = formatByteSize(totalBytes);
      const trimLabel = state.assistantAudioTrimmed === true ? t("export.audio.trimmed") : "";
      el.exportAudioBtn.title = t("export.audio.ready", { turns: turnsLabel, size: sizeLabel, trimmed: trimLabel });
    }
  }
  if (el.exportAudioHint instanceof HTMLElement) {
    if (!hasAudioEvidence) {
      el.exportAudioHint.textContent =
        state.languageMode === "ru" ? "Аудио ассистента (нужен захват)" : "Assistant audio evidence (capture required)";
    } else {
      const turnsLabel = formatLocalizedTurnCount(uniqueTurns);
      const sizeLabel = formatByteSize(totalBytes);
      const trimLabel = state.assistantAudioTrimmed === true ? t("export.audio.trimmed") : "";
      el.exportAudioHint.textContent = t("export.audio.evidence", {
        turns: turnsLabel,
        size: sizeLabel,
        trimmed: trimLabel,
      });
    }
  }
}

function resetAssistantAudioExport() {
  state.assistantAudioChunks = [];
  state.assistantAudioBytesTotal = 0;
  state.assistantAudioSampleRate = 16000;
  state.assistantAudioTrimmed = false;
  syncExportControlAvailability();
}

function copyInt16Bytes(samples) {
  if (!(samples instanceof Int16Array) || samples.length === 0) {
    return new Uint8Array(0);
  }
  const start = samples.byteOffset;
  const end = start + samples.byteLength;
  return new Uint8Array(samples.buffer.slice(start, end));
}

function recordAssistantAudioChunk(samples, sampleRate = 16000, turnId = null) {
  const bytes = copyInt16Bytes(samples);
  if (bytes.byteLength === 0) {
    return;
  }
  const normalizedSampleRate =
    typeof sampleRate === "number" && Number.isFinite(sampleRate) && sampleRate > 0 ? Math.floor(sampleRate) : 16000;
  if (state.assistantAudioChunks.length === 0) {
    state.assistantAudioSampleRate = normalizedSampleRate;
  }

  state.assistantAudioChunks.push({
    bytes,
    turnId: typeof turnId === "string" && turnId.trim().length > 0 ? turnId.trim() : null,
  });
  state.assistantAudioBytesTotal += bytes.byteLength;

  while (state.assistantAudioBytesTotal > MAX_ASSISTANT_AUDIO_EXPORT_BYTES && state.assistantAudioChunks.length > 1) {
    const removed = state.assistantAudioChunks.shift();
    if (removed && removed.bytes instanceof Uint8Array) {
      state.assistantAudioBytesTotal = Math.max(0, state.assistantAudioBytesTotal - removed.bytes.byteLength);
      state.assistantAudioTrimmed = true;
    }
  }
  syncExportControlAvailability();
}

function collectAssistantAudioBytes() {
  if (!Array.isArray(state.assistantAudioChunks) || state.assistantAudioChunks.length === 0) {
    return new Uint8Array(0);
  }
  const totalBytes = state.assistantAudioChunks.reduce((sum, chunk) => {
    if (!chunk || !(chunk.bytes instanceof Uint8Array)) {
      return sum;
    }
    return sum + chunk.bytes.byteLength;
  }, 0);
  if (!Number.isFinite(totalBytes) || totalBytes <= 0) {
    return new Uint8Array(0);
  }
  const merged = new Uint8Array(totalBytes);
  let offset = 0;
  for (const chunk of state.assistantAudioChunks) {
    if (!chunk || !(chunk.bytes instanceof Uint8Array)) {
      continue;
    }
    merged.set(chunk.bytes, offset);
    offset += chunk.bytes.byteLength;
  }
  return merged;
}

function buildAssistantAudioSummary() {
  const uniqueTurns = new Set();
  for (const chunk of state.assistantAudioChunks) {
    const turnId = chunk && typeof chunk.turnId === "string" ? chunk.turnId : null;
    if (turnId) {
      uniqueTurns.add(turnId);
    }
  }
  return {
    totalChunks: state.assistantAudioChunks.length,
    totalBytes: state.assistantAudioBytesTotal,
    sampleRate: state.assistantAudioSampleRate,
    uniqueTurns: uniqueTurns.size,
    trimmed: state.assistantAudioTrimmed === true,
    maxBytes: MAX_ASSISTANT_AUDIO_EXPORT_BYTES,
  };
}

function formatByteSize(bytes) {
  if (typeof bytes !== "number" || !Number.isFinite(bytes) || bytes <= 0) {
    return "0 B";
  }
  if (bytes < 1024) {
    return `${bytes} B`;
  }
  if (bytes < 1024 * 1024) {
    return `${(bytes / 1024).toFixed(1)} KB`;
  }
  return `${(bytes / (1024 * 1024)).toFixed(2)} MB`;
}

function buildPcm16WavBytes(pcmBytes, sampleRate = 16000, channels = 1) {
  const safePcm = pcmBytes instanceof Uint8Array ? pcmBytes : new Uint8Array(0);
  const safeSampleRate =
    typeof sampleRate === "number" && Number.isFinite(sampleRate) && sampleRate > 0 ? Math.floor(sampleRate) : 16000;
  const safeChannels = channels === 2 ? 2 : 1;
  const bitsPerSample = 16;
  const blockAlign = (safeChannels * bitsPerSample) / 8;
  const byteRate = safeSampleRate * blockAlign;
  const dataSize = safePcm.byteLength;
  const buffer = new ArrayBuffer(44 + dataSize);
  const view = new DataView(buffer);
  const out = new Uint8Array(buffer);

  function writeAscii(offset, text) {
    for (let i = 0; i < text.length; i += 1) {
      view.setUint8(offset + i, text.charCodeAt(i));
    }
  }

  writeAscii(0, "RIFF");
  view.setUint32(4, 36 + dataSize, true);
  writeAscii(8, "WAVE");
  writeAscii(12, "fmt ");
  view.setUint32(16, 16, true);
  view.setUint16(20, 1, true);
  view.setUint16(22, safeChannels, true);
  view.setUint32(24, safeSampleRate, true);
  view.setUint32(28, byteRate, true);
  view.setUint16(32, blockAlign, true);
  view.setUint16(34, bitsPerSample, true);
  writeAscii(36, "data");
  view.setUint32(40, dataSize, true);
  out.set(safePcm, 44);
  return out;
}

function buildSessionExportOperatorSessionReplay() {
  const snapshot = isRecord(state.operatorSessionReplaySnapshot) ? state.operatorSessionReplaySnapshot : {};
  const selectedSession = isRecord(snapshot.selectedSession) ? snapshot.selectedSession : null;
  const recentEvents = Array.isArray(snapshot.recentEvents) ? snapshot.recentEvents.slice(0, 20) : [];
  return {
    status: toOptionalText(snapshot.status) ?? "idle",
    loadedAt: toOptionalText(snapshot.loadedAt) ?? toOptionalText(state.operatorSessionReplayLoadedAt),
    totalSessions: Math.max(0, Math.floor(Number(snapshot.totalSessions ?? state.operatorSessionReplaySessions.length ?? 0) || 0)),
    selectedSessionId: toOptionalText(snapshot.selectedSessionId),
    selectedSession,
    totalEvents: Math.max(0, Math.floor(Number(snapshot.totalEvents ?? recentEvents.length) || 0)),
    recentEvents,
  };
}

function buildSessionExportOperatorDiscovery() {
  const snapshot = isRecord(state.operatorDiscoverySnapshot) ? state.operatorDiscoverySnapshot : {};
  return {
    status: toOptionalText(snapshot.status) ?? "idle",
    loadedAt: toOptionalText(snapshot.loadedAt) ?? toOptionalText(state.operatorDiscoveryLoadedAt),
    totalPersonas: Math.max(0, Math.floor(Number(snapshot.totalPersonas ?? 0) || 0)),
    totalRecipes: Math.max(0, Math.floor(Number(snapshot.totalRecipes ?? 0) || 0)),
    agentIds: Array.isArray(snapshot.agentIds) ? snapshot.agentIds.slice(0, 20) : [],
    personas: Array.isArray(snapshot.personas) ? snapshot.personas.slice(0, 8) : [],
    recipes: Array.isArray(snapshot.recipes) ? snapshot.recipes.slice(0, 8) : [],
  };
}

function buildSessionExportPayload() {
  const audioSummary = buildAssistantAudioSummary();
  const selectedStorySegment = getStoryTimelineSelectedSegment();
  const runtimeGuardrailsSignalPaths = buildSessionExportRuntimeGuardrailsEvidence();
  const operatorPurpose = cloneOperatorPurposeDeclaration(state.operatorPurposeDeclaration);
  const operatorSessionReplay = buildSessionExportOperatorSessionReplay();
  const operatorDiscovery = buildSessionExportOperatorDiscovery();
  return {
    schemaVersion: 1,
    generatedAt: toIsoNow(),
    context: {
      wsUrl: state.wsUrl,
      apiBaseUrl: state.apiBaseUrl,
      sessionId: state.sessionId,
      runId: state.runId,
      userId: state.userId,
      mode: state.mode,
      sessionState: state.sessionState,
      connectionStatus: state.connectionStatus,
      targetLanguage: toOptionalText(el.targetLanguage?.value) ?? null,
    },
    approvals: {
      pendingApprovalId: state.pendingApproval?.approvalId ?? null,
      pendingApprovalStatus: state.pendingApproval?.status ?? null,
      approvalStatusText: toNodeText(el.approvalStatus, "idle"),
    },
    kpi: {
      target: {
        price: toNodeText(el.targetPrice, "-"),
        delivery: toNodeText(el.targetDelivery, "-"),
        sla: toNodeText(el.targetSla, "-"),
      },
      currentOffer: {
        price: toNodeText(el.currentPrice, "-"),
        delivery: toNodeText(el.currentDelivery, "-"),
        sla: toNodeText(el.currentSla, "-"),
      },
      finalOffer: {
        price: toNodeText(el.finalPrice, "-"),
        delivery: toNodeText(el.finalDelivery, "-"),
        sla: toNodeText(el.finalSla, "-"),
      },
      constraintStatus: toNodeText(el.constraintStatus, "-"),
      fallbackAssetStatus: toNodeText(el.fallbackAssetStatus, "-"),
    },
    storyTimeline: {
      title: state.storyTimelineTitle,
      totalSegments: state.storyTimelineSegments.length,
      selectedIndex: state.storyTimelineSelectedIndex > 0 ? state.storyTimelineSelectedIndex : null,
      pendingVideoJobs: Math.max(0, Math.floor(state.storyTimelinePendingJobs ?? 0)),
      selectedSegment: selectedStorySegment,
      segments: state.storyTimelineSegments,
    },
    audio: {
      exportFormat: "pcm16-wav",
      ...audioSummary,
    },
    operatorEvidence: {
      operatorPurpose,
      operatorSessionReplay,
      operatorDiscovery,
      runtimeGuardrailsSignalPaths,
    },
    transcript: collectEntryLane(el.transcript, "transcript"),
    events: collectEntryLane(el.events, "events"),
    operatorSummary: collectEntryLane(el.operatorSummary, "operator_summary"),
    tasks: collectEntryLane(el.tasks, "tasks"),
  };
}

function toMarkdownExport(payload) {
  const lines = [];
  lines.push("# Live Agent Session Export");
  lines.push("");
  lines.push(`- generatedAt: ${payload.generatedAt}`);
  lines.push(`- sessionId: ${payload.context.sessionId ?? "-"}`);
  lines.push(`- runId: ${payload.context.runId ?? "-"}`);
  lines.push(`- userId: ${payload.context.userId ?? "-"}`);
  lines.push(`- mode: ${payload.context.mode ?? "-"}`);
  lines.push(`- connectionStatus: ${payload.context.connectionStatus ?? "-"}`);
  lines.push(`- sessionState: ${payload.context.sessionState ?? "-"}`);
  lines.push(`- targetLanguage: ${payload.context.targetLanguage ?? "-"}`);
  lines.push("");
  lines.push("## KPI Snapshot");
  lines.push("");
  lines.push(`- target: price=${payload.kpi.target.price}, delivery=${payload.kpi.target.delivery}, sla=${payload.kpi.target.sla}`);
  lines.push(
    `- current: price=${payload.kpi.currentOffer.price}, delivery=${payload.kpi.currentOffer.delivery}, sla=${payload.kpi.currentOffer.sla}`,
  );
  lines.push(`- final: price=${payload.kpi.finalOffer.price}, delivery=${payload.kpi.finalOffer.delivery}, sla=${payload.kpi.finalOffer.sla}`);
  lines.push(`- constraintStatus: ${payload.kpi.constraintStatus}`);
  lines.push(`- fallbackAsset: ${payload.kpi.fallbackAssetStatus}`);
  lines.push("");
  lines.push("## Story Timeline Snapshot");
  lines.push("");
  lines.push(`- title: ${payload.storyTimeline?.title ?? "-"}`);
  lines.push(`- totalSegments: ${payload.storyTimeline?.totalSegments ?? 0}`);
  lines.push(`- selectedIndex: ${payload.storyTimeline?.selectedIndex ?? "-"}`);
  lines.push(`- pendingVideoJobs: ${payload.storyTimeline?.pendingVideoJobs ?? 0}`);
  if (
    payload.storyTimeline?.selectedSegment &&
    typeof payload.storyTimeline.selectedSegment === "object" &&
    typeof payload.storyTimeline.selectedSegment.index === "number"
  ) {
    const selectedSegment = payload.storyTimeline.selectedSegment;
    lines.push(
      `- selectedSegment: #${selectedSegment.index} ${toOptionalText(selectedSegment.text) ?? "(empty segment text)"}`,
    );
  }
  lines.push("");
  lines.push("## Audio Export Snapshot");
  lines.push("");
  lines.push(`- format: ${payload.audio.exportFormat ?? "pcm16-wav"}`);
  lines.push(`- sampleRate: ${payload.audio.sampleRate ?? 16000}`);
  lines.push(`- totalChunks: ${payload.audio.totalChunks ?? 0}`);
  lines.push(`- totalBytes: ${payload.audio.totalBytes ?? 0}`);
  lines.push(`- uniqueTurns: ${payload.audio.uniqueTurns ?? 0}`);
  lines.push(`- trimmed: ${payload.audio.trimmed === true}`);
  lines.push("");
  lines.push("## Operator Purpose");
  lines.push("");
  if (payload.operatorEvidence?.operatorPurpose && typeof payload.operatorEvidence.operatorPurpose === "object") {
    lines.push(`- category: ${payload.operatorEvidence.operatorPurpose.category ?? "other"}`);
    lines.push(`- declaredAt: ${payload.operatorEvidence.operatorPurpose.declaredAt ?? "-"}`);
    lines.push(`- purpose: ${payload.operatorEvidence.operatorPurpose.purpose ?? "-"}`);
  } else {
    lines.push("- purpose: (not declared)");
  }
  lines.push("");
  lines.push("## Session Replay");
  lines.push("");
  lines.push(`- status: ${payload.operatorEvidence?.operatorSessionReplay?.status ?? "idle"}`);
  lines.push(`- loadedAt: ${payload.operatorEvidence?.operatorSessionReplay?.loadedAt ?? "-"}`);
  lines.push(`- totalSessions: ${payload.operatorEvidence?.operatorSessionReplay?.totalSessions ?? 0}`);
  lines.push(`- selectedSessionId: ${payload.operatorEvidence?.operatorSessionReplay?.selectedSessionId ?? "-"}`);
  lines.push(`- totalEvents: ${payload.operatorEvidence?.operatorSessionReplay?.totalEvents ?? 0}`);
  if ((payload.operatorEvidence?.operatorSessionReplay?.recentEvents?.length ?? 0) === 0) {
    lines.push("- recentEvents: (empty)");
  } else {
    for (const item of payload.operatorEvidence.operatorSessionReplay.recentEvents) {
      lines.push(
        `- ${item.type ?? "event"} @ ${item.createdAt ?? "unknown"} :: ${item.message ?? item.stage ?? item.runId ?? "n/a"}`,
      );
    }
  }
  lines.push("");
  lines.push("## Cross-Agent Discovery");
  lines.push("");
  lines.push(`- status: ${payload.operatorEvidence?.operatorDiscovery?.status ?? "idle"}`);
  lines.push(`- loadedAt: ${payload.operatorEvidence?.operatorDiscovery?.loadedAt ?? "-"}`);
  lines.push(`- totalPersonas: ${payload.operatorEvidence?.operatorDiscovery?.totalPersonas ?? 0}`);
  lines.push(`- totalRecipes: ${payload.operatorEvidence?.operatorDiscovery?.totalRecipes ?? 0}`);
  lines.push(`- agentIds: ${(payload.operatorEvidence?.operatorDiscovery?.agentIds ?? []).join(",") || "none"}`);
  lines.push("## Runtime Guardrails Signal Paths");
  lines.push("");
  lines.push(`- status: ${payload.operatorEvidence?.runtimeGuardrailsSignalPaths?.status ?? "awaiting_refresh"}`);
  lines.push(`- signals: ${payload.operatorEvidence?.runtimeGuardrailsSignalPaths?.signalsSummary ?? "n/a"}`);
  lines.push(`- coverage: ${payload.operatorEvidence?.runtimeGuardrailsSignalPaths?.coverageSummary ?? "n/a"}`);
  lines.push(`- sandbox: ${payload.operatorEvidence?.runtimeGuardrailsSignalPaths?.sandboxSummary ?? "n/a"}`);
  lines.push(`- skills: ${payload.operatorEvidence?.runtimeGuardrailsSignalPaths?.skillsSummary ?? "n/a"}`);
  lines.push(`- topSignal: ${payload.operatorEvidence?.runtimeGuardrailsSignalPaths?.topSignal ?? "n/a"}`);
  lines.push(`- historyStatus: ${payload.operatorEvidence?.runtimeGuardrailsSignalPaths?.historyStatus ?? "n/a"}`);
  lines.push(`- lifecycleCounts: ${payload.operatorEvidence?.runtimeGuardrailsSignalPaths?.lifecycleSummary ?? "none"}`);
  if (
    payload.operatorEvidence?.runtimeGuardrailsSignalPaths?.primaryPath &&
    typeof payload.operatorEvidence.runtimeGuardrailsSignalPaths.primaryPath === "object"
  ) {
    const primaryPath = payload.operatorEvidence.runtimeGuardrailsSignalPaths.primaryPath;
    lines.push(`- primaryPath: ${primaryPath.title ?? "Recovery path"} [${primaryPath.lifecycle?.statusText ?? "active"}]`);
  } else {
    lines.push("- primaryPath: (none)");
  }
  if ((payload.operatorEvidence?.runtimeGuardrailsSignalPaths?.paths?.length ?? 0) === 0) {
    lines.push("- signalPaths: (empty)");
  } else {
    for (const path of payload.operatorEvidence.runtimeGuardrailsSignalPaths.paths) {
      lines.push(
        `- ${path.title ?? "Recovery path"} [${path.lifecycle?.statusText ?? "active"}] :: ${path.summaryText ?? "n/a"} :: ${path.lifecycle?.detailText ?? "n/a"}`,
      );
    }
  }
  lines.push("");
  lines.push("## Transcript");
  lines.push("");
  if (payload.transcript.length === 0) {
    lines.push("- (empty)");
  } else {
    for (const row of payload.transcript) {
      lines.push(`- ${row.title}: ${row.message}`);
    }
  }
  lines.push("");
  lines.push("## Events");
  lines.push("");
  if (payload.events.length === 0) {
    lines.push("- (empty)");
  } else {
    for (const row of payload.events) {
      lines.push(`- ${row.title}: ${row.message}`);
    }
  }
  lines.push("");
  lines.push("## Operator Summary");
  lines.push("");
  if (payload.operatorSummary.length === 0) {
    lines.push("- (empty)");
  } else {
    for (const row of payload.operatorSummary) {
      lines.push(`- ${row.title}: ${row.message}`);
    }
  }
  lines.push("");
  lines.push("## Notes");
  lines.push("");
  lines.push("- Audio is streamed realtime; this export includes audio snapshot metadata.");
  lines.push("- Use `Export Session Audio (WAV)` for downloadable assistant output audio.");
  return lines.join("\n");
}

function triggerDownload(filename, contents, mimeType) {
  const blob = new Blob([contents], { type: mimeType });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = filename;
  document.body.appendChild(link);
  link.click();
  link.remove();
  window.setTimeout(() => {
    URL.revokeObjectURL(url);
  }, 0);
}

function buildSessionExportBaseName() {
  const sessionPart = sanitizeFileNamePart(state.sessionId, "session");
  const runPart = sanitizeFileNamePart(state.runId, "run");
  const stamp = new Date()
    .toISOString()
    .replace(/[:.]/g, "-")
    .replace("T", "_")
    .replace("Z", "");
  return `live-agent-${sessionPart}-${runPart}-${stamp}`;
}

function focusExportMenuAction(edge = "start") {
  const actionButtons = [el.exportMarkdownBtn, el.exportJsonBtn, el.exportAudioBtn].filter(
    (button) => button instanceof HTMLButtonElement && !button.disabled,
  );
  if (actionButtons.length === 0) {
    return focusExportMenuSummary();
  }
  const targetButton = edge === "end" ? actionButtons[actionButtons.length - 1] : actionButtons[0];
  targetButton.focus();
  return document.activeElement === targetButton;
}

function focusExportMenuSummary() {
  const summary = el.exportMenu instanceof HTMLDetailsElement ? el.exportMenu.querySelector(":scope > summary") : null;
  if (summary instanceof HTMLElement) {
    summary.focus();
    return document.activeElement === summary;
  }
  return false;
}

function closeExportMenu(options = {}) {
  if (el.exportMenu instanceof HTMLDetailsElement) {
    el.exportMenu.open = false;
    const summary = el.exportMenu.querySelector(":scope > summary");
    if (summary instanceof HTMLElement) {
      summary.setAttribute("aria-expanded", "false");
      if (options.restoreFocus === true) {
        scheduleDeferredFocus(() => {
          focusExportMenuSummary();
        }, LIVE_CONTEXT_DISCLOSURE_FOCUS_DELAYS);
      }
    }
  }
}

function exportSessionMarkdown() {
  const payload = buildSessionExportPayload();
  const markdown = toMarkdownExport(payload);
  const fileName = `${buildSessionExportBaseName()}.md`;
  triggerDownload(fileName, markdown, "text/markdown;charset=utf-8");
  setExportStatus(`markdown exported (${fileName})`);
  appendTranscript("system", `Session markdown export downloaded: ${fileName}`);
}

function exportSessionJson() {
  const payload = buildSessionExportPayload();
  const fileName = `${buildSessionExportBaseName()}.json`;
  triggerDownload(fileName, `${JSON.stringify(payload, null, 2)}\n`, "application/json;charset=utf-8");
  setExportStatus(`json exported (${fileName})`);
  appendTranscript("system", `Session JSON export downloaded: ${fileName}`);
}

function exportSessionAudio() {
  const pcmBytes = collectAssistantAudioBytes();
  if (!(pcmBytes instanceof Uint8Array) || pcmBytes.byteLength === 0) {
    setExportStatus("audio export skipped (no audio)");
    appendTranscript("system", "Session audio export skipped: no assistant audio captured yet");
    return;
  }
  const sampleRate =
    typeof state.assistantAudioSampleRate === "number" && Number.isFinite(state.assistantAudioSampleRate)
      ? Math.max(8000, Math.floor(state.assistantAudioSampleRate))
      : 16000;
  const wavBytes = buildPcm16WavBytes(pcmBytes, sampleRate, 1);
  const fileName = `${buildSessionExportBaseName()}.wav`;
  triggerDownload(fileName, wavBytes, "audio/wav");
  const sizeText = formatByteSize(pcmBytes.byteLength);
  setExportStatus(`audio exported (${fileName})`);
  appendTranscript("system", `Session audio export downloaded: ${fileName} (${sizeText})`);
}

function normalizeTaskRecord(value) {
  if (!value || typeof value !== "object") {
    return null;
  }
  const taskId = typeof value.taskId === "string" ? value.taskId : null;
  if (!taskId || taskId.trim().length === 0) {
    return null;
  }
  return {
    taskId: taskId.trim(),
    sessionId: typeof value.sessionId === "string" ? value.sessionId : state.sessionId,
    runId: typeof value.runId === "string" ? value.runId : null,
    intent: typeof value.intent === "string" ? value.intent : null,
    route: typeof value.route === "string" ? value.route : null,
    status: typeof value.status === "string" ? value.status : "running",
    progressPct: typeof value.progressPct === "number" ? value.progressPct : 0,
    stage: typeof value.stage === "string" ? value.stage : "unknown",
    updatedAt: typeof value.updatedAt === "string" ? value.updatedAt : new Date().toISOString(),
    error: typeof value.error === "string" ? value.error : null,
  };
}

function applyIntentTemplateFromActiveTasks(intentValue, messageTemplate) {
  setActiveTab("live-negotiator");
  if (el.intent instanceof HTMLSelectElement && typeof intentValue === "string" && intentValue.trim().length > 0) {
    el.intent.value = intentValue.trim();
    syncCustomSelectControl(el.intent);
    setUiTaskFieldsVisibility();
  }
  if (
    (el.targetLanguage instanceof HTMLInputElement || el.targetLanguage instanceof HTMLSelectElement) &&
    intentValue === "translation" &&
    el.targetLanguage.value.trim().length === 0
  ) {
    el.targetLanguage.value = "en";
    if (el.targetLanguage instanceof HTMLSelectElement) {
      syncCustomSelectControl(el.targetLanguage);
    }
  }
  if (el.message instanceof HTMLTextAreaElement && typeof messageTemplate === "string" && messageTemplate.trim().length > 0) {
    el.message.value = messageTemplate.trim();
  } else if (el.message instanceof HTMLTextAreaElement && intentValue === "translation") {
    el.message.value = "";
  }
  if (el.message instanceof HTMLTextAreaElement) {
    window.requestAnimationFrame(() => {
      el.message.focus();
      const caret = el.message.value.length;
      el.message.setSelectionRange(caret, caret);
    });
  }
}

