function syncDeviceNodeSurfaceVisibility(hasNodes = state.deviceNodes instanceof Map && state.deviceNodes.size > 0) {
  const revealFleet = Boolean(hasNodes);
  setDeviceNodeSurfaceHidden(el.deviceNodeSelectionStrip, !revealFleet);
  setDeviceNodeSurfaceHidden(el.deviceNodeFleetSummary, !revealFleet);
  setDeviceNodeSurfaceHidden(el.deviceNodeSnapshot, !revealFleet);
  setDeviceNodeSurfaceHidden(el.deviceNodeAdvancedControls, !revealFleet);
  setDeviceNodeSurfaceHidden(el.deviceNodeListShellRail, !revealFleet);
  setDeviceNodeSurfaceHidden(el.deviceNodeListHint, !revealFleet);
}

function syncDeviceNodeSupportLayout() {
  if (!(el.deviceNodeStack instanceof HTMLElement)) {
    return;
  }
  const hasNodes = state.deviceNodes.size > 0;
  syncDeviceNodeSurfaceVisibility(hasNodes);
  const primaryOpen = el.deviceNodePrimaryShell instanceof HTMLDetailsElement ? el.deviceNodePrimaryShell.open : false;
  const advancedOpen =
    el.deviceNodeAdvancedControls instanceof HTMLDetailsElement ? el.deviceNodeAdvancedControls.open : false;
  let layout = "dual-collapsed";
  if (!hasNodes) {
    layout = primaryOpen ? "empty-primary" : "empty-idle";
  } else if (primaryOpen && advancedOpen) {
    layout = "dual-open";
  } else if (primaryOpen) {
    layout = "primary-focus";
  } else if (advancedOpen) {
    layout = "advanced-focus";
  }
  el.deviceNodeStack.dataset.supportLayout = layout;
}

function selectDeviceNode(node, options = {}) {
  if (!node) {
    applyDeviceNodeToForm(null);
    return;
  }
  applyDeviceNodeToForm(node);
  if (options.openPrimary === true) {
    if (options.closeAdvanced === true) {
      setDeviceNodeAdvancedShellOpen(false);
    }
    setDeviceNodePrimaryShellOpen(true);
    if (options.reveal !== false && el.deviceNodePrimaryShell instanceof HTMLElement) {
      requestAnimationFrame(() => {
        el.deviceNodePrimaryShell.scrollIntoView({ block: "nearest" });
      });
    }
  }
  if (options.openAdvanced === true) {
    setDeviceNodeAdvancedShellOpen(true);
    if (options.closePrimary === true) {
      setDeviceNodePrimaryShellOpen(false);
    }
    if (options.reveal !== false && el.deviceNodeAdvancedControls instanceof HTMLElement) {
      requestAnimationFrame(() => {
        el.deviceNodeAdvancedControls.scrollIntoView({ block: "nearest" });
      });
    }
  }
}

