  const operatorEvidenceDrawerTabs = Array.from(document.querySelectorAll("[data-operator-evidence-view]"))
    .filter((button) => button instanceof HTMLButtonElement);
  const focusOperatorEvidenceDrawerButtonByIndex = (index) => {
    if (operatorEvidenceDrawerTabs.length === 0) {
      return;
    }
    const boundedIndex = (index + operatorEvidenceDrawerTabs.length) % operatorEvidenceDrawerTabs.length;
    const nextButton = operatorEvidenceDrawerTabs[boundedIndex];
    nextButton.focus();
    setOperatorEvidenceDrawerView(nextButton.dataset.operatorEvidenceView ?? "");
  };
  for (const button of operatorEvidenceDrawerTabs) {
    button.addEventListener("click", () => {
      setOperatorEvidenceDrawerView(button.dataset.operatorEvidenceView ?? "");
    });
    button.addEventListener("keydown", (event) => {
      const currentIndex = operatorEvidenceDrawerTabs.findIndex((candidate) => candidate === button);
      if (currentIndex < 0) {
        return;
      }
      if (event.key === "ArrowRight" || event.key === "ArrowDown") {
        event.preventDefault();
        focusOperatorEvidenceDrawerButtonByIndex(currentIndex + 1);
        return;
      }
      if (event.key === "ArrowLeft" || event.key === "ArrowUp") {
        event.preventDefault();
        focusOperatorEvidenceDrawerButtonByIndex(currentIndex - 1);
        return;
      }
      if (event.key === "Home") {
        event.preventDefault();
        focusOperatorEvidenceDrawerButtonByIndex(0);
        return;
      }
      if (event.key === "End") {
        event.preventDefault();
        focusOperatorEvidenceDrawerButtonByIndex(operatorEvidenceDrawerTabs.length - 1);
        return;
      }
      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        setOperatorEvidenceDrawerView(button.dataset.operatorEvidenceView ?? "", { focus: true });
      }
    });
  }
